<?php
if ( ! defined( 'ABSPATH' ) ) {
    exit;
}
class MLP_Projects {
    const LS_KEY = 'mlp_projects';
    public static function init() {
        add_action( 'wp_head',   [ __CLASS__, 'output_styles'  ], 99 );
        add_action( 'wp_footer', [ __CLASS__, 'output_popup'   ],  1 );
        add_action( 'init',               [ __CLASS__, 'mlp_handle_preview_endpoint' ], 1 );
        add_filter( 'query_vars',         [ __CLASS__, 'mlp_register_query_vars'     ]    );
        add_filter( 'redirect_canonical', [ __CLASS__, 'mlp_prevent_canonical_redirect' ] );
        add_action( 'init',                   [ __CLASS__, 'mlp_disable_page_cache_for_share_urls' ], 0 );
        add_action( 'init',                   [ __CLASS__, 'mlp_serve_og_to_bots'        ], 2 );
        add_action( 'init',                   [ __CLASS__, 'mlp_handle_og_image_endpoint' ], 3 );
        add_action( 'wp_head',                [ __CLASS__, 'mlp_output_og_tags'           ], 1 );
        add_filter( 'pre_get_document_title', [ __CLASS__, 'mlp_filter_og_title'          ]    );
    }
    public static function mlp_disable_page_cache_for_share_urls() {
        if ( ! isset( $_GET['mlpsht'] ) && ! isset( $_GET['mlp_og_image'] ) ) return;
        if ( ! defined( 'DONOTCACHEPAGE'   ) ) define( 'DONOTCACHEPAGE',   true );
        if ( ! defined( 'DONOTCACHEOBJECT' ) ) define( 'DONOTCACHEOBJECT', true );
        if ( ! defined( 'DONOTMINIFY'      ) ) define( 'DONOTMINIFY',      true );
        if ( ! defined( 'DONOTCDN'         ) ) define( 'DONOTCDN',         true );
        // Tell HTTP-level caches (reverse proxies, CDNs, Varnish, LiteSpeed)
        // not to store this response.  PHP constants only affect WordPress-aware
        // plugins; HTTP headers are the only way to stop lower-level caches.
        if ( ! headers_sent() ) {
            header( 'Cache-Control: no-store, no-cache, must-revalidate, max-age=0' );
            header( 'Pragma: no-cache' );
            header( 'Expires: ' . gmdate( 'D, d M Y H:i:s', time() - 3600 ) . ' GMT' );
        }
    }
    private static function mlp_call_moderation_ai( array $messages, $cerebras_key = '', $groq_key = '', $provider_index = null ) {
        $providers = [];
        if ( $cerebras_key !== '' ) {
            $providers[] = [
                'name'  => 'Cerebras',
                'url'   => 'https://api.cerebras.ai/v1/chat/completions',
                'key'   => $cerebras_key,
                'model' => 'llama-3.3-70b',
            ];
        }
        if ( $groq_key !== '' ) {
            $providers[] = [
                'name'  => 'Groq',
                'url'   => 'https://api.groq.com/openai/v1/chat/completions',
                'key'   => $groq_key,
                'model' => 'llama-3.3-70b-versatile',
            ];
        }
        if ( $provider_index !== null ) {
            if ( ! isset( $providers[ $provider_index ] ) ) { return null; }
            $providers = [ $providers[ $provider_index ] ];
        }
        foreach ( $providers as $provider ) {
            error_log( '[MLP Text Mod] Trying provider: ' . $provider['name'] );
            $response = wp_remote_post(
                $provider['url'],
                [
                    'timeout' => 12,
                    'headers' => [
                        'Authorization' => 'Bearer ' . $provider['key'],
                        'Content-Type'  => 'application/json',
                    ],
                    'body' => wp_json_encode( [
                        'model'       => $provider['model'],
                        'max_tokens'  => 300,
                        'temperature' => 0,
                        'messages'    => $messages,
                    ] ),
                ]
            );
            if ( is_wp_error( $response ) ) {
                error_log( '[MLP Text Mod] ' . $provider['name'] . ' error: ' . $response->get_error_message() . ' — trying next provider.' );
                continue;
            }
            $resp_code = wp_remote_retrieve_response_code( $response );
            if ( $resp_code < 200 || $resp_code >= 300 ) {
                $retry_after = wp_remote_retrieve_header( $response, 'retry-after' );
                error_log( '[MLP Text Mod] ' . $provider['name'] . ' HTTP ' . $resp_code
                    . ( $retry_after ? ' (Retry-After: ' . $retry_after . 's)' : '' )
                    . ' — trying next provider.' );
                continue;
            }
            $body    = json_decode( wp_remote_retrieve_body( $response ), true );
            $ai_text = $body['choices'][0]['message']['content'] ?? '';
            $ai_text = preg_replace( '/^```(?:json)?\s*/i', '', trim( $ai_text ) );
            $ai_text = preg_replace( '/\s*```$/', '', $ai_text );
            $result = json_decode( $ai_text, true );
            if ( ! is_array( $result ) || ! isset( $result['passed'] ) ) {
                error_log( '[MLP Text Mod] ' . $provider['name'] . ' returned unparseable response — trying next provider.' );
                continue;
            }
            error_log( '[MLP Text Mod] Moderated via ' . $provider['name'] );
            return $result;
        }
        return null; // All providers failed
    }
    private static function mlp_get_provider_index( $ip ) {
        $val = get_transient( 'mlp_prov_' . md5( $ip ) );
        return is_numeric( $val ) ? (int) $val : 0;
    }
    private static function mlp_advance_provider_index( $ip, $total ) {
        $next = ( self::mlp_get_provider_index( $ip ) + 1 ) % max( 1, $total );
        set_transient( 'mlp_prov_' . md5( $ip ), $next, 15 * MINUTE_IN_SECONDS );
    }
    private static function mlp_reset_provider_index( $ip ) {
        delete_transient( 'mlp_prov_' . md5( $ip ) );
    }
    private static function mlp_image_provider_map() {
        return [
            0 => [ 'id' => 'sightengine', 'fn' => [ __CLASS__, 'sightengine_check_image'  ], 'violation' => 'nsfw_image', 'reason' => 'Your project contains an image that violates our content policy (nudity, violence, or offensive material).' ],
            1 => [ 'id' => 'imagga',      'fn' => [ __CLASS__, 'imagga_check_image'        ], 'violation' => 'nsfw_image', 'reason' => 'Your project contains an image that violates our content policy (nudity, violence, or offensive material).' ],
            2 => [ 'id' => 'gvision',     'fn' => [ __CLASS__, 'google_vision_check_image' ], 'violation' => 'nsfw_image', 'reason' => 'Your project contains an image that violates our content policy (nudity, violence, or offensive material).' ],
        ];
    }
    private static function mlp_get_img_provider_index( $ip ) {
        $val = get_transient( 'mlp_imgprov_' . md5( $ip ) );
        return is_numeric( $val ) ? (int) $val : 0;
    }
    private static function mlp_advance_img_provider_index( $ip ) {
        $next = ( self::mlp_get_img_provider_index( $ip ) + 1 ) % 3;
        set_transient( 'mlp_imgprov_' . md5( $ip ), $next, 15 * MINUTE_IN_SECONDS );
    }
    private static function mlp_reset_img_provider_index( $ip ) {
        delete_transient( 'mlp_imgprov_' . md5( $ip ) );
    }
    public static function ajax_moderate_project() {
        @set_time_limit( 45 );
        if ( ! check_ajax_referer( 'mlp_share_project', 'nonce', false ) ) {
            wp_send_json_error( [ 'message' => 'Invalid request.' ], 403 );
        }
        // Emergency bypass: add define( 'MLP_BYPASS_AI_MODERATION', true ); to wp-config.php
        // to skip all AI/image checks and always approve. Use only for testing.
        if ( defined( 'MLP_BYPASS_AI_MODERATION' ) && MLP_BYPASS_AI_MODERATION ) {
            $bypass_token = 'bypass_' . strtolower( wp_generate_password( 16, false, false ) );
            set_transient( 'mlp_mod_' . $bypass_token, [ 'ok' => true, 'ts' => time() ], 300 );
            wp_send_json_success( [ 'mod_token' => $bypass_token, 'passed' => true, 'reason' => '' ] );
            return;
        }
        $rate_max     = 5;                       // Max attempts per window
        $rate_window  = 10 * MINUTE_IN_SECONDS;  // 10 minutes
        $client_ip    = self::get_client_ip();
        $rate_key     = 'mlp_rate_' . md5( $client_ip );
        $rate_data    = get_transient( $rate_key );
        if ( ! is_array( $rate_data ) ) {
            $rate_data = [ 'count' => 0, 'reset_at' => time() + $rate_window ];
        }
        if ( $rate_data['reset_at'] <= time() ) {
            $rate_data = [ 'count' => 0, 'reset_at' => time() + $rate_window ];
        }
        if ( $rate_data['count'] >= $rate_max ) {
            $remaining = max( 1, $rate_data['reset_at'] - time() );
            $time_str  = self::format_seconds_human( $remaining );
            wp_send_json_error( [
                'message'           => 'Wait 10 minutes before publishing again. You have used your publish attempts for this period. Time left: ' . $time_str . '.',
                'rate_limited'      => true,
                'retry_after'       => $remaining,
                'retry_after_human' => $time_str,
            ], 429 );
            return;
        }
        $ts_token  = isset( $_POST['cf_turnstile_token'] ) ? sanitize_text_field( wp_unslash( $_POST['cf_turnstile_token'] ) ) : '';
        $ts_secret = defined( 'MLP_TURNSTILE_SECRET_KEY' ) ? MLP_TURNSTILE_SECRET_KEY : '';
        if ( empty( $ts_token ) ) {
            wp_send_json_error( [ 'message' => 'Please complete the security check before publishing.' ], 403 );
        }
        if ( ! empty( $ts_secret ) ) {
            $ts_response = wp_remote_post(
                'https://challenges.cloudflare.com/turnstile/v0/siteverify',
                [
                    'timeout' => 10,
                    'body'    => [
                        'secret'   => $ts_secret,
                        'response' => $ts_token,
                        'remoteip' => $_SERVER['REMOTE_ADDR'] ?? '',
                    ],
                ]
            );
            if ( is_wp_error( $ts_response ) ) {
                wp_send_json_error( [ 'message' => 'Security check could not be verified. Please try again.' ], 503 );
            }
            $ts_body = json_decode( wp_remote_retrieve_body( $ts_response ), true );
            if ( empty( $ts_body['success'] ) ) {
                wp_send_json_error( [ 'message' => 'Security check failed. Please refresh the captcha and try again.' ], 403 );
            }
        }
        $rate_data['count']++;
        set_transient( $rate_key, $rate_data, max( 60, $rate_data['reset_at'] - time() ) );
        $content = isset( $_POST['content'] ) ? wp_unslash( $_POST['content'] ) : '';
        if ( ! is_string( $content ) || $content === '' || strlen( $content ) > 500000 ) {
            wp_send_json_error( [ 'message' => 'Content too large or missing.' ], 400 );
        }
        $html_portion = '';
        if ( preg_match( '/\bHTML:\s*\n(.*?)(?=\n\n(?:CSS:|JS:|Tab:|Description:|Project name:)|$)/si', $content, $html_match ) ) {
            $html_portion = trim( $html_match[1] );
        }
        if ( $html_portion !== '' && ! preg_match( '/<[a-z][a-z0-9]*[\s>\/]/i', $html_portion ) ) {
            wp_send_json_error(
                [ 'message' => 'Your HTML tab does not appear to contain valid HTML. Please add HTML tags (e.g. <html>, <div>, <p>) before publishing.' ],
                400
            );
            return;
        }
        $project_name = isset( $_POST['project_name'] ) ? sanitize_text_field( wp_unslash( $_POST['project_name'] ) ) : '';
        if ( strlen( $project_name ) > 200 ) {
            $project_name = mb_substr( $project_name, 0, 200 );
