            $history_political_regex = '/(?:(?:heil|glory\s+to|praise|long\s+live|salute\s+to)\s+(?:hitler|mussolini|himmler|goebbels|stalin|pol\s+pot|mao\s+zedong|idi\s+amin|saddam\s+hussein|bin\s+laden|al[\s\-]?baghdadi|pinochet|franco|mengele)|(?:hitler|mussolini|himmler|goebbels|stalin|pol\s+pot|idi\s+amin|pinochet|mengele|bin\s+laden|al[\s\-]?baghdadi)\s+(?:was\s+right|had\s+the\s+right\s+idea|is\s+my\s+hero|is\s+a\s+hero|did\s+nothing\s+wrong|should\s+have\s+won|was\s+a\s+great\s+(?:man|leader)|is\s+an\s+inspiration)|(?:worship|idolize|admire|support|glorif[ying]+)\s+(?:hitler|mussolini|himmler|goebbels|stalin|pol\s+pot|idi\s+amin|pinochet|mengele|bin\s+laden|al[\s\-]?baghdadi)|(?:holocaust|shoah)\s+(?:never\s+happened|was\s+fake|is\s+a\s+lie|is\s+a\s+myth|was\s+exaggerated)|(?:six\s+million|6\s+million)\s+(?:lie|myth|fake|never\s+happened)|(?:genocide|ethnic\s+cleansing|mass\s+murder)\s+(?:was\s+justified|was\s+right|is\s+the\s+answer|should\s+happen\s+again)|(?:join|support|promote|spread|share)\s+(?:nazism|national\s+socialism|fascism|neo[\s\-]?nazism|the\s+kkk|white\s+(?:nationalism|supremacy|power)|jihadism|isis|isil|daesh|al[\s\-]?qaeda|boko\s+haram)|(?:white|racial)\s+(?:supremacy|superiority)\s+(?:is\s+(?:true|right|fact|real)|must\s+(?:rise|prevail|win))|(?:nazis?|fascists?|kkk|white\s+nationalists?)\s+(?:were|are)\s+(?:right|correct|justified|heroes?)|(?:death\s+to|kill\s+all|exterminate|wipe\s+out)\s+(?:jews?|muslims?|christians?|blacks?|whites?|arabs?|asians?)|(?:sub[\s\-]?human|untermensch|vermin|parasites?|cockroaches?)\s+(?:referring\s+to\s+any\s+ethnic\s+(?:or\s+)?religious\s+group|jews?|muslims?|blacks?|whites?|arabs?|asians?)|(?:race\s+war|racial\s+holy\s+war|rahowa)\s+(?:now|is\s+coming|is\s+necessary|is\s+needed)|(?:accelerationism|accelerate\s+the\s+collapse)\s+(?:manifesto|guide|plan)|(?:vote\s+(?:fraud|rigging|manipulation|stuffing)|election\s+(?:fraud|rigging|manipulation|interference|is\s+stolen|was\s+stolen))\s+(?:guide|how\s+to|tutorial|method)|(?:how\s+to|guide\s+to)\s+(?:rig|steal|manipulate|hack)\s+(?:an?\s+)?election|(?:fake|false)\s+(?:voter|election|ballot)\s+(?:registration|records?|results?)|(?:join|become\s+(?:a|one\s+of)\s+(?:us|our))\s+(?:and\s+)?(?:fight\s+(?:for|against)|rise\s+up\s+against)\s+(?:the\s+)?(?:government|state|system|establishment|elites?|globalists?|zionists?)|(?:red[\s\-]?pill|wake\s+up)\s+(?:sheeple|normies|the\s+masses)\s+(?:to\s+the\s+)?(?:truth\s+about|real\s+agenda\s+of)|(?:great\s+replacement|white\s+genocide)\s+(?:is\s+real|is\s+happening|theory|manifesto)|(?:assassinate|kill|murder|execute)\s+(?:the\s+)?(?:president|prime\s+minister|senator|politician|leader|government\s+official)|(?:armed|violent)\s+(?:revolution|uprising|insurrection|overthrow)\s+(?:is\s+(?:needed|necessary|justified|the\s+only\s+way)|against\s+the\s+government)|(?:bomb|attack|shoot)\s+(?:a\s+)?(?:government\s+building|parliament|congress|white\s+house|capitol))/i';
        }
        if ( preg_match( $history_political_regex, $full_text_to_scan ) ) {
            wp_send_json_error(
                [
                    'message' => 'Your project contains content that is not allowed: '
                        . 'glorification of historical villains or war criminals, '
                        . 'promotion of harmful ideologies (Nazism, fascism, white supremacy, etc.), '
                        . 'Holocaust denial, genocide promotion, '
                        . 'or political propaganda designed to manipulate, radicalise, or incite violence. '
                        . 'Please remove this content and try again.',
                ],
                400
            );
            return;
        }
        $cerebras_key = defined( 'MLP_CEREBRAS_API_KEY' ) ? MLP_CEREBRAS_API_KEY : '';
        $groq_key     = defined( 'MLP_GROQ_API_KEY'     ) ? MLP_GROQ_API_KEY     : '';
        if ( empty( $cerebras_key ) && empty( $groq_key ) ) {
            $mod_token = 'nokey_' . strtolower( wp_generate_password( 16, false, false ) );
            set_transient( 'mlp_mod_' . $mod_token, [ 'ok' => true, 'ts' => time() ], 300 );
            wp_send_json_success( [ 'mod_token' => $mod_token, 'passed' => true, 'reason' => '' ] );
            return;
        }
        $content_hash     = 'mlp_modv5_' . sha1( $author_name . '|' . $project_name . '|' . $project_description . '|' . $content );
        $cached_mod       = get_transient( $content_hash );
        if ( is_array( $cached_mod ) ) {
            if ( $cached_mod['passed'] === true ) {
                error_log( '[MLP Text Mod] Cache HIT (pass) — skipping AI for hash ' . substr( $content_hash, 10, 8 ) );
                $mod_token = 'cached_' . strtolower( wp_generate_password( 18, false, false ) );
                set_transient( 'mlp_mod_' . $mod_token, [ 'ok' => true, 'ts' => time(), 'cached' => true ], 300 );
                wp_send_json_success( [ 'mod_token' => $mod_token, 'passed' => true, 'reason' => '' ] );
                return;
            } else {
                error_log( '[MLP Text Mod] Cache HIT (fail) — skipping AI for hash ' . substr( $content_hash, 10, 8 ) );
                wp_send_json_error( [
                    'passed'     => false,
                    'reason'     => $cached_mod['reason'] ?: 'Your project contains content that violates our sharing policy.',
                    'violations' => $cached_mod['violations'] ?? [],
                ], 200 );
                return;
            }
        }
        $chunk_size = 12000;
        $content_len = mb_strlen( $content );
        $chunks = [];
        if ( $content_len === 0 ) {
            $chunks[] = '';
        } else {
            for ( $offset = 0; $offset < $content_len; $offset += $chunk_size ) {
                $chunks[] = mb_substr( $content, $offset, $chunk_size );
            }
        }
        $max_chunks = 25; // 25 * 12K = 300KB which matches the 500KB content cap
        if ( count( $chunks ) > $max_chunks ) {
            $chunks = array_slice( $chunks, 0, $max_chunks );
        }
        static $system_prompt = null;
        if ( $system_prompt === null ) {
        $system_prompt = 'You are a content moderation AI. Reject any content that contains a clear violation from the list below.

REJECT for any of these (flag each violation type found):
1. Profanity / obscene language — any use of words such as fuck, fucking, shit, bitch, cunt, cock, pussy, asshole, dickhead, motherfucker, whore, slut, bastard, prick, twat, wank, or similar profanity or obscene slurs, whether in visible text, variable names, comments, strings, or anywhere else in the project.
2. Malware — code that explicitly steals passwords, hijacks browsers, or installs software without consent. CDN links (jsdelivr, unpkg, cdnjs, cloudflare, googleapis, wikimedia, github, imgur, giphy, unsplash, pexels, ytimg, twimg, etc.) are NOT malware.
3. Phishing — a fake login page that explicitly impersonates a real service (e.g. fake Google login).
4. Explicit hate speech — racial or ethnic slurs, Nazi glorification, Holocaust denial, calls for genocide. Normal historical or political discussion is NOT a violation.
5. Explicit pornographic text — detailed sexual descriptions visible to users. Images cannot be seen by you, so never flag image URLs or alt text.
6. Scam pages — pages asking users to enter game credentials in exchange for free currency.
7. Clear hacking tools — DDoS panels, keylogger builders, phishing kits (not security tutorials).

NEVER reject for:
- Any image URL, img src attribute, or alt text — you cannot see images
- Medical, scientific, anatomical, or educational content
- External URLs, CDN links, or domain names in the code
- Game simulations, educational tools, portfolios, animations

If a violation is found, you MUST list it in the violations array. Do not return passed=false with an empty violations array.
Respond ONLY with a JSON object (no markdown):
{"passed": true_or_false, "violations": ["list","of","violation","types","found"], "reason": "brief explanation if failed, empty string if passed"}';
        } // end static $system_prompt init
        $passed = true;
        $reason = '';
        foreach ( $chunks as $chunk_idx => $chunk_snippet ) {
            if ( $chunk_idx === 0 ) {
                $user_msg = "Moderate this project.\n\nAUTHOR DISPLAY NAME:\n"
                    . ( $author_name !== '' ? $author_name : '(none provided)' )
                    . "\n\nPROJECT NAME/TITLE:\n"
                    . ( $project_name !== '' ? $project_name : '(none provided)' )
                    . "\n\nPROJECT DESCRIPTION:\n"
                    . ( $project_description !== '' ? $project_description : '(none provided)' )
                    . "\n\nPROJECT CODE (chunk 1 of " . count( $chunks ) . "):\n"
                    . $chunk_snippet;
            } else {
                $user_msg = "Moderate this project code.\n\nPROJECT CODE (chunk "
                    . ( $chunk_idx + 1 ) . " of " . count( $chunks ) . "):\n"
                    . $chunk_snippet;
            }
            // Pass null as provider_index so ALL providers are tried in order.
            $result = self::mlp_call_moderation_ai(
                [ [ 'role' => 'system', 'content' => $system_prompt ], [ 'role' => 'user', 'content' => $user_msg ] ],
                $cerebras_key, $groq_key, null
            );
            if ( $result === null ) {
                // All AI providers unavailable — fail-open, allow the project through.
                error_log( '[MLP Text Mod] All providers failed chunk ' . ($chunk_idx+1) . ' — failing open.' );
                break; // $passed remains true
            }
            $chunk_passed = ( $result['passed'] === true );
            if ( ! $chunk_passed ) {
                $violations = $result['violations'] ?? [];
                if ( empty( $violations ) ) {
                    // AI flagged content but gave no violation list — treat as generic violation, still reject.
                    $violations = [ 'policy_violation' ];
                    error_log( '[MLP Text Mod] AI returned passed=false but no violations — using generic violation.' );
                }
                $passed = false;
                $reason = $result['reason'] ?? 'Content violates moderation policy.';
                break; // Fail fast on first bad chunk
            }
        }
        if ( $passed ) {
            $image_sources = self::extract_image_sources( $content );
            if ( ! empty( $image_sources ) ) {
                $img_providers_map = self::mlp_image_provider_map();
                // Trusted domains — academic publishers, major CDNs, known-safe hosts.
                // Images from these domains skip AI scanning entirely.
                $trusted_img_domains = [
                    'els-cdn.com',          // Elsevier academic publisher
                    'wikimedia.org',
                    'wikipedia.org',
                    'githubusercontent.com',
                    'googleusercontent.com',
                    'gstatic.com',
                    'googleapis.com',
                    'jsdelivr.net',
                    'unpkg.com',
                    'cdnjs.cloudflare.com',
                    'cloudflare.com',
                    'imgur.com',
                    'giphy.com',
                    'unsplash.com',
                    'pexels.com',
                    'pixabay.com',
                    'flickr.com',
                    'staticflickr.com',
                    'ytimg.com',       // YouTube thumbnails
                    'twimg.com',       // Twitter/X media
                    'fbcdn.net',       // Facebook CDN
                    'discord.com',
                    'discordapp.com',
                    'redd.it',
                    'reddit.com',
                ];
                foreach ( $image_sources as $img_src ) {
                    // Skip scanning for trusted domains.
                    $img_host = strtolower( parse_url( $img_src, PHP_URL_HOST ) ?? '' );
                    $is_trusted = false;
                    foreach ( $trusted_img_domains as $trusted ) {
                        if ( $img_host === $trusted || str_ends_with( $img_host, '.' . $trusted ) ) {
                            $is_trusted = true;
                            break;
                        }
                    }
                    if ( $is_trusted ) {
                        error_log( '[MLP Image Mod] Trusted domain — skipping scan: ' . mb_substr( $img_src, 0, 80 ) );
                        continue;
                    }
                    $img_blocked = false;
                    $img_checked = false;
                    // Try each image provider in order until one gives a definitive result.
                    foreach ( $img_providers_map as $img_provider_try ) {
                        $result = self::cached_image_check( $img_provider_try['id'], $img_src, $img_provider_try['fn'] );
                        if ( $result === null ) {
                            error_log( '[MLP Image Mod] "' . $img_provider_try['id'] . '" unavailable for: ' . mb_substr( $img_src, 0, 80 ) . ' — trying next.' );
                            continue; // Try next provider
                        }
                        $img_checked = true;
                        if ( $result === false ) {
                            $img_blocked    = true;
                            $img_provider   = $img_provider_try;
                        }
                        break; // Got a definitive result
                    }
                    if ( $img_blocked ) {
                        error_log( '[MLP Image Mod] "' . $img_provider['id'] . '" blocked: ' . mb_substr( $img_src, 0, 80 ) );
                        wp_send_json_error( [ 'passed' => false, 'reason' => $img_provider['reason'], 'violations' => [ $img_provider['violation'] ] ], 200 );
                        return;
                    }
                    if ( ! $img_checked ) {
                        error_log( '[MLP Image Mod] All providers unavailable for: ' . mb_substr( $img_src, 0, 80 ) . ' — failing open.' );
                        // All providers unavailable — fail-open, allow through.
                    }
                }
            }
            set_transient( $content_hash, [ 'passed' => true, 'reason' => '', 'violations' => [] ], DAY_IN_SECONDS );
            $mod_token = 'ok_' . strtolower( wp_generate_password( 18, false, false ) );
            set_transient( 'mlp_mod_' . $mod_token, [ 'ok' => true, 'ts' => time() ], 300 );
            wp_send_json_success( [ 'mod_token' => $mod_token, 'passed' => true, 'reason' => '' ] );
        } else {
            set_transient( $content_hash, [
                'passed'     => false,
                'reason'     => $reason ?: 'Your project contains content that violates our sharing policy.',
                'violations' => $result['violations'] ?? [],
            ], HOUR_IN_SECONDS );
            error_log( '[MLP Moderation] Project rejected. Violations: ' . wp_json_encode( $result['violations'] ?? [] ) . ' | Reason: ' . $reason );
            wp_send_json_error( [
                'passed'     => false,
                'reason'     => $reason ?: 'Your project contains content that violates our sharing policy.',
                'violations' => $result['violations'] ?? [],
            ], 200 ); // 200 so JS can read the body
        }
    }
    private static function sightengine_check_image( $image_src ) {
        $se_user   = defined( 'MLP_SIGHTENGINE_USER' )   ? MLP_SIGHTENGINE_USER   : '';
        $se_secret = defined( 'MLP_SIGHTENGINE_SECRET' ) ? MLP_SIGHTENGINE_SECRET : '';
        if ( empty( $se_user ) || empty( $se_secret ) ) {
            return null; // Not configured — fail-open
        }
        $body = [
            'models'     => 'nudity-2.1,offensive,scam,gore-2.0,text-content',
            'api_user'   => $se_user,
            'api_secret' => $se_secret,
        ];
        if ( strncmp( $image_src, 'data:', 5 ) === 0 ) {
            $comma = strpos( $image_src, ',' );
            if ( $comma === false ) {
                return null;
            }
            $body['image'] = substr( $image_src, $comma + 1 );
            $endpoint      = 'https://api.sightengine.com/1.0/check.json';
        } else {
            $body['url'] = $image_src;
            $endpoint    = 'https://api.sightengine.com/1.0/check.json';
        }
        $response = wp_remote_post( $endpoint, [
            'timeout' => 15,
            'body'    => $body,
        ] );
        if ( is_wp_error( $response ) ) {
            error_log( '[MLP Sightengine] API error: ' . $response->get_error_message() );
            return null; // Fail-open on connection error
        }
        $data = json_decode( wp_remote_retrieve_body( $response ), true );
        if ( empty( $data['status'] ) || $data['status'] !== 'success' ) {
            error_log( '[MLP Sightengine] Unexpected response: ' . wp_remote_retrieve_body( $response ) );
            return null;
        }
        $nudity = $data['nudity'] ?? [];
        if (
            ( isset( $nudity['sexual_activity'] ) && $nudity['sexual_activity'] > 0.5 ) ||
            ( isset( $nudity['sexual_display']  ) && $nudity['sexual_display']  > 0.5 ) ||
            ( isset( $nudity['erotica']          ) && $nudity['erotica']         > 0.5 ) ||
            ( isset( $nudity['raw']              ) && $nudity['raw']             > 0.5 ) ||
            ( isset( $nudity['partial']          ) && $nudity['partial']         > 0.6 )
        ) {
            return false;
        }
        $offensive = $data['offensive'] ?? [];
        if ( isset( $offensive['prob'] ) && $offensive['prob'] > 0.5 ) {
            return false;
        }
        $text_content = $data['text'] ?? [];
        if ( isset( $text_content['profanity'] ) && $text_content['profanity'] > 0.5 ) {
            return false;
        }
        $gore = $data['gore'] ?? [];
        if ( isset( $gore['prob'] ) && $gore['prob'] > 0.7 ) {
            return false;
        }
        $scam = $data['scam'] ?? [];
        if ( isset( $scam['prob'] ) && $scam['prob'] > 0.6 ) {
            return false;
        }
        return true; // Passed all checks
    }
    private static function imagga_check_image( $image_src ) {
        $imagga_key    = defined( 'MLP_IMAGGA_KEY' )    ? MLP_IMAGGA_KEY    : '';
        $imagga_secret = defined( 'MLP_IMAGGA_SECRET' ) ? MLP_IMAGGA_SECRET : '';
        if ( empty( $imagga_key ) || empty( $imagga_secret ) ) {
            return null; // Not configured — fail-open
        }
        $args = [
            'timeout' => 15,
            'headers' => [
                'Authorization' => 'Basic ' . base64_encode( $imagga_key . ':' . $imagga_secret ),
            ],
        ];
        if ( strncmp( $image_src, 'data:', 5 ) === 0 ) {
            $comma = strpos( $image_src, ',' );
            if ( $comma === false ) {
                return null;
            }
            $mime    = 'image/jpeg';
            $matches = [];
            if ( preg_match( '/^data:([^;]+);base64,/', $image_src, $matches ) ) {
                $mime = $matches[1];
            }
            $raw_data = base64_decode( substr( $image_src, $comma + 1 ) );
            if ( $raw_data === false ) {
                return null;
            }
            $boundary = wp_generate_password( 24, false );
            $body  = "--{$boundary}\r\n";
            $body .= "Content-Disposition: form-data; name=\"image\"; filename=\"image.jpg\"\r\n";
            $body .= "Content-Type: {$mime}\r\n\r\n";
            $body .= $raw_data . "\r\n";
            $body .= "--{$boundary}--\r\n";
            $args['headers']['Content-Type'] = 'multipart/form-data; boundary=' . $boundary;
            $args['body'] = $body;
            $upload_response = wp_remote_post( 'https://api.imagga.com/v2/uploads', $args );
            if ( is_wp_error( $upload_response ) ) {
                error_log( '[MLP Imagga] Upload error: ' . $upload_response->get_error_message() );
                return null;
            }
            $upload_data = json_decode( wp_remote_retrieve_body( $upload_response ), true );
            $upload_id   = $upload_data['result']['upload_id'] ?? '';
            if ( empty( $upload_id ) ) {
                error_log( '[MLP Imagga] Upload failed: ' . wp_remote_retrieve_body( $upload_response ) );
                return null;
            }
            unset( $args['headers']['Content-Type'], $args['body'] );
            $check_response = wp_remote_get(
                'https://api.imagga.com/v2/content?image_upload_id=' . urlencode( $upload_id ),
                $args
            );
            wp_remote_request( 'https://api.imagga.com/v2/uploads/' . urlencode( $upload_id ), array_merge( $args, [ 'method' => 'DELETE' ] ) );
        } else {
            $check_response = wp_remote_get(
                'https://api.imagga.com/v2/content?image_url=' . urlencode( $image_src ),
                $args
            );
        }
        if ( is_wp_error( $check_response ) ) {
            error_log( '[MLP Imagga] Check error: ' . $check_response->get_error_message() );
            return null;
        }
        $data = json_decode( wp_remote_retrieve_body( $check_response ), true );
        if ( empty( $data['result']['categories'] ) ) {
            error_log( '[MLP Imagga] Unexpected response: ' . wp_remote_retrieve_body( $check_response ) );
            return null; // Fail-open on unexpected response
        }
        $blocked_categories = [
            'adult content' => 50,  // block if score > 50
            'suggestive'    => 60,
            'violence'      => 60,
            'drug use'      => 60,
            'gore'          => 50,
            'scam'          => 60,
        ];
        foreach ( $data['result']['categories'] as $category ) {
            $name  = strtolower( $category['name']  ?? '' );
            $score = floatval( $category['score'] ?? 0 );
            foreach ( $blocked_categories as $blocked => $threshold ) {
                if ( strpos( $name, $blocked ) !== false && $score > $threshold ) {
                    error_log( '[MLP Imagga] Blocked image. Category: ' . $name . ' Score: ' . $score );
                    return false;
                }
            }
        }
        return true; // Passed all checks
    }
    private static function google_vision_check_image( $image_src ) {
        $gv_key = defined( 'MLP_GOOGLE_VISION_KEY' ) ? MLP_GOOGLE_VISION_KEY : '';
        if ( empty( $gv_key ) ) {
            return null; // Not configured — fail-open
        }
        if ( strncmp( $image_src, 'data:', 5 ) === 0 ) {
            $comma = strpos( $image_src, ',' );
            if ( $comma === false ) {
                return null;
            }
            $b64_content = substr( $image_src, $comma + 1 );
            $image_block = [ 'content' => $b64_content ];
        } else {
            $image_block = [ 'source' => [ 'imageUri' => $image_src ] ];
        }
        $response = wp_remote_post(
            'https://vision.googleapis.com/v1/images:annotate?key=' . $gv_key,
            [
                'timeout' => 15,
                'headers' => [ 'Content-Type' => 'application/json' ],
                'body'    => wp_json_encode( [
                    'requests' => [
                        [
                            'image'    => $image_block,
                            'features' => [
                                [ 'type' => 'SAFE_SEARCH_DETECTION' ],
                            ],
                        ],
                    ],
                ] ),
            ]
        );
        if ( is_wp_error( $response ) ) {
            error_log( '[MLP Google Vision] API error: ' . $response->get_error_message() );
            return null;
        }
        $body = json_decode( wp_remote_retrieve_body( $response ), true );
        if ( ! empty( $body['error'] ) || ! empty( $body['responses'][0]['error'] ) ) {
            $err = $body['error']['message'] ?? ( $body['responses'][0]['error']['message'] ?? 'unknown error' );
            error_log( '[MLP Google Vision] API returned error: ' . $err );
            return null; // Fail-open on API error
        }
        $safe_search = $body['responses'][0]['safeSearchAnnotation'] ?? null;
        if ( ! is_array( $safe_search ) ) {
            error_log( '[MLP Google Vision] No safeSearchAnnotation in response.' );
            return null;
        }
        $block_on = [ 'VERY_LIKELY' ]; // Raise threshold — 'LIKELY' causes too many false positives on medical/artistic content
        $checked_fields = [ 'adult', 'violence' ]; // 'racy' removed — too aggressive for educational/medical images
        foreach ( $checked_fields as $field ) {
            $likelihood = $safe_search[ $field ] ?? 'UNKNOWN';
            if ( in_array( $likelihood, $block_on, true ) ) {
                error_log( '[MLP Google Vision] Blocked image. Field: ' . $field . ' Likelihood: ' . $likelihood );
                return false;
            }
        }
        return true; // Passed SafeSearch
    }
    private static function get_client_ip() {
        $candidates = [
            'HTTP_CF_CONNECTING_IP',  // Cloudflare
            'HTTP_X_FORWARDED_FOR',
            'HTTP_X_REAL_IP',
            'REMOTE_ADDR',
        ];
        foreach ( $candidates as $key ) {
            if ( ! empty( $_SERVER[ $key ] ) ) {
                $val = $_SERVER[ $key ];
                if ( $key === 'HTTP_X_FORWARDED_FOR' && strpos( $val, ',' ) !== false ) {
                    $val = trim( explode( ',', $val )[0] );
                }
                $val = trim( wp_unslash( $val ) );
                if ( filter_var( $val, FILTER_VALIDATE_IP ) ) {
                    return $val;
                }
            }
        }
        return 'unknown';
    }
    private static function format_seconds_human( $seconds ) {
        $seconds = max( 0, (int) $seconds );
        $minutes = (int) floor( $seconds / 60 );
        $secs    = $seconds % 60;
        if ( $minutes <= 0 ) {
            return $secs . ' second' . ( $secs === 1 ? '' : 's' );
        }
        if ( $secs === 0 ) {
            return $minutes . ' minute' . ( $minutes === 1 ? '' : 's' );
        }
        return $minutes . ' minute' . ( $minutes === 1 ? '' : 's' )
            . ' ' . $secs . ' second' . ( $secs === 1 ? '' : 's' );
    }
    private static function cached_image_check( $provider, $image_src, callable $check_fn, $ttl_seconds = DAY_IN_SECONDS ) {
        $key = 'mlp_imgmod5_' . $provider . '_' . md5( $image_src );
        $cached = get_transient( $key );
        if ( $cached === 'pass' ) {
            return true;
        }
        if ( $cached === 'fail' ) {
            return false;
        }
        $result = $check_fn( $image_src );
        if ( $result === true ) {
            set_transient( $key, 'pass', $ttl_seconds );
        } elseif ( $result === false ) {
            set_transient( $key, 'fail', $ttl_seconds );
        }
        return $result;
    }
    private static function fetch_image_as_base64( $image_src ) {
        if ( strncmp( $image_src, 'data:', 5 ) === 0 ) {
            if ( preg_match( '/^data:([a-z0-9.+\-\/]+);base64,(.+)$/i', $image_src, $m ) ) {
                return [ 'b64' => $m[2], 'mime' => $m[1] ];
            }
            return null;
        }
        $resp = wp_remote_get( $image_src, [
            'timeout'     => 10,
            'redirection' => 3,
            'user-agent'  => 'MLP-ImageModeration/1.0',
        ] );
        if ( is_wp_error( $resp ) ) {
            return null;
        }
        $code = wp_remote_retrieve_response_code( $resp );
        if ( $code < 200 || $code >= 300 ) {
            return null;
        }
        $body = wp_remote_retrieve_body( $resp );
        if ( empty( $body ) || strlen( $body ) > 8 * 1024 * 1024 ) {
            return null;
        }
        $mime = wp_remote_retrieve_header( $resp, 'content-type' );
        if ( is_array( $mime ) ) {
            $mime = $mime[0] ?? '';
        }
        if ( empty( $mime ) || strpos( $mime, 'image/' ) !== 0 ) {
            static $finfo_handle = null;
            if ( $finfo_handle === null && function_exists( 'finfo_open' ) ) {
                $finfo_handle = finfo_open( FILEINFO_MIME_TYPE );
            }
            $finfo = $finfo_handle;
            if ( $finfo ) {
                $sniffed = finfo_buffer( $finfo, $body );
                if ( $sniffed && strpos( $sniffed, 'image/' ) === 0 ) {
                    $mime = $sniffed;
                } else {
                    return null;
                }
            } else {
                return null;
            }
        }
        return [ 'b64' => base64_encode( $body ), 'mime' => $mime ];
    }
    private static function gemini_check_image( $image_src ) {
        $gem_key = defined( 'MLP_GEMINI_KEY' ) ? MLP_GEMINI_KEY : '';
        if ( empty( $gem_key ) ) {
            return null;
        }
        $img = self::fetch_image_as_base64( $image_src );
        if ( $img === null ) {
            return null; // Could not fetch — fail-open
        }
        $prompt = 'You are an image classifier. Your task is to detect whether an image depicts a real human being or a clearly humanoid character that is the main subject. Be accurate — only flag images that clearly and obviously contain a person or human figure.
Answer has_human=TRUE if the image clearly contains:
- Real people (photos, screenshots of people)
- Illustrated or drawn human characters that are the main subject
- Cartoon or anime characters that are clearly humanoid and the focus of the image
Answer has_human=FALSE for:
- Pure animals, nature, landscapes, food, vehicles, objects, buildings
- Abstract art or patterns
- UI screenshots, code, charts, diagrams
- Icons or tiny incidental human silhouettes in a UI (e.g. a small user icon in a nav bar)
- Stick figures or extremely abstract/minimal symbols
Be conservative — only return true if a human or clearly humanoid figure is prominently present. If uncertain, return false.
Respond with ONLY a single JSON object in this exact format, no markdown, no explanation: {"has_human": true_or_false, "confidence": "high"_or_"medium"_or_"low"}';
        $response = wp_remote_post(
            'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' . rawurlencode( $gem_key ),
            [
                'timeout' => 20,
                'headers' => [ 'Content-Type' => 'application/json' ],
                'body'    => wp_json_encode( [
                    'contents' => [
                        [
                            'parts' => [
                                [ 'text' => $prompt ],
                                [
                                    'inline_data' => [
                                        'mime_type' => $img['mime'],
                                        'data'      => $img['b64'],
                                    ],
                                ],
                            ],
                        ],
                    ],
                    'generationConfig' => [
                        'temperature'     => 0,
                        'maxOutputTokens' => 80,
                    ],
                ] ),
            ]
        );
        if ( is_wp_error( $response ) ) {
            error_log( '[MLP Gemini Vision] API error: ' . $response->get_error_message() );
            return null;
        }
        $body = json_decode( wp_remote_retrieve_body( $response ), true );
        if ( ! empty( $body['error'] ) ) {
            error_log( '[MLP Gemini Vision] API returned error: ' . ( $body['error']['message'] ?? 'unknown' ) );
            return null;
        }
        $text = $body['candidates'][0]['content']['parts'][0]['text'] ?? '';
        $text = preg_replace( '/^```(?:json)?\s*/i', '', trim( $text ) );
        $text = preg_replace( '/\s*```$/', '', $text );
        $parsed = json_decode( $text, true );
        if ( ! is_array( $parsed ) || ! isset( $parsed['has_human'] ) ) {
            error_log( '[MLP Gemini Vision] Could not parse response: ' . mb_substr( $text, 0, 200 ) );
            return null;
        }
        if ( $parsed['has_human'] === true ) {
            error_log( '[MLP Gemini Vision] Blocked image (human detected): ' . mb_substr( $image_src, 0, 80 ) );
            return false;
        }
        return true;
    }
    private static function groq_check_image( $image_src ) {
        $groq_key = defined( 'MLP_GROQ_API_KEY' ) ? MLP_GROQ_API_KEY : '';
        if ( empty( $groq_key ) ) {
            return null;
        }
        if ( strncmp( $image_src, 'data:', 5 ) === 0 ) {
            $image_url_value = $image_src;
        } elseif ( preg_match( '#^https?://#i', $image_src ) ) {
            $image_url_value = $image_src;
        } else {
            return null;
        }
        $prompt = 'You are an image classifier. Detect whether the image clearly depicts a real human being or a prominently humanoid character.
Answer has_human=TRUE if the image clearly contains:
- Real people in photos or screenshots
- Illustrated or drawn human characters that are the main subject
- Cartoon or anime characters that are clearly humanoid and the focus of the image
Answer has_human=FALSE for:
- Animals, nature, landscapes, food, vehicles, objects, buildings
- Abstract art or geometric patterns
- UI screenshots, code, charts, diagrams
- Small incidental human icons in a UI (e.g. a tiny user icon in a nav bar)
- Stick figures or extremely abstract symbols
Only return true if a human or clearly humanoid figure is prominently present. If uncertain, return false.
Respond with ONLY a single JSON object, no markdown, no extra text: {"has_human": true_or_false, "confidence": "high"_or_"medium"_or_"low"}';
        $response = wp_remote_post(
            'https://api.groq.com/openai/v1/chat/completions',
            [
                'timeout' => 20,
                'headers' => [
                    'Authorization' => 'Bearer ' . $groq_key,
                    'Content-Type'  => 'application/json',
                ],
                'body' => wp_json_encode( [
                    'model'       => 'meta-llama/llama-4-scout-17b-16e-instruct',
                    'temperature' => 0,
                    'max_tokens'  => 80,
                    'messages'    => [
                        [
                            'role'    => 'user',
                            'content' => [
                                [ 'type' => 'text', 'text' => $prompt ],
                                [
                                    'type'      => 'image_url',
                                    'image_url' => [ 'url' => $image_url_value ],
                                ],
                            ],
                        ],
                    ],
                ] ),
            ]
        );
        if ( is_wp_error( $response ) ) {
            error_log( '[MLP Groq Vision] API error: ' . $response->get_error_message() );
            return null;
        }
        $body = json_decode( wp_remote_retrieve_body( $response ), true );
        if ( ! empty( $body['error'] ) ) {
            error_log( '[MLP Groq Vision] API returned error: ' . ( $body['error']['message'] ?? 'unknown' ) );
            return null;
        }
        $text = $body['choices'][0]['message']['content'] ?? '';
        $text = preg_replace( '/^```(?:json)?\s*/i', '', trim( $text ) );
        $text = preg_replace( '/\s*```$/', '', $text );
        $parsed = json_decode( $text, true );
        if ( ! is_array( $parsed ) || ! isset( $parsed['has_human'] ) ) {
            error_log( '[MLP Groq Vision] Could not parse response: ' . mb_substr( $text, 0, 200 ) );
            return null;
        }
        if ( $parsed['has_human'] === true ) {
            error_log( '[MLP Groq Vision] Blocked image (human detected): ' . mb_substr( $image_src, 0, 80 ) );
            return false;
        }
        return true;
    }
    private static function extract_image_sources( $content ) {
        $sources = [];
        preg_match_all(
            '/data:image\/(?:png|jpe?g|gif|webp|svg\+xml|bmp|avif)[^"\'`\s)>]*/i',
            $content,
            $b64_matches
        );
        foreach ( $b64_matches[0] as $src ) {
            $sources[] = $src;
        }
        preg_match_all(
            '/data:image[^\w][^"\'`\s]{10,}/i',
            $content,
            $b64_loose_matches
        );
        foreach ( $b64_loose_matches[0] as $src ) {
            if ( preg_match( '/base64,/i', $src ) ) {
                $sources[] = $src;
            }
        }
        preg_match_all(
            '/["\']([A-Za-z0-9+\/]{100,}={0,2})["\']/',
            $content,
            $raw_b64_matches
        );
        foreach ( $raw_b64_matches[1] as $b64str ) {
            $prefix = substr( $b64str, 0, 8 );
            $known_image_prefixes = [ 'iVBOR', '/9j/4', 'R0lGO', 'UklGR', 'PHN2Zy', 'Qk0', 'AAAAF' ];
            foreach ( $known_image_prefixes as $img_prefix ) {
                if ( strncmp( $prefix, $img_prefix, strlen( $img_prefix ) ) === 0 ) {
                    if ( strncmp( $prefix, '/9j/', 4 ) === 0 ) {
                        $sources[] = 'data:image/jpeg;base64,' . $b64str;
                    } elseif ( strncmp( $prefix, 'iVBOR', 5 ) === 0 ) {
                        $sources[] = 'data:image/png;base64,' . $b64str;
                    } elseif ( strncmp( $prefix, 'R0lGO', 5 ) === 0 ) {
                        $sources[] = 'data:image/gif;base64,' . $b64str;
                    } elseif ( strncmp( $prefix, 'UklGR', 5 ) === 0 ) {
                        $sources[] = 'data:image/webp;base64,' . $b64str;
                    } elseif ( strncmp( $prefix, 'PHN2Zy', 6 ) === 0 ) {
                        $sources[] = 'data:image/svg+xml;base64,' . $b64str;
                    } else {
                        $sources[] = 'data:image/png;base64,' . $b64str;
                    }
                    break;
                }
            }
        }
        preg_match_all( '/<img[^>]+src=["\']([^"\']+)["\'][^>]*>/i', $content, $img_matches );
        foreach ( $img_matches[1] as $src ) {
            if ( filter_var( $src, FILTER_VALIDATE_URL ) ) {
                $sources[] = $src;
            }
        }
        preg_match_all( '/url\(["\']?(https?:\/\/[^"\')\s]+)["\']?\)/i', $content, $css_matches );
        foreach ( $css_matches[1] as $src ) {
            // Only include URLs that clearly point to image files — skip fonts, CSS, JS, etc.
            if ( preg_match( '/\.(?:png|jpe?g|gif|webp|svg|bmp|avif|ico|tiff?)(?:[?#]|$)/i', $src ) ) {
                $sources[] = $src;
            }
        }
        $sources = array_values( array_unique( $sources ) );
        return array_slice( $sources, 0, 10 );
    }
    public static function ajax_save_shared_project() {
        if ( ! check_ajax_referer( 'mlp_share_project', 'nonce', false ) ) {
            wp_send_json_error( [ 'message' => 'Invalid share request.' ], 403 );
        }
        $mod_token = isset( $_POST['mod_token'] ) ? sanitize_text_field( wp_unslash( $_POST['mod_token'] ) ) : '';
        if ( $mod_token === '' ) {
            wp_send_json_error( [ 'message' => 'Content has not been moderated. Please use the Publish button.' ], 403 );
        }
        $mod_record = get_transient( 'mlp_mod_' . $mod_token );
        if ( ! is_array( $mod_record ) || empty( $mod_record['ok'] ) ) {
            wp_send_json_error( [ 'message' => 'Moderation token is invalid or expired. Please publish again.' ], 403 );
        }
        delete_transient( 'mlp_mod_' . $mod_token );
        $payload = isset( $_POST['payload'] ) ? wp_unslash( $_POST['payload'] ) : '';
        if ( ! is_string( $payload ) || $payload === '' || strlen( $payload ) > 2097152 ) {
            wp_send_json_error( [ 'message' => 'Project share data is invalid.' ], 400 );
        }
        $decoded = json_decode( $payload, true );
        if ( ! is_array( $decoded ) || empty( $decoded['id'] ) ) {
            wp_send_json_error( [ 'message' => 'Project share data is invalid.' ], 400 );
        }
        $existing_token = isset( $_POST['existing_token'] ) ? sanitize_key( wp_unslash( $_POST['existing_token'] ) ) : '';
        if ( $existing_token !== '' ) {
            $existing = get_option( 'mlp_share_' . $existing_token, null );
            if ( is_array( $existing ) ) {
                if ( ! empty( $existing['admin_deleted'] ) ) {
                    wp_send_json_error( [ 'message' => 'This project has been removed by an administrator and cannot be republished. Please appeal via Discord (https://discord.gg/C5B9YCumB4) or email aminekhd@pterocos.eu.org.' ], 403 );
                    return;
                }
                update_option(
                    'mlp_share_' . $existing_token,
                    [
                        'created'    => $existing['created'] ?? time(),
                        'updated'    => time(),
                        'payload'    => $payload,
                        'mod_token'  => $mod_token,
                        'project_id' => $decoded['id'] ?? ( $existing['project_id'] ?? '' ),
                        'shared_by'  => $decoded['sharedBy'] ?? ( $existing['shared_by'] ?? '' ),
                        'views'      => $existing['views'] ?? 0,
                        'likes'      => $existing['likes'] ?? 0,
                        'made'       => $existing['made']  ?? 0,
                        'forks'      => $existing['forks'] ?? 0,
                    ],
                    false
                );
                // Delete both the legacy unversioned transient and the old
                // version-aware transient so no stale screenshot survives.
                $old_version = isset( $existing['updated'] ) ? (int) $existing['updated']
                             : ( isset( $existing['created'] ) ? (int) $existing['created'] : 0 );
                delete_transient( 'mlp_ogimg_' . $existing_token );
                if ( $old_version > 0 ) {
                    delete_transient( 'mlp_ogimg_' . $existing_token . '_' . $old_version );
                }
                self::mlp_trigger_bg_screenshot( $existing_token );
                wp_send_json_success( [ 'token' => $existing_token, 'republished' => true ] );
                return;
            }
        }
        $new_project_id = $decoded['id'] ?? '';
        if ( $new_project_id !== '' ) {
            global $wpdb;
            $rows = $wpdb->get_results(
                "SELECT option_name, option_value FROM {$wpdb->options} WHERE option_name LIKE 'mlp_share_%'",
                ARRAY_A
            );
            foreach ( $rows as $row ) {
                $rec = maybe_unserialize( $row['option_value'] );
                if ( ! is_array( $rec ) || ( $rec['project_id'] ?? '' ) !== $new_project_id ) continue;
                if ( ! empty( $rec['admin_deleted'] ) ) {
                    wp_send_json_error( [ 'message' => 'This project has been removed by an administrator and cannot be republished. Please appeal via Discord (https://discord.gg/C5B9YCumB4) or email aminekhd@pterocos.eu.org.' ], 403 );
                    return;
                }
            }
        }
        $token = strtolower( wp_generate_password( 22, false, false ) );
        update_option(
            'mlp_share_' . $token,
            [
                'created'    => time(),
                'payload'    => $payload,
                'mod_token'  => $mod_token,
                'project_id' => $decoded['id'] ?? '',
                'shared_by'  => $decoded['sharedBy'] ?? '',
            ],
            false
        );
        self::mlp_trigger_bg_screenshot( $token );
        wp_send_json_success( [ 'token' => $token ] );
    }
    public static function ajax_get_shared_project() {
        $token = isset( $_REQUEST['token'] ) ? sanitize_key( wp_unslash( $_REQUEST['token'] ) ) : '';
        if ( $token === '' ) {
            wp_send_json_error( [ 'message' => 'Missing share token.' ], 400 );
        }
        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || empty( $record['payload'] ) ) {
            wp_send_json_error( [ 'message' => 'Share link not found.' ], 404 );
        }
        if ( ! empty( $record['admin_deleted'] ) ) {
            wp_send_json_error( [ 'message' => 'This project has been removed and is no longer available.' ], 410 );
        }
        $skip_count = isset( $_REQUEST['count'] ) && $_REQUEST['count'] === '0';
        if ( ! $skip_count ) {
            $remote_ip = $_SERVER['REMOTE_ADDR'] ?? '';
            $dedupe_key = 'mlp_vw_' . $token . '_' . substr( md5( $remote_ip ), 0, 12 );
            if ( ! get_transient( $dedupe_key ) ) {
                $current_views = isset( $record['views'] ) ? intval( $record['views'] ) : 0;
                $record['views']       = $current_views + 1;
                $record['last_viewed'] = time();
                update_option( 'mlp_share_' . $token, $record, false );
                set_transient( $dedupe_key, 1, 300 ); // 5 min dedupe per IP
                self::record_view_event( $token );
            }
        }
        $remote_ip_for_rx = $_SERVER['REMOTE_ADDR'] ?? '';
        $ip_hash_for_rx   = substr( md5( $remote_ip_for_rx ), 0, 12 );
        wp_send_json_success( [
            'payload'      => $record['payload'],
            'views'        => isset( $record['views'] ) ? intval( $record['views'] ) : 0,
            'likes'        => isset( $record['likes'] ) ? intval( $record['likes'] ) : 0,
            'made'         => isset( $record['made']  ) ? intval( $record['made']  ) : 0,
            'viewer_liked' => (bool) get_transient( 'mlp_rx_' . $token . '_like_' . $ip_hash_for_rx ),
            'viewer_made'  => (bool) get_transient( 'mlp_rx_' . $token . '_made_' . $ip_hash_for_rx ),
        ] );
    }
    /* ------------------------------------------------------------------ */
    /*  User self-serve: delete own published shares by project ID          */
    /* ------------------------------------------------------------------ */
    public static function ajax_delete_my_shares() {
        if ( ! check_ajax_referer( 'mlp_share_project', 'nonce', false ) ) {
            wp_send_json_error( [ 'message' => 'Invalid request.' ], 403 );
        }
        $raw_ids = isset( $_POST['project_ids'] ) ? wp_unslash( $_POST['project_ids'] ) : [];
        if ( ! is_array( $raw_ids ) || empty( $raw_ids ) ) {
            wp_send_json_success( [ 'deleted' => 0 ] );
        }
        $ids = array_values( array_filter( array_map( 'sanitize_text_field', (array) $raw_ids ) ) );
        if ( empty( $ids ) ) {
            wp_send_json_success( [ 'deleted' => 0 ] );
        }
        global $wpdb;
        $rows = $wpdb->get_results(
            "SELECT option_name, option_value FROM {$wpdb->options}
             WHERE option_name LIKE 'mlp\_share\_%'",
            ARRAY_A
        );
        $deleted = 0;
        foreach ( $rows as $row ) {
            $data = maybe_unserialize( $row['option_value'] );
            if ( ! is_array( $data ) ) {
                continue;
            }
            $proj_id = isset( $data['project_id'] ) ? (string) $data['project_id'] : '';
            if ( $proj_id === '' || ! in_array( $proj_id, $ids, true ) ) {
                continue;
            }
            $token = substr( $row['option_name'], strlen( 'mlp_share_' ) );
            delete_option( 'mlp_share_' . $token );
            $lt = '_transient_mlp_vw_' . $wpdb->esc_like( $token ) . '_%';
            $lo = '_transient_timeout_mlp_vw_' . $wpdb->esc_like( $token ) . '_%';
            $wpdb->query( $wpdb->prepare(
                "DELETE FROM {$wpdb->options} WHERE option_name LIKE %s OR option_name LIKE %s",
                $lt, $lo
            ) );
            $deleted++;
        }
        wp_send_json_success( [ 'deleted' => $deleted ] );
    }
    /* ------------------------------------------------------------------ */
    /*  Reactions — likes & "made with this" counters                       */
    /* ------------------------------------------------------------------ */
    public static function ajax_react_to_share() {
        if ( ! check_ajax_referer( 'mlp_share_project', 'nonce', false ) ) {
            wp_send_json_error( [ 'message' => 'Invalid request.' ], 403 );
        }
        $token    = isset( $_POST['token'] )    ? sanitize_key( wp_unslash( $_POST['token'] ) )    : '';
        $reaction = isset( $_POST['reaction'] ) ? sanitize_key( wp_unslash( $_POST['reaction'] ) ) : '';
        $state    = isset( $_POST['state'] )    ? intval( $_POST['state'] )                       : 1;
        if ( $token === '' || ! in_array( $reaction, [ 'like', 'made' ], true ) ) {
            wp_send_json_error( [ 'message' => 'Invalid reaction request.' ], 400 );
        }
        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || empty( $record['payload'] ) ) {
            wp_send_json_error( [ 'message' => 'Share link not found.' ], 404 );
        }
        if ( ! empty( $record['admin_deleted'] ) ) {
            wp_send_json_error( [ 'message' => 'This project is no longer available.' ], 410 );
        }
        $remote_ip   = $_SERVER['REMOTE_ADDR'] ?? '';
        $ip_hash     = substr( md5( $remote_ip ), 0, 12 );
        $rl_key      = 'mlp_rx_rl_' . $ip_hash;
        $rl_max      = 60;
        $rl_window   = 10 * MINUTE_IN_SECONDS;
        $rl_data     = get_transient( $rl_key );
        if ( ! is_array( $rl_data ) ) {
            $rl_data = [ 'count' => 0, 'reset_at' => time() + $rl_window ];
        }
        if ( $rl_data['reset_at'] <= time() ) {
            $rl_data = [ 'count' => 0, 'reset_at' => time() + $rl_window ];
        }
        if ( $rl_data['count'] >= $rl_max ) {
            wp_send_json_error( [ 'message' => 'Too many reactions in a short time. Try again in a few minutes.' ], 429 );
        }
        $rl_data['count']++;
        set_transient( $rl_key, $rl_data, max( 60, $rl_data['reset_at'] - time() ) );
        $field      = ( $reaction === 'like' ) ? 'likes' : 'made';
        $dedupe_key = 'mlp_rx_' . $token . '_' . $reaction . '_' . $ip_hash;
        $already_on = (bool) get_transient( $dedupe_key );
        $current = isset( $record[ $field ] ) ? intval( $record[ $field ] ) : 0;
        if ( $state ) {
            if ( ! $already_on ) {
                $current++;
                set_transient( $dedupe_key, 1, DAY_IN_SECONDS );
            }
        } else {
            if ( $already_on ) {
                $current = max( 0, $current - 1 );
                delete_transient( $dedupe_key );
            }
        }
        $record[ $field ]            = $current;
        $record[ $field . '_at' ]    = time();
        update_option( 'mlp_share_' . $token, $record, false );
        wp_send_json_success( [
            'token'        => $token,
            'likes'        => isset( $record['likes'] ) ? intval( $record['likes'] ) : 0,
            'made'         => isset( $record['made']  ) ? intval( $record['made']  ) : 0,
            'viewer_liked' => (bool) get_transient( 'mlp_rx_' . $token . '_like_' . $ip_hash ),
            'viewer_made'  => (bool) get_transient( 'mlp_rx_' . $token . '_made_' . $ip_hash ),
        ] );
    }
    public static function ajax_get_share_reactions() {
        $raw    = isset( $_POST['tokens'] ) ? wp_unslash( $_POST['tokens'] ) : '';
        $tokens = is_array( $raw ) ? $raw : json_decode( $raw, true );
        if ( ! is_array( $tokens ) || empty( $tokens ) ) {
            wp_send_json_success( [ 'reactions' => (object) [] ] );
            return;
        }
        $tokens    = array_map( 'sanitize_key', array_slice( $tokens, 0, 100 ) );
        $tokens    = array_values( array_filter( $tokens, 'strlen' ) );
        if ( empty( $tokens ) ) {
            wp_send_json_success( [ 'reactions' => (object) [] ] );
            return;
        }
        $remote_ip = $_SERVER['REMOTE_ADDR'] ?? '';
        $ip_hash   = substr( md5( $remote_ip ), 0, 12 );
        global $wpdb;
        $option_names = array_map( function( $t ) { return 'mlp_share_' . $t; }, $tokens );
        $ph           = implode( ',', array_fill( 0, count( $option_names ), '%s' ) );
        $rows         = $wpdb->get_results(
            $wpdb->prepare( "SELECT option_name, option_value FROM {$wpdb->options} WHERE option_name IN ($ph)", ...$option_names ),
            ARRAY_A
        );
        $records = [];
        foreach ( $rows as $row ) {
            $tok             = substr( $row['option_name'], strlen( 'mlp_share_' ) );
            $records[ $tok ] = maybe_unserialize( $row['option_value'] );
        }
        $t_map = [];
        foreach ( $tokens as $tok ) {
            $t_map[ '_transient_mlp_rx_' . $tok . '_like_' . $ip_hash ] = [ $tok, 'like' ];
            $t_map[ '_transient_mlp_rx_' . $tok . '_made_' . $ip_hash ] = [ $tok, 'made' ];
        }
        $tkeys       = array_keys( $t_map );
        $tph         = implode( ',', array_fill( 0, count( $tkeys ), '%s' ) );
        $t_rows      = $wpdb->get_results(
            $wpdb->prepare( "SELECT option_name FROM {$wpdb->options} WHERE option_name IN ($tph)", ...$tkeys ),
            ARRAY_A
        );
        $viewer_liked = [];
        $viewer_made  = [];
        foreach ( $t_rows as $tr ) {
            if ( isset( $t_map[ $tr['option_name'] ] ) ) {
                [ $tok, $type ] = $t_map[ $tr['option_name'] ];
                if ( $type === 'like' ) $viewer_liked[ $tok ] = true;
                else                   $viewer_made[ $tok ]  = true;
            }
        }
        $out = [];
        foreach ( $tokens as $token ) {
            if ( isset( $records[ $token ] ) && is_array( $records[ $token ] ) ) {
                $rec           = $records[ $token ];
                $out[ $token ] = [
                    'likes'        => isset( $rec['likes'] ) ? intval( $rec['likes'] ) : 0,
                    'made'         => isset( $rec['made']  ) ? intval( $rec['made']  ) : 0,
                    'viewer_liked' => isset( $viewer_liked[ $token ] ),
                    'viewer_made'  => isset( $viewer_made[ $token ] ),
                ];
            }
        }
        wp_send_json_success( [ 'reactions' => (object) $out ] );
    }
    public static function ajax_get_project_views() {
        $raw    = isset( $_POST['tokens'] ) ? wp_unslash( $_POST['tokens'] ) : '';
        $tokens = is_array( $raw ) ? $raw : json_decode( $raw, true );
        if ( ! is_array( $tokens ) || empty( $tokens ) ) {
            wp_send_json_success( [ 'views' => (object) [] ] );
            return;
        }
        $tokens = array_values( array_filter( array_map( 'sanitize_key', array_slice( $tokens, 0, 100 ) ), 'strlen' ) );
        if ( empty( $tokens ) ) {
            wp_send_json_success( [ 'views' => (object) [] ] );
            return;
        }
        $cache_key = 'mlp_pst_' . md5( implode( ',', $tokens ) );
        $cached_result = get_transient( $cache_key );
        if ( $cached_result !== false ) { wp_send_json_success( $cached_result ); return; }
        global $wpdb;
        $option_names = array_map( function( $t ) { return 'mlp_share_' . $t; }, $tokens );
        $ph           = implode( ',', array_fill( 0, count( $option_names ), '%s' ) );
        $rows         = $wpdb->get_results(
            $wpdb->prepare( "SELECT option_name, option_value FROM {$wpdb->options} WHERE option_name IN ($ph)", ...$option_names ),
            ARRAY_A
        );
        $views = [];
        foreach ( $rows as $row ) {
            $tok           = substr( $row['option_name'], strlen( 'mlp_share_' ) );
            $rec           = maybe_unserialize( $row['option_value'] );
            $views[ $tok ] = is_array( $rec ) && isset( $rec['views'] ) ? intval( $rec['views'] ) : 0;
        }
        wp_send_json_success( [ 'views' => (object) $views ] );
    }
    public static function ajax_check_project_status() {
        $raw    = isset( $_POST['tokens'] ) ? wp_unslash( $_POST['tokens'] ) : '';
        $tokens = is_array( $raw ) ? $raw : json_decode( $raw, true );
        if ( ! is_array( $tokens ) || empty( $tokens ) ) {
            wp_send_json_success( [ 'deleted' => [], 'active' => (object) [] ] );
            return;
        }
        $tokens = array_values( array_filter( array_map( 'sanitize_key', array_slice( $tokens, 0, 100 ) ), 'strlen' ) );
        if ( empty( $tokens ) ) {
            wp_send_json_success( [ 'deleted' => [], 'active' => (object) [] ] );
            return;
        }
        global $wpdb;
        $option_names = array_map( function( $t ) { return 'mlp_share_' . $t; }, $tokens );
        $ph           = implode( ',', array_fill( 0, count( $option_names ), '%s' ) );
        $rows         = $wpdb->get_results(
            $wpdb->prepare( "SELECT option_name, option_value FROM {$wpdb->options} WHERE option_name IN ($ph)", ...$option_names ),
            ARRAY_A
        );
        $found = [];
        foreach ( $rows as $row ) {
            $tok           = substr( $row['option_name'], strlen( 'mlp_share_' ) );
            $found[ $tok ] = maybe_unserialize( $row['option_value'] );
        }
        $deleted  = [];
        $active   = [];
        $base_url = home_url( '/?mlpsht=' ); // cached once
        foreach ( $tokens as $token ) {
            if ( ! isset( $found[ $token ] ) || ! is_array( $found[ $token ] ) ) continue;
            $record = $found[ $token ];
            if ( ! empty( $record['admin_deleted'] ) ) {
                $deleted[] = $token;
            } else {
                $active[ $token ] = [ 'share_url' => $base_url . $token ];
            }
        }
        $result = [ 'deleted' => $deleted, 'active' => (object) $active ];
        set_transient( $cache_key, $result, 60 );
        wp_send_json_success( $result );
    }
    /* ------------------------------------------------------------------ */
    /*  Analytics — per-share view events + aggregated stats                */
    /* ------------------------------------------------------------------ */
    const ANALYTICS_MAX_EVENTS     = 5000;
    const ANALYTICS_RETENTION_DAYS = 90;
    private static function record_view_event( $token ) {
        $key    = 'mlp_share_an_' . $token;
        $events = get_option( $key, [] );
        if ( ! is_array( $events ) ) {
            $events = [];
        }
        $country = '';
        if ( ! empty( $_SERVER['HTTP_CF_IPCOUNTRY'] ) ) {
            $cc = strtoupper( substr( sanitize_text_field( $_SERVER['HTTP_CF_IPCOUNTRY'] ), 0, 2 ) );
            if ( ctype_alpha( $cc ) && $cc !== 'XX' && $cc !== 'T1' ) {
                $country = $cc;
            }
        }
        $referrer_host = '';
        $raw_ref       = isset( $_SERVER['HTTP_REFERER'] ) ? (string) $_SERVER['HTTP_REFERER'] : '';
        if ( $raw_ref !== '' ) {
            $parts = wp_parse_url( $raw_ref );
            if ( ! empty( $parts['host'] ) ) {
                $host = strtolower( $parts['host'] );
                if ( strpos( $host, 'www.' ) === 0 ) {
                    $host = substr( $host, 4 );
                }
                $referrer_host = $host;
            }
        }
        static $self_host = null;
        if ( $self_host === null ) {
            $self_host = strtolower( (string) wp_parse_url( home_url(), PHP_URL_HOST ) );
            if ( $self_host !== '' && strpos( $self_host, 'www.' ) === 0 ) {
                $self_host = substr( $self_host, 4 );
            }
        }
        if ( $referrer_host !== '' && $referrer_host === $self_host ) {
            $referrer_host = '';
        }
        $ua     = isset( $_SERVER['HTTP_USER_AGENT'] ) ? (string) $_SERVER['HTTP_USER_AGENT'] : '';
        $device = self::parse_device_from_ua( $ua );
        $events[] = [
            't' => time(),
            'c' => $country,
            'r' => $referrer_host,
            'd' => $device,
        ];
        $cutoff = time() - ( self::ANALYTICS_RETENTION_DAYS * DAY_IN_SECONDS );
        $events = array_values( array_filter( $events, function( $e ) use ( $cutoff ) {
            return is_array( $e ) && isset( $e['t'] ) && (int) $e['t'] >= $cutoff;
        } ) );
        if ( count( $events ) > self::ANALYTICS_MAX_EVENTS ) {
            $events = array_slice( $events, -self::ANALYTICS_MAX_EVENTS );
        }
        update_option( $key, $events, false );
    }
    private static function parse_device_from_ua( $ua ) {
        if ( ! is_string( $ua ) || $ua === '' ) {
            return 'desktop';
        }
        $u = strtolower( $ua );
        if ( strpos( $u, 'ipad' ) !== false )                                   return 'tablet';
        if ( strpos( $u, 'tablet' ) !== false )                                 return 'tablet';
        if ( strpos( $u, 'android' ) !== false && strpos( $u, 'mobile' ) === false ) return 'tablet';
        if ( strpos( $u, 'kindle' ) !== false || strpos( $u, 'silk' ) !== false ) return 'tablet';
        if ( preg_match( '/iphone|ipod|android.*mobile|windows phone|blackberry|opera mini|opera mobi|mobile/i', $u ) ) {
            return 'mobile';
        }
        return 'desktop';
    }
    public static function ajax_get_project_analytics() {
        $token = isset( $_REQUEST['token'] ) ? sanitize_key( wp_unslash( $_REQUEST['token'] ) ) : '';
        if ( $token === '' ) {
            wp_send_json_error( [ 'message' => 'Missing share token.' ], 400 );
        }
        $share = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $share ) ) {
            wp_send_json_error( [ 'message' => 'Share not found.' ], 404 );
        }
        $range_in   = isset( $_REQUEST['range'] ) ? intval( $_REQUEST['range'] ) : 30;
        $range_days = in_array( $range_in, [ 7, 30, 90 ], true ) ? $range_in : 30;
        $events = get_option( 'mlp_share_an_' . $token, [] );
        if ( ! is_array( $events ) ) {
            $events = [];
        }
        $tz_offset = (int) ( get_option( 'gmt_offset' ) * HOUR_IN_SECONDS );
        $now_local = time() + $tz_offset;
        $daily = [];
        for ( $i = $range_days - 1; $i >= 0; $i-- ) {
            $d = gmdate( 'Y-m-d', $now_local - ( $i * DAY_IN_SECONDS ) );
            $daily[ $d ] = 0;
        }
        $window_cutoff = time() - ( $range_days * DAY_IN_SECONDS );
        $referrers     = [];
        $countries     = [];
        $devices       = [ 'desktop' => 0, 'mobile' => 0, 'tablet' => 0 ];
        $total_range   = 0;
        $total_all     = 0;
        foreach ( $events as $e ) {
            if ( ! is_array( $e ) || empty( $e['t'] ) ) continue;
            $total_all++;
            if ( (int) $e['t'] < $window_cutoff ) continue;
            $total_range++;
            $d_local = gmdate( 'Y-m-d', (int) $e['t'] + $tz_offset );
            if ( isset( $daily[ $d_local ] ) ) {
                $daily[ $d_local ]++;
            }
            $r = isset( $e['r'] ) ? (string) $e['r'] : '';
            if ( $r !== '' ) {
                if ( ! isset( $referrers[ $r ] ) ) $referrers[ $r ] = 0;
                $referrers[ $r ]++;
            }
            $c = isset( $e['c'] ) ? (string) $e['c'] : '';
            if ( $c !== '' ) {
                if ( ! isset( $countries[ $c ] ) ) $countries[ $c ] = 0;
                $countries[ $c ]++;
            }
            $dv = isset( $e['d'] ) ? (string) $e['d'] : 'desktop';
            if ( ! in_array( $dv, [ 'desktop', 'mobile', 'tablet' ], true ) ) {
                $dv = 'desktop';
            }
            $devices[ $dv ]++;
        }
        $daily_list = [];
        $peak       = [ 'date' => null, 'views' => 0 ];
        foreach ( $daily as $date => $views ) {
            $daily_list[] = [ 'date' => $date, 'views' => $views ];
            if ( $views > $peak['views'] ) {
                $peak = [ 'date' => $date, 'views' => $views ];
            }
        }
        arsort( $referrers );
        arsort( $countries );
        $top_referrers = [];
        $i = 0;
        foreach ( $referrers as $host => $views ) {
            if ( $i++ >= 8 ) break;
            $top_referrers[] = [ 'host' => $host, 'views' => (int) $views ];
        }
        $top_countries = [];
        $i = 0;
        foreach ( $countries as $code => $views ) {
            if ( $i++ >= 8 ) break;
            $top_countries[] = [
                'code'  => $code,
                'name'  => self::country_code_to_name( $code ),
                'flag'  => self::country_code_to_flag( $code ),
                'views' => (int) $views,
            ];
        }
        $referrer_total = array_sum( $referrers );
        $country_total  = array_sum( $countries );
        $device_total   = $devices['desktop'] + $devices['mobile'] + $devices['tablet'];
        wp_send_json_success( [
            'token'           => $token,
            'range_days'      => $range_days,
            'daily'           => $daily_list,
            'total_range'     => $total_range,
            'total_all'       => max( $total_all, isset( $share['views'] ) ? (int) $share['views'] : 0 ),
            'peak'            => $peak,
            'referrers'       => $top_referrers,
            'referrer_total'  => $referrer_total,
            'direct_views'    => max( 0, $total_range - $referrer_total ),
            'countries'       => $top_countries,
            'country_total'   => $country_total,
            'devices'         => $devices,
            'device_total'    => $device_total,
            'last_viewed'     => isset( $share['last_viewed'] ) ? (int) $share['last_viewed'] : 0,
            'created'         => isset( $share['created'] ) ? (int) $share['created'] : 0,
        ] );
    }
