                'QA'=>'Qatar',
                'RO'=>'Romania','RS'=>'Serbia','RU'=>'Russia','RW'=>'Rwanda',
                'SA'=>'Saudi Arabia','SE'=>'Sweden','SG'=>'Singapore','SI'=>'Slovenia','SK'=>'Slovakia','SN'=>'Senegal','SO'=>'Somalia','SR'=>'Suriname','SV'=>'El Salvador','SY'=>'Syria',
                'TH'=>'Thailand','TJ'=>'Tajikistan','TM'=>'Turkmenistan','TN'=>'Tunisia','TR'=>'Turkey','TT'=>'Trinidad & Tobago','TW'=>'Taiwan','TZ'=>'Tanzania',
                'UA'=>'Ukraine','UG'=>'Uganda','US'=>'United States','UY'=>'Uruguay','UZ'=>'Uzbekistan',
                'VE'=>'Venezuela','VN'=>'Vietnam',
                'YE'=>'Yemen',
                'ZA'=>'South Africa','ZM'=>'Zambia','ZW'=>'Zimbabwe',
            ];
        }
        $code = strtoupper( (string) $code );
        return isset( $names[ $code ] ) ? $names[ $code ] : $code;
    }
    private static function country_code_to_flag( $code ) {
        if ( ! is_string( $code ) || strlen( $code ) !== 2 ) return '';
        $code = strtoupper( $code );
        if ( ! ctype_alpha( $code ) ) return '';
        $a = function_exists( 'mb_chr' ) ? mb_chr( 0x1F1E6 + ( ord( $code[0] ) - 65 ), 'UTF-8' ) : '';
        $b = function_exists( 'mb_chr' ) ? mb_chr( 0x1F1E6 + ( ord( $code[1] ) - 65 ), 'UTF-8' ) : '';
        return $a . $b;
    }
    /* ------------------------------------------------------------------ */
    /*  Shortcode page detection                                            */
    /* ------------------------------------------------------------------ */
    private static function is_shortcode_page( $tag = 'mobile_live_preview' ) {
        static $cache = [];
        if ( isset( $cache[ $tag ] ) ) {
            return $cache[ $tag ];
        }
        $post = get_post();
        if ( ! $post instanceof WP_Post ) {
            return $cache[ $tag ] = false;
        }
        return $cache[ $tag ] = has_shortcode( $post->post_content, $tag );
    }
