              <button type="button" id="mlp-proj-storage-help-btn"
                      aria-label="What do these storage options mean?"
                      title="What do these storage options mean?"
                      style="display:inline-flex;align-items:center;justify-content:center;
                             width:18px;height:18px;border-radius:50%;border:none;cursor:pointer;
                             font-size:0.7rem;font-weight:600;line-height:1;
                             color:#2563eb;background:rgba(37,99,235,0.12);
                             font-family:var(--mlp-font);transition:background 0.15s;">?</button>
            </label>
            <div id="mlp-proj-storage-help" style="display:none;margin-top:6px;padding:10px 12px;
                  border:1px solid rgba(37,99,235,0.25);background:rgba(37,99,235,0.05);
                  border-radius:8px;font-size:0.74rem;line-height:1.55;color:var(--mlp-text-muted);">
              <div style="margin-bottom:8px;">
                <strong style="color:var(--mlp-text);">Default</strong><br/>
                The project is saved only in this browser's local storage on this device.
                It's fast and works offline, but if you clear your browser data, switch
                devices, or your storage is wiped, the project is gone for good.
              </div>
              <div>
                <strong style="color:var(--mlp-text);">GitHub Gist (save on both)</strong><br/>
                The project is saved locally <em>and</em> pushed to a private GitHub Gist
                you control. You get a real backup synced to your GitHub account, so you
                can recover or open it from any device. Requires a Gist token (set up via
                the GitHub menu in the nav).
              </div>
            </div>
            <select id="mlp-proj-storage-input" class="mlp-field-input">
              <option value="local" selected>Default</option>
              <option value="github-gist">GitHub Gist (save on both this device and Gist)</option>
            </select>
