    <div class="mlp-modal mlp-modal-sm mlp-onboard-modal">
      <div class="mlp-onboard-hero">
        <div class="mlp-onboard-avatar-preview" id="mlp-onboard-avatar-preview"></div>
        <h2 class="mlp-onboard-title">Welcome to Pterocos</h2>
        <p class="mlp-onboard-sub">Choose a username to get started</p>
      </div>
      <div class="mlp-modal-body">
        <label class="mlp-field-label" for="mlp-username-input">Your name</label>
        <input type="text" id="mlp-username-input" class="mlp-field-input" placeholder="e.g. Alex, dev_wizard…" maxlength="32" autocomplete="off"/>
        <p class="mlp-onboard-hint">This is shown on your editor nav bar.</p>
      </div>
      <div class="mlp-modal-footer">
        <button id="mlp-username-save-btn" class="mlp-btn-primary" style="width:100%;">Let's go →</button>
      </div>
    </div>
  </div>
  <!-- ── Profile settings modal ── -->
  <div id="mlp-settings-modal" class="mlp-modal-backdrop" style="display:none;">
    <div class="mlp-modal mlp-modal-sm">
      <div class="mlp-modal-header">
        <h3>Profile Settings</h3>
        <button id="mlp-settings-modal-close" class="mlp-modal-close" aria-label="Close">&#x2715;</button>
      </div>
      <div class="mlp-modal-body">
        <!-- Avatar section -->
        <div class="mlp-settings-avatar-row">
          <div class="mlp-settings-avatar-wrap">
            <div class="mlp-settings-avatar" id="mlp-settings-avatar-preview"></div>
          </div>
          <div class="mlp-settings-avatar-info">
            <span class="mlp-settings-avatar-label">Profile photo</span>
            <div style="display:flex;gap:6px;margin-top:4px;flex-wrap:wrap;">
              <label class="mlp-btn-ghost mlp-btn-xs" style="cursor:pointer;display:inline-flex;align-items:center;gap:5px;">
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>
                Upload
                <input type="file" id="mlp-avatar-file-input" accept="image/*" style="display:none;"/>
              </label>
              <button type="button" id="mlp-avatar-remove-btn" class="mlp-btn-ghost mlp-btn-xs" style="color:#ef4444;">Remove</button>
            </div>
            <span class="mlp-settings-avatar-hint">JPG/PNG/GIF up to 2 MB.</span>
          </div>
        </div>
        <!-- Name -->
        <label class="mlp-field-label" for="mlp-settings-name-input" style="margin-top:16px;">Display name</label>
        <input type="text" id="mlp-settings-name-input" class="mlp-field-input" placeholder="Your name" maxlength="32" autocomplete="off"/>
        <!-- Danger zone -->
        <div class="mlp-settings-danger-zone">
          <span class="mlp-settings-danger-zone-label">Danger Zone</span>
          <button id="mlp-settings-delete-account-btn" class="mlp-btn-delete-account" type="button">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
              <polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/>
            </svg>
            Delete Account &amp; All Data
          </button>
        </div>
      </div>
      <div class="mlp-modal-footer">
        <button id="mlp-settings-cancel-btn" class="mlp-btn-ghost">Cancel</button>
        <button id="mlp-settings-save-btn" class="mlp-btn-primary">Save changes</button>
      </div>
    </div>
  </div>
  <!-- Keyboard Shortcuts modal -->
  <div id="mlp-keybinds-modal" class="mlp-modal-backdrop" style="display:none;">
    <div class="mlp-modal mlp-modal-sm">
      <div class="mlp-modal-header">
        <h3 style="display:flex;align-items:center;gap:9px;">
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><rect x="2" y="6" width="20" height="12" rx="2"/><path d="M6 10h.01M10 10h.01M14 10h.01M18 10h.01M6 14h12"/></svg>
          Keyboard Shortcuts
        </h3>
        <button id="mlp-keybinds-modal-close" class="mlp-modal-close" aria-label="Close">&#x2715;</button>
      </div>
      <div class="mlp-modal-body">
        <p style="font-size:0.78rem;color:var(--mlp-text-muted);margin:0 0 16px;line-height:1.55;">
          Customize keyboard shortcuts. Click <strong>Change</strong> next to any shortcut, then press the key you want to use.
        </p>
        <div class="mlp-keybinds-section-label">Navigation</div>
        <div class="mlp-keybinds-list">
          <div class="mlp-keybind-row" id="mlp-keybind-row-newProject">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">New project</span>
              <span class="mlp-keybind-desc">Open the new project dialog</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key" id="mlp-keybind-key-newProject">N</kbd>
              <button class="mlp-keybind-change-btn" data-action="newProject" type="button">Change</button>
              <button class="mlp-keybind-reset-btn" data-action="newProject" type="button" title="Reset to default">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.5"/></svg>
              </button>
            </div>
          </div>
          <div class="mlp-keybind-row" id="mlp-keybind-row-search">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Focus search</span>
              <span class="mlp-keybind-desc">Jump to the search bar</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key" id="mlp-keybind-key-search">/</kbd>
              <button class="mlp-keybind-change-btn" data-action="search" type="button">Change</button>
              <button class="mlp-keybind-reset-btn" data-action="search" type="button" title="Reset to default">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.5"/></svg>
              </button>
            </div>
          </div>
          <div class="mlp-keybind-row" id="mlp-keybind-row-settings">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Open settings</span>
              <span class="mlp-keybind-desc">Open the profile settings dialog</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key" id="mlp-keybind-key-settings">,</kbd>
              <button class="mlp-keybind-change-btn" data-action="settings" type="button">Change</button>
              <button class="mlp-keybind-reset-btn" data-action="settings" type="button" title="Reset to default">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.5"/></svg>
              </button>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Show shortcuts</span>
              <span class="mlp-keybind-desc">Open this shortcuts dialog</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">?</kbd>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Close / Escape</span>
              <span class="mlp-keybind-desc">Close modals or the overlay</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Esc</kbd>
            </div>
          </div>
        </div>
        <div class="mlp-keybinds-section-label" style="margin-top:14px;">Filters</div>
        <div class="mlp-keybinds-list">
          <div class="mlp-keybind-row" id="mlp-keybind-row-filterAll">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Show all</span>
              <span class="mlp-keybind-desc">Clear filters and show every project</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key" id="mlp-keybind-key-filterAll">A</kbd>
              <button class="mlp-keybind-change-btn" data-action="filterAll" type="button">Change</button>
              <button class="mlp-keybind-reset-btn" data-action="filterAll" type="button" title="Reset to default">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.5"/></svg>
              </button>
            </div>
          </div>
          <div class="mlp-keybind-row" id="mlp-keybind-row-filterFavorites">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Filter favorites</span>
              <span class="mlp-keybind-desc">Toggle the Favorites filter</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key" id="mlp-keybind-key-filterFavorites">F</kbd>
              <button class="mlp-keybind-change-btn" data-action="filterFavorites" type="button">Change</button>
              <button class="mlp-keybind-reset-btn" data-action="filterFavorites" type="button" title="Reset to default">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.5"/></svg>
              </button>
            </div>
          </div>
          <div class="mlp-keybind-row" id="mlp-keybind-row-filterPinned">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Filter pinned</span>
              <span class="mlp-keybind-desc">Toggle the Pinned filter</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key" id="mlp-keybind-key-filterPinned">P</kbd>
              <button class="mlp-keybind-change-btn" data-action="filterPinned" type="button">Change</button>
              <button class="mlp-keybind-reset-btn" data-action="filterPinned" type="button" title="Reset to default">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.5"/></svg>
              </button>
            </div>
          </div>
        </div>
        <div class="mlp-keybinds-section-label" style="margin-top:14px;">Sorting</div>
        <div class="mlp-keybinds-list">
          <div class="mlp-keybind-row" id="mlp-keybind-row-sortDir">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Reverse sort order</span>
              <span class="mlp-keybind-desc">Toggle ascending / descending (when sort is active)</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key" id="mlp-keybind-key-sortDir">D</kbd>
              <button class="mlp-keybind-change-btn" data-action="sortDir" type="button">Change</button>
              <button class="mlp-keybind-reset-btn" data-action="sortDir" type="button" title="Reset to default">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-4.5"/></svg>
              </button>
            </div>
          </div>
        </div>
        <div class="mlp-keybinds-section-label" style="margin-top:14px;">Editor</div>
        <p style="font-size:0.72rem;color:var(--mlp-text-muted);margin:0 0 8px;line-height:1.5;">
          These shortcuts work while the code editor is open. They use modifier keys and cannot be remapped.
        </p>
        <div class="mlp-keybinds-list">
          <div class="mlp-keybind-row mlp-keybind-row-readonly mlp-keybind-row-editor">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Run / refresh preview</span>
              <span class="mlp-keybind-desc">Re-render the live preview iframe</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Ctrl+Enter</kbd>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly mlp-keybind-row-editor">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Save current tab</span>
              <span class="mlp-keybind-desc">Persist the active tab to local storage</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Ctrl+S</kbd>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly mlp-keybind-row-editor">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Fullscreen editor</span>
              <span class="mlp-keybind-desc">Toggle the fullscreen code editor overlay</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Ctrl+Shift+F</kbd>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly mlp-keybind-row-editor">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">Fullscreen preview</span>
              <span class="mlp-keybind-desc">Toggle the fullscreen preview pane</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Ctrl+Shift+P</kbd>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly mlp-keybind-row-editor">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">HTML panel</span>
              <span class="mlp-keybind-desc">Switch to the HTML code panel</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Alt+1</kbd>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly mlp-keybind-row-editor">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">CSS panel</span>
              <span class="mlp-keybind-desc">Switch to the CSS code panel</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Alt+2</kbd>
            </div>
          </div>
          <div class="mlp-keybind-row mlp-keybind-row-readonly mlp-keybind-row-editor">
            <div class="mlp-keybind-info">
              <span class="mlp-keybind-label">JS panel</span>
              <span class="mlp-keybind-desc">Switch to the JavaScript code panel</span>
            </div>
            <div class="mlp-keybind-controls">
              <kbd class="mlp-keybind-key">Alt+3</kbd>
            </div>
          </div>
        </div>
        <p id="mlp-keybind-listening-hint" style="display:none;font-size:0.75rem;color:var(--mlp-accent);margin:14px 0 0;text-align:center;font-weight:500;">
          Press any key to assign it &mdash; <span style="opacity:0.7;">Esc to cancel</span>
        </p>
      </div>
      <div class="mlp-modal-footer">
        <button id="mlp-keybinds-reset-all-btn" class="mlp-btn-ghost" type="button" style="margin-right:auto;">Reset all</button>
        <button id="mlp-keybinds-close-btn" class="mlp-btn-primary" type="button">Done</button>
      </div>
    </div>
  </div>
  <!-- Gist Token setup modal (opened from nav GitHub dropdown) -->
  <div id="mlp-gist-token-modal" class="mlp-modal-backdrop" style="display:none;">
    <div class="mlp-modal mlp-modal-sm">
      <div class="mlp-modal-header">
        <h3 style="display:flex;align-items:center;gap:10px;flex:1;min-width:0;">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" xmlns="http://www.w3.org/2000/svg" style="flex-shrink:0;">
            <path d="M12 2C6.477 2 2 6.477 2 12c0 4.418 2.865 8.166 6.839 9.489.5.09.682-.218.682-.483 0-.237-.009-.868-.013-1.703-2.782.605-3.369-1.342-3.369-1.342-.454-1.156-1.11-1.463-1.11-1.463-.908-.62.069-.608.069-.608 1.003.07 1.531 1.032 1.531 1.032.892 1.53 2.341 1.088 2.91.832.091-.647.349-1.088.635-1.338-2.22-.253-4.555-1.113-4.555-4.951 0-1.093.39-1.987 1.029-2.688-.103-.253-.446-1.272.098-2.65 0 0 .84-.27 2.75 1.026A9.564 9.564 0 0 1 12 6.844c.85.004 1.705.115 2.504.337 1.909-1.296 2.747-1.027 2.747-1.027.546 1.379.202 2.398.1 2.651.64.701 1.028 1.595 1.028 2.688 0 3.848-2.339 4.695-4.566 4.942.359.309.678.919.678 1.852 0 1.336-.012 2.415-.012 2.742 0 .267.18.578.688.48C19.138 20.163 22 16.418 22 12c0-5.523-4.477-10-10-10z"/>
          </svg>
          <span style="white-space:nowrap;">Gist Token</span>
          <span id="mlp-gist-token-modal-pill" class="mlp-gist-pill mlp-gist-pill-off" role="status" aria-live="polite">
            <span class="mlp-gist-pill-dot" aria-hidden="true"></span>
            <span id="mlp-gist-token-modal-pill-label">Disconnected</span>
          </span>
        </h3>
        <button id="mlp-gist-token-modal-close" class="mlp-modal-close" aria-label="Close">&#x2715;</button>
      </div>
      <div class="mlp-modal-body">
        <p style="font-size:0.78rem;color:var(--mlp-text-muted);margin:0 0 14px;line-height:1.55;">
          Connect a private GitHub Gist to back up your projects automatically across devices.
          Generate a <a href="https://github.com/settings/tokens/new?description=MLP+Backup&scopes=gist" target="_blank" rel="noopener noreferrer" style="color:var(--mlp-accent);text-decoration:none;font-weight:500;">Personal Access Token</a>
          with the <code style="font-size:0.72rem;background:var(--mlp-border-muted);padding:1px 5px;border-radius:3px;font-family:var(--mlp-font-mono);">gist</code> scope and paste it below.
        </p>
        <label class="mlp-field-label" for="mlp-gist-token-modal-input" style="display:flex;align-items:center;gap:6px;">
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="opacity:0.7;">
            <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/>
            <path d="M7 11V7a5 5 0 0 1 10 0v4"/>
          </svg>
          Personal Access Token
        </label>
        <div style="display:flex;gap:7px;align-items:center;margin-top:6px;">
          <input type="password" id="mlp-gist-token-modal-input" class="mlp-field-input"
                 placeholder="ghp_xxxxxxxxxxxxxxxxxxxx"
                 autocomplete="new-password" spellcheck="false"
                 style="flex:1;font-family:var(--mlp-font-mono);font-size:0.8rem;"/>
          <button id="mlp-gist-token-modal-test-btn" type="button" class="mlp-btn-ghost"
                  title="Verify the token against GitHub before saving"
                  style="white-space:nowrap;padding:7px 12px;font-size:0.78rem;display:inline-flex;align-items:center;gap:6px;">
            <svg id="mlp-gist-test-icon" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0;">
              <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/>
            </svg>
            <span id="mlp-gist-test-label">Test</span>
          </button>
        </div>
        <div id="mlp-gist-token-modal-status" style="margin-top:10px;font-size:0.74rem;color:var(--mlp-text-muted);min-height:18px;line-height:1.5;"></div>
        <div style="margin-top:18px;padding:12px 14px;border:1px solid var(--mlp-border);border-radius:8px;background:rgba(220,38,38,0.04);">
          <div style="display:flex;align-items:center;gap:7px;margin-bottom:6px;">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#dc2626" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0;">
              <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>
            </svg>
            <span style="font-size:0.78rem;font-weight:600;color:#dc2626;">Remove Gist Connection</span>
          </div>
          <p style="font-size:0.72rem;color:var(--mlp-text-muted);margin:0 0 10px;line-height:1.5;">
            Deletes your saved token and disconnects this device from the Gist. Your local projects will not be affected.
          </p>
          <button id="mlp-gist-token-modal-delete-btn" type="button" style="
              display:inline-flex;align-items:center;gap:6px;padding:7px 12px;
              border:1px solid rgba(220,38,38,0.4);background:transparent;color:#dc2626;
              border-radius:6px;font-size:0.76rem;font-weight:500;cursor:pointer;
              font-family:var(--mlp-font);transition:background 0.15s, border-color 0.15s;">
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0;">
              <polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/>
            </svg>
            Delete Gist Token
          </button>
        </div>
      </div>
      <div class="mlp-modal-footer">
        <button id="mlp-gist-token-modal-copy-id-btn" type="button" class="mlp-btn-ghost"
                style="margin-right:auto;display:inline-flex;align-items:center;gap:6px;"
