/* ── card action buttons row ─────────────────────────────────── */
#mlp-projects-overlay .mlp-pcard-actions {
    display: flex !important;
    gap: 6px !important;
    align-items: center !important;
    flex-wrap: wrap !important;
    padding-top: 2px !important;
}
#mlp-projects-overlay .mlp-pcard-actions .mlp-row-btn {
    padding: 4px 11px !important;
    font-size: 0.76rem !important;
    border-radius: var(--mlp-radius-sm, 4px) !important;
    font-family: var(--mlp-font) !important;
    border: 1px solid transparent !important;
}
#mlp-projects-overlay .mlp-pcard-actions .mlp-row-btn-go {
    background: var(--mlp-accent, #fb923c) !important;
    color: #fff !important;
    border-color: transparent !important;
}
#mlp-projects-overlay .mlp-pcard-actions .mlp-row-btn-go:hover {
    background: var(--mlp-accent-hover, #f97316) !important;
}
#mlp-projects-overlay .mlp-pcard-actions .mlp-row-btn-more {
    padding: 4px 10px !important;
    font-size: 0.76rem !important;
    border: 1px solid var(--mlp-border, #1f2937) !important;
    background: transparent !important;
    color: var(--mlp-text-secondary, #9ca3af) !important;
}
#mlp-projects-overlay .mlp-pcard-actions .mlp-row-btn-more:hover {
    background: var(--mlp-bg, #0b1220) !important;
    color: var(--mlp-text-primary, #e5e7eb) !important;
