/* ── Glassmorphism card style ─────────────────────────────────── */
#mlp-projects-overlay .mlp-proj-cards-grid {
    background: linear-gradient(135deg, rgba(234,88,12,0.04) 0%, rgba(251,191,36,0.02) 50%, rgba(59,130,246,0.04) 100%) !important;
    border-radius: 12px !important;
    padding: 8px 4px 14px !important;
}
#mlp-projects-overlay .mlp-pcard {
    background: rgba(255,255,255,0.52) !important;
    backdrop-filter: blur(16px) saturate(180%) !important;
    -webkit-backdrop-filter: blur(16px) saturate(180%) !important;
    border: 1px solid rgba(255,255,255,0.78) !important;
    box-shadow: 0 2px 14px rgba(0,0,0,0.06), inset 0 1px 0 rgba(255,255,255,0.92) !important;
    transition: transform 0.16s, box-shadow 0.16s, border-color 0.16s, background 0.16s !important;
}
#mlp-projects-overlay .mlp-pcard:hover {
    background: rgba(255,255,255,0.72) !important;
    border-color: rgba(234,88,12,0.38) !important;
    box-shadow: 0 8px 30px rgba(0,0,0,0.10), inset 0 1px 0 rgba(255,255,255,1) !important;
    transform: translateY(-4px) !important;
}
#mlp-projects-overlay .mlp-pcard-body {
    background: transparent !important;
}
#mlp-projects-overlay .mlp-pcard-thumb {
    background: linear-gradient(135deg, rgba(234,88,12,0.06), rgba(251,191,36,0.05)) !important;
    border-bottom: 1px solid rgba(255,255,255,0.55) !important;
}
#mlp-projects-overlay .mlp-pcard-stat {
    background: rgba(255,255,255,0.55) !important;
    border-color: rgba(255,255,255,0.75) !important;
    backdrop-filter: blur(6px) !important;
    -webkit-backdrop-filter: blur(6px) !important;
}
#mlp-projects-overlay .mlp-pcard-actions .mlp-row-btn-more {
    background: rgba(255,255,255,0.40) !important;
    border-color: rgba(255,255,255,0.65) !important;
    backdrop-filter: blur(6px) !important;
    -webkit-backdrop-filter: blur(6px) !important;
}
#mlp-projects-overlay .mlp-pcard-actions .mlp-row-btn-more:hover {
    background: rgba(255,255,255,0.70) !important;
    border-color: rgba(234,88,12,0.30) !important;
}
/* dark theme glass */
#mlp-projects-overlay[data-mlp-theme="dark"] .mlp-proj-cards-grid {
    background: linear-gradient(135deg, rgba(234,88,12,0.06) 0%, rgba(15,23,42,0.20) 50%, rgba(59,130,246,0.05) 100%) !important;
}
#mlp-projects-overlay[data-mlp-theme="dark"] .mlp-pcard {
    background: rgba(255,255,255,0.05) !important;
    border: 1px solid rgba(255,255,255,0.11) !important;
