     * Without this, the main plugin would always load whatever tabs
     * happened to be in mlp_saved_tabs from the previous session,
     * which may belong to a completely different project.
     * ═══════════════════════════════════════════════════════════════ */
    (function bootRestore() {
        var lastId = null;
        try { lastId = localStorage.getItem(LAST_ID_KEY); } catch (e) {}
        if (!lastId) return;
        var projects = getProjects();
        for (var i = 0; i < projects.length; i++) {
            if (projects[i].id === lastId) {
                window.mlpCurrentProjectId = lastId;
                restoreTabsFromProject(projects[i]);
                var _bootProjId = lastId;
                scheduleReloadTabsForProject(_bootProjId, 16);
                var _restoredProj = projects[i];
                setTimeout(function() {
                    try {
                        if (window._mlpEditorReactBar && typeof window._mlpEditorReactBar.update === "function") {
                            window._mlpEditorReactBar.update(_restoredProj);
                        }
                    } catch (e) {}
                }, 0);
                return;
            }
        }
        try { localStorage.removeItem(LAST_ID_KEY); } catch (e) {}
    }());
    /* ── Auto-save on page unload ─────────────────────────────────── */
    window.addEventListener('beforeunload', function () {
        flushTabsToProject(window.mlpCurrentProjectId || null);
    });
    /* Also flush on visibility change (tab hidden / phone lock screen) */
    document.addEventListener('visibilitychange', function () {
        if (document.visibilityState === 'hidden') {
            flushTabsToProject(window.mlpCurrentProjectId || null);
        }
    });
    /* ── Wrap window.mlpLoadProject ───────────────────────────────── */
    var _origLoadProject = window.mlpLoadProject;
    window.mlpLoadProject = function (p) {
        if (!p || !p.id) return;
        /* DuckDB projects must never open the HTML/CSS/JS editor */
        if (p.type === 'duckdb') {
            if (typeof window.mlpOpenDuckDBEditor === 'function') {
                window.mlpOpenDuckDBEditor(p.id);
            } else {
                /* DuckDB script not yet loaded — wait for it, then open */
                var _ddbWait = 0;
                var _ddbInterval = setInterval(function() {
                    _ddbWait += 100;
                    if (typeof window.mlpOpenDuckDBEditor === 'function') {
                        clearInterval(_ddbInterval);
                        window.mlpOpenDuckDBEditor(p.id);
                    } else if (_ddbWait >= 5000) {
                        clearInterval(_ddbInterval);
                    }
                }, 100);
            }
            return;
        }
        flushTabsToProject(window.mlpCurrentProjectId || null);
        window.mlpCurrentProjectId = p.id;
        var freshProjects = getProjects();
        var freshP = null;
        for (var i = 0; i < freshProjects.length; i++) {
            if (freshProjects[i].id === p.id) { freshP = freshProjects[i]; break; }
        }
        restoreTabsFromProject(freshP || p);
        try { localStorage.setItem(LAST_ID_KEY, p.id); } catch (e) {}
        try {
            var allProjs = getProjects();
            for (var li = 0; li < allProjs.length; li++) {
                if (allProjs[li].id === p.id) {
                    allProjs[li].lastOpenedAt = new Date().toISOString();
                    saveProjects(allProjs);
                    break;
                }
            }
        } catch (e) {}
        if (typeof _origLoadProject === 'function') {
            _origLoadProject(freshP || p);
        }
        scheduleReloadTabsForProject(p.id, 12);
        try {
            if (typeof window._mlpRefreshSyncPillForActive === 'function') {
                window._mlpRefreshSyncPillForActive();
            } else {
                setTimeout(function() {
                    if (typeof window._mlpRefreshSyncPillForActive === 'function') {
                        window._mlpRefreshSyncPillForActive();
                    }
                }, 200);
            }
        } catch(e) {}
        try {
            if (window._mlpEditorReactBar && typeof window._mlpEditorReactBar.update === "function") {
                window._mlpEditorReactBar.update(freshP || p);
            }
        } catch(e) {}
    };
    /* ══════════════════════════════════════════════════════════════
     * Editor reaction bar — top-right floating Like / Made-it buttons
     *
     * Visible ONLY when the current active project has a
     * sourceShareToken (i.e. it was imported from another users share
     * link). Always hidden for projects the viewer owns or that they
     * created from scratch — there is nothing to react to in those
     * cases.
     *
     * Shares the same backend endpoints (mlp_react_to_share /
     * mlp_get_share_reactions) and the same window._mlpReactions cache
     * used by the projects-overlay rendering, so counts stay in sync.
     * ══════════════════════════════════════════════════════════════ */
    window._mlpEditorReactBar = (function() {
        var bar = null;
        var currentToken = null;
        function fmt(n) {
            n = parseInt(n, 10) || 0;
            return (n >= 1000) ? (Math.round(n / 100) / 10) + "k" : String(n);
        }
        function ensureBar() {
            if (bar) return bar;
            bar = document.createElement("div");
            bar.id = "mlp-editor-react-bar";
            bar.className = "mlp-erb-hidden";
            bar.innerHTML =
                '<button type="button" class="mlp-erb-btn" data-react-kind="like" title="Like this shared project">' +
                    '<span class="mlp-erb-emoji">👍</span>' +
                    '<span class="mlp-erb-num">0</span>' +
                    '<span class="mlp-erb-label">like</span>' +
                '</button>' +
                '<button type="button" class="mlp-erb-btn" data-react-kind="dislike" title="Dislike this shared project">' +
                    '<span class="mlp-erb-emoji">👎</span>' +
                    '<span class="mlp-erb-num">0</span>' +
                    '<span class="mlp-erb-label">dislike</span>' +
                '</button>';
            document.body.appendChild(bar);
            var btns = bar.querySelectorAll(".mlp-erb-btn");
            for (var i = 0; i < btns.length; i++) {
                btns[i].addEventListener("click", onBtnClick);
            }
            return bar;
        }
        function onBtnClick(e) {
            e.preventDefault();
            e.stopPropagation();
            var btn = e.currentTarget;
            if (btn.hasAttribute("disabled") || !currentToken) return;
            var kind = btn.getAttribute("data-react-kind");
            if (kind !== "like" && kind !== "dislike") return;
            var otherKind = (kind === "like") ? "dislike" : "like";
            var otherBtn  = bar.querySelector('[data-react-kind="' + otherKind + '"]');
            if (otherBtn && otherBtn.classList.contains("mlp-react-on")) {
                otherBtn.classList.remove("mlp-react-on");
                var otherLabel = otherBtn.querySelector(".mlp-erb-label");
                var otherNum   = otherBtn.querySelector(".mlp-erb-num");
                var otherCurN  = parseInt((otherNum && otherNum.textContent) || "0", 10) || 0;
                if (otherNum)   otherNum.textContent   = fmt(Math.max(0, otherCurN - 1));
                if (otherLabel) otherLabel.textContent  = otherKind;
                if (window.fetch && MLP_AJAX_URL) {
                    var ofd = new FormData();
                    ofd.append("action",   "mlp_react_to_share");
                    ofd.append("nonce",    MLP_SHARE_NONCE);
                    ofd.append("token",    currentToken);
                    ofd.append("reaction", otherKind === "dislike" ? "made" : "like");
                    ofd.append("state",    "0");
                    fetch(MLP_AJAX_URL, { method: "POST", body: ofd, credentials: "same-origin" }).catch(function(){});
                }
            }
            var wasOn   = btn.classList.contains("mlp-react-on");
            var nextOn  = !wasOn;
            var numEl   = btn.querySelector(".mlp-erb-num");
            var labelEl = btn.querySelector(".mlp-erb-label");
            var curN    = parseInt((numEl && numEl.textContent) || "0", 10) || 0;
            btn.classList.toggle("mlp-react-on", nextOn);
            if (numEl)   numEl.textContent   = fmt(Math.max(0, curN + (nextOn ? 1 : -1)));
            if (labelEl) labelEl.textContent = (kind === "like")
                ? (nextOn ? "liked" : "like")
                : (nextOn ? "disliked" : "dislike");
            btn.setAttribute("disabled", "disabled");
            if (bar) bar.classList.add("mlp-erb-hidden");
            if (!window.fetch || !MLP_AJAX_URL) {
                btn.removeAttribute("disabled");
                return;
            }
            var fd = new FormData();
            fd.append("action",   "mlp_react_to_share");
            fd.append("nonce",    MLP_SHARE_NONCE);
            fd.append("token",    currentToken);
            fd.append("reaction", kind === "dislike" ? "made" : "like");
            fd.append("state",    nextOn ? "1" : "0");
            var sentToken = currentToken;
            fetch(MLP_AJAX_URL, { method: "POST", body: fd, credentials: "same-origin" })
                .then(function(r){ return r.json(); })
                .then(function(j) {
                    btn.removeAttribute("disabled");
                    if (!j || !j.success || !j.data) {
                        btn.classList.toggle("mlp-react-on", wasOn);
                        if (numEl)   numEl.textContent   = fmt(curN);
                        if (labelEl) labelEl.textContent = (kind === "like")
                            ? (wasOn ? "liked" : "like")
                            : (wasOn ? "disliked" : "dislike");
                        if (typeof showToast === "function") {
                            showToast("Could not save", (j && j.data && j.data.message) || "Please try again in a moment.", "warning", 3500);
                        }
                        return;
                    }
                    window._mlpReactions = window._mlpReactions || {};
                    window._mlpReactions[sentToken] = {
                        likes:        parseInt(j.data.likes, 10) || 0,
                        made:         parseInt(j.data.made,  10) || 0,
                        viewer_liked: !!j.data.viewer_liked,
                        viewer_made:  !!j.data.viewer_made
                    };
                })
                .catch(function() {
                    btn.removeAttribute("disabled");
                    btn.classList.toggle("mlp-react-on", wasOn);
                    if (numEl)   numEl.textContent   = fmt(curN);
                    if (labelEl) labelEl.textContent = (kind === "like")
                        ? (wasOn ? "liked" : "like")
                        : (wasOn ? "disliked" : "dislike");
                    if (typeof showToast === "function") {
                        showToast("Could not save", "Network error — please try again.", "warning", 3500);
                    }
                });
        }
        function renderFromCache() {
            if (!bar || !currentToken) return;
            var rx = (window._mlpReactions && window._mlpReactions[currentToken])
                  || { likes: 0, made: 0, viewer_liked: false, viewer_made: false };
            var likeBtn    = bar.querySelector('[data-react-kind="like"]');
            var dislikeBtn = bar.querySelector('[data-react-kind="dislike"]');
            if (likeBtn) {
                likeBtn.classList.toggle("mlp-react-on", !!rx.viewer_liked);
                var ln = likeBtn.querySelector(".mlp-erb-num");
                var ll = likeBtn.querySelector(".mlp-erb-label");
                if (ln) ln.textContent = fmt(rx.likes);
                if (ll) ll.textContent = rx.viewer_liked ? "liked" : "like";
            }
            if (dislikeBtn) {
                dislikeBtn.classList.toggle("mlp-react-on", !!rx.viewer_made);
                var mn = dislikeBtn.querySelector(".mlp-erb-num");
                var ml = dislikeBtn.querySelector(".mlp-erb-label");
                if (mn) mn.textContent = fmt(rx.made);
                if (ml) ml.textContent = rx.viewer_made ? "disliked" : "dislike";
            }
        }
        function fetchLatest() {
            if (!currentToken || !window.fetch || !MLP_AJAX_URL) return;
            var sentToken = currentToken;
            var fd = new FormData();
            fd.append("action", "mlp_get_share_reactions");
            fd.append("tokens", JSON.stringify([sentToken]));
            fetch(MLP_AJAX_URL, { method: "POST", body: fd, credentials: "same-origin" })
                .then(function(r){ return r.json(); })
                .then(function(j) {
                    if (!j || !j.success || !j.data || !j.data.reactions) return;
                    var arr = j.data.reactions[sentToken];
                    if (!arr) return;
                    window._mlpReactions = window._mlpReactions || {};
                    window._mlpReactions[sentToken] = {
                        likes:        parseInt(arr.likes, 10) || 0,
                        made:         parseInt(arr.made,  10) || 0,
                        viewer_liked: !!arr.viewer_liked,
                        viewer_made:  !!arr.viewer_made
                    };
                    if (sentToken === currentToken) renderFromCache();
                })
                .catch(function(){});
        }
        return {
            update: function(project) {
                var token = (project && project.sourceShareToken) ? String(project.sourceShareToken) : "";
                if (!token) {
                    currentToken = null;
                    if (bar) bar.classList.add("mlp-erb-hidden");
                    return;
                }
                ensureBar();
                currentToken = token;
                renderFromCache();
                bar.classList.remove("mlp-erb-hidden");
                fetchLatest();
            },
            hide: function() {
                currentToken = null;
                if (bar) bar.classList.add("mlp-erb-hidden");
            }
        };
    })();
    /* ══════════════════════════════════════════════════════════════
     * flushTabsToProject  — capture BOTH saved and unsaved tabs
     *
     * mlp_saved_tabs  = only tabs the user explicitly saved (these get
     *                   the 💾 icon; the main plugin owns this key).
     * project.allTabs = full snapshot of ALL in-memory tabs including
     *                   unsaved ones (our own field — not touched by
     *                   the main plugin).
     *
     * We NEVER add unsaved tabs to mlp_saved_tabs — that would make
     * them appear as saved when the project is reopened.
     * ══════════════════════════════════════════════════════════════ */
    function flushTabsToProject(id) {
        if (!id) return;
        try {
            var changes = {};
            if (window.monacoInstances) {
                Object.keys(window.monacoInstances).forEach(function(instanceId) {
                    var inst = window.monacoInstances[instanceId];
                    if (!inst) return;
                    if (inst.activeTabId) {
                        changes.activeTabId = inst.activeTabId;
                    }
                    if (inst.activeTabId && inst.tabs[inst.activeTabId]) {
                        try {
                            if (inst.htmlEditor) inst.tabs[inst.activeTabId].html = inst.htmlEditor.getValue();
                            if (inst.cssEditor)  inst.tabs[inst.activeTabId].css  = inst.cssEditor.getValue();
                            if (inst.jsEditor)   inst.tabs[inst.activeTabId].js   = inst.jsEditor.getValue();
                        } catch(e) {}
                    }
                    var allTabs = {};
                    Object.keys(inst.tabs || {}).forEach(function(tabId) {
                        var t = inst.tabs[tabId];
                        if (t) {
                            allTabs[tabId] = {
                                id: t.id,
                                title: t.title,
                                emoji: t.emoji || '📄',
                                isForked: t.isForked || false,
                                isReadOnly: !!t.isReadOnly,
                                html: t.html || '',
                                css:  t.css  || '',
                                js:   t.js   || '',
                                preprocessors: t.preprocessors || { html: 'html', css: 'css', js: 'javascript' },
                                timestamp: Date.now()
                            };
                        }
                    });
                    if (Object.keys(allTabs).length > 0) {
                        changes.allTabs = allTabs;
                    }
                });
            }
            try {
                var raw = localStorage.getItem(TABS_KEY);
                if (raw) {
                    var parsed = JSON.parse(raw);
                    if (parsed && typeof parsed === 'object' && Object.keys(parsed).length > 0) {
                        changes.savedTabs = parsed;
                    }
                }
            } catch(e) {}
            if (Object.keys(changes).length > 0) {
                updateProjectById(id, changes);
            }
        } catch(e) {}
    }
    /* ══════════════════════════════════════════════════════════════
     * restoreTabsFromProject  — write saved tabs back to mlp_saved_tabs
     *
     * Only the savedTabs (💾) go into mlp_saved_tabs so the main plugin
     * shows them correctly. The allTabs snapshot is handled separately
     * in mlpReloadTabsForProject.
     * ══════════════════════════════════════════════════════════════ */
    function restoreTabsFromProject(p) {
        if (p && p.savedTabs && typeof p.savedTabs === 'object' &&
                Object.keys(p.savedTabs).length > 0) {
            try { localStorage.setItem(TABS_KEY, JSON.stringify(p.savedTabs)); }
            catch (e) { localStorage.removeItem(TABS_KEY); }
        } else {
            localStorage.removeItem(TABS_KEY);
        }
    }
    /* ══════════════════════════════════════════════════════════════
     * mlpReloadTabsForProject  — reload all tabs into the live editor
     *
     * Priority:
     *  1. Use project.allTabs (full snapshot with saved+unsaved flags)
     *  2. Fall back to mlp_saved_tabs (only saved tabs, no unsaved ones)
     *  3. Empty project → create one blank tab
     *
     * A tab is shown with the 💾 icon only if its id exists in
     * mlp_saved_tabs (the main plugin checks this via isTabSaved()).
     * ══════════════════════════════════════════════════════════════ */
    function mlpReloadTabsForProject(projectId) {
        if (!window.monacoInstances || Object.keys(window.monacoInstances).length === 0) return false;
        try {
            var projects = getProjects();
            var project = null;
            for (var i = 0; i < projects.length; i++) {
                if (projects[i].id === projectId) { project = projects[i]; break; }
            }
            var tabsToLoad = {};
            if (project && project.allTabs && Object.keys(project.allTabs).length > 0) {
                tabsToLoad = project.allTabs;
            } else {
                try {
                    var raw = localStorage.getItem('mlp_saved_tabs');
                    if (raw) tabsToLoad = JSON.parse(raw) || {};
                } catch(e) {}
            }
            Object.keys(window.monacoInstances).forEach(function(instanceId) {
                var inst = window.monacoInstances[instanceId];
                if (!inst) return;
                Object.keys(inst.tabs || {}).forEach(function(tabId) { delete inst.tabs[tabId]; });
                jQuery('#mlp-tabs-list-' + instanceId + ' .mlp-tab').remove();
                var tabEntries = Object.values(tabsToLoad);
                var firstTabId = null;
                var activeTabId = (project && project.activeTabId && tabsToLoad[project.activeTabId]) ? project.activeTabId : null;
                tabEntries.forEach(function(t) {
                    if (!t || !t.id) return;
                    inst.tabs[t.id] = {
                        id: t.id,
                        title: t.title || 'Untitled',
                        emoji: t.emoji || '📄',
                        isForked: t.isForked || false,
                        isReadOnly: !!t.isReadOnly,
                        html: t.html || '',
                        css:  t.css  || '',
                        js:   t.js   || '',
                        preprocessors: t.preprocessors || { html: 'html', css: 'css', js: 'javascript' },
                        active: false
                    };
                    if (typeof window.mlpCreateTabElement === 'function') {
                        window.mlpCreateTabElement(instanceId, t.id, t.title || 'Untitled', t.emoji || '📄', t.isForked || false, !!t.isReadOnly);
                    }
                    if (!firstTabId) firstTabId = t.id;
                });
                if ((activeTabId || firstTabId) && typeof window.mlpSwitchTab === 'function') {
                    window.mlpSwitchTab(instanceId, activeTabId || firstTabId);
                } else if (!firstTabId) {
                    var newId = 'tab-' + Date.now() + '-' + Math.random().toString(36).substr(2, 6);
                    inst.tabs[newId] = {
                        id: newId, title: 'Preview 1', emoji: '📄',
                        isForked: false, isReadOnly: false,
                        html: '', css: '', js: '',
                        preprocessors: { html: 'html', css: 'css', js: 'javascript' },
                        active: false
                    };
                    inst.tabCounter = (inst.tabCounter || 1) + 1;
                    if (typeof window.mlpCreateTabElement === 'function') {
                        window.mlpCreateTabElement(instanceId, newId, 'Preview 1', '📄', false, false);
                    }
                    if (typeof window.mlpSwitchTab === 'function') {
                        window.mlpSwitchTab(instanceId, newId);
                    }
                }
            });
            return true;
        } catch(e) {
            console.error('[MLP Projects] mlpReloadTabsForProject error:', e);
            return false;
        }
    }
    function scheduleReloadTabsForProject(projectId, attemptsLeft) {
        attemptsLeft = attemptsLeft || 12;
        setTimeout(function() {
            var loaded = false;
            try { loaded = mlpReloadTabsForProject(projectId); } catch(e) { loaded = false; }
            if (!loaded && attemptsLeft > 1) {
                scheduleReloadTabsForProject(projectId, attemptsLeft - 1);
            }
        }, 250);
    }
    /* ── mlpSaveToProject (called by main plugin on explicit save) ── */
    window.mlpSaveToProject = function (html, css, js) {
        var id = window.mlpCurrentProjectId;
        if (!id) return;
        var changes = {};
        if (html !== undefined) changes.html = html;
        if (css  !== undefined) changes.css  = css;
        if (js   !== undefined) changes.js   = js;
        try {
            var raw = localStorage.getItem(TABS_KEY);
            if (raw) {
                var parsed = JSON.parse(raw);
                if (parsed && typeof parsed === 'object') changes.savedTabs = parsed;
            }
        } catch (e) {}
        updateProjectById(id, changes);
    };
    /* ── Helpers ──────────────────────────────────────────────────── */
    function fmtDate(iso) {
        try { return new Date(iso).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' }); }
        catch (e) { return '—'; }
    }
    function escHtml(str) {
        return (str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    }
    /* ── Profile / User system ────────────────────────────────────── */
    var USER_KEY   = 'mlp_user_profile';  // { name, avatar (base64 or null) }
    /* Unique default avatar colours — 12 vivid pairs (bg, text) */
    var AVATAR_PALETTES = [
        ['#6366f1','#fff'], ['#0ea5e9','#fff'], ['#10b981','#fff'],
        ['#f59e0b','#fff'], ['#ef4444','#fff'], ['#8b5cf6','#fff'],
        ['#ec4899','#fff'], ['#14b8a6','#fff'], ['#f97316','#fff'],
        ['#64748b','#fff'], ['#a855f7','#fff'], ['#06b6d4','#fff']
    ];
    function hashStr(s) {
        var h = 0;
        for (var i = 0; i < s.length; i++) { h = (h * 31 + s.charCodeAt(i)) >>> 0; }
        return h;
    }
    /** Get initials (up to 2 chars) from a name */
    function getInitials(name) {
        name = (name || '').trim();
        if (!name) return '?';
        var parts = name.split(/\s+/);
        if (parts.length >= 2) return (parts[0][0] + parts[parts.length-1][0]).toUpperCase();
        return name.slice(0, 2).toUpperCase();
    }
    /** Pick a stable palette for a name */
    function paletteFor(name) {
        return AVATAR_PALETTES[hashStr(name || '') % AVATAR_PALETTES.length];
    }
    /** Render an avatar into an element: either an <img> or styled initials */
    function renderAvatar(el, profile) {
        if (!el) return;
        var name   = (profile && profile.name) || '';
        var avatar = (profile && profile.avatar) || null;
        if (avatar) {
            el.style.background = 'transparent';
            el.innerHTML = '<img src="' + escHtml(avatar) + '" alt="' + escHtml(name) + '"/>';
        } else {
            var pal = paletteFor(name);
            el.style.background = pal[0];
            el.style.color      = pal[1];
            el.textContent      = getInitials(name);
        }
    }
    function getProfile() {
        try {
            var raw = localStorage.getItem(USER_KEY);
            return raw ? JSON.parse(raw) : null;
        } catch(e) { return null; }
    }
    function saveProfile(p) {
        try { localStorage.setItem(USER_KEY, JSON.stringify(p)); } catch(e) {}
    }
    /** Update every avatar/name spot in the nav */
    function applyProfileToNav(profile) {
        var nameEl   = document.getElementById('mlp-nav-username-label');
        var avatarEl = document.getElementById('mlp-nav-avatar');
        if (nameEl) nameEl.textContent = (profile && profile.name) ? profile.name : 'You';
        renderAvatar(avatarEl, profile);
        var sidebarNameEl   = document.getElementById('mlp-sidebar-profile-name');
        var sidebarAvatarEl = document.getElementById('mlp-sidebar-avatar');
        if (sidebarNameEl) sidebarNameEl.textContent = (profile && profile.name) ? profile.name : 'You';
        renderAvatar(sidebarAvatarEl, profile);
        /* ── Persist joinedAt on first profile use, then show "Member since" ─ */
        if (profile) {
            if (!profile.joinedAt) {
                profile.joinedAt = new Date().toISOString();
                saveProfile(profile);
            }
            var memberSinceEl = document.getElementById('mlp-sidebar-member-since');
            if (memberSinceEl) {
                try {
                    var _jd = new Date(profile.joinedAt);
                    var _mo = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
                    memberSinceEl.textContent = 'Since ' + _mo[_jd.getMonth()] + ' ' + _jd.getFullYear();
                } catch(e) { memberSinceEl.textContent = ''; }
            }
        }
    }
    /* ── Apply premium UI state ─────────────────────────────────── */
    function applyPremiumUI() {
        var premium = isPremium();
        var planLabel = document.getElementById('mlp-plan-label');
        var planIcon  = document.getElementById('mlp-plan-icon');
        var planWrap  = planLabel && planLabel.parentElement;
        if (planLabel) {
            planLabel.textContent = 'Developer';
        }
        var planChip = document.getElementById('mlp-sidebar-plan-chip');
        if (planChip) { planChip.classList.remove('mlp-plan-premium'); }
    }
    /* ── Auto-update onboarding avatar preview as user types ───── */
    function wireOnboardPreview() {
        var input   = document.getElementById('mlp-username-input');
        var preview = document.getElementById('mlp-onboard-avatar-preview');
        if (!input || !preview) return;
        function update() { renderAvatar(preview, { name: input.value || '?' }); }
        update();
        input.addEventListener('input', update);
    }
    /* ── Show onboarding modal if no profile saved ──────────────── */
    function mlpValidateStoredAvatar(profile, callback) {
        if (!profile || !profile.avatar) {
            callback(profile);
            return;
        }
        var avatar = profile.avatar;
        if (typeof avatar !== 'string' || avatar.indexOf('data:image/') !== 0) {
            profile.avatar = null;
            saveProfile(profile);
            callback(profile);
            return;
        }
        if (avatar.length > 3 * 1024 * 1024) {
            profile.avatar = null;
            saveProfile(profile);
            callback(profile);
            return;
        }
        var done = false;
        var nsfwDone = false, nsfwBad = false;
        var ocrDone  = false, ocrBad  = false;
        function onBothDone() {
            if (!nsfwDone || !ocrDone) return;
            if (done) return;
            done = true;
            if (nsfwBad || ocrBad) {
                console.warn('[MLP Avatar] Stored avatar failed moderation check (nsfw=' + nsfwBad + ' ocr=' + ocrBad + '). Removing.');
                profile.avatar = null;
                saveProfile(profile);
            }
            callback(profile);
        }
        mlpNsfwCheck(avatar, function(isNsfw) {
            nsfwBad  = isNsfw;
            nsfwDone = true;
            onBothDone();
        });
        mlpAvatarTextCheck(avatar, function(isOffensive) {
            ocrBad  = isOffensive;
            ocrDone = true;
            onBothDone();
        });
    }
    function maybeShowOnboarding() {
        var profile = getProfile();
        /* ── Sync from comment username if profile has no name yet ── */
        if ((!profile || !profile.name)) {
            var commentName = '';
            try { commentName = (localStorage.getItem('mlp_commenter_name') || '').trim(); } catch(e) {}
            if (commentName) {
                profile = { name: commentName, avatar: null };
                saveProfile(profile);
            }
        }
        if (profile && profile.name) {
            mlpValidateStoredAvatar(profile, function(cleanProfile) {
                applyProfileToNav(cleanProfile);
            });
            return;
        }
        var modal = document.getElementById('mlp-username-modal');
        if (!modal) return;
        modal.style.display = 'flex';
        wireOnboardPreview();
        var input   = document.getElementById('mlp-username-input');
        var saveBtn = document.getElementById('mlp-username-save-btn');
        if (input) setTimeout(function () { input.focus(); }, 80);
        function doSave() {
            var name = input ? input.value.trim() : '';
            if (!name) { if (input) input.focus(); return; }
            var p = { name: name, avatar: null };
            saveProfile(p);
            try { localStorage.setItem('mlp_commenter_name', name); } catch(e) {}
            modal.style.display = 'none';
            applyProfileToNav(p);
        }
        if (saveBtn) saveBtn.addEventListener('click', doSave);
        if (input) input.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') doSave();
        });
    }
    /* ── Settings modal ─────────────────────────────────────────── */
    function wireSettingsModal(onCategoryCreated) {
        var profileBtn   = document.getElementById('mlp-profile-btn');
        var modal        = document.getElementById('mlp-settings-modal');
        var closeBtn     = document.getElementById('mlp-settings-modal-close');
        var cancelBtn2   = document.getElementById('mlp-settings-cancel-btn');
        var saveBtn2     = document.getElementById('mlp-settings-save-btn');
        var nameInput2   = document.getElementById('mlp-settings-name-input');
        var fileInput    = document.getElementById('mlp-avatar-file-input');
        var removeBtn    = document.getElementById('mlp-avatar-remove-btn');
        var avatarPrev   = document.getElementById('mlp-settings-avatar-preview');
        if (!profileBtn || !modal) return;
        var pendingAvatar = undefined; // undefined = no change, null = remove, string = new data URL
        function openSettings() {
            var profile = getProfile() || {};
            pendingAvatar = undefined;
            if (nameInput2) nameInput2.value = profile.name || '';
            renderAvatar(avatarPrev, profile);
            modal.style.display = 'flex';
            if (nameInput2) setTimeout(function(){ nameInput2.focus(); }, 60);
        }
        function closeSettings() { modal.style.display = 'none'; }
        /* Profile dropdown toggle */
        var profileDropdown  = document.getElementById('mlp-profile-dropdown');
        var profileCaret     = document.getElementById('mlp-profile-caret');
        var profileDdSettings = document.getElementById('mlp-profile-dd-settings');
        function openProfileDropdown() {
            if (!profileDropdown) return;
            profileDropdown.style.display = 'block';
            profileBtn.classList.add('mlp-profile-btn-open');
            if (profileCaret) profileCaret.classList.add('mlp-profile-caret-open');
            profileBtn.setAttribute('aria-expanded', 'true');
        }
        function closeProfileDropdown() {
            if (!profileDropdown) return;
            profileDropdown.style.display = 'none';
            profileBtn.classList.remove('mlp-profile-btn-open');
            if (profileCaret) profileCaret.classList.remove('mlp-profile-caret-open');
            profileBtn.setAttribute('aria-expanded', 'false');
        }
        function toggleProfileDropdown(e) {
            e.stopPropagation();
            if (profileDropdown && profileDropdown.style.display === 'block') {
                closeProfileDropdown();
            } else {
                openProfileDropdown();
            }
        }
        profileBtn.addEventListener('click', toggleProfileDropdown);
        /* Clicking Settings item in dropdown opens the settings modal */
        if (profileDdSettings) {
            profileDdSettings.addEventListener('click', function(e) {
                e.stopPropagation();
                closeProfileDropdown();
                openSettings();
            });
        }
        /* Close dropdown when clicking outside */
        document.addEventListener('click', function(e) {
            var wrap = document.getElementById('mlp-profile-dropdown-wrap');
            if (wrap && !wrap.contains(e.target)) closeProfileDropdown();
            var cWrap = document.getElementById('mlp-community-dropdown-wrap');
            if (cWrap && !cWrap.contains(e.target)) closeCommunityDropdown();
            var gWrap = document.getElementById('mlp-github-dropdown-wrap');
            if (gWrap && !gWrap.contains(e.target)) closeGithubDropdown();
        });
        /* GitHub dropdown (nav) */
        var githubBtn      = document.getElementById('mlp-github-btn');
        var githubDropdown = document.getElementById('mlp-github-dropdown');
        var githubCaret    = document.getElementById('mlp-github-caret');
        function openGithubDropdown() {
            if (!githubDropdown) return;
            githubDropdown.style.display = 'block';
            if (githubBtn) githubBtn.setAttribute('aria-expanded', 'true');
            if (githubCaret) githubCaret.classList.add('mlp-profile-caret-open');
        }
        function closeGithubDropdown() {
            if (!githubDropdown) return;
            githubDropdown.style.display = 'none';
            if (githubBtn) githubBtn.setAttribute('aria-expanded', 'false');
            if (githubCaret) githubCaret.classList.remove('mlp-profile-caret-open');
        }
        if (githubBtn) {
            githubBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                if (githubDropdown && githubDropdown.style.display === 'block') {
                    closeGithubDropdown();
                } else {
                    openGithubDropdown();
                }
            });
            githubBtn.addEventListener('keydown', function(e) {
                if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); githubBtn.click(); }
            });
        }
        /* Gist Token modal (opened from GitHub dropdown) */
        (function() {
            var gtModal       = document.getElementById('mlp-gist-token-modal');
            var gtOpenBtn     = document.getElementById('mlp-github-dd-gist-token');
            var gtCloseBtn    = document.getElementById('mlp-gist-token-modal-close');
            var gtCancelBtn   = document.getElementById('mlp-gist-token-modal-cancel-btn');
            var gtSaveBtn     = document.getElementById('mlp-gist-token-modal-save-btn');
            var gtDeleteBtn   = document.getElementById('mlp-gist-token-modal-delete-btn');
            var gtTestBtn     = document.getElementById('mlp-gist-token-modal-test-btn');
            var gtTestLabel   = document.getElementById('mlp-gist-test-label');
            var gtInput       = document.getElementById('mlp-gist-token-modal-input');
            var gtStatus      = document.getElementById('mlp-gist-token-modal-status');
            var gtPill        = document.getElementById('mlp-gist-token-modal-pill');
            var gtPillLabel   = document.getElementById('mlp-gist-token-modal-pill-label');
            var gtCopyIdBtn   = document.getElementById('mlp-gist-token-modal-copy-id-btn');
            function setPill(state, label) {
                if (!gtPill) return;
                gtPill.classList.remove('mlp-gist-pill-on','mlp-gist-pill-off','mlp-gist-pill-pending','mlp-gist-pill-checking');
                gtPill.classList.add('mlp-gist-pill-' + state);
                if (gtPillLabel && label) gtPillLabel.textContent = label;
            }
            if (!gtModal) return;
            function readTokenState() {
                var tok = '';
                try { tok = (typeof mlpGetGistToken === 'function') ? mlpGetGistToken() : (localStorage.getItem('mlp_gist_token') || ''); } catch(e) {}
                var gid = '';
                try { gid = (typeof mlpGetGistId === 'function') ? mlpGetGistId() : (localStorage.getItem('mlp_gist_id') || ''); } catch(e) {}
                var last = '';
                try { last = localStorage.getItem('mlp_gist_last_sync') || ''; } catch(e) {}
                return { tok: tok, gid: gid, last: last };
            }
            function refreshGtStatus() {
                if (!gtStatus) return;
                var s = readTokenState();
                if (!s.tok) {
                    gtStatus.style.color = 'var(--mlp-text-muted)';
                    gtStatus.textContent = 'Cloud backup is currently disabled.';
                    setPill('off', 'Disconnected');
                } else if (s.gid) {
                    gtStatus.style.color = 'var(--mlp-success-text, #16a34a)';
                    gtStatus.textContent = '✓ Gist connected' + (s.last ? ' — last synced ' + new Date(s.last).toLocaleTimeString() : '') + '.';
                    setPill('on', 'Connected');
                } else {
                    gtStatus.style.color = 'var(--mlp-text-muted)';
                    gtStatus.textContent = 'Token saved. A Gist will be created on your next save.';
                    setPill('pending', 'Pending');
                }
                if (gtCopyIdBtn) {
                    var hasId = !!s.gid;
                    gtCopyIdBtn.disabled = !hasId;
                    gtCopyIdBtn.style.opacity = hasId ? '' : '0.4';
                    gtCopyIdBtn.title = hasId ? 'Copy Gist ID: ' + s.gid : 'No Gist ID yet — make a backup first';
                }
            }
            function openGistTokenModal() {
                closeGithubDropdown();
                if (gtInput) {
                    gtInput.value = '';
                    var existing = readTokenState().tok;
                    gtInput.placeholder = existing ? '•••• token saved (paste to replace)' : 'ghp_xxxxxxxxxxxxxxxxxxxx';
                }
                refreshGtStatus();
                gtModal.style.display = 'flex';
            }
            function closeGistTokenModal() {
                gtModal.style.display = 'none';
            }
            if (gtOpenBtn)   gtOpenBtn.addEventListener('click', function(e){ e.stopPropagation(); openGistTokenModal(); });
            if (gtCloseBtn)  gtCloseBtn.addEventListener('click', closeGistTokenModal);
            if (gtCancelBtn) gtCancelBtn.addEventListener('click', closeGistTokenModal);
            gtModal.addEventListener('click', function(e){ if (e.target === gtModal) closeGistTokenModal(); });
            if (gtCopyIdBtn) {
                gtCopyIdBtn.addEventListener('click', function() {
                    var gid = '';
                    try { gid = localStorage.getItem('mlp_gist_id') || ''; } catch(e) {}
                    if (!gid) return;
                    try {
                        navigator.clipboard.writeText(gid).then(function() {
                            var orig = gtCopyIdBtn.innerHTML;
                            gtCopyIdBtn.textContent = '✓ Copied!';
                            setTimeout(function(){ gtCopyIdBtn.innerHTML = orig; }, 2000);
                        }).catch(function() { fallbackCopyGistId(gid); });
                    } catch(e) { fallbackCopyGistId(gid); }
                });
            }
            function fallbackCopyGistId(gid) {
                var ta = document.createElement('textarea');
                ta.value = gid; ta.style.position = 'fixed'; ta.style.opacity = '0';
                document.body.appendChild(ta); ta.select();
                try { document.execCommand('copy'); } catch(e) {}
                document.body.removeChild(ta);
                if (gtCopyIdBtn) {
                    var orig = gtCopyIdBtn.innerHTML;
                    gtCopyIdBtn.textContent = '✓ Copied!';
                    setTimeout(function(){ gtCopyIdBtn.innerHTML = orig; }, 2000);
                }
            }
            function setTestBtnState(state) {
                if (!gtTestBtn || !gtTestLabel) return;
                gtTestBtn.disabled = (state === 'loading');
                gtTestBtn.style.opacity = (state === 'loading') ? '0.6' : '';
                gtTestBtn.style.cursor  = (state === 'loading') ? 'wait' : 'pointer';
                gtTestLabel.textContent = (state === 'loading') ? 'Testing…' : 'Test';
            }
            if (gtTestBtn) {
                gtTestBtn.addEventListener('click', function() {
                    var pasted = (gtInput && gtInput.value.trim()) || '';
                    var saved  = readTokenState().tok || '';
                    var token  = pasted || saved;
                    if (!token) {
                        gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                        gtStatus.textContent = '⚠ Paste a token first, or save one to test the existing connection.';
                        return;
                    }
                    if (!token.match(/^(ghp_|github_pat_)[A-Za-z0-9_]{10,}$/)) {
                        gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                        gtStatus.textContent = '⚠ That does not look like a valid GitHub PAT. It should start with ghp_ or github_pat_.';
                        return;
                    }
                    setTestBtnState('loading');
                    setPill('checking', 'Checking…');
                    gtStatus.style.color = 'var(--mlp-text-muted)';
                    gtStatus.textContent = 'Contacting GitHub…';
                    fetch('https://api.github.com/user', {
                        method: 'GET',
                        headers: {
                            'Authorization': 'token ' + token,
                            'Accept':        'application/vnd.github+json',
                            'X-GitHub-Api-Version': '2022-11-28'
                        }
                    }).then(function(res) {
                        var scopesHdr = res.headers.get('X-OAuth-Scopes') || '';
                        var scopes = scopesHdr.split(',').map(function(s){ return s.trim(); }).filter(Boolean);
                        return res.json().then(function(body) {
                            return { ok: res.ok, status: res.status, body: body, scopes: scopes };
                        }).catch(function() {
                            return { ok: res.ok, status: res.status, body: null, scopes: scopes };
                        });
                    }).then(function(r) {
                        setTestBtnState('idle');
                        if (r.status === 401) {
                            gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                            gtStatus.textContent = '✗ GitHub rejected this token. It may be invalid, revoked, or expired.';
                            setPill('off', 'Invalid');
                            return;
                        }
                        if (r.status === 403) {
                            gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                            gtStatus.textContent = '✗ GitHub blocked the request (403). Rate-limited or token lacks access.';
                            setPill('off', 'Blocked');
                            return;
                        }
                        if (!r.ok) {
                            gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                            gtStatus.textContent = '✗ Test failed (HTTP ' + r.status + '). Try again in a moment.';
                            setPill('off', 'Failed');
                            return;
                        }
                        var login = (r.body && r.body.login) ? r.body.login : 'your account';
                        var isClassic = /^ghp_/.test(token);
                        if (isClassic && r.scopes.length && r.scopes.indexOf('gist') === -1) {
                            gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                            gtStatus.textContent = '✗ Token is valid for ' + login + ', but it is missing the "gist" scope. Recreate it with the gist scope checked.';
                            setPill('off', 'Missing scope');
                            return;
                        }
                        gtStatus.style.color = 'var(--mlp-success-text, #16a34a)';
                        gtStatus.textContent = '✓ Connected as ' + login + '. Token works' + (isClassic ? ' and has the gist scope.' : '. Make sure your fine-grained PAT allows Gist access.');
                        var hasGid = !!readTokenState().gid;
                        setPill(hasGid ? 'on' : 'pending', hasGid ? 'Connected' : 'Verified');
                    }).catch(function() {
                        setTestBtnState('idle');
                        gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                        gtStatus.textContent = '✗ Could not reach GitHub. Check your internet connection and try again.';
                        setPill('off', 'Offline');
                    });
                });
            }
            if (gtSaveBtn && gtInput) {
                gtSaveBtn.addEventListener('click', function() {
                    var val = gtInput.value.trim();
                    if (!val) {
                        gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                        gtStatus.textContent = '⚠ Please paste a token first.';
                        return;
                    }
                    if (!val.match(/^(ghp_|github_pat_)[A-Za-z0-9_]{10,}$/)) {
                        gtStatus.style.color = 'var(--mlp-danger, #dc2626)';
                        gtStatus.textContent = '⚠ That does not look like a valid GitHub PAT. It should start with ghp_ or github_pat_.';
                        return;
                    }
                    try { localStorage.setItem('mlp_gist_token', val); } catch(e) {}
                    try { localStorage.removeItem('mlp_gist_id'); } catch(e) {}
                    try { if (typeof _mlpGistSyncing !== 'undefined') _mlpGistSyncing = false; } catch(e) {}
                    try { if (typeof _mlpGistLastSync !== 'undefined') _mlpGistLastSync = 0; } catch(e) {}
                    try {
                        if (typeof mlpPushToGist === 'function' && typeof getProjects === 'function') {
                            mlpPushToGist(getProjects());
                        }
                    } catch(e) {}
                    gtInput.value = '';
                    gtInput.placeholder = '•••• token saved (paste to replace)';
                    gtStatus.style.color = 'var(--mlp-success-text, #16a34a)';
                    gtStatus.textContent = '✓ Token saved! Pushing to GitHub Gist…';
                    setPill('pending', 'Saving…');
                    setTimeout(refreshGtStatus, 1500);
                });
            }
            if (gtDeleteBtn) {
                gtDeleteBtn.addEventListener('click', function() {
                    if (!confirm('Remove your saved Gist token? Cloud backup will be disabled on this device.')) return;
                    try { localStorage.removeItem('mlp_gist_token'); } catch(e) {}
                    try { localStorage.removeItem('mlp_gist_id'); } catch(e) {}
                    if (gtInput) { gtInput.value = ''; gtInput.placeholder = 'ghp_xxxxxxxxxxxxxxxxxxxx'; }
                    refreshGtStatus();
                });
            }
            document.addEventListener('keydown', function(e) {
                if (e.key === 'Escape' && gtModal.style.display !== 'none') closeGistTokenModal();
            });
        })();
        /* Community dropdown */
        var communityBtn      = document.getElementById('mlp-community-btn');
        var communityDropdown = document.getElementById('mlp-community-dropdown');
        var communityCaret    = document.getElementById('mlp-community-caret');
        function openCommunityDropdown() {
            if (!communityDropdown) return;
            communityDropdown.style.display = 'block';
            if (communityBtn) communityBtn.setAttribute('aria-expanded', 'true');
            if (communityCaret) communityCaret.classList.add('mlp-profile-caret-open');
        }
        function closeCommunityDropdown() {
            if (!communityDropdown) return;
            communityDropdown.style.display = 'none';
            if (communityBtn) communityBtn.setAttribute('aria-expanded', 'false');
            if (communityCaret) communityCaret.classList.remove('mlp-profile-caret-open');
        }
        if (communityBtn) {
            communityBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                if (communityDropdown && communityDropdown.style.display === 'block') {
                    closeCommunityDropdown();
                } else {
                    openCommunityDropdown();
                }
            });
            communityBtn.addEventListener('keydown', function(e) {
                if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); communityBtn.click(); }
            });
        }
        if (closeBtn)   closeBtn.addEventListener('click', closeSettings);
        if (cancelBtn2) cancelBtn2.addEventListener('click', closeSettings);
        modal.addEventListener('click', function(e){ if (e.target === modal) closeSettings(); });
        /* Sidebar settings gear also opens settings */
        var sidebarSettingsBtn = document.getElementById('mlp-sidebar-settings-btn');
        if (sidebarSettingsBtn) sidebarSettingsBtn.addEventListener('click', openSettings);
        /* ── Category creation popup ─────────────────────────────────── */
        (function initCategoryPopup() {
            var CAT_KEY = 'mlp_categories';
            function loadCats() { try { return JSON.parse(localStorage.getItem(CAT_KEY) || '[]'); } catch(e) { return []; } }
            function saveCats(c) { try { localStorage.setItem(CAT_KEY, JSON.stringify(c)); } catch(e) {} }
            var newCatBtn = document.getElementById('mlp-sidebar-new-cat-btn');
            if (!newCatBtn) return;
            /* Build popup, append to body so it's outside the overlay's CSS reset */
            var popup = document.createElement('div');
            popup.className = 'mlp-cat-create-popup';
            popup.style.display = 'none';
            popup.innerHTML =
                '<div class="mlp-cat-create-popup-title">' +
                  '<span>New Category</span>' +
                  '<button class="mlp-cat-create-popup-close" type="button" title="Close" aria-label="Close">&times;</button>' +
                '</div>' +
                '<input class="mlp-cat-create-popup-input" type="text" placeholder="Max 5 chars…" maxlength="5" autocomplete="off"/>' +
                '<button class="mlp-cat-create-popup-btn" type="button">Create</button>';
            document.body.appendChild(popup);
            var popupInput  = popup.querySelector('.mlp-cat-create-popup-input');
            var popupCreate = popup.querySelector('.mlp-cat-create-popup-btn');
            var popupClose  = popup.querySelector('.mlp-cat-create-popup-close');
            var popupOpen = false;
            function openCatPopup() {
                var rect = newCatBtn.getBoundingClientRect();
                popup.style.left = Math.min(rect.right + 6, window.innerWidth - 240) + 'px';
                popup.style.top  = rect.bottom + 4 + 'px';
                popup.style.display = 'block';
                popupInput.value = '';
                popupOpen = true;
                setTimeout(function() { popupInput.focus(); }, 30);
            }
            function closeCatPopup() {
                popup.style.display = 'none';
                popupOpen = false;
            }
            function createCategory() {
                var name = (popupInput.value || '').trim();
                if (!name) { popupInput.focus(); return; }
                var cats = loadCats();
                cats.push({ id: 'cat-' + Date.now() + '-' + Math.random().toString(36).substr(2,5), name: name, projectIds: [] });
                saveCats(cats);
                closeCatPopup();
                if (typeof onCategoryCreated === 'function') { onCategoryCreated(); }
            }
            newCatBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                if (popupOpen) { closeCatPopup(); } else { openCatPopup(); }
            });
            popupClose.addEventListener('click', closeCatPopup);
            popupCreate.addEventListener('click', createCategory);
            popupInput.addEventListener('keydown', function(e) {
                if (e.key === 'Enter') { e.preventDefault(); createCategory(); }
                if (e.key === 'Escape') { closeCatPopup(); }
            });
            document.addEventListener('click', function(e) {
                if (popupOpen && !popup.contains(e.target) && e.target !== newCatBtn) {
                    closeCatPopup();
                }
            });
        })();
        /* File upload */
        if (fileInput) {
            fileInput.addEventListener('change', function() {
                var file = fileInput.files && fileInput.files[0];
                if (!file) return;
                if (file.size > 2 * 1024 * 1024) {
                    alert('Image is too large. Please choose a file under 2 MB.');
                    fileInput.value = '';
                    return;
                }
                var headerReader = new FileReader();
                headerReader.onload = function (hEv) {
                    var b = new Uint8Array(hEv.target.result);
                    var isPng  = b[0]===0x89 && b[1]===0x50 && b[2]===0x4E && b[3]===0x47;
                    var isJpeg = b[0]===0xFF && b[1]===0xD8;
                    var isGif  = b[0]===0x47 && b[1]===0x49 && b[2]===0x46;           // GIF8
                    var isWebp = b[8]===0x57 && b[9]===0x45 && b[10]===0x42 && b[11]===0x50; // RIFF????WEBP
                    var isBmp  = b[0]===0x42 && b[1]===0x4D;                           // BM
                    if (!isPng && !isJpeg && !isGif && !isWebp && !isBmp) {
                        alert('Invalid image file. Only JPG, PNG, GIF, WebP, and BMP are accepted. Please choose a real image.');
                        fileInput.value = '';
                        return;
                    }
                    var fullReader = new FileReader();
                    fullReader.onload = function (ev) {
                        var rawDataUrl = ev.target.result;
                        var img = new Image();
                        img.onerror = function () {
                            alert('This file could not be decoded as an image. Please try a different one.');
                            fileInput.value = '';
                        };
                        img.onload = function () {
                            if (img.width < 10 || img.height < 10) {
                                alert('Image is too small. Please choose a photo that is at least 10 × 10 pixels.');
                                fileInput.value = '';
                                return;
                            }
                            var MAX_PX  = 512;
                            var scale   = Math.min(MAX_PX / img.width, MAX_PX / img.height, 1);
                            var canvas  = document.createElement('canvas');
                            canvas.width  = Math.round(img.width  * scale);
                            canvas.height = Math.round(img.height * scale);
                            var ctx = canvas.getContext('2d');
                            ctx.fillStyle = '#ffffff';
                            ctx.fillRect(0, 0, canvas.width, canvas.height);
                            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                            var sanitizedDataUrl = canvas.toDataURL('image/jpeg', 0.88);
                            var _nsfwDone = false, _nsfwResult = false;
                            var _ocrDone  = false, _ocrResult  = false;
                            var _guardFired = false; // prevent double-alert
                            function _onBothDone() {
                                if (!_nsfwDone || !_ocrDone) return; // wait for both
                                if (_guardFired) return;
                                if (_nsfwResult) {
                                    _guardFired = true;
                                    alert('This image was flagged as inappropriate (visual content) and cannot be used as your avatar. Please choose a different image.');
                                    fileInput.value = '';
                                    return;
                                }
                                if (_ocrResult) {
                                    _guardFired = true;
                                    alert('This image contains offensive text and cannot be used as your avatar. Please choose a different image.');
                                    fileInput.value = '';
                                    return;
                                }
                                pendingAvatar = sanitizedDataUrl;
                                renderAvatar(avatarPrev, {
                                    name:   nameInput2 ? nameInput2.value : '',
                                    avatar: pendingAvatar
                                });
                            }
                            mlpNsfwCheck(sanitizedDataUrl, function (isNsfw) {
                                _nsfwResult = isNsfw;
                                _nsfwDone   = true;
                                _onBothDone();
                            });
                            mlpAvatarTextCheck(sanitizedDataUrl, function (isOffensive) {
                                _ocrResult = isOffensive;
                                _ocrDone   = true;
                                _onBothDone();
                            });
                        };
                        img.src = rawDataUrl;
                    };
                    fullReader.readAsDataURL(file);
                };
                headerReader.readAsArrayBuffer(file.slice(0, 12));
            });
        }
        /* Remove photo */
        if (removeBtn) {
            removeBtn.addEventListener('click', function() {
                pendingAvatar = null;
                fileInput.value = '';
                renderAvatar(avatarPrev, { name: nameInput2 ? nameInput2.value : '', avatar: null });
            });
        }
        /* Save */
        if (saveBtn2) {
            saveBtn2.addEventListener('click', function() {
                var name = nameInput2 ? nameInput2.value.trim() : '';
                if (!name) { if (nameInput2) nameInput2.focus(); return; }
                var current = getProfile() || {};
                var newAvatar = (pendingAvatar !== undefined) ? pendingAvatar : (current.avatar || null);
                var p = { name: name, avatar: newAvatar };
                saveProfile(p);
                try { localStorage.setItem('mlp_commenter_name', name); } catch(e) {}
                applyProfileToNav(p);
                closeSettings();
            });
        }
        if (nameInput2) {
            nameInput2.addEventListener('keydown', function(e) {
                if (e.key === 'Enter' && saveBtn2) saveBtn2.click();
                if (e.key === 'Escape') closeSettings();
            });
        }
        /* ── GitHub Gist token settings UI removed — managed via the
              navbar GitHub → Gist Token modal instead. ──────────────── */
        /* ── Delete account button in settings modal ────────────────── */
        var deleteAccountBtn = document.getElementById('mlp-settings-delete-account-btn');
        if (deleteAccountBtn) {
            deleteAccountBtn.addEventListener('click', function() {
                if (deleteAccountBtn.disabled) return;
                closeSettings();
                openDelAccountModal();
            });
        }
        mlpSyncDeleteAccountBtn();
    }
    /* ── Disable delete-account while any project is banned ── */
    function mlpSyncDeleteAccountBtn() {
        var btn = document.getElementById('mlp-settings-delete-account-btn');
        if (!btn) return;
        var projects = getProjects();
        var blocked = projects.some(function(p) {
            return p && p.adminDeleted;
        });
        if (blocked) {
            btn.disabled = true;
            btn.title = 'Account deletion is disabled while one of your projects is under an admin restriction.';
            btn.style.opacity = '0.45';
            btn.style.cursor  = 'not-allowed';
        } else {
            btn.disabled = false;
            btn.title    = '';
            btn.style.opacity = '';
            btn.style.cursor  = '';
        }
    }
    /* ── Delete Account modal ─────────────────────────────────────── */
    function openDelAccountModal() {
        var delAccModal   = document.getElementById('mlp-del-account-modal');
        var confirmInput  = document.getElementById('mlp-del-account-confirm-input');
        var confirmBtn    = document.getElementById('mlp-del-account-confirm-btn');
        var cancelBtn     = document.getElementById('mlp-del-account-cancel-btn');
        var closeBtn      = document.getElementById('mlp-del-account-modal-close');
        if (!delAccModal) return;
        if (confirmInput) { confirmInput.value = ''; }
        if (confirmBtn)   { confirmBtn.disabled = true; confirmBtn.classList.add('mlp-btn-danger-full'); }
        delAccModal.style.display = 'flex';
        if (confirmInput) setTimeout(function(){ confirmInput.focus(); }, 60);
        function checkInput() {
            var val = confirmInput ? confirmInput.value.trim().toUpperCase() : '';
            if (confirmBtn) {
                confirmBtn.disabled = (val !== 'DELETE');
            }
        }
        if (confirmInput) confirmInput.addEventListener('input', checkInput);
        function closeDelAcc() {
            delAccModal.style.display = 'none';
            if (confirmInput) {
                confirmInput.removeEventListener('input', checkInput);
                confirmInput.value = '';
            }
        }
        if (closeBtn)  closeBtn.addEventListener('click', closeDelAcc);
        if (cancelBtn) cancelBtn.addEventListener('click', closeDelAcc);
        delAccModal.addEventListener('click', function(e){ if(e.target === delAccModal) closeDelAcc(); });
        if (confirmBtn) {
            confirmBtn.addEventListener('click', function() {
                if (confirmBtn.disabled) return;
                window.mlpCurrentProjectId = null;
                closeDelAcc();
                function doWipeAndReload() {
                    try { localStorage.clear(); } catch(e) {}
                    try { sessionStorage.clear(); } catch(e) {}
                    try {
                        var delReq = indexedDB.deleteDatabase(MLP_IDB_NAME);
                        delReq.onerror = function(){};
                        _mlpIdb = null; _mlpIdbReady = false;
                    } catch(e) {}
                    if (window.caches) {
                        try {
                            caches.keys().then(function(names) {
                                return Promise.all(names.map(function(n) { return caches.delete(n); }));
                            }).catch(function(){});
                        } catch(e) {}
                    }
                    if (navigator.serviceWorker) {
                        try {
                            navigator.serviceWorker.getRegistrations().then(function(regs) {
                                regs.forEach(function(r) { r.unregister(); });
                            }).catch(function(){});
                        } catch(e) {}
                    }
                    try {
                        window.location.reload(true);
                    } catch(e) {
                        window.location.href = window.location.href;
                    }
                }
                var _publishedIds = [];
                try {
                    var _raw = localStorage.getItem('mlp_projects');
                    if (_raw) {
                        var _projs = JSON.parse(_raw);
                        if (Array.isArray(_projs)) {
                            _projs.forEach(function(q) {
                                if (q && q.id && (q.shareToken || q.shareUrl)) {
                                    _publishedIds.push(String(q.id));
                                }
                            });
                        }
                    }
                } catch(e) {}
                function runWipe() { setTimeout(doWipeAndReload, 120); }
                if (_publishedIds.length > 0 && MLP_AJAX_URL && MLP_SHARE_NONCE) {
                    var _fd = new FormData();
                    _fd.append('action', 'mlp_delete_my_shares');
                    _fd.append('nonce', MLP_SHARE_NONCE);
                    _publishedIds.forEach(function(pid) { _fd.append('project_ids[]', pid); });
                    var _wipeTimer = setTimeout(runWipe, 4000);
                    fetch(MLP_AJAX_URL, { method: 'POST', body: _fd, credentials: 'same-origin' })
                        .then(function() { clearTimeout(_wipeTimer); runWipe(); })
                        .catch(function() { clearTimeout(_wipeTimer); runWipe(); });
                } else {
                    runWipe();
                }
            });
        }
    }
    /* ── DOM init ─────────────────────────────────────────────────── */
    function init() {
        var overlay     = document.getElementById('mlp-projects-overlay');
        if (!overlay) return;
        /* ── Theme (light/dark) toggle ─────────────────────────────── */
        var THEME_KEY = 'mlp_projects_theme';
        function applyTheme(theme) {
            var t = (theme === 'dark') ? 'dark' : 'light';
            overlay.setAttribute('data-mlp-theme', t);
            var btn = document.getElementById('mlp-theme-toggle-btn');
            if (btn) {
                btn.setAttribute('title', t === 'dark' ? 'Switch to light theme' : 'Switch to dark theme');
                btn.setAttribute('aria-label', t === 'dark' ? 'Switch to light theme' : 'Switch to dark theme');
            }
        }
        var savedTheme = null;
        try { savedTheme = localStorage.getItem(THEME_KEY); } catch(e) {}
        if (!savedTheme) {
            try {
                savedTheme = (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) ? 'dark' : 'light';
            } catch(e) { savedTheme = 'light'; }
        }
        applyTheme(savedTheme);
        var themeBtn = document.getElementById('mlp-theme-toggle-btn');
        if (themeBtn) {
            themeBtn.addEventListener('click', function() {
                var current = overlay.getAttribute('data-mlp-theme') === 'dark' ? 'dark' : 'light';
                var next = current === 'dark' ? 'light' : 'dark';
                applyTheme(next);
                try { localStorage.setItem(THEME_KEY, next); } catch(e) {}
            });
        }
        /* Sidebar collapse toggle */
        var SIDEBAR_KEY = 'mlp_sidebar_collapsed';
        var sidebarBtn = document.getElementById('mlp-sidebar-toggle-btn');
        var isMobile = function() { return window.innerWidth <= 720; };
        /* On mobile: always collapsed, toggle button hidden via CSS */
        if (isMobile()) {
            overlay.classList.add('mlp-sidebar-collapsed');
        } else {
            try {
                if (localStorage.getItem(SIDEBAR_KEY) === '1') {
                    overlay.classList.add('mlp-sidebar-collapsed');
                }
            } catch(e) {}
        }
        if (sidebarBtn) {
            sidebarBtn.addEventListener('click', function() {
                if (isMobile()) { return; } /* Blocked on mobile */
                var collapsed = overlay.classList.toggle('mlp-sidebar-collapsed');
                try { localStorage.setItem(SIDEBAR_KEY, collapsed ? '1' : '0'); } catch(e) {}
            });
        }
        /* ── Sort state — declared early so render() can use it ──────── */
        var currentSort    = 'pinned';
        var currentSortDir = 1;
        try { var ss = localStorage.getItem(SORT_KEY); if(ss){ var sp = JSON.parse(ss); currentSort = sp.k||'pinned'; currentSortDir = sp.d||1; } } catch(e){}
        /* ── Boot profile ───────────────────────────────────────────── */
        maybeShowOnboarding();
        wireSettingsModal(renderSidebar);
        applyPremiumUI();
        /* ── Partners / Projects / Community nav switching ──────────────────────── */
        (function() {
            var projectsView      = document.getElementById('mlp-projects-view');
            var partnersView      = document.getElementById('mlp-partners-view');
            var projectsBtn       = document.getElementById('mlp-nav-projects-btn');
            var partnersBtn       = document.getElementById('mlp-nav-partners-btn');
            var pageHeader        = document.querySelector('#mlp-projects-overlay .mlp-page-header');
            function hideAll() {
                [projectsView, partnersView].forEach(function(v) { if (v) v.style.display = 'none'; });
                [projectsBtn,  partnersBtn].forEach(function(b)  { if (b) b.classList.remove('mlp-sidebar-link-active'); });
                if (pageHeader) pageHeader.style.display = 'none';
            }
            function showProjects() {
                hideAll();
                if (projectsView) projectsView.style.display = '';
                if (pageHeader)   pageHeader.style.display   = '';
                if (projectsBtn)  projectsBtn.classList.add('mlp-sidebar-link-active');
            }
            function showPartners() {
                hideAll();
                if (partnersView) partnersView.style.display = '';
                if (partnersBtn)  partnersBtn.classList.add('mlp-sidebar-link-active');
            }
            if (projectsBtn) projectsBtn.addEventListener('click', showProjects);
            if (partnersBtn) partnersBtn.addEventListener('click', showPartners);
            function mlpForkProject(item, btn) {
                if (!item || !item.payload) return;
                var payload = item.payload || {};
                function genId() {
                    return 'mlp_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2,8);
                }
                var newId = genId();
                var origName = payload.name || 'Untitled';
                var newName  = 'Fork of ' + origName;
                var newProject = {
                    id:          newId,
                    name:        newName,
                    visibility:  'private',
                    html:        payload.html || '',
                    css:         payload.css  || '',
                    js:          payload.js   || '',
                    savedTabs:   payload.savedTabs  || null,
                    allTabs:     payload.allTabs     || null,
                    activeTabId: payload.activeTabId || '',
                    description: payload.description || '',
                    iconColor:   payload.iconColor   || '',
                    emoji:       payload.emoji        || '',
                    createdAt:   new Date().toISOString(),
                    updatedAt:   new Date().toISOString(),
                    pinned:      false,
                    favorite:    false,
                    forkedFrom:  item.token || ''
                };
                try {
                    var lsKey = typeof LS_KEY !== 'undefined' ? LS_KEY : 'mlp_projects';
                    var existing = [];
                    try { existing = JSON.parse(localStorage.getItem(lsKey)||'[]'); } catch(e){ existing = []; }
                    if (!Array.isArray(existing)) existing = [];
                    existing.unshift(newProject);
                    localStorage.setItem(lsKey, JSON.stringify(existing));
                } catch(e) {
                    if (typeof showToast === 'function') showToast('Error', 'Could not fork project.', 'danger');
                    return;
                }
                var forkToken = item.token || '';
                if (forkToken) {
                    try {
                        var _forkCountsKey = 'mlp_fork_counts';
                        var _forkCounts = {};
                        try { _forkCounts = JSON.parse(localStorage.getItem(_forkCountsKey) || '{}'); } catch(e) { _forkCounts = {}; }
                        _forkCounts[forkToken] = (_forkCounts[forkToken] || 0) + 1;
                        localStorage.setItem(_forkCountsKey, JSON.stringify(_forkCounts));
                    } catch(e) {}
                }
                if (forkToken && window.fetch && MLP_AJAX_URL && typeof MLP_SHARE_NONCE !== 'undefined') {
                    var forkFd = new URLSearchParams();
                    forkFd.set('action', 'mlp_increment_fork');
                    forkFd.set('nonce', MLP_SHARE_NONCE);
                    forkFd.set('token', forkToken);
                    window.fetch(MLP_AJAX_URL, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8' },
                        body: forkFd.toString()
                    }).then(function(r){ return r.json(); }).then(function(j) {
                        if (j && j.success && j.data) {
                            var newForks = parseInt(j.data.forks, 10) || 0;
                            try {
                                var _fck2 = 'mlp_fork_counts';
                                var _fc2 = {};
                                try { _fc2 = JSON.parse(localStorage.getItem(_fck2) || '{}'); } catch(e) { _fc2 = {}; }
                                _fc2[forkToken] = newForks;
                                localStorage.setItem(_fck2, JSON.stringify(_fc2));
                            } catch(e) {}
                            var _mf = document.getElementById('mlp-community-modal-forks');
                            var _mfs = document.getElementById('mlp-community-modal-forks-stat');
                            if (_mf) { _mf.textContent = mlpFmtCount(newForks); }
                            if (_mfs) { _mfs.style.display = ''; }
                        }
                    }).catch(function(){});
                }
                var forksStatEl = document.getElementById('mlp-community-modal-forks-stat');
                var forksEl = document.getElementById('mlp-community-modal-forks');
                if (forksEl && item.token === forkToken) {
                    var curForks = parseInt((forksEl && forksEl.textContent) || '0', 10) || 0;
                    curForks++;
                    if (forksEl) forksEl.textContent = typeof mlpFmtCount === 'function' ? mlpFmtCount(curForks) : String(curForks);
                    if (forksStatEl) forksStatEl.style.display = '';
                }
                if (btn) {
                    btn.disabled = true;
                    btn.innerHTML = '<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg> Forked!';
                }
                if (typeof showToast === 'function') {
                    showToast('Forked!', '"' + origName + '" added to your projects as "' + newName + '"', 'success');
                }
                if (typeof render === 'function') {
                    try { render(); } catch(e) {}
                }
            }
            function mlpOpenShareUrlModal(url, token, projectName) {
                var modal     = document.getElementById('mlp-share-url-modal');
                var inputEl   = document.getElementById('mlp-share-url-modal-input');
                var copyBtn   = document.getElementById('mlp-share-url-modal-copy');
                var closeBtn  = document.getElementById('mlp-share-url-modal-close');
                var okBtn     = document.getElementById('mlp-share-url-modal-ok');
                if (!modal || !inputEl) return;
                inputEl.value = url || '';
                if (copyBtn) copyBtn.textContent = 'Copy';
                var _suToken = token || '';
                if (!_suToken && url) { try { _suToken = new URL(url).searchParams.get('mlpsht') || ''; } catch(e){} }
                mlpSetEmbedInput('mlp-share-url-modal-embed', 'mlp-share-url-modal-copy-embed', _suToken, projectName || '');
                var copyEmbedBtn = document.getElementById('mlp-share-url-modal-copy-embed');
                if (copyEmbedBtn) {
                    copyEmbedBtn.addEventListener('click', function() {
                        var embedInp = document.getElementById('mlp-share-url-modal-embed');
                        if (!embedInp || !embedInp.value) return;
                        try { embedInp.select(); document.execCommand('copy'); } catch(ex) {}
                        if (navigator.clipboard) navigator.clipboard.writeText(embedInp.value).catch(function(){});
                        var orig = copyEmbedBtn.textContent;
                        copyEmbedBtn.textContent = '\u2713 Copied!';
                        setTimeout(function() { copyEmbedBtn.textContent = orig; }, 1800);
                        if (typeof showToast === 'function') showToast('Embed Copied', 'CodePen-style embed code copied to clipboard.', 'success');
                    });
                }
                modal.style.display = 'flex';
                setTimeout(function() { try { inputEl.select(); } catch(e) {} }, 60);
            }
            (function wireShareUrlModal() {
                var modal    = document.getElementById('mlp-share-url-modal');
                var inputEl  = document.getElementById('mlp-share-url-modal-input');
                var copyBtn  = document.getElementById('mlp-share-url-modal-copy');
                var closeBtn = document.getElementById('mlp-share-url-modal-close');
                var okBtn    = document.getElementById('mlp-share-url-modal-ok');
                if (!modal) return;
                function closeModal() { modal.style.display = 'none'; }
                if (closeBtn) closeBtn.addEventListener('click', closeModal);
                if (okBtn)    okBtn.addEventListener('click', closeModal);
                modal.addEventListener('click', function(e) { if (e.target === modal) closeModal(); });
                if (copyBtn && inputEl) {
                    copyBtn.addEventListener('click', function() {
                        if (!inputEl.value) return;
                        try { inputEl.select(); document.execCommand('copy'); } catch(e) {}
                        if (navigator.clipboard) navigator.clipboard.writeText(inputEl.value).catch(function(){});
                        copyBtn.textContent = '\u2713 Copied!';
                        setTimeout(function() { copyBtn.textContent = 'Copy'; }, 1800);
                        if (typeof showToast === 'function') showToast('Link Copied', 'Project URL copied to clipboard.', 'success');
                    });
                }
            })();
            var MLP_DONATE_SERVICES = {
                buymeacoffee: { label: 'Buy Me a Coffee', base: 'https://buymeacoffee.com/' },
                kofi:         { label: 'Ko-fi',           base: 'https://ko-fi.com/' },
                patreon:      { label: 'Patreon',         base: 'https://patreon.com/' },
                paypal:       { label: 'PayPal.me',       base: 'https://paypal.me/' },
                github:       { label: 'GitHub Sponsors', base: 'https://github.com/sponsors/' },
                liberapay:    { label: 'Liberapay',       base: 'https://liberapay.com/' },
                opencollective: { label: 'Open Collective', base: 'https://opencollective.com/' }
            };
            function mlpBuildDonateUrl(service, username) {
                if (!service || !username) return '';
                var svc = MLP_DONATE_SERVICES[service];
                if (!svc) return '';
                return svc.base + encodeURIComponent(username.trim());
            }
            var _mlpDonationTargetProjectId = null;
            function mlpOpenDonationModal(projectId) {
                _mlpDonationTargetProjectId = projectId || null;
                var modal    = document.getElementById('mlp-donation-modal');
                var chk      = document.getElementById('mlp-donation-enabled-chk');
                var fields   = document.getElementById('mlp-donation-fields');
                var selEl    = document.getElementById('mlp-donation-service-sel');
                var usrEl    = document.getElementById('mlp-donation-username-inp');
                var prevEl   = document.getElementById('mlp-donation-preview-url');
                if (!modal) return;
                var existing = {};
                if (projectId) {
                    try {
                        var projs = JSON.parse(localStorage.getItem('mlp_projects') || '[]');
                        for (var i = 0; i < projs.length; i++) {
                            var pid = projs[i].id || projs[i].shareToken || '';
                            if (pid === projectId || projs[i].shareToken === projectId) {
                                existing = projs[i];
                                _mlpDonationTargetProjectId = projs[i].id;
                                break;
                            }
                        }
                    } catch(e) {}
                }
                if (chk) chk.checked = !!existing.donationEnabled;
                var _emojiEl = document.getElementById('mlp-donation-enabled-emoji');
                if (_emojiEl) _emojiEl.textContent = (chk && chk.checked) ? '\u2705' : '\u2B1C';
                if (fields) fields.style.display = chk && chk.checked ? '' : 'none';
                if (selEl) selEl.value = existing.donationService || '';
                if (usrEl) usrEl.value = existing.donationUsername || '';
                if (prevEl) {
                    var previewUrl = mlpBuildDonateUrl(existing.donationService || '', existing.donationUsername || '');
                    prevEl.textContent = previewUrl ? ('Preview: ' + previewUrl) : '';
                }
                modal.style.display = 'flex';
            }
            (function wireDonationModal() {
                var modal    = document.getElementById('mlp-donation-modal');
                var chk      = document.getElementById('mlp-donation-enabled-chk');
                var emojiEl  = document.getElementById('mlp-donation-enabled-emoji');
                var label    = document.getElementById('mlp-donation-enabled-label');
                var fields   = document.getElementById('mlp-donation-fields');
                var selEl    = document.getElementById('mlp-donation-service-sel');
                var usrEl    = document.getElementById('mlp-donation-username-inp');
                var prevEl   = document.getElementById('mlp-donation-preview-url');
                var closeBtn = document.getElementById('mlp-donation-modal-close');
                var cancelBtn= document.getElementById('mlp-donation-modal-cancel');
                var saveBtn  = document.getElementById('mlp-donation-modal-save');
                if (!modal) return;
                function syncEmoji() {
                    if (!emojiEl || !chk) return;
                    emojiEl.textContent = chk.checked ? '\u2705' : '\u2B1C';
                }
                function closeModal() { modal.style.display = 'none'; }
                if (closeBtn)  closeBtn.addEventListener('click',  closeModal);
                if (cancelBtn) cancelBtn.addEventListener('click', closeModal);
                modal.addEventListener('click', function(e) { if (e.target === modal) closeModal(); });
                if (label) {
                    label.addEventListener('click', function(e) {
                        e.preventDefault();
                        if (chk) {
                            chk.checked = !chk.checked;
                            syncEmoji();
