        function closeModal() { modal.style.display = 'none'; }
        /* ── Project-type UI toggle ─────────────────────────────────── */
        function _mlpSetProjTypeUI(type) {
            var isNonHtml  = (type === 'python' || type === 'ruby' || type === 'sql' || type === 'lua' || type === 'duckdb' || type === 'rust' || type === 'csharp' || type === 'php');
            var visSec     = document.getElementById('mlp-proj-html-only-vis');
            var configRow  = document.getElementById('mlp-proj-html-only-config-row');
            var tplSec     = document.getElementById('mlp-proj-html-only-tpl');
