        })();
        (function wireConfigToggle() {
            var toggle = document.getElementById('mlp-proj-config-toggle');
            var panel  = document.getElementById('mlp-proj-config-panel');
            if (!toggle || !panel) return;
            toggle.addEventListener('click', function() {
                var isOpen = panel.style.display !== 'none';
                panel.style.display = isOpen ? 'none' : '';
                toggle.classList.toggle('mlp-config-open', !isOpen);
                toggle.setAttribute('aria-expanded', String(!isOpen));
            });
        })();
        /* ── Delete confirm modal ───────────────────────────────────── */
        function openDelModal(id, name) {
