        /* ── Move-to-Gist modal (existing local project → linked Gist) ── */
        var _moveGistTargetId = null;
        function openMoveToGistModal(p) {
            if (!p || !p.id) return;
            _moveGistTargetId = p.id;
            var modalEl = document.getElementById('mlp-move-gist-modal');
            var nameEl  = document.getElementById('mlp-move-gist-proj-name');
            var inputEl = document.getElementById('mlp-move-gist-input');
            var statusEl= document.getElementById('mlp-move-gist-status');
            var testBtn = document.getElementById('mlp-move-gist-test-btn');
            var confirmBtn = document.getElementById('mlp-move-gist-confirm-btn');
            if (nameEl)   nameEl.textContent = p.name || 'this project';
            if (inputEl)  inputEl.value = '';
            if (statusEl) { statusEl.textContent = ''; statusEl.style.color = 'var(--mlp-text-muted)'; }
            if (testBtn)  { testBtn.disabled = false; testBtn.textContent = 'Test'; }
            if (confirmBtn) { confirmBtn.disabled = false; confirmBtn.textContent = 'Move & Sync'; }
            if (modalEl)  modalEl.style.display = 'flex';
            setTimeout(function(){ if (inputEl) inputEl.focus(); }, 60);
        }
        function closeMoveToGistModal() {
            _moveGistTargetId = null;
            var modalEl = document.getElementById('mlp-move-gist-modal');
            if (modalEl) modalEl.style.display = 'none';
        }
        (function wireMoveGistModal() {
            var modalEl    = document.getElementById('mlp-move-gist-modal');
            var closeBtn   = document.getElementById('mlp-move-gist-modal-close');
            var cancelBtn  = document.getElementById('mlp-move-gist-cancel-btn');
            var inputEl    = document.getElementById('mlp-move-gist-input');
            var testBtn    = document.getElementById('mlp-move-gist-test-btn');
            var confirmBtn = document.getElementById('mlp-move-gist-confirm-btn');
            var statusEl   = document.getElementById('mlp-move-gist-status');
            if (!modalEl || !confirmBtn) return;
            function setStat(msg, isErr) {
                if (!statusEl) return;
                statusEl.textContent = msg || '';
                statusEl.style.color = isErr ? '#dc2626' : (msg && msg.indexOf('✓') === 0 ? '#10b981' : 'var(--mlp-text-muted)');
            }
            function parseId(raw) {
                if (!raw) return '';
                var s = String(raw).trim()
                    .replace(/^https?:\/\/gist\.github\.com\/[^/]+\//i, '')
                    .replace(/^https?:\/\/gist\.github\.com\//i, '')
                    .replace(/\?.*$/, '').replace(/#.*$/, '').replace(/\/$/, '').trim();
                if (s.indexOf('/') !== -1) s = s.split('/').filter(Boolean).pop() || '';
                if (!/^[a-f0-9]{4,}$/i.test(s)) return '';
                return s;
            }
            if (closeBtn)  closeBtn.addEventListener('click', closeMoveToGistModal);
            if (cancelBtn) cancelBtn.addEventListener('click', closeMoveToGistModal);
            modalEl.addEventListener('click', function(e){ if (e.target === modalEl) closeMoveToGistModal(); });
            if (testBtn) {
                testBtn.addEventListener('click', function(e) {
                    e.preventDefault();
                    if (testBtn.disabled) return;
                    var gid = parseId(inputEl ? inputEl.value : '');
                    if (!gid) { setStat('Please enter a valid Gist URL or ID first.', true); return; }
                    var hasToken = false; try { hasToken = !!localStorage.getItem('mlp_gist_token'); } catch(_){}
                    if (!hasToken) { setStat('No Gist token. Add one via the GitHub menu in the nav first.', true); return; }
                    if (typeof window._mlpTestGist !== 'function') { setStat('Gist tester not loaded yet.', true); return; }
                    testBtn.disabled = true; testBtn.textContent = 'Testing…';
                    setStat('Talking to GitHub…', false);
                    window._mlpTestGist(gid).then(function(info) {
                        testBtn.disabled = false; testBtn.textContent = 'Test';
                        var ownerStr = info.owner ? ' (owner: ' + info.owner + ')' : '';
                        setStat('✓ Gist found and writable' + ownerStr, false);
                    }).catch(function(err) {
                        testBtn.disabled = false; testBtn.textContent = 'Test';
                        var msg = (err && err.message) || 'Test failed';
                        if (err && err.status === 404) msg = 'Gist not found, or your token cannot see it.';
                        else if (err && err.status === 403) msg = 'Token is missing the "gist" scope, or rate-limited.';
                        else if (err && err.status === 401) msg = 'Token is invalid or expired.';
                        setStat('✗ ' + msg, true);
                    });
                });
            }
            confirmBtn.addEventListener('click', function() {
                if (confirmBtn.disabled) return;
                if (!_moveGistTargetId) { setStat('No project selected.', true); return; }
                var hasToken = false; try { hasToken = !!localStorage.getItem('mlp_gist_token'); } catch(_){}
                if (!hasToken) { setStat('No Gist token. Add one via the GitHub menu in the nav first.', true); return; }
                var raw = (inputEl && inputEl.value || '').trim();
                if (/^(ghp_|github_pat_)/i.test(raw)) {
                    setStat('That looks like a GitHub token — tokens go in the GitHub menu in the nav. Leave this blank to auto-create a new Gist.', true);
                    if (inputEl) { inputEl.focus(); inputEl.select(); }
                    return;
                }
                var pid = _moveGistTargetId;
                var pid_proj = (typeof getProjects === 'function') ? getProjects().find(function(x){ return x && x.id === pid; }) : null;
                if (!raw) {
                    if (typeof window._mlpCreateNewGistForProject !== 'function') {
                        setStat('Gist creator not loaded yet.', true); return;
                    }
                    if (!pid_proj) { setStat('Project not found.', true); return; }
                    confirmBtn.disabled = true; confirmBtn.textContent = 'Creating…';
                    setStat('Creating a new private Gist on GitHub…', false);
                    window._mlpCreateNewGistForProject(pid_proj).then(function(newGid) {
                        try {
                            var arr = getProjects();
                            for (var i = 0; i < arr.length; i++) {
                                if (arr[i].id === pid) { arr[i].storage = 'github-gist'; arr[i].gistId = newGid; break; }
                            }
                            saveProjects(arr);
                        } catch(e) {}
                        confirmBtn.disabled = false; confirmBtn.textContent = 'Move & Sync';
                        closeMoveToGistModal();
                        showToast('Backed up to Gist', 'Created a new private Gist (' + String(newGid).slice(0, 8) + '…) for "' + (pid_proj.name || 'Untitled') + '".', 'success', 5000);
                        render(searchInput.value);
                        if (typeof window._mlpRefreshSyncPillForActive === 'function') window._mlpRefreshSyncPillForActive();
                    }).catch(function(err) {
                        confirmBtn.disabled = false; confirmBtn.textContent = 'Move & Sync';
                        setStat('✗ ' + ((err && err.message) || 'Could not create Gist.'), true);
                    });
                    return;
                }
                var gid = parseId(raw);
                if (!gid) { setStat('That doesn\'t look like a Gist URL or ID. Either fix it, or leave blank to create a new one.', true); return; }
                if (typeof window._mlpMoveProjectToGist !== 'function') { setStat('Move helper not loaded yet.', true); return; }
                confirmBtn.disabled = true; confirmBtn.textContent = 'Moving…';
                setStat('Pushing project to Gist…', false);
                window._mlpMoveProjectToGist(pid, gid).then(function() {
                    confirmBtn.disabled = false; confirmBtn.textContent = 'Move & Sync';
                    closeMoveToGistModal();
                    showToast('Moved to Gist', 'Project is now backed up to GitHub Gist on every save.', 'success', 4000);
                    render(searchInput.value);
                }).catch(function(err) {
                    confirmBtn.disabled = false; confirmBtn.textContent = 'Move & Sync';
                    setStat('✗ ' + ((err && err.message) || 'Move failed'), true);
                });
            });
        })();
        /* ── Close overlay ──────────────────────────────────────────── */
        function closePopup() {
            overlay.classList.add('mlp-proj-hidden');
            document.body.style.overflow = '';
        }
        /* ── Build table row ────────────────────────────────────────── */
        function calcProjectSize(p) {
            var total = 0;
            var addStr = function(s) { total += (s || '').length; };
            addStr(p.html); addStr(p.css); addStr(p.js);
            if (p.savedTabs && typeof p.savedTabs === 'object') {
                try { addStr(JSON.stringify(p.savedTabs)); } catch(e) {}
            }
            if (p.allTabs && typeof p.allTabs === 'object') {
                try { addStr(JSON.stringify(p.allTabs)); } catch(e) {}
            }
            return total;
        }
        function fmtSize(bytes) {
            if (bytes < 1024) return bytes + ' B';
            if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
            return (bytes / (1024 * 1024)).toFixed(2) + ' MB';
        }
        function getSizeClass(bytes) {
            if (bytes < 5 * 1024) return 'mlp-size-sm';
            if (bytes < 50 * 1024) return 'mlp-size-md';
            return 'mlp-size-lg';
        }
        function getLastOpenedId() {
            try { return localStorage.getItem(LAST_ID_KEY); } catch(e) { return null; }
        }
        function highlightText(text, query) {
            if (!query) return escHtml(text);
            var idx = text.toLowerCase().indexOf(query.toLowerCase());
            if (idx === -1) return escHtml(text);
            return escHtml(text.slice(0, idx)) +
                '<mark class="mlp-highlight">' + escHtml(text.slice(idx, idx + query.length)) + '</mark>' +
                escHtml(text.slice(idx + query.length));
        }
        function collectProjectSearchText(p) {
            var tagsText = (Array.isArray(p.tags) ? p.tags.join(' ') : '');
            var parts = [p.name || '', p.description || '', p.notes || '', tagsText, p.html || '', p.css || '', p.js || ''];
            function addTabs(tabs) {
                if (!tabs || typeof tabs !== 'object') return;
                for (var key in tabs) {
                    if (!tabs.hasOwnProperty(key)) continue;
                    var tab = tabs[key];
                    if (typeof tab === 'string') parts.push(tab);
                    else if (tab && typeof tab === 'object') {
                        parts.push(tab.name || '', tab.title || '', tab.html || '', tab.css || '', tab.js || '', tab.code || '', tab.content || '');
                    }
                }
            }
            addTabs(p.savedTabs);
            addTabs(p.allTabs);
            return parts.join('\n');
        }
        function getProjectSearchHit(p, query) {
            if (!query) return '';
            var q = query.toLowerCase();
            if ((p.name || '').toLowerCase().indexOf(q) !== -1) return '';
            var text = collectProjectSearchText(p);
            var idx = text.toLowerCase().indexOf(q);
            if (idx === -1) return '';
            var start = Math.max(0, idx - 34);
            var end = Math.min(text.length, idx + query.length + 48);
            var snippet = text.slice(start, end).replace(/\s+/g, ' ').trim();
            return (start > 0 ? '…' : '') + snippet + (end < text.length ? '…' : '');
        }
        function projectMatchesFilter(p, filter) {
            if (!filter) return true;
            return collectProjectSearchText(p).toLowerCase().indexOf(filter.toLowerCase()) !== -1;
        }
        function closeAllMoreDropdowns() {
            document.querySelectorAll('.mlp-more-dropdown').forEach(function(d){ d.style.display = 'none'; });
            document.querySelectorAll('#mlp-projects-overlay .mlp-row-btn-more').forEach(function(b){ b.classList.remove('mlp-more-open'); });
        }
        if (!window._mlpMoreOutsideListener) {
            window._mlpMoreOutsideListener = true;
            document.addEventListener('click', function(e) {
                if (!e.target.closest || !e.target.closest('.mlp-more-wrap')) { closeAllMoreDropdowns(); }
            });
        }
        /* ── Share URL builder (must be above buildRow) ─────────────── */
        function getShareBaseUrl() {
            var cleanSearch = '';
            try {
                var params = new URLSearchParams(window.location.search || '');
                params.delete('mlpsh');
                params.delete('mlpsht');
                cleanSearch = params.toString();
            } catch(e) {}
            return window.location.origin + window.location.pathname + (cleanSearch ? '?' + cleanSearch : '');
        }
        function appendShareParam(base, key, value) {
            var hashIndex = base.indexOf('#');
            var hash = '';
            if (hashIndex !== -1) {
                hash = base.slice(hashIndex);
                base = base.slice(0, hashIndex);
            }
            return base + (base.indexOf('?') === -1 ? '?' : '&') + encodeURIComponent(key) + '=' + encodeURIComponent(value) + hash;
        }
        function getProjectDisplayUrl(p) {
            var host = (window.location && window.location.host) ? window.location.host : 'pterocos.eu.org';
            var id = p && p.id ? String(p.id) : '';
            if (!id) return host + '/…';
            return host + '/?project=' + id.slice(0, 10) + '…';
        }
        function utf8ToB64Url(str) {
            var b64;
            try {
                if (window.TextEncoder) {
                    var bytes = new TextEncoder().encode(str);
                    var bin = '';
                    for (var i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
                    b64 = btoa(bin);
                } else {
                    b64 = btoa(unescape(encodeURIComponent(str)));
                }
            } catch(e) {
                b64 = btoa(unescape(encodeURIComponent(str)));
            }
            return b64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
        }
        function b64UrlToUtf8(str) {
            var b64 = String(str || '').replace(/-/g, '+').replace(/_/g, '/');
            while (b64.length % 4) b64 += '=';
            var bin = atob(b64);
            try {
                if (window.TextDecoder) {
                    var bytes = new Uint8Array(bin.length);
                    for (var i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
                    return new TextDecoder().decode(bytes);
                }
            } catch(e) {}
            return decodeURIComponent(escape(bin));
        }
        function buildSharePayload(p) {
            var fresh = getFreshProject(p.id, p);
            var shareAllTabs   = fresh.allTabs   ? JSON.parse(JSON.stringify(fresh.allTabs))   : null;
            var shareSavedTabs = fresh.savedTabs ? JSON.parse(JSON.stringify(fresh.savedTabs)) : null;
            var topHtml = fresh.html || '';
            var topCss  = fresh.css  || '';
            var topJs   = fresh.js   || '';
            var tabsSrc = shareAllTabs || shareSavedTabs;
            if (tabsSrc && typeof tabsSrc === 'object') {
                var tabKeys = Object.keys(tabsSrc);
                if (tabKeys.length === 1) {
                    var soleTab = tabsSrc[tabKeys[0]];
                    if (soleTab) {
                        if (!topHtml) topHtml = soleTab.html || soleTab.content || '';
                        if (!topCss)  topCss  = soleTab.css  || '';
                        if (!topJs)   topJs   = soleTab.js   || '';
                    }
                }
            }
            return {
                id:          fresh.id,
                name:        fresh.name        || 'Untitled',
                description: fresh.description || '',
                createdAt:   fresh.createdAt   || new Date().toISOString(),
                updatedAt:   fresh.updatedAt   || new Date().toISOString(),
                visibility:  'public',
                type:        fresh.type        || 'html',
                python:      fresh.type === 'python' ? (fresh.python || '') : undefined,
                sql:         fresh.type === 'sql'    ? (fresh.sql    || '') : undefined,
                lua:         fresh.type === 'lua'    ? (fresh.lua    || '') : undefined,
                duckdb:      fresh.type === 'duckdb' ? (fresh.duckdb || '') : undefined,
                ruby:           fresh.type === 'ruby'   ? (fresh.ruby   || '') : undefined,
                rust:           fresh.type === 'rust'   ? (fresh.rust   || '') : undefined,
                csharp:         fresh.type === 'csharp' ? (fresh.csharp || '') : undefined,
                php:            fresh.type === 'php'    ? (fresh.php    || '') : undefined,
                phpOutput:      fresh.type === 'php'    ? (fresh.phpOutput      || '') : undefined,
                phpOutputIsHtml:fresh.type === 'php'    ? (!!fresh.phpOutputIsHtml)     : undefined,
                phpOutputAt:    fresh.type === 'php'    ? (fresh.phpOutputAt    || '') : undefined,
                iconColor:   fresh.iconColor   || '',
                emoji:       fresh.emoji       || '',
                html:        topHtml,
                css:         topCss,
                js:          topJs,
                savedTabs:   shareSavedTabs,
                allTabs:     shareAllTabs,
                activeTabId: fresh.activeTabId || '',
                pinHash:     fresh.pinHash     || null,
                sharedBy:    (function(){try{return (JSON.parse(localStorage.getItem('mlp_user_profile')||'{}').name||'').trim();}catch(e){return '';}}()),
                memberSince: (function(){try{return JSON.parse(localStorage.getItem('mlp_user_profile')||'{}').joinedAt||'';}catch(e){return '';}}()),
                sharedByAvatar: (function() {
                    try {
                        var pr = JSON.parse(localStorage.getItem('mlp_user_profile')||'{}');
                        if (pr.avatar) return pr.avatar;
                        var name = pr.name || '?';
                        var palettes = [
                            ['#6366f1','#fff'], ['#0ea5e9','#fff'], ['#10b981','#fff'],
                            ['#f59e0b','#fff'], ['#ef4444','#fff'], ['#8b5cf6','#fff'],
                            ['#ec4899','#fff'], ['#14b8a6','#fff'], ['#f97316','#fff'],
                            ['#64748b','#fff'], ['#a855f7','#fff'], ['#06b6d4','#fff']
                        ];
                        var h = 0;
                        for (var ci = 0; ci < name.length; ci++) { h = (h * 31 + name.charCodeAt(ci)) >>> 0; }
                        var pal = palettes[h % palettes.length];
                        var parts = name.trim().split(/\s+/);
                        var initials = parts.length >= 2
                            ? (parts[0][0] + parts[parts.length-1][0]).toUpperCase()
                            : name.slice(0,2).toUpperCase();
                        var canvas = document.createElement('canvas');
                        canvas.width = 128; canvas.height = 128;
                        var ctx = canvas.getContext('2d');
                        ctx.fillStyle = pal[0];
                        ctx.fillRect(0, 0, 128, 128);
                        ctx.fillStyle = pal[1];
                        ctx.font = 'bold 52px -apple-system, BlinkMacSystemFont, sans-serif';
                        ctx.textAlign = 'center';
                        ctx.textBaseline = 'middle';
                        ctx.fillText(initials, 64, 64);
                        return canvas.toDataURL('image/png');
                    } catch(e) { return null; }
                })()
            };
        }
        function buildInlineShareUrlFromJson(json) {
