                        : '<iframe class="mlp-pcard-iframe" sandbox="allow-scripts" data-mlp-srcdoc="' + escHtml(previewSrcdoc) + '"></iframe>'
                    ) +
                    '<div class="mlp-pcard-thumb-overlay"></div>' +
                    lockBadge +
                '</div>' +
                '<div class="mlp-pcard-body">' +
                    '<div class="mlp-pcard-header">' +
                        '<button class="' + _pinClass  + '" type="button" title="' + _pinTitle  + '">&#128204;</button>' +
                        '<button class="' + _starClass + '" type="button" title="' + _starTitle + '">&#11088;</button>' +
                        '<a class="mlp-pcard-name" href="#" title="' + escHtml((p.name || 'Untitled') + (isPythonProj ? '.py' : isRubyProj ? '.ruby' : isSQLProj ? '.db' : isLuaProj ? '.lua' : isDuckDBProj ? '.sql' : isRustProj ? '.rs' : isCsProj ? '.cs' : isPhpProj ? '.php' : '.html')) + '">' + escHtml((p.name || 'Untitled') + (isPythonProj ? '.py' : isRubyProj ? '.ruby' : isSQLProj ? '.db' : isLuaProj ? '.lua' : isDuckDBProj ? '.sql' : isRustProj ? '.rs' : isCsProj ? '.cs' : isPhpProj ? '.php' : '.html')) + '</a>' +
                        visBadge +
                        '<div class="mlp-more-wrap">' +
                            '<button class="mlp-row-btn-more mlp-row-btn-dots" type="button" title="Options">&#8942;</button>' +
                            '<div class="mlp-more-dropdown" style="display:none;">' + dropdownItems + '</div>' +
                        '</div>' +
                    '</div>' +
                    '<div class="mlp-pcard-stats">' +
                        '<span class="mlp-pcard-stat mlp-pcard-stat-likes"  title="Likes">&#10084;&#65039; ' + likesVal + '</span>' +
                        '<span class="mlp-pcard-stat mlp-pcard-stat-views"  title="Views">&#128065; '        + viewsVal + '</span>' +
                        '<span class="mlp-pcard-stat mlp-pcard-stat-comments" title="Comments">&#128172; 0</span>' +
                    '</div>' +
                    '<div class="mlp-pcard-actions">' + _actionBtns + '</div>' +
                '</div>';

            /* ── Pin button ── */
            card.querySelector('.mlp-pin-btn').addEventListener('click', function(e) {
                e.stopPropagation();
                updateProjectById(p.id, { pinned: !p.pinned });
                render(searchInput ? searchInput.value : '');
            });
            /* ── Star button ── */
            card.querySelector('.mlp-star-btn').addEventListener('click', function(e) {
                e.stopPropagation();
                updateProjectById(p.id, { favorite: !p.favorite });
                render(searchInput ? searchInput.value : '');
            });
            /* ── Click to open project ── */
            card.querySelector('.mlp-pcard-name').addEventListener('click', function(e) {
                e.preventDefault();
                goCode(p);
            });
            card.querySelector('.mlp-pcard-thumb-overlay').addEventListener('click', function(e) {
                e.preventDefault();
                goCode(p);
            });
            /* ── Open button ── */
            card.querySelector('.mlp-pcard-open-btn').addEventListener('click', function(e) {
                e.stopPropagation();
                goCode(p);
            });
            /* ── Publish / Republish button ── */
            var _pubBtn = card.querySelector('.mlp-pcard-pub-btn');
            if (_pubBtn) _pubBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                openShareModal(p);
            });
            /* ── Republish button ── */
            var _republishBtn = card.querySelector('.mlp-pcard-republish-btn');
            if (_republishBtn) _republishBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                if (p.adminDeleted) { mlpShowAppealModal(p); return; }
                openRepublishModal(p);
            });
            /* ── Get Link button ── */
            var _glBtn = card.querySelector('.mlp-pcard-getlink-btn');
            if (_glBtn) _glBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                openGetLinkPopup(p);
            });

            /* ── Three-dot menu ── */
            var moreBtn  = card.querySelector('.mlp-row-btn-more.mlp-row-btn-dots');
            var moreDrop = card.querySelector('.mlp-more-dropdown');
            moreBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                var isOpen = moreDrop.style.display !== 'none';
                closeAllMoreDropdowns();
                if (!isOpen) {
                    /* Move dropdown to the overlay root so it escapes the card's
                       overflow:hidden and transform (which creates a new containing
                       block for position:fixed, causing the dropdown to be clipped) */
                    var _overlayRoot = document.getElementById('mlp-projects-overlay') || document.body;
                    if (moreDrop.parentNode !== _overlayRoot) { _overlayRoot.appendChild(moreDrop); }
                    var rect = moreBtn.getBoundingClientRect();
                    /* Measure invisibly — no paint, no flash */
                    moreDrop.style.visibility = 'hidden';
                    moreDrop.style.display    = 'block';
                    moreDrop.style.top        = '0';
                    moreDrop.style.left       = '0';
                    var dropW = moreDrop.offsetWidth  || 205;
                    var dropH = moreDrop.offsetHeight || 260;
                    var viewH = window.innerHeight || document.documentElement.clientHeight;
                    var viewW = window.innerWidth  || document.documentElement.clientWidth;
                    var topPos  = (viewH - rect.bottom >= dropH + 8)
                        ? rect.bottom + 4
                        : Math.max(8, rect.top - dropH - 4);
                    var leftPos = Math.min(Math.max(8, rect.right - dropW), viewW - dropW - 8);
                    /* Set final position then reveal in one paint — GPU animation starts here */
                    moreDrop.style.top        = topPos  + 'px';
                    moreDrop.style.left       = leftPos + 'px';
                    moreDrop.style.right      = 'auto';
                    moreDrop.style.visibility = '';
                    moreBtn.classList.add('mlp-more-open');
                }
            });

            /* ── Dropdown item listeners ── */
            card.querySelector('.mlp-more-rename').addEventListener('click', function() { closeAllMoreDropdowns(); openRenameModal(p.id, p.name); });
            card.querySelector('.mlp-more-dup').addEventListener('click', function() { closeAllMoreDropdowns(); duplicateProject(p); });
            card.querySelector('.mlp-more-notes').addEventListener('click', function() { closeAllMoreDropdowns(); openNotesModal(p); });
            card.querySelector('.mlp-more-lock').addEventListener('click', function() { closeAllMoreDropdowns(); openPinModal(p); });
            card.querySelector('.mlp-more-desc').addEventListener('click', function() { closeAllMoreDropdowns(); openDescModal(p); });
            card.querySelector('.mlp-more-tags').addEventListener('click', function() { closeAllMoreDropdowns(); openTagsEditor(p); });
            card.querySelector('.mlp-more-export-zip').addEventListener('click', function() { closeAllMoreDropdowns(); exportProjectAsZip(p); });
            var moveGistBtn = card.querySelector('.mlp-more-move-gist');
            if (moveGistBtn) moveGistBtn.addEventListener('click', function() { closeAllMoreDropdowns(); openMoveToGistModal(p); });
            var publishBtn = card.querySelector('.mlp-more-publish');
            if (publishBtn) publishBtn.addEventListener('click', function() { closeAllMoreDropdowns(); openShareModal(p); });
            var getLinkBtn = card.querySelector('.mlp-more-getlink');
            if (getLinkBtn) getLinkBtn.addEventListener('click', function() { closeAllMoreDropdowns(); openGetLinkPopup(p); });
            var delItem = card.querySelector('.mlp-more-del-item');
            if (delItem) delItem.addEventListener('click', function() { closeAllMoreDropdowns(); openDelModal(p.id, p.name); });

            /* ── Keep a stub tr so bulk-selection code won't error ── */
            var tr = document.createElement('tr');
            if (isActive) tr.className = 'mlp-row-active';
            if (p.pinned) tr.className = (tr.className ? tr.className + ' ' : '') + 'mlp-row-pinned';
            if (p.favorite) tr.className = (tr.className ? tr.className + ' ' : '') + 'mlp-row-favorited';
            return card;
        }
            /* ── Backup modal ────────────────────────────────────────── */
        function hasSavedTabs(p) {
            return !!(p.savedTabs && typeof p.savedTabs === 'object' && Object.keys(p.savedTabs).length > 0);
        }
        function downloadProjectBackup(p) {
            try {
                var backup = {
                    exportedAt:  new Date().toISOString(),
                    exportedBy:  'MLP Projects Backup',
                    version:     1,
                    project:     p
                };
                var json = JSON.stringify(backup, null, 2);
                var blob = new Blob([json], { type: 'application/json' });
                var url  = URL.createObjectURL(blob);
                var a    = document.createElement('a');
                a.href     = url;
                a.download = (p.name || 'project').replace(/[^a-z0-9_-]/gi, '_') + '_backup_' + new Date().toISOString().slice(0,10) + '.json';
                document.body.appendChild(a);
                a.click();
                setTimeout(function() { URL.revokeObjectURL(url); document.body.removeChild(a); }, 1000);
                try {
                    var nowIso = new Date().toISOString();
                    var allP = getProjects();
                    for (var bi = 0; bi < allP.length; bi++) {
                        if (allP[bi].id === p.id) { allP[bi].lastBackupAt = nowIso; saveProjects(allP); break; }
                    }
                } catch(e) {}
                return true;
            } catch(e) {
                return false;
            }
        }
        var _backupPendingProject  = null;
        var _backupPendingCallback = null;
        function openBackupModal(p, onProceed) {
            var modal     = document.getElementById('mlp-backup-modal');
            var nameEl    = document.getElementById('mlp-backup-proj-name');
            var countEl   = document.getElementById('mlp-backup-tab-count');
            var sizeEl    = document.getElementById('mlp-backup-size-label');
            var dateEl    = document.getElementById('mlp-backup-date-label');
            var dlBtn     = document.getElementById('mlp-backup-download-btn');
            var skipBtn   = document.getElementById('mlp-backup-skip-btn');
            if (!modal) { onProceed(); return; }
            _backupPendingProject  = p;
            _backupPendingCallback = onProceed;
            if (nameEl) nameEl.textContent = p.name || 'Untitled';
            var tabCount = 0;
            if (p.allTabs)   tabCount = Object.keys(p.allTabs).length;
            else if (p.savedTabs) tabCount = Object.keys(p.savedTabs).length;
            if (countEl) countEl.textContent = tabCount + ' saved tab' + (tabCount !== 1 ? 's' : '');
            var sz = calcProjectSize(p);
            if (sizeEl) sizeEl.textContent = fmtSize(sz) + ' of code';
            if (dateEl) dateEl.textContent = 'Modified: ' + (p.updatedAt ? fmtDate(p.updatedAt) : '—');
            modal.style.display = 'flex';
            if (dlBtn) {
                dlBtn.onclick = function() {
                    downloadProjectBackup(_backupPendingProject);
                    modal.style.display = 'none';
                    if (_backupPendingCallback) _backupPendingCallback();
                    _backupPendingProject  = null;
                    _backupPendingCallback = null;
                    showToast('Backup Downloaded', 'Your code has been saved as a .json file.', 'success');
                };
            }
            if (skipBtn) {
                skipBtn.onclick = function() {
                    modal.style.display = 'none';
                    if (_backupPendingCallback) _backupPendingCallback();
                    _backupPendingProject  = null;
                    _backupPendingCallback = null;
                };
            }
        }
            /* ── Go Code helper (with backup gate) ──────────────────── */
        function goCode(p) {
            if (p.pinHash) {
                openUnlockModal(p, function() { goCodeDirect(p); });
                return;
            }
            goCodeDirect(p);
        }
        function goCodeDirect(p) {
            var fresh = null;
            var all = getProjects();
            for (var i = 0; i < all.length; i++) {
                if (all[i].id === p.id) { fresh = all[i]; break; }
            }
            var target = fresh || p;
            /* Python projects → open Python editor overlay instead */
            if (target.type === 'python') {
                closePopup();
                if (typeof window.mlpOpenPythonEditor === 'function') {
                    window.mlpOpenPythonEditor(target.id);
                }
                return;
            }
            /* SQL projects → open SQL editor overlay instead */
            if (target.type === 'sql') {
                closePopup();
                if (typeof window.mlpOpenSQLEditor === 'function') {
                    window.mlpOpenSQLEditor(target.id);
                }
                return;
            }
            /* Lua projects → open Lua editor overlay instead */
            if (target.type === 'lua') {
                closePopup();
                if (typeof window.mlpOpenLuaEditor === 'function') {
                    window.mlpOpenLuaEditor(target.id);
                }
                return;
            }
            /* DuckDB projects → open DuckDB editor overlay instead */
            if (target.type === 'duckdb') {
                closePopup();
                if (typeof window.mlpOpenDuckDBEditor === 'function') {
                    window.mlpOpenDuckDBEditor(target.id);
                }
                return;
            }
            /* Ruby projects → open Ruby editor overlay instead */
            if (target.type === 'ruby') {
                closePopup();
                if (typeof window.mlpOpenRubyEditor === 'function') {
                    window.mlpOpenRubyEditor(target.id);
                }
                return;
            }
            /* Rust projects → open Rust editor overlay instead */
            if (target.type === 'rust') {
                closePopup();
                if (typeof window.mlpOpenRustEditor === 'function') {
                    window.mlpOpenRustEditor(target.id);
                }
                return;
            }
            /* C# projects → open C# editor overlay instead */
            if (target.type === 'csharp') {
                closePopup();
                if (typeof window.mlpOpenCsEditor === 'function') {
                    window.mlpOpenCsEditor(target.id);
                }
                return;
            }
            /* PHP projects → open PHP editor overlay instead */
            if (target.type === 'php') {
                closePopup();
                if (typeof window.mlpOpenPhpEditor === 'function') {
                    window.mlpOpenPhpEditor(target.id);
                }
                return;
            }
            if (hasSavedTabs(target)) {
                openBackupModal(target, function() {
                    window.mlpLoadProject(target);
                    closePopup();
                });
            } else {
                window.mlpLoadProject(target);
                closePopup();
            }
        }
        var toastContainer = document.getElementById('mlp-toast-container');
        function showToast(title, msg, type, durationMs, extraClass) {
            if (!toastContainer) return;
            type = type || 'info';
            var iconPaths = {
                success: '<polyline points="20 6 9 17 4 12"/>',
                danger:  '<line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>',
                warning: '<path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>',
                info:    '<circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/>'
            };
            var t = document.createElement('div');
            t.className = 'mlp-toast mlp-toast-' + type + (extraClass ? ' ' + extraClass : '');
            var msgHtml = msg ? (extraClass ? msg : escHtml(msg)) : '';
            t.innerHTML =
                '<div class="mlp-toast-icon-wrap">' +
                    '<svg viewBox="0 0 24 24" stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5">' + (iconPaths[type] || iconPaths.info) + '</svg>' +
                '</div>' +
                '<div class="mlp-toast-body">' +
                    '<span class="mlp-toast-title">' + escHtml(title) + '</span>' +
                    (msg ? '<span class="mlp-toast-msg">' + msgHtml + '</span>' : '') +
                '</div>' +
                '<button class="mlp-toast-close" aria-label="Dismiss">' +
                    '<svg viewBox="0 0 24 24" stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>' +
                '</button>' +
                '<div class="mlp-toast-progress"><div class="mlp-toast-progress-bar"></div></div>';
            function dismiss() {
                t.classList.add('mlp-toast-out');
                setTimeout(function() { if (t.parentNode) t.parentNode.removeChild(t); }, 260);
            }
            t.querySelector('.mlp-toast-close').addEventListener('click', dismiss);
            toastContainer.appendChild(t);
            var timer = setTimeout(dismiss, durationMs || 3000);
            t.querySelector('.mlp-toast-close').addEventListener('click', function() { clearTimeout(timer); });
        }
        /* ── Undo toast ──────────────────────────────────────────────── */
        function showUndoToast(projName, onUndo) {
            if (!toastContainer) return;
            var t = document.createElement('div');
            t.className = 'mlp-toast mlp-toast-danger';
            t.innerHTML =
                '<div class="mlp-toast-icon-wrap"><svg viewBox="0 0 24 24" stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/></svg></div>' +
                '<div class="mlp-toast-body"><span class="mlp-toast-title">Deleted "' + escHtml(projName) + '"</span>' +
                '<button class="mlp-toast-undo">↩ Undo</button></div>' +
                '<button class="mlp-toast-close" aria-label="Dismiss"><svg viewBox="0 0 24 24" stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button>' +
                '<div class="mlp-toast-progress"><div class="mlp-toast-progress-bar" style="animation-duration:5s;"></div></div>';
            function dismiss() {
                t.classList.add('mlp-toast-out');
                setTimeout(function(){ if(t.parentNode) t.parentNode.removeChild(t); }, 260);
            }
            t.querySelector('.mlp-toast-close').addEventListener('click', dismiss);
            t.querySelector('.mlp-toast-undo').addEventListener('click', function() { onUndo(); dismiss(); });
            toastContainer.appendChild(t);
            var timer = setTimeout(dismiss, 5000);
            t.querySelector('.mlp-toast-close').addEventListener('click', function(){ clearTimeout(timer); });
        }
        /* ── Rename modal ───────────────────────────────────────────── */
        var renameModal      = document.getElementById('mlp-proj-rename-modal');
        var renameInput      = document.getElementById('mlp-proj-rename-input');
        var renameCloseBtn   = document.getElementById('mlp-proj-rename-modal-close');
        var renameCancelBtn  = document.getElementById('mlp-proj-rename-cancel-btn');
        var renameSaveBtn    = document.getElementById('mlp-proj-rename-save-btn');
        var renameTargetId   = null;
        function openRenameModal(id, currentName) {
            renameTargetId = id;
            if (renameInput) renameInput.value = currentName || '';
            if (renameModal) renameModal.style.display = 'flex';
            if (renameInput) setTimeout(function(){ renameInput.focus(); renameInput.select(); }, 60);
        }
        function closeRenameModal() { if (renameModal) renameModal.style.display = 'none'; renameTargetId = null; }
        if (renameCloseBtn)  renameCloseBtn.addEventListener('click', closeRenameModal);
        if (renameCancelBtn) renameCancelBtn.addEventListener('click', closeRenameModal);
        if (renameModal)     renameModal.addEventListener('click', function(e){ if (e.target === renameModal) closeRenameModal(); });
        if (renameSaveBtn) {
            renameSaveBtn.addEventListener('click', function() {
                var name = renameInput ? renameInput.value.trim() : '';
                if (!name || !renameTargetId) { if (renameInput) renameInput.focus(); return; }
                updateProjectById(renameTargetId, { name: name });
                closeRenameModal();
                render(searchInput.value);
                showToast('Project Renamed', 'Now called "' + name + '".', 'success');
            });
        }
        if (renameInput) {
            renameInput.addEventListener('keydown', function(e) {
                if (e.key === 'Enter')  renameSaveBtn && renameSaveBtn.click();
                if (e.key === 'Escape') closeRenameModal();
            });
        }
        /* ── Duplicate project ──────────────────────────────────────── */
        function duplicateProject(p) {
            var currentProjects = getProjects();
            var now  = new Date().toISOString();
            var copy = {};
            for (var k in p) { if (p.hasOwnProperty(k)) copy[k] = p[k]; }
            copy.id        = generateId();
            copy.name      = (p.name || 'Untitled') + ' (copy)';
            copy.createdAt = now;
            copy.updatedAt = now;
            var projects = getProjects();
            projects.push(copy);
            saveProjects(projects);
            render(searchInput.value);
            showToast('Project Duplicated', '"' + copy.name + '" is ready to edit.', 'info');
        }
        /* ── Publish modal (AI moderation gate) ──────────────────────── */
        var _sharePendingProject = null;
        var _mlpTurnstileToken   = '';  // set by Turnstile callback
        var _mlpRepublishTurnstileToken = '';
        window.mlpTurnstileCallback = function(token) {
            _mlpTurnstileToken = token;
            var runBtn = document.getElementById('mlp-publish-run-btn');
            if (runBtn) runBtn.disabled = false;
        };
        window.mlpTurnstileExpired = function() {
            _mlpTurnstileToken = '';
            var runBtn = document.getElementById('mlp-publish-run-btn');
            if (runBtn) runBtn.disabled = true;
        };
        window.mlpTurnstileError = function() {
            _mlpTurnstileToken = '';
            var runBtn = document.getElementById('mlp-publish-run-btn');
            if (runBtn) runBtn.disabled = true;
        };
        window.mlpRepublishTurnstileCallback = function(token) {
            _mlpRepublishTurnstileToken = token;
            var runBtn = document.getElementById('mlp-republish-run-btn');
            if (runBtn) runBtn.disabled = false;
        };
        window.mlpRepublishTurnstileExpired = function() {
            _mlpRepublishTurnstileToken = '';
            var runBtn = document.getElementById('mlp-republish-run-btn');
            if (runBtn) runBtn.disabled = true;
        };
        window.mlpRepublishTurnstileError = function() {
            _mlpRepublishTurnstileToken = '';
            var runBtn = document.getElementById('mlp-republish-run-btn');
            if (runBtn) runBtn.disabled = true;
        };
        function setPublishStep(step) {
            ['pre','checking','rejected','approved'].forEach(function(s) {
                var el = document.getElementById('mlp-publish-step-' + s);
                if (el) el.style.display = (s === step) ? 'block' : 'none';
            });
        }
        function buildFinalUrl(token, payloadJson) {
            if (token) {
                return appendShareParam(getShareBaseUrl(), 'mlpsht', token);
            }
            return buildInlineShareUrlFromJson(payloadJson);
        }
        function buildEmbedCode(token, title) {
            if (!token) return '';
            var src = window.location.origin + '/?mlp_html_preview=' + encodeURIComponent(token);
            var t   = (title || 'Embedded Project').replace(/"/g, '&quot;');
            return '<iframe height="300" style="width:100%;" scrolling="no" title="' + t + '" src="' + src + '" frameborder="no" loading="lazy" allowtransparency="true" allowfullscreen="true"></iframe>';
        }
        function mlpSetEmbedInput(inputId, btnId, token, title) {
            var inp = document.getElementById(inputId);
            var btn = document.getElementById(btnId);
            if (!inp) return;
            inp.value = token ? buildEmbedCode(token, title) : '';
            if (btn) {
                btn.disabled = !token;
                btn.onclick = function() {
                    if (!inp.value) return;
                    try { inp.select(); document.execCommand('copy'); } catch(e) {}
                    if (navigator.clipboard) navigator.clipboard.writeText(inp.value).catch(function(){});
                    var orig = btn.textContent;
                    btn.textContent = '\u2713 Copied!';
                    setTimeout(function() { btn.textContent = orig; }, 1800);
                    showToast('Embed Copied', 'CodePen-style embed code copied to clipboard.', 'success');
                };
            }
        }
        function stripTabTimestamps(tabs) {
            if (!tabs || typeof tabs !== 'object') return tabs;
            var out = {};
            Object.keys(tabs).forEach(function(k) {
                var t = tabs[k];
                if (!t) { out[k] = t; return; }
                out[k] = {
                    id: t.id, title: t.title, emoji: t.emoji,
                    isForked: t.isForked, isReadOnly: t.isReadOnly,
                    html: t.html || '', css: t.css || '', js: t.js || '',
                    preprocessors: t.preprocessors
                };
            });
            return out;
        }
        function computeShareContentHash(p) {
            try {
                return JSON.stringify({
                    html: p.html || '',
                    css:  p.css  || '',
                    js:   p.js   || '',
                    python: p.python || '',
                    lua:    p.lua    || '',
                    ruby:   p.ruby   || '',
                    php:       p.php       || '',
                    phpOutput: p.phpOutput || '',
                    savedTabs: stripTabTimestamps(p.savedTabs) || null,
                    allTabs:   stripTabTimestamps(p.allTabs)   || null
                });
            } catch(e) { return ''; }
        }
        window.mlpOpenShareModal = function(p) { openShareModal(p); };
        function openShareModal(p) {
            if (p && p.adminDeleted) {
                mlpShowAppealModal(p);
                return;
            }
            // Flush PHP editor content to localStorage before building the payload
            if (p && p.type === 'php' && typeof window.mlpPhpFlushBeforeShare === 'function') {
                window.mlpPhpFlushBeforeShare();
            }
            _sharePendingProject = p;
            var modal    = document.getElementById('mlp-share-modal');
            var titleEl  = document.getElementById('mlp-share-proj-title');
            var runBtn   = document.getElementById('mlp-publish-run-btn');
            var copyBtn  = document.getElementById('mlp-share-copy-link-btn');
            var domainInput = document.getElementById('mlp-share-domain-input');
            if (!modal) return;
            if (titleEl) titleEl.textContent = p.name || 'Untitled';
            if (p.id && window.mlpCurrentProjectId && p.id === window.mlpCurrentProjectId) {
                flushTabsToProject(p.id);
                var freshAll = getProjects();
                for (var fi = 0; fi < freshAll.length; fi++) {
                    if (freshAll[fi].id === p.id) { p = freshAll[fi]; _sharePendingProject = p; break; }
                }
            }
            var currentHash   = computeShareContentHash(p);
            var publishedHash = p.shareContentHash || null;
            var contentChanged = publishedHash !== null && (currentHash !== publishedHash);
            if (p.shareUrl && !contentChanged) {
                setPublishStep('approved');
                if (domainInput) domainInput.value = p.shareUrl;
                if (copyBtn)    { copyBtn.disabled = false; }
                if (runBtn)     { runBtn.style.display = 'none'; }
                var _reuseToken = p.shareToken || '';
                if (!_reuseToken && p.shareUrl) { try { _reuseToken = new URL(p.shareUrl).searchParams.get('mlpsht') || ''; } catch(e){} }
                mlpSetEmbedInput('mlp-share-embed-input', 'mlp-share-copy-embed-btn', _reuseToken, p.name || '');
            } else {
                if (contentChanged) {
                    updateProjectById(p.id, { shareUrl: null, shareToken: null, shareContentHash: null });
                    p = Object.assign({}, p, { shareUrl: null, shareToken: null });
                    _sharePendingProject = p;
                }
                setPublishStep('pre');
                if (runBtn) {
                    runBtn.style.display = 'inline-flex';
                    runBtn.disabled = true;   // disabled until Turnstile passes
                    runBtn.innerHTML = '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0;display:inline-block;"><path d="M22 2L11 13"/><path d="M22 2L15 22L11 13L2 9L22 2Z"/></svg> Publish &amp; Get Link';
                }
                _mlpTurnstileToken = '';
                (function() {
                    var el = document.getElementById('mlp-turnstile-widget');
                    if (!el) return;
                    var sitekey = el.getAttribute('data-sitekey');
                    if (!sitekey) return;
                    if (window.turnstile) {
                        try { window.turnstile.remove('#mlp-turnstile-widget'); } catch(e) {}
                        el.innerHTML = '';
                        try {
                            window.turnstile.render('#mlp-turnstile-widget', {
                                sitekey: sitekey,
                                callback: window.mlpTurnstileCallback,
                                'expired-callback': window.mlpTurnstileExpired,
                                'error-callback': window.mlpTurnstileError,
                                theme: 'light'
                            });
                        } catch(e) {}
                    }
                })();
                if (copyBtn)    copyBtn.disabled = true;
                if (domainInput) domainInput.value = '';
            }
            modal.style.display = 'flex';
        }
        function closeShareModal() {
            var modal = document.getElementById('mlp-share-modal');
            if (modal) modal.style.display = 'none';
            _sharePendingProject = null;
        }
        function collectProjectContent(p) {
            var parts = [];
            if (p.name)        parts.push('Project name: ' + p.name);
            if (p.description) parts.push('Description: ' + p.description);
            if (p.python)      parts.push('Python:\n' + p.python);
            if (p.lua)         parts.push('Lua:\n' + p.lua);
            if (p.ruby)        parts.push('Ruby:\n' + p.ruby);
            if (p.sql)         parts.push('SQL:\n' + p.sql);
            if (p.csharp)      parts.push('C#:\n' + p.csharp);
            if (p.rust)        parts.push('Rust:\n' + p.rust);
            if (p.duckdb)      parts.push('DuckDB:\n' + p.duckdb);
            if (p.php)         parts.push('PHP:\n' + p.php);
            if (p.html)        parts.push('HTML:\n' + p.html);
            if (p.css)         parts.push('CSS:\n' + p.css);
            if (p.js)          parts.push('JS:\n' + p.js);
            [p.savedTabs, p.allTabs].forEach(function(tabs) {
                if (!tabs || typeof tabs !== 'object') return;
                Object.keys(tabs).forEach(function(tid) {
                    var t = tabs[tid];
                    if (!t) return;
                    if (t.title || t.name) parts.push('Tab: ' + (t.title || t.name));
                    // Support both html/css/js fields (allTabs) and content field (savedTabs)
                    var tabHtml = t.html || t.content || '';
                    if (tabHtml) parts.push(tabHtml);
                    if (t.css)   parts.push(t.css);
                    if (t.js)    parts.push(t.js);
                });
            });
            return parts.join('\n\n').slice(0, 80000);
        }
