        function mlpUpdateKbdHint() {
            var b = mlpGetKeybinds();
            function disp(v) { return (v === '/' || v === ',') ? v : v.toUpperCase(); }
            var hintNew    = document.getElementById('mlp-kbd-hint-new');
            var hintSearch = document.getElementById('mlp-kbd-hint-search');
            var hintFav    = document.getElementById('mlp-kbd-hint-filterFav');
            var hintPin    = document.getElementById('mlp-kbd-hint-filterPin');
            if (hintNew)    hintNew.textContent    = disp(b.newProject);
            if (hintSearch) hintSearch.textContent = disp(b.search);
            if (hintFav)    hintFav.textContent    = disp(b.filterFavorites);
            if (hintPin)    hintPin.textContent    = disp(b.filterPinned);
        }
        mlpUpdateKbdHint();
        document.addEventListener('keydown', function(e) {
            var overlay = document.getElementById('mlp-projects-overlay');
            if (!overlay || overlay.classList.contains('mlp-proj-hidden')) return;
            var tag = (e.target && e.target.tagName) ? e.target.tagName.toLowerCase() : '';
            var isInput = (tag === 'input' || tag === 'textarea' || tag === 'select');
            if (e.key === 'Escape') {
                var openModals = ['mlp-proj-modal','mlp-proj-del-modal','mlp-proj-rename-modal',
                    'mlp-settings-modal','mlp-keybinds-modal','mlp-username-modal','mlp-del-account-modal',
                    'mlp-notes-modal','mlp-pin-modal','mlp-unlock-modal','mlp-desc-modal','mlp-bulk-del-modal','mlp-share-modal','mlp-republish-modal','mlp-owner-modal'];
                var closed = false;
                for (var i = 0; i < openModals.length; i++) {
                    var m = document.getElementById(openModals[i]);
                    if (m && m.style.display !== 'none') { m.style.display = 'none'; closed = true; break; }
                }
                if (!closed) {
                    overlay.classList.add('mlp-proj-hidden');
                    document.body.style.overflow = '';
                }
                return;
            }
            /* Fixed shortcut: ? opens the keybinds modal */
            if (e.key === '?' && !isInput) {
                e.preventDefault();
