            }
            if (k === binds.filterFavorites || e.key === binds.filterFavorites) {
                e.preventDefault();
                var chipFav = document.querySelector('#mlp-filter-status-group .mlp-filter-chip[data-filter="favorites"]');
                if (chipFav) chipFav.click();
