        /* ── Render table ───────────────────────────────────────────── */
        function updateProjectCounter(count) {
            var elCur = document.getElementById('mlp-proj-count-current');
            var elMax = document.getElementById('mlp-proj-count-max');
            if (!elCur || !elMax) return;
            elCur.textContent = count;
            elMax.textContent = '∞';
            elCur.classList.remove('mlp-count-warn', 'mlp-count-full');
        }
        function sortProjects(arr, key) {
            var copy = arr.slice();
            if (key === 'favorite') {
                var favs    = copy.filter(function(p){ return p.favorite; });
                var nonFavs = copy.filter(function(p){ return !p.favorite; });
                function byMod(a, b) {
                    var av = a.updatedAt || a.createdAt || '';
                    var bv = b.updatedAt || b.createdAt || '';
                    return av < bv ? 1 : av > bv ? -1 : 0;
                }
                favs.sort(byMod); nonFavs.sort(byMod);
                return favs.concat(nonFavs);
            }
            var pinned = copy.filter(function(p){ return p.pinned; });
            var rest   = copy.filter(function(p){ return !p.pinned; });
            function sortArr(a) {
                var dir = currentSortDir;
                a.sort(function(x, y) {
                    var xv, yv;
                    if (key === 'name')     { xv = (x.name||'').toLowerCase(); yv = (y.name||'').toLowerCase(); return dir * (xv < yv ? -1 : xv > yv ? 1 : 0); }
                    if (key === 'created')  { xv = x.createdAt||''; yv = y.createdAt||''; return dir * (xv < yv ? -1 : xv > yv ? 1 : 0); }
                    if (key === 'modified') { xv = x.updatedAt||x.createdAt||''; yv = y.updatedAt||y.createdAt||''; return dir * (xv < yv ? -1 : xv > yv ? 1 : 0); }
                    if (key === 'opened')   { xv = x.lastOpenedAt||''; yv = y.lastOpenedAt||''; return dir * (xv < yv ? -1 : xv > yv ? 1 : 0); }
                    if (key === 'views')    {
                        var xtk = getShareToken(x), ytk = getShareToken(y);
                        var xvw = (window._mlpViewCounts && window._mlpViewCounts[xtk]) || 0;
                        var yvw = (window._mlpViewCounts && window._mlpViewCounts[ytk]) || 0;
                        return dir * (xvw - yvw);
                    }
                    if (key === 'size')     { return dir * (calcProjectSize(x) - calcProjectSize(y)); }
                    return 0;
                });
            }
            if (key === 'pinned') { return pinned.concat(rest); }
            sortArr(pinned); sortArr(rest);
            return pinned.concat(rest);
        }
        function updateStorageBar() {
            var barText   = document.getElementById('mlp-storage-bar-text');
            var segLocal  = document.getElementById('mlp-storage-seg-local');
            var segGist   = document.getElementById('mlp-storage-seg-gist');
            var track     = document.getElementById('mlp-storage-bar-track');
            var legLocal  = document.getElementById('mlp-storage-legend-local');
            var legGist   = document.getElementById('mlp-storage-legend-gist');
            if (!barText || !segLocal) return;
            var storageWrap = document.getElementById('mlp-storage-bar-wrap');
            if (storageWrap) {
                storageWrap.style.display = getProjects().length > 0 ? 'block' : 'none';
            }
            try {
                var maxBytes = 5 * 1024 * 1024;
                var localBytes = 0;
                try {
                    for (var k in localStorage) {
                        if (localStorage.hasOwnProperty(k)) {
                            localBytes += (localStorage.getItem(k) || '').length * 2;
                        }
                    }
                } catch(_e) {}
                var gistBytes = 0;
                try {
                    if (localStorage.getItem('mlp_gist_token')) {
                        var rawProj = localStorage.getItem(LS_KEY) || '';
                        gistBytes = rawProj.length * 2;
                    }
                } catch(_e) {}
                var totalBytes = localBytes + gistBytes;
                var pctLocal  = Math.min(100, (localBytes  / maxBytes) * 100);
                var pctGist   = Math.min(100, (gistBytes   / maxBytes) * 100);
                var pctTotal  = Math.min(100, (totalBytes  / maxBytes) * 100);
                if (segLocal)  segLocal.style.width  = pctLocal.toFixed(2)  + '%';
                if (segGist)   segGist.style.width   = pctGist.toFixed(2)   + '%';
                if (track) {
                    track.classList.toggle('mlp-storage-warn', pctTotal > 70);
                    track.classList.toggle('mlp-storage-crit', pctTotal > 90);
                }
                barText.textContent = fmtSize(totalBytes) + ' used \u00b7 5 MB total (' + pctTotal.toFixed(0) + '%)';
                if (legLocal)  legLocal.textContent  = 'Local '  + fmtSize(localBytes);
                if (legGist)   legGist.textContent   = 'Gist '   + fmtSize(gistBytes);
            } catch(e) {}
        }
        /* ── Lazy-load iframes via IntersectionObserver ─────────────── */
        var _mlpCardObserver = (function() {
            if (!window.IntersectionObserver) return null;
            return new IntersectionObserver(function(entries) {
                entries.forEach(function(entry) {
                    if (!entry.isIntersecting) return;
                    var iframe = entry.target;
                    var src = iframe.getAttribute('data-mlp-srcdoc');
                    if (src) {
                        iframe.srcdoc = src;
                        iframe.removeAttribute('data-mlp-srcdoc');
                    }
                    _mlpCardObserver.unobserve(iframe);
                });
            }, { rootMargin: '200px 0px', threshold: 0 });
        })();
        function mlpObserveCardIframes(container) {
            if (!_mlpCardObserver) {
                container.querySelectorAll('iframe[data-mlp-srcdoc]').forEach(function(f) {
                    f.srcdoc = f.getAttribute('data-mlp-srcdoc');
                    f.removeAttribute('data-mlp-srcdoc');
                });
                return;
            }
            container.querySelectorAll('iframe[data-mlp-srcdoc]').forEach(function(f) {
                _mlpCardObserver.observe(f);
            });
        }

        /* ── Pagination state ─────────────────────────────────────── */
        var _mlpPage     = 1;
        var _mlpPageSize = 16; /* 4 columns × 4 rows */
        var _mlpLastFilter = '';

        function renderPagination(total, page) {
            var pagEl = document.getElementById('mlp-proj-pagination');
            if (!pagEl) return;
            var totalPages = Math.ceil(total / _mlpPageSize);
            if (totalPages <= 1) { pagEl.style.display = 'none'; pagEl.innerHTML = ''; return; }
            pagEl.style.display = 'flex';
            var html = '';
            /* Prev */
            html += '<button class="mlp-pag-btn mlp-pag-prev"' + (page <= 1 ? ' disabled' : '') + '>&#8592;</button>';
            /* Page numbers — show first, last, current ±2, with ellipsis */
            var pages = [];
            for (var p = 1; p <= totalPages; p++) {
                if (p === 1 || p === totalPages || (p >= page - 2 && p <= page + 2)) {
                    pages.push(p);
                }
            }
            var prev = 0;
            for (var j = 0; j < pages.length; j++) {
                if (prev && pages[j] - prev > 1) {
                    html += '<span style="display:inline-flex;align-items:center;padding:0 4px;color:var(--mlp-text-muted,#94a3b8);font-size:0.8rem;">…</span>';
                }
                html += '<button class="mlp-pag-btn' + (pages[j] === page ? ' mlp-pag-active' : '') + '" data-page="' + pages[j] + '">' + pages[j] + '</button>';
                prev = pages[j];
            }
            /* Next */
            html += '<button class="mlp-pag-btn mlp-pag-next"' + (page >= totalPages ? ' disabled' : '') + '>&#8594;</button>';
            pagEl.innerHTML = html;
            pagEl.querySelector('.mlp-pag-prev').addEventListener('click', function() {
                if (_mlpPage > 1) { _mlpPage--; render(_mlpLastFilter); }
            });
            pagEl.querySelector('.mlp-pag-next').addEventListener('click', function() {
                if (_mlpPage < totalPages) { _mlpPage++; render(_mlpLastFilter); }
            });
            pagEl.querySelectorAll('.mlp-pag-btn[data-page]').forEach(function(btn) {
                btn.addEventListener('click', function() {
                    var pg = parseInt(this.getAttribute('data-page'), 10);
                    if (pg !== _mlpPage) { _mlpPage = pg; render(_mlpLastFilter); }
                });
            });
        }

        function render(filter) {
            /* Reset to page 1 when the filter/search term changes */
            if (filter !== _mlpLastFilter) { _mlpPage = 1; }
            _mlpLastFilter = filter || '';
            /* Skip this pass if the user has a three-dot dropdown open — destroying
               the card DOM while they interact with it causes the menu to vanish.
               The next render (triggered after they close it, or on next data change)
               will catch up. */
            if (document.querySelector('#mlp-projects-overlay .mlp-more-dropdown[style*="block"]')) {
                return;
            }
            /* Disconnect any previous iframe observations */
            if (_mlpCardObserver) {
                tbody.querySelectorAll('iframe[data-mlp-srcdoc]').forEach(function(f) {
                    _mlpCardObserver.unobserve(f);
                });
            }
            tbody.innerHTML = '';
            var projects = getProjects();
            var sorted   = sortProjects(projects, currentSort);
            var filtered = sorted.filter(function (p) {
                if (!projectMatchesStatus(p, currentStatusFilter)) return false;
                if (currentTagFilter && !projectHasTag(p, currentTagFilter)) return false;
                if (filter && !projectMatchesFilter(p, filter)) return false;
                return true;
            });
            /* Clamp page to valid range */
            var totalPages = Math.max(1, Math.ceil(filtered.length / _mlpPageSize));
            if (_mlpPage > totalPages) _mlpPage = totalPages;
            var pageStart = (_mlpPage - 1) * _mlpPageSize;
            var paginated = filtered.slice(pageStart, pageStart + _mlpPageSize);
            var _welcomeEl = document.getElementById('mlp-welcome-banner');
            var _welcomeShown = false;
            if (_welcomeEl) {
                var _wDismissed = false;
                try { _wDismissed = !!localStorage.getItem('mlp_welcome_dismissed'); } catch(e) {}
                _welcomeShown = (projects.length === 0 && !_wDismissed);
                _welcomeEl.style.display = _welcomeShown ? 'block' : 'none';
            }
            emptyEl.style.display = (!_welcomeShown && filtered.length === 0) ? 'flex' : 'none';
            var frag = document.createDocumentFragment();
            for (var i = 0; i < paginated.length; i++) {
                frag.appendChild(buildRow(paginated[i], filter || ''));
            }
            tbody.appendChild(frag);
            mlpObserveCardIframes(tbody);
            renderPagination(filtered.length, _mlpPage);
            renderFilterChips(projects);
            renderSidebar(projects);
            updateProjectCounter(projects.length);
            updateStorageBar();
            updateLocalOnlyNudge(projects);
            mlpSyncBanUI();
        }
        /* ── Ban UI sync — banner + new-project button ──────────────── */
        function mlpSyncBanUI() {
            var projects = getProjects();
            var isBanned = projects.some(function(p) { return p && p.adminDeleted; });
            var banner = document.getElementById('mlp-ban-banner');
            if (banner) banner.style.display = isBanned ? 'flex' : 'none';
            var newBtn = document.getElementById('mlp-proj-new-btn');
            if (newBtn) newBtn.style.display = isBanned ? 'none' : '';
        }
        /* ── Local-only nudge banner: ask user once to migrate ─────── */
        var _nudgeWired = false;
        function updateLocalOnlyNudge(projects) {
            var banner = document.getElementById('mlp-local-nudge');
            if (!banner) return;
            var dismissed = false;
            try { dismissed = localStorage.getItem('mlp_local_nudge_dismissed_v1') === '1'; } catch(_){}
            var hasToken = false;
            try { hasToken = !!localStorage.getItem('mlp_gist_token'); } catch(_){}
            var localCount = 0;
            for (var i = 0; i < projects.length; i++) {
                if (projects[i].storage !== 'github-gist') localCount++;
            }
            if (dismissed || !hasToken || localCount < 2) {
                banner.style.display = 'none';
                return;
            }
            var countEl = document.getElementById('mlp-local-nudge-count');
            if (countEl) countEl.textContent = localCount + ' project' + (localCount === 1 ? '' : 's');
            banner.style.display = '';
            if (_nudgeWired) return;
            _nudgeWired = true;
            var migBtn = document.getElementById('mlp-local-nudge-migrate');
            var disBtn = document.getElementById('mlp-local-nudge-dismiss');
            if (migBtn) {
                migBtn.addEventListener('click', function() {
                    if (migBtn.disabled) return;
                    if (typeof window._mlpBulkMigrateLocalToGist !== 'function') {
                        showToast('Not ready', 'Migration helper is still loading. Try again in a moment.', 'danger');
                        return;
                    }
                    if (!confirm('Create a new private Gist for each local project and back them up to GitHub? You can undo this per-project later.')) return;
                    migBtn.disabled = true;
                    var orig = migBtn.textContent;
                    migBtn.textContent = 'Migrating…';
                    window._mlpBulkMigrateLocalToGist(function(progress) {
                        if (progress && progress.total) {
                            migBtn.textContent = 'Migrating ' + progress.done + ' / ' + progress.total + '…';
                        }
                    }).then(function(result) {
                        migBtn.disabled = false;
                        migBtn.textContent = orig;
                        var ok = (result && result.success) || 0;
                        var fail = (result && result.failed) || 0;
                        if (ok > 0 && fail === 0) {
                            showToast('Migration complete', 'Backed up ' + ok + ' project' + (ok===1?'':'s') + ' to GitHub Gist.', 'success', 4500);
                        } else if (ok > 0 && fail > 0) {
                            showToast('Partial success', 'Migrated ' + ok + ', ' + fail + ' failed. See console for details.', 'info', 5000);
                        } else {
                            showToast('Migration failed', 'No projects could be migrated. Check your Gist token.', 'danger', 5000);
                        }
                        try { localStorage.setItem('mlp_local_nudge_dismissed_v1', '1'); } catch(_){}
                        render(searchInput.value);
                    }).catch(function(err) {
                        migBtn.disabled = false;
                        migBtn.textContent = orig;
                        showToast('Migration failed', (err && err.message) || 'Unknown error', 'danger', 5000);
                    });
                });
            }
            if (disBtn) {
                disBtn.addEventListener('click', function() {
                    try { localStorage.setItem('mlp_local_nudge_dismissed_v1', '1'); } catch(_){}
                    banner.style.display = 'none';
                });
            }
        }
        /* ── Render sidebar ─────────────────────────────────────────── */
        var _sidebarExpandedIds = {};
        var _sidebarSelectedId = null;
        function getSidebarTabs(p) {
            var tabs = {};
            if (p.allTabs && typeof p.allTabs === 'object' && Object.keys(p.allTabs).length > 0) {
                tabs = p.allTabs;
            } else if (p.savedTabs && typeof p.savedTabs === 'object' && Object.keys(p.savedTabs).length > 0) {
                tabs = p.savedTabs;
            } else {
                return [];
            }
            return Object.keys(tabs).map(function(k) { return tabs[k]; }).filter(function(t) { return t && t.id; });
        }
        var MLP_SIDEBAR_PAGE_SIZE = 11;
        function renderSidebar(projects) {
            var CAT_KEY = 'mlp_categories';
            function loadCats() { try { return JSON.parse(localStorage.getItem(CAT_KEY) || '[]'); } catch(e) { return []; } }
            function saveCats(c) { try { localStorage.setItem(CAT_KEY, JSON.stringify(c)); } catch(e) {} }
            var section = document.getElementById('mlp-sidebar-manage-section');
            var nav     = document.getElementById('mlp-sidebar-project-nav');
            if (!section || !nav) return;
            if (!projects) projects = getProjects();
            if (projects.length === 0) { section.style.display = 'none'; nav.innerHTML = ''; return; }
            section.style.display = 'block';
            var prevShowAll = nav._mlpShowAll;
            nav.innerHTML = '';
            nav._mlpShowAll = prevShowAll;
            var categories = loadCats();
            /* Map projectId → true for every categorised project */
            var categorisedIds = {};
            categories.forEach(function(cat) {
                (cat.projectIds || []).forEach(function(pid) { categorisedIds[pid] = true; });
            });
            var uncategorized = projects.filter(function(p) { return !categorisedIds[p.id]; });
            /* ── SVG helpers ─────────────────────────────────────────────── */
            var SVG_HTML  = '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#e34c26" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/></svg>';
            var SVG_CSS   = '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#264de4" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2L2 7l10 5 10-5-10-5z"/><path d="M2 17l10 5 10-5"/><path d="M2 12l10 5 10-5"/></svg>';
            var SVG_JS    = '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#e8c530" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="4 17 10 11 4 5"/><line x1="12" y1="19" x2="20" y2="19"/></svg>';
            var FILE_DEFS = [
                { name: 'index.html', pane: 'html', icon: SVG_HTML },
                { name: 'style.css',  pane: 'css',  icon: SVG_CSS  },
                { name: 'script.js',  pane: 'js',   icon: SVG_JS   }
            ];
            /* ── Build a single project row (with file sub-tree) ─────────── */
            function buildProjectRow(p, container) {
                var isActive   = (window.mlpCurrentProjectId === p.id);
                var isSelected = (_sidebarSelectedId === p.id) || isActive;
                var isExpanded = !!_sidebarExpandedIds[p.id];
                var tabList    = getSidebarTabs(p);
                var hasTabs    = (p.type !== 'python' && p.type !== 'sql' && p.type !== 'rust' && p.type !== 'csharp' && p.type !== 'php') && (tabList.length > 0);
                var link = document.createElement('a');
                link.href = '#';
                link.className = 'mlp-sidebar-link mlp-sidebar-project-link' +
                    (isSelected ? ' mlp-sidebar-proj-active' : '') +
                    (isExpanded ? ' mlp-proj-expanded' : '');
                link.dataset.projectId = p.id;
                link.setAttribute('draggable', 'true');
                link.innerHTML =
                    '<i class="fa-solid fa-folder mlp-sidebar-proj-icon"></i>' +
                    '<span class="mlp-sidebar-proj-name">' + escHtml((p.name || 'Untitled') + (p.type === 'python' ? '.py' : p.type === 'ruby' ? '.ruby' : p.type === 'sql' ? '.db' : p.type === 'lua' ? '.lua' : p.type === 'rust' ? '.rs' : p.type === 'csharp' ? '.cs' : p.type === 'php' ? '.php' : '.html')) + '</span>' +
                    '<span class="mlp-sidebar-proj-chevron" aria-hidden="true">\u203A</span>';
                link.title = p.name || 'Untitled';
                /* Drag-and-drop source */
                link.addEventListener('dragstart', function(e) {
                    e.dataTransfer.clearData();
                    e.dataTransfer.setData('text/plain', p.id);
                    e.dataTransfer.effectAllowed = 'move';
                    link.classList.add('mlp-drag-active');
                    e.stopPropagation();
                });
                link.addEventListener('dragend', function() { link.classList.remove('mlp-drag-active'); });
                var tabsEl = document.createElement('div');
                tabsEl.className = 'mlp-sidebar-proj-tabs' + (isExpanded ? ' mlp-proj-tabs-open' : '');
                if (hasTabs) {
                    tabList.forEach(function(tab) {
                        var isActiveTab = isActive && (p.activeTabId === tab.id);
                        var filesKey = '__files__' + p.id + '__' + tab.id;
                        var filesOpen = !!_sidebarExpandedIds[filesKey];
                        /* ── Tab header row ─────────────────────────────── */
                        var tLink = document.createElement('a');
                        tLink.href = '#';
                        tLink.className = 'mlp-sidebar-tab-link' +
                            (isActiveTab  ? ' mlp-tab-link-active' : '') +
                            (filesOpen    ? ' mlp-tab-files-open'  : '');
                        tLink.innerHTML =
                            '<span class="mlp-sidebar-tab-emoji">' + escHtml(tab.emoji || '\uD83D\uDCC4') + '</span>' +
                            '<span class="mlp-sidebar-tab-name">'  + escHtml(tab.title || 'Untitled') + '</span>' +
                            '<span class="mlp-tab-file-chevron" aria-hidden="true">\u203A</span>';
                        tLink.title = tab.title || 'Untitled';
                        /* ── File sub-list ──────────────────────────────── */
                        var filesEl = document.createElement('div');
                        filesEl.className = 'mlp-sidebar-tab-files';
                        filesEl.style.display = filesOpen ? 'block' : 'none';
                        FILE_DEFS.forEach(function(fd) {
                            var fLink = document.createElement('a');
                            fLink.href = '#';
                            fLink.className = 'mlp-sidebar-file-link';
                            fLink.innerHTML =
                                '<span class="mlp-sidebar-file-icon">' + fd.icon + '</span>' +
                                '<span class="mlp-sidebar-file-name">' + escHtml(fd.name) + '</span>';
                            fLink.title = fd.name + ' \u2014 ' + (tab.title || 'Untitled');
                            (function(capturedTab, capturedPane) {
                                fLink.addEventListener('click', function(e) {
                                    e.preventDefault(); e.stopPropagation();
                                    var tid = capturedTab.id;
                                    var openAndSwitch = function() {
                                        _openProjectAtTab(p, tid);
                                        setTimeout(function() {
                                            var btn = document.querySelector('.mlp-tab-button-horizontal[data-tab="' + capturedPane + '"]');
                                            if (btn) btn.click();
                                        }, 400);
                                    };
                                    if (p.pinHash) { openUnlockModal(p, openAndSwitch); }
                                    else { openAndSwitch(); }
                                });
                            })(tab, fd.pane);
                            filesEl.appendChild(fLink);
                        });
                        /* Toggle file list when clicking a tab row */
                        tLink.addEventListener('click', function(e) {
                            e.preventDefault(); e.stopPropagation();
                            if (_sidebarExpandedIds[filesKey]) {
                                delete _sidebarExpandedIds[filesKey];
                                filesEl.style.display = 'none';
                                tLink.classList.remove('mlp-tab-files-open');
                            } else {
                                _sidebarExpandedIds[filesKey] = true;
                                filesEl.style.display = 'block';
                                tLink.classList.add('mlp-tab-files-open');
                            }
                        });
                        tabsEl.appendChild(tLink);
                        tabsEl.appendChild(filesEl);
                    });
                }
                link.addEventListener('click', function(e) {
                    e.preventDefault();
                    _sidebarSelectedId = p.id;
                    var allLinks = nav.querySelectorAll('.mlp-sidebar-project-link');
                    for (var j = 0; j < allLinks.length; j++) {
                        allLinks[j].classList.remove('mlp-sidebar-proj-active');
                    }
                    link.classList.add('mlp-sidebar-proj-active');
                    if (!hasTabs) { goCode(p); return; }
                    if (_sidebarExpandedIds[p.id]) {
                        delete _sidebarExpandedIds[p.id];
                        link.classList.remove('mlp-proj-expanded');
                        tabsEl.classList.remove('mlp-proj-tabs-open');
                    } else {
                        _sidebarExpandedIds[p.id] = true;
                        link.classList.add('mlp-proj-expanded');
                        tabsEl.classList.add('mlp-proj-tabs-open');
                    }
                });
                container.appendChild(link);
                if (hasTabs) container.appendChild(tabsEl);
            }
            /* ── Helper: make a drop zone ────────────────────────────────── */
            function makeDropZone(el, onDrop) {
                el.addEventListener('dragover', function(e) {
                    e.preventDefault(); e.dataTransfer.dropEffect = 'move';
                    el.classList.add('mlp-cat-drop-over');
                });
                el.addEventListener('dragleave', function(e) {
                    if (!el.contains(e.relatedTarget)) el.classList.remove('mlp-cat-drop-over');
                });
                el.addEventListener('drop', function(e) {
                    e.preventDefault(); el.classList.remove('mlp-cat-drop-over');
                    var pid = e.dataTransfer.getData('text/plain');
                    if (pid) onDrop(pid);
                });
            }
            /* ── Render each category section ────────────────────────────── */
            categories.forEach(function(cat) {
                var catProjects = [];
                (cat.projectIds || []).forEach(function(pid) {
                    for (var i = 0; i < projects.length; i++) {
                        if (projects[i].id === pid) { catProjects.push(projects[i]); break; }
                    }
                });
                var isCollapsed = !!_sidebarExpandedIds['__cat__' + cat.id + '__collapsed'];
                var catSec = document.createElement('div');
                catSec.className = 'mlp-sidebar-cat-section';
                catSec.dataset.catId = cat.id;
                /* Drop zone: move project into this category */
                makeDropZone(catSec, function(pid) {
                    var cats = loadCats();
                    cats.forEach(function(c) {
                        c.projectIds = (c.projectIds || []).filter(function(id) { return id !== pid; });
                    });
                    for (var ci = 0; ci < cats.length; ci++) {
                        if (cats[ci].id === cat.id) {
                            if ((cats[ci].projectIds || []).indexOf(pid) === -1) {
                                (cats[ci].projectIds = cats[ci].projectIds || []).push(pid);
                            }
                            break;
                        }
                    }
                    saveCats(cats);
                    renderSidebar(projects);
                });
                var catBody = document.createElement('div');
                catBody.className = 'mlp-sidebar-cat-body';
                catBody.style.display = isCollapsed ? 'none' : 'block';
                var header = document.createElement('div');
                header.className = 'mlp-sidebar-cat-header';
                header.innerHTML =
                    '<svg class="mlp-sidebar-cat-chevron' + (isCollapsed ? '' : ' mlp-cat-open') + '" width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"/></svg>' +
                    '<span class="mlp-sidebar-cat-emoji">\uD83D\uDCC1</span>' +
                    '<span class="mlp-sidebar-cat-name">' + escHtml(cat.name) + '</span>' +
                    '<span class="mlp-sidebar-cat-count">' + catProjects.length + '</span>' +
                    '<button class="mlp-sidebar-cat-rename" type="button" title="Rename category" aria-label="Rename category">&#9998;</button>' +
                    '<button class="mlp-sidebar-cat-del" type="button" title="Delete category" aria-label="Delete category">\xD7</button>';
                header.querySelector('.mlp-sidebar-cat-del').addEventListener('click', function(e) {
                    e.stopPropagation();
                    var cats = loadCats().filter(function(c) { return c.id !== cat.id; });
                    saveCats(cats);
                    renderSidebar(projects);
                });
                header.querySelector('.mlp-sidebar-cat-rename').addEventListener('click', function(e) {
                    e.stopPropagation();
                    var nameSpan = header.querySelector('.mlp-sidebar-cat-name');
                    if (!nameSpan || header.querySelector('.mlp-sidebar-cat-rename-input')) return;
                    var currentName = nameSpan.textContent;
                    var inp = document.createElement('input');
                    inp.type = 'text';
                    inp.className = 'mlp-sidebar-cat-rename-input';
                    inp.value = currentName;
                    inp.maxLength = 5;
                    inp.autocomplete = 'off';
                    nameSpan.replaceWith(inp);
                    inp.focus();
                    inp.select();
                    function commitRename() {
                        var newName = inp.value.trim();
                        if (!newName) newName = currentName;
                        var cats = loadCats();
                        for (var ri = 0; ri < cats.length; ri++) {
                            if (cats[ri].id === cat.id) { cats[ri].name = newName; break; }
                        }
                        saveCats(cats);
                        cat.name = newName;
                        var restored = document.createElement('span');
                        restored.className = 'mlp-sidebar-cat-name';
                        restored.textContent = newName;
                        inp.replaceWith(restored);
                    }
                    inp.addEventListener('keydown', function(ev) {
                        if (ev.key === 'Enter') { ev.preventDefault(); inp.blur(); }
                        if (ev.key === 'Escape') { inp.value = currentName; inp.blur(); }
                        ev.stopPropagation();
                    });
                    inp.addEventListener('blur', commitRename);
                    inp.addEventListener('click', function(ev) { ev.stopPropagation(); });
                });
                header.addEventListener('click', function(e) {
                    if (e.target.classList.contains('mlp-sidebar-cat-del')) return;
                    var key = '__cat__' + cat.id + '__collapsed';
                    var chevron = header.querySelector('.mlp-sidebar-cat-chevron');
                    if (_sidebarExpandedIds[key]) {
                        delete _sidebarExpandedIds[key];
                        catBody.style.display = 'block';
                        if (chevron) chevron.classList.add('mlp-cat-open');
                    } else {
                        _sidebarExpandedIds[key] = true;
                        catBody.style.display = 'none';
                        if (chevron) chevron.classList.remove('mlp-cat-open');
                    }
                });
                catProjects.forEach(function(p) { buildProjectRow(p, catBody); });
                if (catProjects.length === 0) {
                    var emptyMsg = document.createElement('div');
                    emptyMsg.className = 'mlp-sidebar-cat-empty';
                    emptyMsg.textContent = 'Drag projects here';
                    catBody.appendChild(emptyMsg);
                }
                catSec.appendChild(header);
                catSec.appendChild(catBody);
                nav.appendChild(catSec);
            });
            /* ── Uncategorised label (only when categories exist) ─────────── */
            if (categories.length > 0 && uncategorized.length > 0) {
                var uncatLabel = document.createElement('div');
                uncatLabel.className = 'mlp-sidebar-uncat-label';
                uncatLabel.textContent = 'Uncategorized';
                nav.appendChild(uncatLabel);
            }
            /* ── Uncategorised drop zone + project rows ───────────────────── */
            var showAll = (uncategorized.length <= MLP_SIDEBAR_PAGE_SIZE) || !!nav._mlpShowAll;
            var visible = showAll ? uncategorized : uncategorized.slice(0, MLP_SIDEBAR_PAGE_SIZE);
            var uncatZone = document.createElement('div');
            uncatZone.className = 'mlp-sidebar-uncat-zone';
            makeDropZone(uncatZone, function(pid) {
                var cats = loadCats();
                cats.forEach(function(c) {
                    c.projectIds = (c.projectIds || []).filter(function(id) { return id !== pid; });
                });
                saveCats(cats);
                renderSidebar(projects);
            });
            for (var i = 0; i < visible.length; i++) { buildProjectRow(visible[i], uncatZone); }
            nav.appendChild(uncatZone);
            /* ── Load more / Show less ────────────────────────────────────── */
            if (!showAll && uncategorized.length > MLP_SIDEBAR_PAGE_SIZE) {
                var remaining = uncategorized.length - MLP_SIDEBAR_PAGE_SIZE;
                var moreBtn = document.createElement('button');
                moreBtn.type = 'button';
                moreBtn.className = 'mlp-sidebar-load-more-btn';
                moreBtn.innerHTML =
                    '<span>Load ' + remaining + ' more</span>' +
                    '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"/></svg>';
                moreBtn.addEventListener('click', function() { nav._mlpShowAll = true; renderSidebar(projects); });
                nav.appendChild(moreBtn);
            } else if (showAll && uncategorized.length > MLP_SIDEBAR_PAGE_SIZE) {
                var lessBtn = document.createElement('button');
                lessBtn.type = 'button';
                lessBtn.className = 'mlp-sidebar-load-more-btn';
                lessBtn.innerHTML =
                    '<span>Show less</span>' +
                    '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="18 15 12 9 6 15"/></svg>';
                lessBtn.addEventListener('click', function() { nav._mlpShowAll = false; renderSidebar(projects); });
                nav.appendChild(lessBtn);
            }
        }
        /* Open project and, once loaded, switch to a specific tab */
        function _openProjectAtTab(p, tabId) {
            var fresh = null;
            var all = getProjects();
            for (var i = 0; i < all.length; i++) {
                if (all[i].id === p.id) { fresh = all[i]; break; }
            }
            var target = fresh || p;
            var originalActiveTabId = target.activeTabId;
            target.activeTabId = tabId;
            if (hasSavedTabs(target)) {
                openBackupModal(target, function() {
                    window.mlpLoadProject(target);
                    closePopup();
                    target.activeTabId = originalActiveTabId;
                });
            } else {
                window.mlpLoadProject(target);
                closePopup();
                target.activeTabId = originalActiveTabId;
            }
        }
        /* ── Delete confirm (with Undo) ──────────────────────────────── */
        delConfirmBtn.addEventListener('click', function () {
            if (!pendingDeleteId) return;
            var id = pendingDeleteId;
            var projects = getProjects();
            var deletedProj = null;
            var projName = '';
            for (var i = 0; i < projects.length; i++) {
                if (projects[i].id === id) { deletedProj = projects[i]; projName = projects[i].name || 'Project'; break; }
            }
            closeDelModal();
            deleteProjectById(id);
            var wasActive = (window.mlpCurrentProjectId === id);
            if (wasActive) {
                window.mlpCurrentProjectId = null;
                try { localStorage.removeItem(LAST_ID_KEY); } catch(e) {}
                try { localStorage.removeItem(TABS_KEY); } catch(e) {}
                document.querySelectorAll(
                    '.mlp-fullscreen-editor-overlay, .mlp-share-overlay, .mlp-backup-overlay'
                ).forEach(function (el) { el.style.display = 'none'; });
                if (typeof window.mlpResetToDefault === 'function') { window.mlpResetToDefault(); }
            }
            render(searchInput.value);
            if (deletedProj) {
                _undoProject = { proj: deletedProj, wasActive: wasActive };
                if (_undoTimer) clearTimeout(_undoTimer);
                showUndoToast(projName, function() {
                    if (!_undoProject) return;
                    var restored = _undoProject.proj;
                    var projs = getProjects();
                    projs.push(restored);
                    saveProjects(projs);
                    _undoProject = null;
                    render(searchInput.value);
                    showToast('Restored', '"' + escHtml(restored.name||'Project') + '" has been restored.', 'success');
                });
                _undoTimer = setTimeout(function(){ _undoProject = null; }, 5500);
            } else {
                showToast('Project Deleted', '"' + projName + '" has been permanently removed.', 'danger');
            }
        });
        delModalClose.addEventListener('click', closeDelModal);
        delCancelBtn.addEventListener('click', closeDelModal);
        delModal.addEventListener('click', function (e) { if (e.target === delModal) closeDelModal(); });
        /* ── Toolbar events ─────────────────────────────────────────── */
        searchInput.addEventListener('input', function () { render(this.value); });
        newBtn.addEventListener('click', openModal);
        modalClose.addEventListener('click', closeModal);
        cancelBtn.addEventListener('click', closeModal);
        modal.addEventListener('click', function (e) { if (e.target === modal) closeModal(); });
        /* ── Template carousel ───────────────────────────────────────── */
        (function initTemplateSelector() {
            var hiddenInput = document.getElementById('mlp-proj-template-input');
            var track       = document.getElementById('mlp-tpl-track');
            var prevBtn     = document.getElementById('mlp-tpl-prev');
            var nextBtn     = document.getElementById('mlp-tpl-next');
            var dotsWrap    = document.getElementById('mlp-tpl-dots');
            if (!hiddenInput || !track || !prevBtn || !nextBtn) return;

            var cards    = Array.prototype.slice.call(track.querySelectorAll('.mlp-tpl-card'));
            var dots     = dotsWrap ? Array.prototype.slice.call(dotsWrap.querySelectorAll('.mlp-tpl-dot')) : [];
            var VISIBLE  = 2;                          /* cards shown per page */
            var PAGES    = Math.ceil(cards.length / VISIBLE);
            var curPage  = 0;

            function getCardW() {
                /* card width = half the viewport minus half the gap */
                return cards[0] ? cards[0].offsetWidth : 0;
            }
            function getShift() {
                /* shift by one full "page" = VISIBLE cards + gaps */
                var cw   = getCardW();
                var gap  = 8;
                return curPage * (VISIBLE * (cw + gap));
            }
            function render() {
                track.style.transform = 'translateX(-' + getShift() + 'px)';
                prevBtn.disabled = (curPage === 0);
                nextBtn.disabled = (curPage >= PAGES - 1);
                dots.forEach(function(d, i) {
                    d.classList.toggle('mlp-tpl-dot-active', i === curPage);
                });
            }
            function selectCard(card) {
                cards.forEach(function(c) {
                    c.classList.remove('mlp-tpl-selected');
                    c.setAttribute('aria-selected', 'false');
                });
                card.classList.add('mlp-tpl-selected');
                card.setAttribute('aria-selected', 'true');
                hiddenInput.value = card.getAttribute('data-tpl') || 'blank';
            }
            cards.forEach(function(card) {
                card.addEventListener('click', function() { selectCard(card); });
                card.addEventListener('keydown', function(e) {
                    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); selectCard(card); }
                });
            });
            prevBtn.addEventListener('click', function() {
                if (curPage > 0) { curPage--; render(); }
            });
            nextBtn.addEventListener('click', function() {
                if (curPage < PAGES - 1) { curPage++; render(); }
            });
            dots.forEach(function(dot) {
                dot.addEventListener('click', function() {
                    var p = parseInt(dot.getAttribute('data-page'), 10);
                    if (!isNaN(p)) { curPage = p; render(); }
                });
            });
            /* Reset to page 0 + Blank selected each time the modal opens */
            var _origOpen = openModal;
            openModal = function() {
                _origOpen();
                curPage = 0;
                hiddenInput.value = 'blank';
                selectCard(cards[0]);
                render();
            };
            render();
        })();
