            var ipSearch  = document.getElementById('mlp-ip-search');
            var ipGrid    = document.getElementById('mlp-ip-grid');
            var textOk    = document.getElementById('mlp-ip-text-ok');
            var activeMode = 'text'; // 'text' | 'emoji'
            var isOpen = false;
            function setMode(m) {
                activeMode = m;
                if (m === 'text') {
                    tabText.style.borderBottomColor  = 'var(--mlp-accent,#ea580c)';
                    tabText.style.color              = 'var(--mlp-accent,#ea580c)';
                    tabText.style.fontWeight         = '700';
                    tabEmoji.style.borderBottomColor = 'transparent';
                    tabEmoji.style.color             = 'var(--mlp-text-muted,#64748b)';
                    tabEmoji.style.fontWeight        = '600';
                    textPanel.style.display  = '';
                    emojiPanel.style.display = 'none';
                } else {
                    tabEmoji.style.borderBottomColor = 'var(--mlp-accent,#ea580c)';
                    tabEmoji.style.color             = 'var(--mlp-accent,#ea580c)';
                    tabEmoji.style.fontWeight        = '700';
                    tabText.style.borderBottomColor  = 'transparent';
                    tabText.style.color              = 'var(--mlp-text-muted,#64748b)';
                    tabText.style.fontWeight         = '600';
                    textPanel.style.display  = 'none';
                    emojiPanel.style.display = 'flex';
                    renderGrid(ALL_EMOJI);
                    setTimeout(function(){ if(ipSearch) ipSearch.focus(); }, 40);
                }
            }
            function renderGrid(list) {
                ipGrid.innerHTML = '';
                if (!list.length) {
                    var msg = document.createElement('span');
                    msg.textContent = 'No results';
                    msg.style.cssText = 'font-size:0.75rem;color:var(--mlp-text-muted,#64748b);padding:10px;';
                    ipGrid.appendChild(msg);
                    return;
                }
                list.forEach(function(em) {
                    var b = document.createElement('button');
                    b.type = 'button';
                    b.textContent = em;
                    b.title = em;
                    b.style.cssText =
                        'background:none;border:none;cursor:pointer;font-size:1.4rem;' +
                        'width:36px;height:36px;display:inline-flex;align-items:center;' +
                        'justify-content:center;border-radius:6px;transition:background 0.08s;flex-shrink:0;';
                    b.addEventListener('mouseenter', function(){ b.style.background='rgba(0,0,0,0.07)'; });
                    b.addEventListener('mouseleave', function(){ b.style.background='none'; });
                    b.addEventListener('click', function(e){
                        e.preventDefault(); e.stopPropagation();
                        iconInput.value = em;
                        closePanel();
                        iconInput.focus();
                    });
                    ipGrid.appendChild(b);
                });
            }
            function positionPanel() {
                var rect = triggerBtn.getBoundingClientRect();
                var spaceBelow = window.innerHeight - rect.bottom;
                panel.style.left  = Math.max(8, rect.left) + 'px';
                if (spaceBelow >= 320) {
                    panel.style.top    = (rect.bottom + 6) + 'px';
                    panel.style.bottom = 'auto';
                } else {
                    panel.style.bottom = (window.innerHeight - rect.top + 6) + 'px';
                    panel.style.top    = 'auto';
                }
            }
            function openPanel(mode) {
                setMode(mode || 'text');
                positionPanel();
                panel.style.display = 'flex';
                isOpen = true;
                if (mode === 'text' || !mode) {
                    setTimeout(function(){ iconInput.focus(); }, 30);
                }
            }
            function closePanel() {
                panel.style.display = 'none';
                isOpen = false;
            }
            /* Trigger button */
            triggerBtn.addEventListener('click', function(e) {
                e.preventDefault(); e.stopPropagation();
                if (isOpen) { closePanel(); } else { openPanel('text'); }
            });
            /* '<' key in the icon input */
            iconInput.addEventListener('keydown', function(e) {
                if (e.key === '<') {
                    e.preventDefault();
                    openPanel('emoji');
                }
                if (e.key === 'Escape') { closePanel(); }
            });
            /* Tab buttons */
            tabText.addEventListener('click',  function(e){ e.stopPropagation(); setMode('text'); });
            tabEmoji.addEventListener('click', function(e){ e.stopPropagation(); setMode('emoji'); });
            /* "Focus text field" button in text tab */
            if (textOk) {
                textOk.addEventListener('click', function(e){
                    e.stopPropagation();
                    closePanel();
                    iconInput.focus();
                });
            }
            /* Emoji search */
            if (ipSearch) {
                ipSearch.addEventListener('input', function() {
                    var q = this.value.trim();
                    if (!q) { renderGrid(ALL_EMOJI); return; }
                    /* Basic name hints for common emoji */
                    var NAMES = {
                        '😀':'grin','😃':'smile','😄':'happy','😁':'beam','😆':'laugh',
                        '😅':'sweat','🤣':'rofl','😂':'joy','🙂':'slight smile','😉':'wink',
                        '😊':'blush','😇':'angel','🥰':'love','😍':'heart eyes','🤩':'star struck',
                        '😘':'kiss','😎':'cool','🤓':'nerd','🧐':'monocle','😴':'sleep',
                        '😷':'mask','🤒':'sick','🤕':'hurt','🤢':'nauseated','🤧':'sneeze',
                        '😤':'huff','😡':'angry','😠':'mad','🤬':'rage','😈':'devil',
                        '👿':'imp','💀':'skull','☠️':'crossbones','💩':'poop','🤡':'clown',
                        '👻':'ghost','👽':'alien','👾':'monster','🤖':'robot',
                        '❤️':'heart red','🧡':'heart orange','💛':'heart yellow',
                        '💚':'heart green','💙':'heart blue','💜':'heart purple',
                        '🖤':'heart black','🤍':'heart white','🤎':'heart brown',
                        '👍':'thumbs up','👎':'thumbs down','👋':'wave','🤝':'handshake',
                        '🙏':'pray thanks','💪':'muscle strong','🔥':'fire hot',
                        '⭐':'star','🌟':'glowing star','✨':'sparkles','🎉':'party',
                        '🎊':'confetti','🎁':'gift present','🏆':'trophy win',
                        '🥇':'gold medal','🏅':'medal','🎯':'target','🎮':'game',
                        '🚀':'rocket','✈️':'plane','🌍':'earth','🌈':'rainbow',
                        '☀️':'sun','🌙':'moon','❄️':'snow','⚡':'lightning',
                        '💡':'idea light bulb','🔑':'key','🔒':'lock','🔓':'unlock',
                        '📦':'box package','📝':'memo','📚':'books','🔧':'wrench tool',
                        '🛠️':'tools','💎':'diamond','💰':'money','🌸':'flower cherry',
                        '🐶':'dog','🐱':'cat','🐻':'bear','🦊':'fox','🐸':'frog',
                        '🐵':'monkey','🦄':'unicorn','🐍':'snake','🦋':'butterfly',
                        '🌺':'flower hibiscus','🌻':'sunflower','🍄':'mushroom',
                        '🎨':'art palette','🎤':'microphone','🎵':'music note',
                        '🎶':'music notes','🏠':'house home','🏢':'office building',
                        '🌊':'wave ocean','🌪️':'tornado','💧':'droplet water',
                        '🌲':'tree','🌴':'palm tree','🌵':'cactus'
                    };
                    var ql = q.toLowerCase();
                    var res = ALL_EMOJI.filter(function(em){
                        var name = (NAMES[em] || '').toLowerCase();
                        return name.indexOf(ql) !== -1;
                    });
                    if (!res.length) res = ALL_EMOJI; /* fallback: show all if no name match */
                    renderGrid(res);
                });
                ipSearch.addEventListener('keydown', function(e){
                    if (e.key === 'Escape') { closePanel(); iconInput.focus(); }
                });
            }
            /* Close on outside click */
            document.addEventListener('click', function(e) {
                if (!isOpen) return;
                var wrap = document.getElementById('mlp-create-emoji-wrap');
                if (panel.contains(e.target)) return;
                if (wrap && wrap.contains(e.target)) return;
                closePanel();
            });
            /* Reposition on scroll/resize */
            window.addEventListener('scroll', function(){ if(isOpen) positionPanel(); }, true);
            window.addEventListener('resize', function(){ if(isOpen) positionPanel(); });
            /* Close when the main modal backdrop is clicked (modal closes) */
            modal.addEventListener('click', function(e){
                if (e.target === modal) closePanel();
            });
        })();
        /* ── Storage dropdown wiring (show/hide gist input) ─────────── */
        var storageEl   = document.getElementById('mlp-proj-storage-input');
        var gistWrap    = document.getElementById('mlp-proj-gist-wrap');
        var gistNoAuth  = document.getElementById('mlp-proj-gist-noauth');
        var gistAuth    = document.getElementById('mlp-proj-gist-auth');
        var gistLoading = document.getElementById('mlp-proj-gist-loading');
        var gistSelect  = document.getElementById('mlp-proj-gist-select');
        var gistAccount = document.getElementById('mlp-proj-gist-account');
        var gistManualWrap = document.getElementById('mlp-proj-gist-manual-wrap');
        var gistInput   = document.getElementById('mlp-proj-gist-input');
        var gistStatus  = document.getElementById('mlp-proj-gist-status');
        function setGistStatus(msg, isErr) {
            if (!gistStatus) return;
            gistStatus.textContent = msg || '';
            gistStatus.style.color = isErr ? '#dc2626' : 'var(--mlp-text-muted)';
        }
        function setProjTokenStatus(msg, isErr) {
            var el = document.getElementById('mlp-proj-gist-token-status');
            if (!el) return;
            el.textContent = msg || '';
            el.style.color = isErr ? '#dc2626' : (msg && msg.indexOf('✓') === 0 ? '#10b981' : 'var(--mlp-text-muted)');
        }
        var _projGistsCache = null;       // [{ id, description, files, public, updated_at, owner }, …]
        var _projGistsLoadedAt = 0;
        var _projGistsLoading = false;
        var PROJ_GISTS_CACHE_MS = 60 * 1000; // 1 minute
        function showAuthState(state) {
            if (gistNoAuth)  gistNoAuth.style.display  = (state === 'noauth')  ? '' : 'none';
            if (gistLoading) gistLoading.style.display = (state === 'loading') ? 'flex' : 'none';
            if (gistAuth)    gistAuth.style.display    = (state === 'auth')    ? '' : 'none';
        }
        function renderGistDropdown(gists) {
            if (!gistSelect) return;
            while (gistSelect.firstChild) gistSelect.removeChild(gistSelect.firstChild);
            var optNew = document.createElement('option');
            optNew.value = '__new__';
            optNew.textContent = '＋ Create a new private Gist';
            gistSelect.appendChild(optNew);
            if (Array.isArray(gists) && gists.length) {
                var grp = document.createElement('optgroup');
                grp.label = 'Your Gists (' + gists.length + ')';
                gists.forEach(function(g) {
                    if (!g || !g.id) return;
                    var opt = document.createElement('option');
                    opt.value = g.id;
                    var desc = (g.description || '').trim();
                    var fileNames = g.files ? Object.keys(g.files) : [];
                    var firstFile = fileNames[0] || '';
                    var label = desc || firstFile || ('Gist ' + g.id.slice(0, 8));
                    if (label.length > 60) label = label.slice(0, 57) + '…';
                    var vis = g['public'] ? '🌐' : '🔒';
                    opt.textContent = vis + '  ' + label;
                    opt.title = (desc ? desc + '\n' : '') +
                                'ID: ' + g.id +
                                (fileNames.length ? '\nFiles: ' + fileNames.join(', ') : '');
                    grp.appendChild(opt);
                });
                gistSelect.appendChild(grp);
            } else {
                var opt = document.createElement('option');
                opt.value = '__none__';
                opt.disabled = true;
                opt.textContent = '— No existing gists found —';
                gistSelect.appendChild(opt);
            }
            var optManual = document.createElement('option');
            optManual.value = '__manual__';
            optManual.textContent = 'Other / paste a Gist URL or ID…';
            gistSelect.appendChild(optManual);
        }
        function fetchUserGists(force) {
            if (!force && _projGistsCache && (Date.now() - _projGistsLoadedAt) < PROJ_GISTS_CACHE_MS) {
                return Promise.resolve(_projGistsCache);
            }
            if (_projGistsLoading) {
                return new Promise(function(resolve, reject) {
                    var t = setInterval(function() {
                        if (!_projGistsLoading) {
                            clearInterval(t);
                            if (_projGistsCache) resolve(_projGistsCache); else reject(new Error('Load failed'));
                        }
                    }, 80);
                });
            }
            var token = '';
            try { token = localStorage.getItem('mlp_gist_token') || ''; } catch(e) {}
            if (!token) return Promise.reject(new Error('NO_TOKEN'));
            _projGistsLoading = true;
            return fetch('https://api.github.com/gists?per_page=100', {
                headers: {
                    'Authorization': 'token ' + token,
                    'Accept':        'application/vnd.github+json',
                    'X-GitHub-Api-Version': '2022-11-28'
                }
            }).then(function(res) {
                return res.text().then(function(text) {
                    var json = null;
                    try { json = text ? JSON.parse(text) : null; } catch(_) {}
                    if (!res.ok) {
                        var err = new Error((json && json.message) || ('HTTP ' + res.status));
                        err.status = res.status;
                        throw err;
                    }
                    return Array.isArray(json) ? json : [];
                });
            }).then(function(arr) {
                _projGistsCache = arr;
                _projGistsLoadedAt = Date.now();
                _projGistsLoading = false;
                return arr;
            }).catch(function(err) {
                _projGistsLoading = false;
                throw err;
            });
        }
        function syncProjGistAuthUI(force) {
            var hasToken = false;
            try { hasToken = !!localStorage.getItem('mlp_gist_token'); } catch(_) {}
            if (!hasToken) {
                showAuthState('noauth');
                if (gistAccount) gistAccount.textContent = '';
                return;
            }
            showAuthState('loading');
            setGistStatus('');
            fetchUserGists(force).then(function(gists) {
                renderGistDropdown(gists);
                if (gistSelect) gistSelect.value = '__new__';
                if (gistManualWrap) gistManualWrap.style.display = 'none';
                if (gistAccount) {
                    var login = (gists && gists[0] && gists[0].owner && gists[0].owner.login) || '';
                    gistAccount.textContent = login ? ('@' + login) : '';
                }
                showAuthState('auth');
            }).catch(function(err) {
                if (err && (err.status === 401 || err.message === 'NO_TOKEN')) {
                    try { localStorage.removeItem('mlp_gist_token'); } catch(_) {}
                    showAuthState('noauth');
                    setProjTokenStatus('Saved token was rejected by GitHub. Paste a fresh one.', true);
                } else {
                    renderGistDropdown([]);
                    if (gistSelect) gistSelect.value = '__manual__';
                    if (gistManualWrap) gistManualWrap.style.display = '';
                    showAuthState('auth');
                    setGistStatus('Could not load your gists (' + ((err && err.message) || 'unknown error') +
                                  '). You can still paste a Gist URL or ID below.', true);
                }
            });
        }
        window._mlpSyncProjGistAuthUI = syncProjGistAuthUI;
        function syncStorageUI() {
            if (!storageEl || !gistWrap) return;
            var isGist = (storageEl.value === 'github-gist');
            gistWrap.style.display = isGist ? '' : 'none';
            if (!isGist) {
                setGistStatus('');
                return;
            }
            syncProjGistAuthUI(false);
        }
        if (storageEl) storageEl.addEventListener('change', syncStorageUI);
        if (gistSelect) {
            gistSelect.addEventListener('change', function() {
                var v = gistSelect.value;
                if (gistManualWrap) gistManualWrap.style.display = (v === '__manual__') ? '' : 'none';
                setGistStatus('');
            });
        }
        var gistRefreshBtn  = document.getElementById('mlp-proj-gist-refresh-btn');
        var gistRefreshIcon = document.getElementById('mlp-proj-gist-refresh-icon');
        if (gistRefreshBtn) {
            gistRefreshBtn.addEventListener('click', function(e) {
                e.preventDefault();
                if (gistRefreshIcon) gistRefreshIcon.style.animation = 'mlp-spin 0.8s linear infinite';
                gistRefreshBtn.disabled = true;
                _projGistsCache = null;
                fetchUserGists(true).then(function(gists) {
                    renderGistDropdown(gists);
                    if (gistSelect) gistSelect.value = '__new__';
                    if (gistManualWrap) gistManualWrap.style.display = 'none';
                    setGistStatus('Refreshed — found ' + gists.length + ' gist' + (gists.length === 1 ? '' : 's') + '.', false);
                }).catch(function(err) {
                    setGistStatus('Refresh failed: ' + ((err && err.message) || 'unknown error'), true);
                }).then(function() {
                    if (gistRefreshIcon) gistRefreshIcon.style.animation = '';
                    gistRefreshBtn.disabled = false;
                });
            });
        }
        var gistTokenInput     = document.getElementById('mlp-proj-gist-token-input');
        var gistTokenSaveBtn   = document.getElementById('mlp-proj-gist-token-save-btn');
        var gistTokenSaveLabel = document.getElementById('mlp-proj-gist-token-save-label');
        function saveTokenAndLoad() {
            if (!gistTokenInput) return;
            var raw = (gistTokenInput.value || '').trim();
            if (!raw) {
                setProjTokenStatus('Paste your token above first.', true);
                gistTokenInput.focus();
                return;
            }
            if (!/^(ghp_|github_pat_|gho_|ghu_|ghs_)/i.test(raw)) {
                setProjTokenStatus('That doesn\'t look like a GitHub token. Tokens start with ghp_ or github_pat_.', true);
                return;
            }
            if (gistTokenSaveBtn) gistTokenSaveBtn.disabled = true;
            if (gistTokenSaveLabel) gistTokenSaveLabel.textContent = 'Checking…';
            setProjTokenStatus('Verifying token with GitHub…', false);
            fetch('https://api.github.com/gists?per_page=1', {
                headers: {
                    'Authorization': 'token ' + raw,
                    'Accept':        'application/vnd.github+json',
                    'X-GitHub-Api-Version': '2022-11-28'
                }
            }).then(function(res) {
                if (!res.ok) {
                    var msg = 'HTTP ' + res.status;
                    if (res.status === 401) msg = 'Token is invalid or expired.';
                    else if (res.status === 403) msg = 'Token is missing the "gist" scope, or you\'re rate-limited.';
                    var err = new Error(msg); err.status = res.status; throw err;
                }
                try { localStorage.setItem('mlp_gist_token', raw); } catch(_) {}
                _projGistsCache = null;
                setProjTokenStatus('✓ Connected. Loading your gists…', false);
                if (gistTokenInput) gistTokenInput.value = '';
                if (gistTokenSaveBtn) gistTokenSaveBtn.disabled = false;
                if (gistTokenSaveLabel) gistTokenSaveLabel.textContent = 'Connect';
                syncProjGistAuthUI(true);
            }).catch(function(err) {
                if (gistTokenSaveBtn) gistTokenSaveBtn.disabled = false;
                if (gistTokenSaveLabel) gistTokenSaveLabel.textContent = 'Connect';
                setProjTokenStatus('✗ ' + ((err && err.message) || 'Could not verify token'), true);
            });
        }
        if (gistTokenSaveBtn) gistTokenSaveBtn.addEventListener('click', function(e) { e.preventDefault(); saveTokenAndLoad(); });
        if (gistTokenInput) {
            gistTokenInput.addEventListener('keydown', function(e) {
                if (e.key === 'Enter') { e.preventDefault(); saveTokenAndLoad(); }
            });
        }
        /* ── Test Gist button (manual-entry sub-input only) ─────────── */
        var gistTestBtn   = document.getElementById('mlp-proj-gist-test-btn');
        var gistTestLabel = document.getElementById('mlp-proj-gist-test-label');
        if (gistTestBtn) {
            gistTestBtn.addEventListener('click', function(e) {
                e.preventDefault();
                if (gistTestBtn.disabled) return;
                var raw = gistInput ? gistInput.value.trim() : '';
                var hasToken = false;
                try { hasToken = !!localStorage.getItem('mlp_gist_token'); } catch(_){}
                if (!hasToken) {
                    setGistStatus('Connect a GitHub token above first.', true);
                    return;
                }
                if (!raw) {
                    setGistStatus('Nothing to test — paste a Gist URL or ID, or pick one from the dropdown above.', false);
                    return;
                }
                if (/^(ghp_|github_pat_)/i.test(raw)) {
                    setGistStatus('That looks like a GitHub token — paste it in the Connect box above instead.', true);
                    if (gistInput) { gistInput.focus(); gistInput.select(); }
                    return;
                }
                var gid = parseGistId(raw);
                if (!gid) {
                    setGistStatus('That doesn\'t look like a Gist URL or ID. Either fix it, or pick "Create a new private Gist" above.', true);
                    if (gistInput) gistInput.focus();
                    return;
                }
                if (typeof window._mlpTestGist !== 'function') {
                    setGistStatus('Gist tester not loaded yet. Try again in a moment.', true);
                    return;
                }
                gistTestBtn.disabled = true;
                if (gistTestLabel) gistTestLabel.textContent = 'Testing…';
                setGistStatus('Talking to GitHub…', false);
                window._mlpTestGist(gid).then(function(info) {
                    gistTestBtn.disabled = false;
                    if (gistTestLabel) gistTestLabel.textContent = 'Test Gist';
                    if (gistStatus) {
                        var ownerStr = info.owner ? ' (owner: ' + info.owner + ')' : '';
                        gistStatus.style.color = '#10b981';
                        gistStatus.textContent = '✓ Gist found and writable' + ownerStr +
                            (info.description ? ' — "' + info.description.slice(0, 60) + '"' : '');
                    }
                }).catch(function(err) {
                    gistTestBtn.disabled = false;
                    if (gistTestLabel) gistTestLabel.textContent = 'Test Gist';
                    var msg = (err && err.message) || 'Test failed';
                    if (err && err.status === 404) msg = 'Gist not found, or your token cannot see it (it may be private and owned by someone else).';
                    else if (err && err.status === 403) msg = 'Token is missing the "gist" scope, or rate-limited.';
                    else if (err && err.status === 401) msg = 'Token is invalid or expired. Paste a fresh one in the Connect box.';
                    setGistStatus('✗ ' + msg, true);
                });
            });
        }
