        /* Parse a Gist URL or raw ID into a bare Gist ID. Returns '' if invalid. */
        function parseGistId(raw) {
            if (!raw) return '';
            var s = String(raw).trim()
                .replace(/^https?:\/\/gist\.github\.com\/[^/]+\//i, '')
                .replace(/^https?:\/\/gist\.github\.com\//i, '')
                .replace(/\?.*$/, '').replace(/#.*$/, '')
                .replace(/\/$/, '').trim();
            if (s.indexOf('/') !== -1) {
                s = s.split('/').filter(Boolean).pop() || '';
            }
            if (!/^[a-f0-9]{4,}$/i.test(s)) return '';
            return s;
        }
