ght: 800; margin-bottom: 1rem; }\n    .about p { max-width: 600px; margin: 0 auto; color: #475569; line-height: 1.7; }\n    footer { text-align: center; padding: 2rem; background: #0f172a; color: #94a3b8; font-size: 0.85rem; }\n  </style>\n</head>\n<body>\n  <nav>\n    <span class="logo">Nexus Co.</span>\n    <div class="nav-links"><a href="#services">Services</a><a href="#about">About</a><a href="#">Contact</a></div>\n  </nav>\n  <section class="hero">\n    <h1>Professional Solutions for Your Business</h1>\n    <p>We help companies grow with strategic consulting, design, and technology services tailored to your goals.</p>\n    <a href="#" class="cta">Talk to Us</a>\n  </section>\n  <section class="services" id="services">\n    <h2>What We Offer</h2>\n    <div class="services-grid">\n      <div class="service"><div class="service-icon">&#128202;</div><h3>Strategy &amp; Consulting</h3><p>Data-driven strategies to help your business grow and outperform the competition.</p></div>\n      <div class="service"><div class="service-icon">&#127912;</div><h3>Design &amp; Branding</h3><p>Memorable visual identities and user experiences that connect with your audience.</p></div>\n      <div class="service"><div class="service-icon">&#128187;</div><h3>Web Development</h3><p>Fast, scalable, and modern websites built to your exact specifications.</p></div>\n      <div class="service"><div class="service-icon">&#128226;</div><h3>Marketing</h3><p>Targeted campaigns that drive real results and bring the right customers to you.</p></div>\n    </div>\n  </section>\n  <section class="about" id="about">\n    <h2>About Us</h2>\n    <p>We are a team of dedicated professionals committed to delivering exceptional results. With years of experience across multiple industries, we bring clarity, creativity, and expertise to every project.</p>\n  </section>\n  <footer><p>&copy; 2026 Nexus Co. All rights reserved.</p></footer>\n</body>\n</html>',
