        nameInput.addEventListener('keydown', function (e) {
            if (e.key === 'Enter')  { createBtn.click(); }
            if (e.key === 'Escape') { closeModal(); }
        });
        /* ── Keyboard hint dismiss ──────────────────────────────────── */
        var kbdHint    = document.getElementById('mlp-kbd-hint');
        var kbdDismiss = document.getElementById('mlp-kbd-dismiss');
        if (kbdDismiss && kbdHint) {
            kbdDismiss.addEventListener('click', function() {
                kbdHint.classList.add('mlp-kbd-hidden');
            });
        }
        /* ── Keybinds modal ─────────────────────────────────────────── */
        (function() {
            var keybindsModal     = document.getElementById('mlp-keybinds-modal');
            var keybindsCloseBtn  = document.getElementById('mlp-keybinds-modal-close');
            var keybindsDoneBtn   = document.getElementById('mlp-keybinds-close-btn');
            var keybindsResetAll  = document.getElementById('mlp-keybinds-reset-all-btn');
            var listeningHint     = document.getElementById('mlp-keybind-listening-hint');
            var ddKeybindsBtn     = document.getElementById('mlp-profile-dd-keybinds');
            var listeningAction   = null;
            var listeningAbort    = null;
            var ACTIONS = ['newProject', 'search', 'settings', 'filterAll', 'filterFavorites', 'filterPinned', 'sortDir'];
            function getKeyDisplay(val) {
                if (!val) return '?';
                if (val === '/' || val === ',') return val;
                return val.toUpperCase();
            }
            function refreshKeybindRows() {
                var binds = mlpGetKeybinds();
                ACTIONS.forEach(function(action) {
                    var keyEl = document.getElementById('mlp-keybind-key-' + action);
                    if (keyEl) keyEl.textContent = getKeyDisplay(binds[action]);
                });
                mlpUpdateKbdHint();
            }
            function openKeybindsModal() {
                if (!keybindsModal) return;
                cancelListening();
                refreshKeybindRows();
                keybindsModal.style.display = 'flex';
            }
            window._mlpOpenKeybindsModal = openKeybindsModal;
            function closeKeybindsModal() {
                if (!keybindsModal) return;
                cancelListening();
                keybindsModal.style.display = 'none';
            }
            function startListening(action) {
                cancelListening();
                listeningAction = action;
                var row = document.getElementById('mlp-keybind-row-' + action);
                var btn = row ? row.querySelector('.mlp-keybind-change-btn') : null;
                var keyEl = document.getElementById('mlp-keybind-key-' + action);
                if (row) row.classList.add('mlp-keybind-listening');
                if (btn) btn.textContent = 'Listening…';
                if (keyEl) keyEl.textContent = '?';
                if (listeningHint) listeningHint.style.display = 'block';
                function onKey(e) {
                    e.preventDefault(); e.stopPropagation();
                    if (e.key === 'Escape') { cancelListening(); return; }
                    var mods = ['Control','Alt','Shift','Meta','CapsLock','Tab','Enter','Backspace','Delete','ArrowUp','ArrowDown','ArrowLeft','ArrowRight','F1','F2','F3','F4','F5','F6','F7','F8','F9','F10','F11','F12'];
                    if (mods.indexOf(e.key) !== -1) return;
                    var binds = mlpGetKeybinds();
                    var newKey = e.key.length === 1 ? e.key.toLowerCase() : e.key.toLowerCase();
                    binds[action] = newKey;
                    mlpSaveKeybinds(binds);
                    cancelListening();
                    refreshKeybindRows();
                }
                document.addEventListener('keydown', onKey, true);
                listeningAbort = function() { document.removeEventListener('keydown', onKey, true); };
            }
            function cancelListening() {
                if (listeningAbort) { listeningAbort(); listeningAbort = null; }
                if (listeningAction) {
                    var row = document.getElementById('mlp-keybind-row-' + listeningAction);
                    var btn = row ? row.querySelector('.mlp-keybind-change-btn') : null;
                    if (row) row.classList.remove('mlp-keybind-listening');
                    if (btn) btn.textContent = 'Change';
                }
                listeningAction = null;
                if (listeningHint) listeningHint.style.display = 'none';
                refreshKeybindRows();
            }
            if (ddKeybindsBtn) {
                ddKeybindsBtn.addEventListener('click', function(e) {
                    e.stopPropagation();
                    var profileDropdown = document.getElementById('mlp-profile-dropdown');
                    var profileBtn = document.getElementById('mlp-profile-btn');
                    var profileCaret = document.getElementById('mlp-profile-caret');
                    if (profileDropdown) { profileDropdown.style.display = 'none'; }
                    if (profileBtn) { profileBtn.classList.remove('mlp-profile-btn-open'); profileBtn.setAttribute('aria-expanded','false'); }
                    if (profileCaret) profileCaret.classList.remove('mlp-profile-caret-open');
                    openKeybindsModal();
                });
            }
            if (keybindsCloseBtn) keybindsCloseBtn.addEventListener('click', closeKeybindsModal);
            if (keybindsDoneBtn)  keybindsDoneBtn.addEventListener('click',  closeKeybindsModal);
            if (keybindsModal) {
                keybindsModal.addEventListener('click', function(e) {
                    if (e.target === keybindsModal) closeKeybindsModal();
                });
            }
            if (keybindsResetAll) {
                keybindsResetAll.addEventListener('click', function() {
                    cancelListening();
                    mlpSaveKeybinds({
                        newProject:      MLP_KEYBINDS_DEFAULTS.newProject,
                        search:          MLP_KEYBINDS_DEFAULTS.search,
                        settings:        MLP_KEYBINDS_DEFAULTS.settings,
                        filterAll:       MLP_KEYBINDS_DEFAULTS.filterAll,
                        filterFavorites: MLP_KEYBINDS_DEFAULTS.filterFavorites,
                        filterPinned:    MLP_KEYBINDS_DEFAULTS.filterPinned,
                        sortDir:         MLP_KEYBINDS_DEFAULTS.sortDir
                    });
                    refreshKeybindRows();
                });
            }
            document.addEventListener('click', function(e) {
                ACTIONS.forEach(function(action) {
                    var row = document.getElementById('mlp-keybind-row-' + action);
                    var btn = row ? row.querySelector('.mlp-keybind-change-btn') : null;
                    if (btn && btn.contains(e.target)) {
                        if (listeningAction === action) { cancelListening(); }
                        else { startListening(action); }
                    }
                    var resetBtn = row ? row.querySelector('.mlp-keybind-reset-btn') : null;
                    if (resetBtn && resetBtn.contains(e.target)) {
                        cancelListening();
                        var binds = mlpGetKeybinds();
                        binds[action] = MLP_KEYBINDS_DEFAULTS[action];
                        mlpSaveKeybinds(binds);
                        refreshKeybindRows();
                    }
                });
            });
        })();
        /* ── Sort buttons wiring ────────────────────────────────────── */
        var sortDirBtn = document.getElementById('mlp-sort-dir-btn');
        function syncSortDirBtn() {
            if (!sortDirBtn) return;
            var showDir = (currentSort !== 'pinned');
            sortDirBtn.style.display = showDir ? 'inline-flex' : 'none';
            sortDirBtn.classList.toggle('mlp-dir-asc',  currentSortDir === 1);
            sortDirBtn.classList.toggle('mlp-dir-desc', currentSortDir === -1);
            sortDirBtn.title = currentSortDir === 1 ? 'Ascending (click to reverse)' : 'Descending (click to reverse)';
        }
        if (sortDirBtn) {
            sortDirBtn.addEventListener('click', function() {
                if (currentSort === 'pinned') return;
                currentSortDir *= -1;
                syncSortDirBtn();
                document.querySelectorAll('.mlp-sort-btn').forEach(function(b) {
                    b.classList.remove('mlp-sort-asc', 'mlp-sort-desc');
                });
                try { localStorage.setItem(SORT_KEY, JSON.stringify({k:currentSort,d:currentSortDir})); } catch(e){}
                render(searchInput.value);
            });
        }
        document.querySelectorAll('.mlp-sort-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var key = btn.getAttribute('data-sort');
                if (currentSort === key && key !== 'pinned') {
                    currentSortDir *= -1;
                } else {
                    document.querySelectorAll('.mlp-sort-btn').forEach(function(b){
                        b.classList.remove('mlp-sort-active','mlp-sort-asc','mlp-sort-desc');
                    });
                    currentSort = key; currentSortDir = 1;
                    btn.classList.add('mlp-sort-active');
                }
                _mlpPage = 1;
                syncSortDirBtn();
                try { localStorage.setItem(SORT_KEY, JSON.stringify({k:currentSort,d:currentSortDir})); } catch(e){}
                render(searchInput.value);
            });
        });
        (function(){
            document.querySelectorAll('.mlp-sort-btn').forEach(function(b){
                b.classList.remove('mlp-sort-active','mlp-sort-asc','mlp-sort-desc');
                if(b.getAttribute('data-sort')===currentSort){
                    b.classList.add('mlp-sort-active');
                }
            });
            syncSortDirBtn();
        })();
        /* ── Bulk selection ─────────────────────────────────────────── */
        var bulkSelected = [];
        function updateBulkBar() {
            var cbs = tbody.querySelectorAll('.mlp-row-cb:checked');
            bulkSelected = [];
            cbs.forEach(function(cb){ bulkSelected.push(cb.getAttribute('data-id')); });
            var bar = document.getElementById('mlp-bulk-bar');
            var cnt = document.getElementById('mlp-bulk-count');
            if (bar) bar.style.display = bulkSelected.length > 0 ? 'flex' : 'none';
            if (cnt) cnt.textContent = bulkSelected.length + ' selected';
            tbody.querySelectorAll('tr').forEach(function(tr){
                var cb = tr.querySelector('.mlp-row-cb');
                if (cb) tr.classList.toggle('mlp-row-selected', cb.checked);
            });
        }
        var selectAll = document.getElementById('mlp-select-all');
        if (selectAll) {
            selectAll.addEventListener('change', function() {
                tbody.querySelectorAll('.mlp-row-cb').forEach(function(cb){ cb.checked = selectAll.checked; });
                updateBulkBar();
            });
        }
        var bulkDelBtn    = document.getElementById('mlp-bulk-del-btn');
        var bulkExportBtn = document.getElementById('mlp-bulk-export-btn');
        var bulkCancelBtn = document.getElementById('mlp-bulk-cancel-btn');
        var bulkDelModal  = document.getElementById('mlp-bulk-del-modal');
        var bulkDelCount  = document.getElementById('mlp-bulk-del-count');
        var bulkDelConfirm= document.getElementById('mlp-bulk-del-confirm-btn');
        var bulkDelCancel = document.getElementById('mlp-bulk-del-cancel-btn');
        var bulkDelClose  = document.getElementById('mlp-bulk-del-modal-close');
        if (bulkDelBtn) bulkDelBtn.addEventListener('click', function() {
            if (!bulkSelected.length) return;
            if (bulkDelCount) bulkDelCount.textContent = bulkSelected.length;
            if (bulkDelModal) bulkDelModal.style.display = 'flex';
        });
        function closeBulkDelModal(){ if(bulkDelModal) bulkDelModal.style.display='none'; }
        if (bulkDelClose)  bulkDelClose.addEventListener('click', closeBulkDelModal);
