                    { size: 2, value: 0 },
                    { size: 2, value: stamp.time },
                    { size: 2, value: stamp.date },
                    { size: 4, value: entry.crc },
                    { size: 4, value: entry.size },
                    { size: 4, value: entry.size },
                    { size: 2, value: entry.nameBytes.length },
                    { size: 2, value: 0 },
                    { size: 2, value: 0 },
                    { size: 2, value: 0 },
                    { size: 2, value: 0 },
                    { size: 4, value: 0 },
