           and caused every card preview to reload from scratch. ────────── */
        function mlpUpdateCardStatsInPlace() {
            try {
                if (!tbody) return;
                var cards = tbody.querySelectorAll('.mlp-pcard[data-id]');
                if (!cards.length) return;
                var projs  = getProjects();
                var idMap  = {};
                for (var pi = 0; pi < projs.length; pi++) { idMap[projs[pi].id] = projs[pi]; }
                var fmtN = function(n) { n = parseInt(n, 10) || 0; return (n >= 1000) ? (Math.round(n / 100) / 10) + 'k' : String(n); };
                for (var ci = 0; ci < cards.length; ci++) {
                    var card = cards[ci];
                    var proj = idMap[card.getAttribute('data-id')];
                    if (!proj) continue;
                    var tk = getShareToken(proj);
                    if (!tk) continue;
                    var viewsVal = window._mlpViewCounts[tk];
                    var rxVal    = window._mlpReactions && window._mlpReactions[tk];
                    var viewsEl  = card.querySelector('.mlp-pcard-stat-views');
                    var likesEl  = card.querySelector('.mlp-pcard-stat-likes');
                    if (viewsEl && typeof viewsVal === 'number') viewsEl.innerHTML = '&#128065; ' + fmtN(viewsVal);
                    if (likesEl && rxVal) likesEl.innerHTML = '&#10084;&#65039; ' + fmtN(parseInt(rxVal.likes, 10) || 0);
                }
            } catch(e) {}
        }
        function fetchAllViewCounts() {
            try {
                var projs = getProjects();
                var tokens = [];
                for (var i = 0; i < projs.length; i++) {
                    var tk = getShareToken(projs[i]);
                    if (tk) tokens.push(tk);
                }
                if (!tokens.length) return;
                var fd = new FormData();
                fd.append('action', 'mlp_get_project_views');
                fd.append('tokens', JSON.stringify(tokens));
                fetch(MLP_AJAX_URL, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r){ return r.json(); })
                    .then(function(j) {
                        if (!j || !j.success || !j.data || !j.data.views) return;
                        var v = j.data.views;
                        for (var k in v) { if (Object.prototype.hasOwnProperty.call(v, k)) {
                            window._mlpViewCounts[k] = parseInt(v[k], 10) || 0;
                        }}
                        try { mlpUpdateCardStatsInPlace(); } catch(e) {}
                        try { if (typeof window._mlpStatsPanelRefresh === 'function') window._mlpStatsPanelRefresh(); } catch(e) {}
                        try { if (typeof mlpLoadMyPublishedProjects === 'function') mlpRefreshMyPublishedCards(); } catch(e) {}
                    })
                    .catch(function(){});
                var fdRx = new FormData();
                fdRx.append('action', 'mlp_get_share_reactions');
