                                viewer_liked: !!rx[k].viewer_liked,
                                viewer_made:  !!rx[k].viewer_made
                            };
                        }}
                        try { mlpUpdateCardStatsInPlace(); } catch(e) {}
                    })
                    .catch(function(){});
            } catch(e) {}
        }
        fetchAllViewCounts();
