        (function setupLiveNotifications() {
            var BASELINE_LS = 'mlp_notif_baselines_v1';
            var LIST_LS     = 'mlp_notif_list_v1';
            var POLL_MS     = 25000;   // 25s — keeps it "live" without hammering
            var MAX_ITEMS   = 80;      // hard cap on stored notifications
            var btn       = document.getElementById('mlp-notif-btn');
            var badge     = document.getElementById('mlp-notif-badge');
            var dropdown  = document.getElementById('mlp-notif-dropdown');
            var listEl    = document.getElementById('mlp-notif-list');
            var markBtn   = document.getElementById('mlp-notif-mark-read');
            var clearBtn  = document.getElementById('mlp-notif-clear');
            var wrapEl    = document.getElementById('mlp-notif-wrap');
            if (!btn || !dropdown || !listEl) return;
            function readJSON(key, fallback) {
                try {
                    var raw = localStorage.getItem(key);
                    if (!raw) return fallback;
                    var v = JSON.parse(raw);
                    return v == null ? fallback : v;
                } catch(e) { return fallback; }
            }
            function writeJSON(key, value) {
                try { localStorage.setItem(key, JSON.stringify(value)); } catch(e) {}
            }
            var baselines = readJSON(BASELINE_LS, {}); // { token: { views, likes, made, name } }
            var notifs    = readJSON(LIST_LS, []);     // [{ id, type, token, name, delta, total, ts, read }]
            function persist() {
                writeJSON(BASELINE_LS, baselines);
                if (notifs.length > MAX_ITEMS) notifs = notifs.slice(0, MAX_ITEMS);
                writeJSON(LIST_LS, notifs);
            }
            function escapeHtml(s) {
                return String(s == null ? '' : s)
                    .replace(/&/g, '&amp;').replace(/</g, '&lt;')
                    .replace(/>/g, '&gt;').replace(/"/g, '&quot;')
                    .replace(/'/g, '&#39;');
            }
            function relativeTime(ts) {
                var diff = Math.max(0, Date.now() - ts);
                var s = Math.floor(diff / 1000);
                if (s < 45)            return 'just now';
                if (s < 90)            return '1 min ago';
                var m = Math.floor(s / 60);
                if (m < 60)            return m + ' min ago';
                var h = Math.floor(m / 60);
                if (h < 24)            return h + (h === 1 ? ' hr ago' : ' hrs ago');
                var d = Math.floor(h / 24);
                if (d < 7)             return d + (d === 1 ? ' day ago' : ' days ago');
                try { return new Date(ts).toLocaleDateString(); } catch(e) { return ''; }
            }
            function unreadCount() {
                var n = 0;
                for (var i = 0; i < notifs.length; i++) if (!notifs[i].read) n++;
                return n;
            }
            function renderBadge() {
                var n = unreadCount();
                if (n <= 0) {
                    badge.style.display = 'none';
                    badge.textContent = '0';
                } else {
                    badge.style.display = 'inline-block';
                    badge.textContent = n > 99 ? '99+' : String(n);
                }
            }
            function iconFor(type) {
                if (type === 'like')    return '<span class="mlp-notif-icon mlp-notif-icon-like">👍</span>';
                if (type === 'dislike') return '<span class="mlp-notif-icon mlp-notif-icon-dislike">👎</span>';
                return '<span class="mlp-notif-icon mlp-notif-icon-view">👁</span>';
            }
            function textFor(n) {
                var name = '<strong>' + escapeHtml(n.name || 'Untitled') + '</strong>';
                var delta = n.delta > 1 ? (n.delta + ' new ') : 'a new ';
                if (n.type === 'view') {
                    var unit = n.delta > 1 ? 'views' : 'view';
                    return 'Someone loaded ' + name + ' — ' + delta + unit
                         + ' (total ' + n.total + ').';
                }
                if (n.type === 'like') {
                    var unitL = n.delta > 1 ? 'likes' : 'like';
                    return name + ' got ' + delta + unitL + ' (total ' + n.total + ').';
                }
                if (n.type === 'dislike') {
                    var unitD = n.delta > 1 ? 'dislikes' : 'dislike';
                    return name + ' got ' + delta + unitD + ' (total ' + n.total + ').';
                }
                return '';
            }
            function renderList() {
                if (!notifs.length) {
                    listEl.innerHTML = '<div class="mlp-notif-empty">You\'re all caught up. Views, likes, and dislikes on your shared projects will show up here.</div>';
                    return;
                }
                var html = '';
                for (var i = 0; i < notifs.length; i++) {
                    var n = notifs[i];
                    html +=
                        '<div class="mlp-notif-item' + (n.read ? '' : ' mlp-notif-unread') + '" role="listitem" data-notif-id="' + escapeHtml(n.id) + '">' +
                            iconFor(n.type) +
                            '<div class="mlp-notif-body">' +
                                '<div class="mlp-notif-text">' + textFor(n) + '</div>' +
