            function diffAndEmit() {
                var nameMap = getTokenNameMap();
                var anyChange = false;
                var v  = window._mlpViewCounts || {};
                var rx = window._mlpReactions  || {};
                var seen = {};
                var k;
                for (k in v)  if (Object.prototype.hasOwnProperty.call(v,  k)) seen[k] = 1;
                for (k in rx) if (Object.prototype.hasOwnProperty.call(rx, k)) seen[k] = 1;
                for (var tk in seen) {
                    if (!Object.prototype.hasOwnProperty.call(seen, tk)) continue;
                    if (!Object.prototype.hasOwnProperty.call(nameMap, tk)) continue;
                    var name    = nameMap[tk];
                    var views   = parseInt(v[tk], 10) || 0;
                    var likes   = (rx[tk] && parseInt(rx[tk].likes, 10)) || 0;
                    var made    = (rx[tk] && parseInt(rx[tk].made,  10)) || 0;
                    var prev    = baselines[tk];
                    if (!prev) {
                        baselines[tk] = { views: views, likes: likes, made: made, name: name };
                        anyChange = true;
