                    }
                    var dV = views - (prev.views || 0);
                    var dL = likes - (prev.likes || 0);
                    var dD = made  - (prev.made  || 0);
                    if (dV > 0) { pushNotif('view',    tk, name, dV, views); anyChange = true; }
                    if (dL > 0) { pushNotif('like',    tk, name, dL, likes); anyChange = true; }
                    if (dD > 0) { pushNotif('dislike', tk, name, dD, made);  anyChange = true; }
                    baselines[tk] = {
                        views: Math.max(views, prev.views || 0),
