                            shared.sourceShareToken = shared._sourceShareToken;
                            try { delete shared._sourceShareToken; } catch(e) { shared._sourceShareToken = undefined; }
                        }
                        shared.id           = generateId();
                        shared.importedAt   = new Date().toISOString();
                        shared.importedFrom = shared.sharedBy || 'another user';
                        shared.activity     = [];
