                        try { return JSON.parse(decodeURIComponent(escape(atob(b64)))); } catch(e2) {}
                    }
                    return null;
                }
                function fetchTokenShare(token) {
                    if (!window.fetch || !MLP_AJAX_URL) {
                        showToast('Share Link Unavailable', 'This share link could not be loaded. Please ask the sender to create a new link.', 'danger');
                        return;
                    }
                    var url = MLP_AJAX_URL + '?action=mlp_get_shared_project&token=' + encodeURIComponent(token);
                    fetch(url, { credentials: 'same-origin' })
                        .then(function(res) { return res.json(); })
                        .then(function(resp) {
                            if (!resp || !resp.success || !resp.data || !resp.data.payload) {
                                showToast('Share Link Unavailable', 'This share link could not be found. Please ask the sender to copy the link again.', 'danger');
                                return;
                            }
                            try {
                                var sharedObj = JSON.parse(resp.data.payload);
                                sharedObj._sourceShareToken = token;
                                window._mlpReactions = window._mlpReactions || {};
                                window._mlpReactions[token] = {
                                    likes:        parseInt(resp.data.likes, 10) || 0,
                                    made:         parseInt(resp.data.made,  10) || 0,
                                    viewer_liked: !!resp.data.viewer_liked,
                                    viewer_made:  !!resp.data.viewer_made
                                };
                                importSharedProject(sharedObj);
                            } catch(e) {
                                showToast('Invalid Share Link', 'This project link is damaged. Please ask the sender to copy it again.', 'danger');
                            }
                        })
                        .catch(function() {
                            showToast('Share Link Unavailable', 'Could not load this shared project. Please try again.', 'danger');
                        });
                }
                var raw = '';
                try { raw = sessionStorage.getItem('mlp_pending_share') || ''; } catch(e) {}
                if (!raw) {
                    var h = window.location.hash || '';
                    if (h.indexOf('#mlpsh_') === 0 || h.indexOf('#mlpsht_') === 0) raw = h.slice(1);
                    if (!raw) {
                        var params = new URLSearchParams(window.location.search || '');
                        var token = params.get('mlpsht');
                        var inlineShare = params.get('mlpsh');
                        if (token) raw = 'mlpsht_' + token;
                        else if (inlineShare) raw = 'mlpsh_' + inlineShare;
                    }
                }
                if (!raw || raw === 'mlpsh_err') return;
                if (raw.indexOf('mlpsht_') === 0) {
                    fetchTokenShare(raw.slice('mlpsht_'.length));
                    return;
                }
                var b64 = (raw.indexOf('mlpsh_') === 0) ? raw.slice('mlpsh_'.length) : raw;
                if (!b64) return;
                var shared = decodeInlineShare(b64);
                if (shared && shared.id) {
                    importSharedProject(shared);
                } else {
                    showToast('Invalid Share Link', 'This project link is incomplete or damaged. Please ask the sender to copy it again.', 'danger');
                }
            } catch(e) {}
        })();
        /* ── Notify about shared projects received ──────────────────── */
        setTimeout(function() {
            var count = window._mlpSharedProjectsCount;
            if (count && count > 0) {
                window._mlpSharedProjectsCount = 0;
                showToast(
                    '📬 ' + count + ' Project' + (count > 1 ? 's' : '') + ' Shared With You',
                    count > 1
                        ? count + ' projects were added to your list by another user.'
                        : 'A project was added to your list by another user.',
                    'success'
                );
                render(); // re-render to show the newly merged projects
            }
        }, 600);
        /* ── Welcome banner wiring ───────────────────────────────────────── */
        (function() {
            var wBanner    = document.getElementById('mlp-welcome-banner');
            var wDismiss   = document.getElementById('mlp-welcome-dismiss');
            var wCreateBtn = document.getElementById('mlp-welcome-create-btn');
            var newBtn     = document.getElementById('mlp-proj-new-btn');
            function dismissWelcome() {
                try { localStorage.setItem('mlp_welcome_dismissed', '1'); } catch(e) {}
                if (wBanner) wBanner.style.display = 'none';
            }
            if (wDismiss) {
                wDismiss.addEventListener('click', dismissWelcome);
            }
            if (wCreateBtn && newBtn) {
                wCreateBtn.addEventListener('click', function() {
                    dismissWelcome();
                    newBtn.click();
                });
            }
        })();
        /* ── Public API ─────────────────────────────────────────────── */
        window.mlpProjectsOpen = function () {
            overlay.classList.remove('mlp-proj-hidden');
            render();
        };
        window.mlpDeleteCurrentProject = function () {
            var id = window.mlpCurrentProjectId;
            if (!id) return;
            deleteProjectById(id);
            window.mlpCurrentProjectId = null;
            try { localStorage.removeItem(LAST_ID_KEY); } catch(e) {}
            try { localStorage.removeItem(TABS_KEY); } catch(e) {}
            if (typeof window.mlpResetToDefault === 'function') { window.mlpResetToDefault(); }
            render();
        };
        window.mlpSyncTabsToProject = function () {
            flushTabsToProject(window.mlpCurrentProjectId || null);
        };
    }
    /* ── Admin-delete sync ────────────────────────────────────────────── */
    /* Checks if any public projects were admin-deleted. Runs on page load */
    /* and then every 45 seconds to detect bans without requiring a reload.*/
    function checkAdminDeletedProjects() {
        if (!MLP_AJAX_URL || !window.fetch) return;
        try {
            var projects = getProjects();
            var tokens = [];
            projects.forEach(function(p) {
                if (p.visibility === 'public' && p.shareToken) tokens.push(p.shareToken);
                if (p.visibility === 'public' && !p.shareToken && p.shareUrl) {
                    try {
                        var u = new URL(p.shareUrl);
                        var t = u.searchParams.get('mlpsht') || '';
                        if (!t && p.shareUrl.indexOf('#mlpsht_') !== -1) {
                            t = decodeURIComponent(p.shareUrl.split('#mlpsht_')[1] || '');
                        }
                        if (t) tokens.push(t);
                    } catch(e) {}
                }
                if (p.adminDeleted && p.adminBannedToken) tokens.push(p.adminBannedToken);
            });
            if (!tokens.length) return;
            var body = new URLSearchParams();
            body.set('action', 'mlp_check_project_status');
            body.set('tokens', JSON.stringify(tokens));
            fetch(MLP_AJAX_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8' },
                body: body.toString()
            })
            .then(function(r) { return r.json(); })
            .then(function(resp) {
                if (!resp || !resp.success || !resp.data) return;
                var deletedTokens = resp.data.deleted || [];
                var activeData    = resp.data.active   || {};
                var changed   = false;
                var newlyBanned = false;
                var allProjects = getProjects();
                allProjects.forEach(function(p) {
                    var pToken = p.shareToken || p.adminBannedToken || '';
                    if (!pToken && p.shareUrl) {
                        try {
                            var u = new URL(p.shareUrl);
                            pToken = u.searchParams.get('mlpsht') || '';
                            if (!pToken && p.shareUrl.indexOf('#mlpsht_') !== -1) {
                                pToken = decodeURIComponent(p.shareUrl.split('#mlpsht_')[1] || '');
                            }
                        } catch(e) {}
                    }
                    if (!pToken) return;
                    var isNowBanned = deletedTokens.indexOf(pToken) !== -1;
                    if (isNowBanned && !p.adminDeleted) {
                        updateProjectById(p.id, {
                            visibility:          'private',
                            shareUrl:            null,
                            shareToken:          null,
                            shareContentHash:    null,
                            adminDeleted:        true,
                            adminBannedToken:    pToken,
                            adminCooldownUntil:  null
                        });
                        changed     = true;
                        newlyBanned = true;
                    } else if (!isNowBanned && p.adminDeleted && p.adminBannedToken) {
                        // Was banned but admin has now unbanned it — restore to public
                        var info    = activeData[pToken] || {};
                        var shareUrl = info.share_url || buildFinalUrl(pToken, null);
                        updateProjectById(p.id, {
                            visibility:       'public',
                            shareToken:       pToken,
                            shareUrl:         shareUrl,
                            adminDeleted:     false,
                            adminBannedToken: null,
                            adminCooldownUntil: null
                        });
                        changed = true;
                    }
                });

                if (changed) {
                    try { render(); } catch(e) {}
                    mlpSyncDeleteAccountBtn();
                    try { mlpSyncBanUI(); } catch(e) {}
                    if (newlyBanned) {
                        showToast(
                            'Project Removed',
                            'One or more of your shared projects was removed by an administrator and set back to private.',
                            'danger'
                        );
                    }
                }
            })
            .catch(function() {}); // silent fail — not critical
        } catch(e) {}
    }

    // Run on load, then every 5 min. Pause when tab hidden (Page Visibility API).
    checkAdminDeletedProjects();
    var _cadpTimer = setInterval(checkAdminDeletedProjects, 300000);
    document.addEventListener('visibilitychange', function() {
        if (document.hidden) {
            clearInterval(_cadpTimer);
        } else {
            checkAdminDeletedProjects();
            _cadpTimer = setInterval(checkAdminDeletedProjects, 300000);
        }
    });

    /* ── Boot ─────────────────────────────────────────────────────── */
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

    /* ── Runtime style overrides (injected last to guarantee win) ── */
    (function() {
        var s = document.createElement('style');
        s.id = 'mlp-compact-rows';
        s.textContent = [
            '#mlp-projects-overlay .mlp-storage-badge-local{display:none!important}',
            '#mlp-projects-overlay .mlp-table td{padding-top:5px!important;padding-bottom:5px!important}',
            '#mlp-projects-overlay .mlp-table .mlp-td-name{padding-top:5px!important;padding-bottom:5px!important}',
            '#mlp-projects-overlay .mlp-table .mlp-td-pin{padding-top:5px!important;padding-bottom:5px!important}',
            '#mlp-projects-overlay .mlp-table .mlp-td-star{padding-top:5px!important;padding-bottom:5px!important}',
            '#mlp-projects-overlay .mlp-table .mlp-td-act{padding-top:5px!important;padding-bottom:5px!important}',
            '#mlp-projects-overlay .mlp-row-icon{width:26px!important;height:26px!important}',
            '#mlp-projects-overlay .mlp-row-btn-go{display:none!important}',
            '#mlp-projects-overlay .mlp-row-btn-dots{width:32px!important;height:32px!important;padding:0!important;display:inline-flex!important;align-items:center!important;justify-content:center!important;border-radius:8px!important;background:transparent!important;border:1px solid transparent!important;color:var(--mlp-text-muted)!important;cursor:pointer!important;transition:background 0.15s,border-color 0.15s!important}',
            '#mlp-projects-overlay .mlp-row-btn-dots:hover{background:#f1f5f9!important;border-color:#cbd5e1!important;color:var(--mlp-text-primary)!important}',
            '#mlp-projects-overlay .mlp-row-btn-dots svg{pointer-events:none!important}',
            /* ── Stat pills (codepen dark pill style) ── */
            '#mlp-projects-overlay .mlp-stat-pills-row{display:inline-flex!important;align-items:center!important;gap:6px!important;margin-top:6px!important;flex-wrap:wrap!important}',
            '#mlp-projects-overlay .mlp-stat-pill{display:inline-flex!important;align-items:center!important;gap:5px!important;padding:3px 10px!important;background:#2d2d2d!important;color:#fff!important;border:none!important;border-radius:999px!important;font-size:12px!important;font-weight:600!important;line-height:1.4!important;letter-spacing:0.01em!important;cursor:default!important;margin:0!important}',
            '#mlp-projects-overlay .mlp-stat-pill .mlp-sp-icon{font-size:13px!important;line-height:1!important}',
            '#mlp-projects-overlay .mlp-stat-pill .mlp-vc-num,#mlp-projects-overlay .mlp-stat-pill .mlp-rb-num{color:#fff!important;font-weight:700!important}',
        ].join('');
        document.head.appendChild(s);
    })();

})();

ENDJS;

        return str_replace(
            [ 'MLP_PROJECTS_LS_KEY_PLACEHOLDER', 'MLP_AJAX_URL_PLACEHOLDER2', 'MLP_AJAX_URL_PLACEHOLDER', 'MLP_SHARE_NONCE_PLACEHOLDER' ],
            [ $ls_key, $ajax_url, $ajax_url, $share_nonce ],
            $js
        );
    }

    // =========================================================================
    // STANDALONE HTML PREVIEW — iframe src for CodePen-style embeds
    // =========================================================================

    /**
     * Runs at `init` priority 1 — before WordPress loads the theme.
     * If the request has ?mlp_html_preview=TOKEN, renders the project's
     * HTML, CSS, and JS as a fully self-contained standalone page.
     * This URL is used as the src for CodePen-style <iframe> embeds.
     */
    public static function mlp_handle_preview_endpoint() {
        $token = isset( $_GET['mlp_html_preview'] ) ? sanitize_key( wp_unslash( $_GET['mlp_html_preview'] ) ) : '';
        if ( '' === $token ) return;

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || empty( $record['payload'] ) || ! empty( $record['admin_deleted'] ) ) {
            status_header( 404 );
            exit( 'Not found.' );
        }

        $payload = json_decode( $record['payload'], true );
        $html    = $payload['html'] ?? '';
        $css     = $payload['css']  ?? '';
        $js      = $payload['js']   ?? '';

        // ── Python projects — render code viewer instead of blank HTML/CSS/JS ─
        if ( ( $payload['type'] ?? '' ) === 'python' ) {
            $python_code = $payload['python'] ?? '';
            $proj_name   = htmlspecialchars( $payload['name'] ?? 'Python Project', ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            $escaped_code = htmlspecialchars( $python_code, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            nocache_headers();
            header( 'Content-Type: text/html; charset=utf-8' );
            echo '<!DOCTYPE html><html lang="en"><head>'
               . '<meta charset="utf-8">'
               . '<meta name="viewport" content="width=device-width,initial-scale=1">'
               . '<style>'
               . '*{box-sizing:border-box;margin:0;padding:0}'
               . 'body{background:#0d1117;color:#c9d1d9;font-family:\'JetBrains Mono\',\'Fira Code\',\'Consolas\',monospace;font-size:13px;line-height:1.7;padding:16px;min-height:100vh;}'
               . '.py-header{display:flex;align-items:center;gap:8px;margin-bottom:14px;}'
               . '.py-badge{background:#3b82f6;color:#fff;font-size:11px;font-weight:700;border-radius:4px;padding:2px 8px;letter-spacing:.04em;}'
               . '.py-filename{color:#8b949e;font-size:11px;}'
               . 'pre{color:#79c0ff;white-space:pre-wrap;word-break:break-word;margin:0;}'
               . '.py-empty{color:#6e7681;font-style:italic;}'
               . '</style>'
               . '</head><body>'
               . '<div class="py-header"><span class="py-badge">Python</span><span class="py-filename">' . $proj_name . '.py</span></div>'
               . '<pre>' . ( $escaped_code !== '' ? $escaped_code : '<span class="py-empty"># (empty project)</span>' ) . '</pre>'
               . '</body></html>';
            exit;
        }

        // ── Ruby projects — render code viewer instead of blank HTML/CSS/JS ─
        if ( ( $payload['type'] ?? '' ) === 'ruby' ) {
            $ruby_code    = $payload['ruby'] ?? '';
            $proj_name    = htmlspecialchars( $payload['name'] ?? 'Ruby Project', ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            $escaped_code = htmlspecialchars( $ruby_code, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            nocache_headers();
            header( 'Content-Type: text/html; charset=utf-8' );
            echo '<!DOCTYPE html><html lang="en"><head>'
               . '<meta charset="utf-8">'
               . '<meta name="viewport" content="width=device-width,initial-scale=1">'
               . '<style>'
               . '*{box-sizing:border-box;margin:0;padding:0}'
               . 'body{background:#0d1117;color:#c9d1d9;font-family:\'JetBrains Mono\',\'Fira Code\',\'Consolas\',monospace;font-size:13px;line-height:1.7;padding:16px;min-height:100vh;}'
               . '.rb-header{display:flex;align-items:center;gap:8px;margin-bottom:14px;}'
               . '.rb-badge{background:#dc2626;color:#fff;font-size:11px;font-weight:700;border-radius:4px;padding:2px 8px;letter-spacing:.04em;}'
               . '.rb-filename{color:#8b949e;font-size:11px;}'
               . 'pre{color:#79c0ff;white-space:pre-wrap;word-break:break-word;margin:0;}'
               . '.rb-empty{color:#6e7681;font-style:italic;}'
               . '</style>'
               . '</head><body>'
               . '<div class="rb-header"><span class="rb-badge">💎 Ruby</span><span class="rb-filename">' . $proj_name . '.ruby</span></div>'
               . '<pre>' . ( $escaped_code !== '' ? $escaped_code : '<span class="rb-empty"># (empty project)</span>' ) . '</pre>'
               . '</body></html>';
            exit;
        }

        // ── C# projects — render code viewer instead of blank HTML/CSS/JS ──
        if ( ( $payload['type'] ?? '' ) === 'csharp' ) {
            $csharp_code  = $payload['csharp'] ?? '';
            $proj_name    = htmlspecialchars( $payload['name'] ?? 'C# Project', ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            $escaped_code = htmlspecialchars( $csharp_code, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            nocache_headers();
            header( 'Content-Type: text/html; charset=utf-8' );
            echo '<!DOCTYPE html><html lang="en"><head>'
               . '<meta charset="utf-8">'
               . '<meta name="viewport" content="width=device-width,initial-scale=1">'
               . '<style>'
               . '*{box-sizing:border-box;margin:0;padding:0}'
               . 'body{background:#0e0514;color:#ddd6fe;font-family:\'JetBrains Mono\',\'Fira Code\',\'Consolas\',monospace;font-size:13px;line-height:1.7;padding:16px;min-height:100vh;}'
               . '.cs-header{display:flex;align-items:center;gap:8px;margin-bottom:14px;}'
               . '.cs-badge{background:#7c3aed;color:#fff;font-size:11px;font-weight:700;border-radius:4px;padding:2px 8px;letter-spacing:.04em;}'
               . '.cs-filename{color:#9f7aea;font-size:11px;}'
               . 'pre{color:#c4b5fd;white-space:pre-wrap;word-break:break-word;margin:0;}'
               . '.cs-empty{color:#6e7681;font-style:italic;}'
               . '</style>'
               . '</head><body>'
               . '<div class="cs-header"><span class="cs-badge">C# (.NET)</span><span class="cs-filename">' . $proj_name . '.cs</span></div>'
               . '<pre>' . ( $escaped_code !== '' ? $escaped_code : '<span class="cs-empty">// (empty project)</span>' ) . '</pre>'
               . '</body></html>';
            exit;
        }

        // ── Rust projects — render code viewer instead of blank HTML/CSS/JS ──
        if ( ( $payload['type'] ?? '' ) === 'rust' ) {
            $rust_code    = $payload['rust'] ?? '';
            $proj_name    = htmlspecialchars( $payload['name'] ?? 'Rust Project', ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            $escaped_code = htmlspecialchars( $rust_code, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            nocache_headers();
            header( 'Content-Type: text/html; charset=utf-8' );
            echo '<!DOCTYPE html><html lang="en"><head>'
               . '<meta charset="utf-8">'
               . '<meta name="viewport" content="width=device-width,initial-scale=1">'
               . '<style>'
               . '*{box-sizing:border-box;margin:0;padding:0}'
               . 'body{background:#0f0a05;color:#f0e8e0;font-family:\'JetBrains Mono\',\'Fira Code\',\'Consolas\',monospace;font-size:13px;line-height:1.7;padding:16px;min-height:100vh;}'
               . '.rs-header{display:flex;align-items:center;gap:8px;margin-bottom:14px;}'
               . '.rs-badge{background:#e8632a;color:#fff;font-size:11px;font-weight:700;border-radius:4px;padding:2px 8px;letter-spacing:.04em;}'
               . '.rs-filename{color:#8a6e58;font-size:11px;}'
               . 'pre{color:#fbbf24;white-space:pre-wrap;word-break:break-word;margin:0;}'
               . '.rs-empty{color:#6e7681;font-style:italic;}'
               . '</style>'
               . '</head><body>'
               . '<div class="rs-header"><span class="rs-badge">🦀 Rust</span><span class="rs-filename">' . $proj_name . '.rs</span></div>'
               . '<pre>' . ( $escaped_code !== '' ? $escaped_code : '<span class="rs-empty">// (empty project)</span>' ) . '</pre>'
               . '</body></html>';
            exit;
        }

        // ── PHP projects — split view: code left, output/preview right ───────
        if ( ( $payload['type'] ?? '' ) === 'php' ) {
            $php_code     = $payload['php']            ?? '';
            $php_output   = $payload['phpOutput']      ?? '';
            $php_is_html  = ! empty( $payload['phpOutputIsHtml'] );
            $php_out_at   = $payload['phpOutputAt']    ?? '';
            $proj_name    = htmlspecialchars( $payload['name'] ?? 'PHP Project', ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            $esc_code     = htmlspecialchars( $php_code,   ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );
            $esc_output   = htmlspecialchars( $php_output, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8' );

            $out_at_str = '';
            if ( $php_out_at ) {
                $ts = strtotime( $php_out_at );
                if ( $ts ) $out_at_str = ' · ' . date( 'M j, Y H:i', $ts );
            }

            // Build the right-panel content
            if ( $php_output === '' ) {
                $right_panel = '<div class="php-no-output">'
                    . '<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#555" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>'
                    . '<p>No output yet</p>'
                    . '<span>The author has not run this project yet.</span>'
                    . '</div>';
            } elseif ( $php_is_html ) {
                $encoded_html = base64_encode( $php_output );
                $right_panel = '<div class="php-preview-bar">'
                    . '<span class="php-preview-label">Preview</span>'
                    . '<span class="php-out-ts">' . htmlspecialchars( $out_at_str, ENT_QUOTES, 'UTF-8' ) . '</span>'
                    . '</div>'
                    . '<iframe id="php-preview-frame" class="php-preview-frame" sandbox="allow-scripts" title="PHP Output Preview"></iframe>'
                    . '<script>document.getElementById("php-preview-frame").srcdoc=atob(' . json_encode( $encoded_html ) . ');</script>';
            } else {
                $right_panel = '<div class="php-preview-bar">'
                    . '<span class="php-preview-label">Output</span>'
                    . '<span class="php-out-ts">' . htmlspecialchars( $out_at_str, ENT_QUOTES, 'UTF-8' ) . '</span>'
                    . '</div>'
                    . '<pre class="php-output-pre">' . $esc_output . '</pre>';
            }

            nocache_headers();
            header( 'Content-Type: text/html; charset=utf-8' );
            echo '<!DOCTYPE html>
<html lang="en">
<head>
