.php-code-body::-webkit-scrollbar{width:5px}
.php-code-body::-webkit-scrollbar-thumb{background:#2a2a2a;border-radius:3px}
pre.php-source{color:#c4b5fd;white-space:pre-wrap;word-break:break-word;font-size:12.5px;line-height:1.75}
/* Right — output / preview */
.php-output-pane{width:45%;min-width:260px;max-width:65%;display:flex;flex-direction:column;overflow:hidden}
.php-preview-bar{display:flex;align-items:center;gap:8px;padding:0 14px;height:38px;background:#161616;border-bottom:1px solid #2a2a2a;flex-shrink:0}
.php-preview-label{font-size:10px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:.07em}
.php-out-ts{font-size:10px;color:#555;margin-left:auto}
.php-preview-frame{flex:1;width:100%;border:none;background:#fff}
pre.php-output-pre{flex:1;padding:14px 16px;overflow:auto;color:#d4d4d4;white-space:pre-wrap;word-break:break-word;font-size:12.5px;line-height:1.75;background:#0a0a0a}
.php-no-output{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;background:#0a0a0a;color:#555;padding:24px;text-align:center}
.php-no-output p{font-size:13px;font-weight:600;color:#444}
.php-no-output span{font-size:11px;color:#3a3a3a}
@media(max-width:640px){
    .php-wrap{flex-direction:column}
    .php-output-pane{width:100%;max-width:100%;min-width:0;border-top:1px solid #2a2a2a;height:45vh}
    .php-code-pane{height:55vh}
}
</style>
</head>
<body>
<div class="php-wrap">
  <div class="php-code-pane">
    <div class="php-code-header">
      <span class="php-badge">PHP</span>
      <span class="php-filename">' . $proj_name . '.php</span>
    </div>
    <div class="php-code-body">
      <pre class="php-source">' . ( $esc_code !== '' ? $esc_code : '<span style="color:#555;font-style:italic">&lt;?php  // (empty project)</span>' ) . '</pre>
    </div>
  </div>
  <div class="php-output-pane">
    ' . $right_panel . '
  </div>
</div>
</body>
</html>';
            exit;
        }

        // ── Multi-tab support ─────────────────────────────────────────────────
        // When the project was saved with multiple tabs, content lives in
        // allTabs (preferred) keyed by tab ID.  Fall back to savedTabs for
        // projects that were published with only saved (💾) tabs and no active
        // editing session — in that case allTabs is null but savedTabs holds
        // the full content.  Mirror the same extraction logic used by the JS
        // buildProjectHtml() function so the preview renders correctly for both
        // single-file and multi-tab projects.
        $all_tabs = ( isset( $payload['allTabs'] ) && is_array( $payload['allTabs'] ) && count( $payload['allTabs'] ) > 0 )
            ? $payload['allTabs']
            : ( ( isset( $payload['savedTabs'] ) && is_array( $payload['savedTabs'] ) )
                ? $payload['savedTabs']
                : [] );

        if ( count( $all_tabs ) === 1 ) {
            // ── Single-tab project ────────────────────────────────────────────
            // The one tab may have any custom name (e.g. "My Project", "Tab 1",
            // "index") that does not match "html"/"css"/"js". Rather than leaving
            // $html/$css/$js empty (which produces a blank Discord embed), pull
            // the content directly from that single tab.
            $sole_tab = reset( $all_tabs );
            if ( is_array( $sole_tab ) ) {
                $tab_html = (string) ( $sole_tab['html'] ?? $sole_tab['content'] ?? '' );
                $tab_css  = (string) ( $sole_tab['css']  ?? '' );
                $tab_js   = (string) ( $sole_tab['js']   ?? '' );
                if ( $tab_html !== '' ) $html = $tab_html;
                if ( $tab_css  !== '' ) $css  = $tab_css;
                if ( $tab_js   !== '' ) $js   = $tab_js;
            }
        } else {
            foreach ( $all_tabs as $tid => $t ) {
                if ( ! is_array( $t ) ) continue;
                $label    = strtolower( (string) ( $t['name'] ?? $t['title'] ?? $tid ) );
                $tab_html = (string) ( $t['html'] ?? $t['content'] ?? '' );
                $tab_css  = (string) ( $t['css']  ?? '' );
                $tab_js   = (string) ( $t['js']   ?? '' );
                if ( $label === 'html' || str_contains( $label, '.html' ) ) {
                    if ( $tab_html !== '' ) $html = $tab_html;
                } elseif ( $label === 'css' || str_contains( $label, '.css' ) ) {
                    if ( $tab_css !== '' || $tab_html !== '' ) $css = $tab_css !== '' ? $tab_css : $tab_html;
                } elseif ( $label === 'js' || $label === 'javascript' || str_contains( $label, '.js' ) ) {
                    if ( $tab_js !== '' || $tab_html !== '' ) $js = $tab_js !== '' ? $tab_js : $tab_html;
                }
            }
            // If no tab matched by label (e.g. all tabs have custom names like
            // "Tab 1", "My Page"), fall back to the first tab's content so the
            // preview is never blank.
            if ( $html === '' ) {
                $first_tab = reset( $all_tabs );
                if ( is_array( $first_tab ) ) {
                    $html = (string) ( $first_tab['html'] ?? $first_tab['content'] ?? '' );
                    if ( $css === '' ) $css = (string) ( $first_tab['css'] ?? '' );
                    if ( $js  === '' ) $js  = (string) ( $first_tab['js']  ?? '' );
                }
            }
        }

        nocache_headers();
        header( 'Content-Type: text/html; charset=utf-8' );

        // If the HTML content is already a full document (contains <html> or <!DOCTYPE>),
        // serve it directly — wrapping it in another shell creates double-nested invalid
        // HTML that breaks rendering (and makes Microlink screenshot a garbled page).
        // We still inject any separate $css and $js into the document if present.
        $html_trimmed = ltrim( $html );
        $is_full_doc  = stripos( $html_trimmed, '<!doctype' ) === 0
                     || stripos( $html_trimmed, '<html' ) === 0;

        if ( $is_full_doc ) {
            $out = $html;
            // Inject extra CSS (if any) before </head>
            if ( $css !== '' ) {
                $inject_css = '<style>' . $css . '</style>';
                if ( stripos( $out, '</head>' ) !== false ) {
                    $out = str_ireplace( '</head>', $inject_css . '</head>', $out );
                } else {
                    $out = $inject_css . $out;
                }
            }
            // Inject extra JS (if any) before </body>
            if ( $js !== '' ) {
                $inject_js = '<script>' . $js . '</script>';
                if ( stripos( $out, '</body>' ) !== false ) {
                    $out = str_ireplace( '</body>', $inject_js . '</body>', $out );
                } else {
                    $out .= $inject_js;
                }
            }
            echo $out;
        } else {
            echo '<!DOCTYPE html><html lang="en"><head>'
               . '<meta charset="utf-8">'
               . '<meta name="viewport" content="width=device-width,initial-scale=1">'
               . '<style>*{box-sizing:border-box}body{margin:0}</style>'
               . '<style>' . $css . '</style>'
               . '</head><body>'
               . $html
               . '<script>' . $js . '</script>'
               . '</body></html>';
        }
        exit;
    }

    // =========================================================================
    // CODEPEN-STYLE EMBED SYSTEM
    // =========================================================================

    /**
     * Registers ?mlp_html_preview and ?mlpsht as recognised WordPress query
     * variables so WordPress canonical-redirect logic does not strip them
     * from the URL before the page or JavaScript can use them.
     */
    public static function mlp_register_query_vars( $vars ) {
        $vars[] = 'mlp_html_preview';
        $vars[] = 'mlpsht';
        $vars[] = 'mlp_og_image';
        return $vars;
    }

    /**
     * Prevents WordPress from issuing a canonical redirect when our custom
     * query vars are present. Safety net on top of registering the vars.
     */
    public static function mlp_prevent_canonical_redirect( $redirect_url ) {
        if ( isset( $_GET['mlp_html_preview'] ) || isset( $_GET['mlpsht'] ) || isset( $_GET['mlp_og_image'] ) ) {
            return false;
        }
        return $redirect_url;
    }

    // =========================================================================
    // DISCORD / SOCIAL LINK PREVIEW — OG meta tags
    // =========================================================================

    /**
     * Known social / link-preview bot user-agent substrings.
     * Checked case-insensitively.
     */
    private static $mlp_bot_agents = [
        'discordbot',          // Discord
        'twitterbot',          // Twitter / X
        'facebookexternalhit', // Facebook / Meta
        'linkedinbot',         // LinkedIn
        'slackbot',            // Slack
        'telegrambot',         // Telegram
        'whatsapp',            // WhatsApp
        'applebot',            // Apple iMessage
        'skypeuripreview',     // Skype
        'redditbot',           // Reddit
        'embedly',             // Embedly
        'rogerbot',            // Moz
        'showyoubot',
        'outbrain',
        'ia_archiver',
        'quora link preview',
        'vkshare',             // VKontakte
        'w3c_validator',
        'googlebot',           // Google (also unfurls links)
        'bingbot',
    ];

    /**
     * Returns true when the current HTTP request appears to come from a
     * link-preview / social bot rather than a real browser.
     */
    private static function mlp_is_bot_request() {
        $ua = strtolower( $_SERVER['HTTP_USER_AGENT'] ?? '' );
        if ( $ua === '' ) return false;
        foreach ( self::$mlp_bot_agents as $needle ) {
            if ( strpos( $ua, $needle ) !== false ) return true;
        }
        return false;
    }

    /**
     * Runs at `init` priority 2 — right after mlp_handle_preview_endpoint.
     *
     * When a social / link-preview bot fetches a project share URL
     * (?mlpsht=TOKEN) this method intercepts the request and returns a
     * tiny standalone HTML page containing only the Open Graph + Twitter Card
     * meta tags, then exits.
     *
     * This approach is reliable regardless of:
     *  - Page-caching plugins (the response is dynamic and exits before they run)
     *  - Themes that don't call wp_head()
     *  - Any SEO plugin overriding OG tags
     *  - SPA/JS-rendered page setups
     */
    /**
     * Decodes the JSON payload stored inside a share record and returns
     * [ 'name' => string, 'author' => string ].
     * The payload is the canonical source of truth for project metadata.
     */
    private static function mlp_record_meta( array $record ) {
        $payload = [];
        if ( ! empty( $record['payload'] ) ) {
            $decoded = json_decode( $record['payload'], true );
            if ( is_array( $decoded ) ) $payload = $decoded;
        }
        return [
            'name'   => trim( $payload['name']     ?? '' ) ?: 'Untitled Project',
            'author' => trim( $payload['sharedBy'] ?? '' ),
        ];
    }

    public static function mlp_serve_og_to_bots() {
        $token = isset( $_GET['mlpsht'] ) ? sanitize_key( wp_unslash( $_GET['mlpsht'] ) ) : '';
        if ( '' === $token ) return;
        // After the JS redirect below fires in a browser it appends _load=1.
        // That second request skips this function so WordPress renders the full
        // interactive page instead of serving OG HTML again (avoiding a loop).
        if ( isset( $_GET['_load'] ) ) return;
        // Serve OG meta-tag HTML to ALL visitors — not just detected bots.
        // This is the only way to guarantee Discord gets embed data even when
        // a caching plugin has already stored a browser-targeted response.

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || ! empty( $record['admin_deleted'] ) ) {
            status_header( 404 );
            exit( 'Not found.' );
        }

        $meta        = self::mlp_record_meta( $record );
        $name        = $meta['name'];
        $author      = $meta['author'];
        $description = $author
            ? 'A live coding project by ' . $author . ' — open and remix it for free.'
            : 'A live coding project — open and remix it for free.';

        $share_url  = home_url( '/?mlpsht=' . $token );
        $img_version = isset( $record['updated'] ) ? (int) $record['updated']
                     : ( isset( $record['created'] ) ? (int) $record['created'] : 0 );
        $image_url  = self::mlp_preview_image_url( $token, $img_version );
        $site_name  = get_bloginfo( 'name' );

        $og_image = $image_url ? '
    <meta property="og:image"        content="' . esc_attr( $image_url ) . '" />
    <meta property="og:image:width"  content="1200" />
    <meta property="og:image:height" content="630" />
    <meta name="twitter:image"       content="' . esc_attr( $image_url ) . '" />' : '';

        // Allow Discord (and other bots) to cache this response so they don't
        // need to re-fetch on every paste. A 1-hour TTL is short enough that
        // project updates are reflected quickly, but long enough that Discord's
        // internal embed cache stays warm.
        // Vary: User-Agent tells any intermediate proxy/CDN to store separate
        // cached responses for bots vs regular browsers, preventing a cached
        // browser-page from being served to the bot on a subsequent request.
        header( 'Content-Type: text/html; charset=utf-8' );
        header( 'Cache-Control: public, max-age=3600' );
        header( 'Vary: User-Agent' );
        header( 'X-Robots-Tag: noindex' );
        echo '<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8" />
    <title>' . esc_html( $name ) . ' — ' . esc_html( $site_name ) . '</title>
    <meta property="og:type"        content="website" />
    <meta property="og:site_name"   content="' . esc_attr( $site_name ) . '" />
    <meta property="og:url"         content="' . esc_attr( $share_url ) . '" />
    <meta property="og:title"       content="' . esc_attr( $name ) . '" />
    <meta property="og:description" content="' . esc_attr( $description ) . '" />' . $og_image . '
    <meta name="twitter:card"        content="summary_large_image" />
    <meta name="twitter:title"       content="' . esc_attr( $name ) . '" />
    <meta name="twitter:description" content="' . esc_attr( $description ) . '" />
</head>
<body>
    <p>Redirecting…</p>
    <script>window.location.replace(' . json_encode( $share_url . '&_load=1' ) . ');</script>
</body>
</html>';
        exit;
    }

    /**
     * Returns the share token from the current request, or empty string.
     */
    private static function mlp_current_share_token() {
        return isset( $_GET['mlpsht'] ) ? sanitize_key( wp_unslash( $_GET['mlpsht'] ) ) : '';
    }

    /**
     * Outputs Open Graph and Twitter Card meta tags when a project share URL
     * (?mlpsht=TOKEN) is loaded. This makes Discord, Slack, Twitter, etc.
     * show a rich link preview card instead of a plain URL.
     * (Fallback for non-bot browsers; primary path is mlp_serve_og_to_bots.)
     */
    public static function mlp_output_og_tags() {
        $token = self::mlp_current_share_token();
        if ( '' === $token ) return;

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || ! empty( $record['admin_deleted'] ) ) return;

        $meta        = self::mlp_record_meta( $record );
        $name        = $meta['name'];
        $author      = $meta['author'];
        $description = $author
            ? 'A live coding project by ' . $author . ' — open and remix it for free.'
            : 'A live coding project — open and remix it for free.';

        $share_url   = esc_url( home_url( '/?mlpsht=' . $token ) );
        $img_version = isset( $record['updated'] ) ? (int) $record['updated']
                     : ( isset( $record['created'] ) ? (int) $record['created'] : 0 );
        $image_url   = self::mlp_preview_image_url( $token, $img_version );
        $site_name   = get_bloginfo( 'name' );

        // Remove any OG tags the theme may have already added.
        remove_action( 'wp_head', 'rel_canonical' );

        echo "\n<!-- MLP Projects: Open Graph / Discord preview -->\n";
        echo '<meta property="og:type"        content="website" />' . "\n";
        echo '<meta property="og:site_name"   content="' . esc_attr( $site_name ) . '" />' . "\n";
        echo '<meta property="og:url"         content="' . $share_url . '" />' . "\n";
        echo '<meta property="og:title"       content="' . esc_attr( $name ) . '" />' . "\n";
        echo '<meta property="og:description" content="' . esc_attr( $description ) . '" />' . "\n";
        if ( $image_url ) {
            echo '<meta property="og:image"        content="' . esc_url( $image_url ) . '" />' . "\n";
            echo '<meta property="og:image:width"  content="1200" />' . "\n";
            echo '<meta property="og:image:height" content="630" />' . "\n";
        }
        // Twitter / X Card
        echo '<meta name="twitter:card"        content="summary_large_image" />' . "\n";
        echo '<meta name="twitter:title"       content="' . esc_attr( $name ) . '" />' . "\n";
        echo '<meta name="twitter:description" content="' . esc_attr( $description ) . '" />' . "\n";
        if ( $image_url ) {
            echo '<meta name="twitter:image" content="' . esc_url( $image_url ) . '" />' . "\n";
        }
        echo "<!-- / MLP Projects OG -->\n\n";
    }

    /**
     * Replaces the page <title> with the project name when a share URL is loaded,
     * so the browser tab and link previews show the project name.
     */
    public static function mlp_filter_og_title( $title ) {
        $token = self::mlp_current_share_token();
        if ( '' === $token ) return $title;

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || ! empty( $record['admin_deleted'] ) ) return $title;

        $meta = self::mlp_record_meta( $record );
        $name = $meta['name'];
        return ( $name && $name !== 'Untitled Project' )
            ? $name . ' — ' . get_bloginfo( 'name' )
            : $title;
    }

    /**
     * Returns a screenshot URL for the given token, suitable for og:image.
     * Uses Microlink (free tier) to capture the standalone preview page,
     * with the result cached in a transient for 90 days.
     *
     * Falls back gracefully to the site's custom logo, then its favicon.
     *
     * @param  string $token  The share token.
     * @return string         Absolute image URL, or empty string if none available.
     */
    public static function mlp_preview_image_url( $token, $version = 0 ) {
        // The OG image is generated on-the-fly by mlp_handle_og_image_endpoint,
        // so the URL is always deterministic — no transient caching needed.
        return self::mlp_resolve_screenshot( '', $token, $version );
    }

    /**
     * Returns the URL to the self-hosted OG image endpoint for this token.
     * The image is generated server-side by mlp_handle_og_image_endpoint()
     * using PHP GD — no external service or Cloudflare interference.
     *
     * @param  string $token  The share token.
     * @return string         Absolute PNG image URL.
     */
    /**
     * Calls the Microlink API (free tier) to capture a screenshot of $url
     * and returns the hosted screenshot URL, or '' on failure.
     */
    private static function mlp_fetch_microlink_screenshot( $url ) {
        $response = wp_remote_get(
            'https://api.microlink.io/?' . http_build_query( [
                'url'        => $url,
                'screenshot' => 'true',
                'meta'       => 'false',
            ] ),
            [ 'timeout' => 15 ]
        );
        if ( is_wp_error( $response ) ) return '';
        $code = wp_remote_retrieve_response_code( $response );
        if ( $code < 200 || $code >= 300 ) return '';
        $body = json_decode( wp_remote_retrieve_body( $response ), true );
        $screenshot_url = $body['data']['screenshot']['url'] ?? '';
        return ( $screenshot_url && filter_var( $screenshot_url, FILTER_VALIDATE_URL ) )
            ? $screenshot_url
            : '';
    }

    /**
     * Fire a non-blocking background request to fetch and cache the Microlink
     * screenshot for $token.  Safe to call multiple times — the handler
     * short-circuits if the transient already exists.
     */
    private static function mlp_trigger_bg_screenshot( $token ) {
        wp_remote_post(
            admin_url( 'admin-ajax.php' ),
            [
                'blocking'    => false,
                'timeout'     => 0.01,
                'httpversion' => '1.1',
                'sslverify'   => false,  // loopback SSL often untrusted; skip verify
                'body'        => [
                    'action' => 'mlp_bg_fetch_screenshot',
                    'token'  => $token,
                    'key'    => substr( wp_hash( 'mlp_bg_' . $token ), 0, 16 ),
                ],
            ]
        );
    }

    public static function mlp_resolve_screenshot( $preview_url, $token, $version = 0 ) {
        // Always return the self-hosted image endpoint.
        // That endpoint handles Microlink + GD fallback on its own.
        // Append _v so Discord sees a new URL on every project update and
        // re-fetches instead of serving its cached (stale) embed image.
        $url = home_url( '/?mlp_og_image=' . rawurlencode( $token ) );
        if ( $version > 0 ) {
            $url .= '&_v=' . (int) $version;
        }
        return $url;
    }

    /**
     * Runs at `init` priority 3.
     * Serves a dynamically-generated 1200×630 PNG card for ?mlp_og_image=TOKEN.
     * Used as the og:image / twitter:image for Discord and social link previews.
     * Requires PHP GD (available on virtually all WordPress hosts).
     */
    public static function mlp_handle_og_image_endpoint() {
        $token = isset( $_GET['mlp_og_image'] ) ? sanitize_key( wp_unslash( $_GET['mlp_og_image'] ) ) : '';
        if ( '' === $token ) return;

        // Buffer all output so any PHP notices/warnings that fire before we
        // send headers never corrupt the PNG image bytes.
        ob_start();

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || ! empty( $record['admin_deleted'] ) ) {
            ob_end_clean();
            status_header( 404 );
            exit;
        }

        // ── Screenshot via Microlink ──────────────────────────────────────────────
        // Redirect to Microlink's embed endpoint which returns the raw screenshot
        // image bytes directly (no JSON wrapper).  Discord follows the 302 and
        // shows the actual rendered project output — identical to CodePen's approach.
        //
        // Fast path: background fetch (fired at save time) already cached the
        // Microlink CDN URL → redirect there instantly (no Microlink round-trip).
        //
        // Cold path: transient not ready yet → redirect to Microlink embed URL.
        // Microlink generates + caches the screenshot on first hit; subsequent
        // Discord refreshes are served from Microlink's CDN instantly.
        //
        // The transient key includes the version so that after a republish the
        // old cached screenshot is never served — the new _v in the og:image URL
        // maps to a brand-new transient that starts empty and gets regenerated.
        $rec_version  = isset( $record['updated'] ) ? (int) $record['updated']
                      : ( isset( $record['created'] ) ? (int) $record['created'] : 0 );
        $transient_key = 'mlp_ogimg_' . $token . ( $rec_version > 0 ? '_' . $rec_version : '' );

        $cached = get_transient( $transient_key );
        if ( $cached && is_string( $cached ) && strlen( $cached ) > 10 ) {
            // Always serve image bytes directly — never a redirect.
            // A 302 to an external CDN URL fails silently when the URL expires,
            // causing Discord to show the broken "Image failed to load" icon.
            if ( $cached[0] === '/' && file_exists( $cached ) ) {
                // New format: local file path saved by ajax_bg_fetch_screenshot.
                ob_end_clean();
                header( 'Content-Type: image/png' );
                header( 'Content-Length: ' . filesize( $cached ) );
                header( 'Cache-Control: public, max-age=86400' );
                readfile( $cached );
                exit;
            } elseif ( strncmp( $cached, 'https://', 8 ) === 0 ) {
                // Legacy format: Microlink CDN URL — proxy the bytes so Discord
                // never has to follow a redirect to an external (potentially
                // expired) URL.
                $img = wp_remote_get( $cached, [ 'timeout' => 8, 'sslverify' => false ] );
                if ( ! is_wp_error( $img ) && wp_remote_retrieve_response_code( $img ) === 200 ) {
                    $ct   = wp_remote_retrieve_header( $img, 'content-type' ) ?: 'image/jpeg';
                    $body = wp_remote_retrieve_body( $img );
                    ob_end_clean();
                    header( 'Content-Type: '   . $ct );
                    header( 'Content-Length: ' . strlen( $body ) );
                    header( 'Cache-Control: public, max-age=86400' );
                    echo $body;
                    exit;
                }
                // CDN URL is stale — clear transient and regenerate via GD below.
                delete_transient( $transient_key );
            }
        }

        // No screenshot cached yet.
        //
        // Attempt a SYNCHRONOUS Microlink screenshot (5 s API + 4 s download).
        // Many WordPress hosts block loopback HTTP, making the old fire-and-forget
        // background-fetch approach silently fail — Microlink never ran and every
        // Discord embed always showed the plain GD text card instead of the real
        // rendered page.  Doing it synchronously here means Discord gets the actual
        // rendered preview on the very FIRST embed, without needing any loopback.
        //
        // Worst-case: Microlink times out (complex page) → fall through to GD card
        // below, Discord shows a text preview, and on the next embed refresh
        // Microlink's cached result will be returned quickly (< 1 s).
        $preview_url = home_url( '/?mlp_html_preview=' . rawurlencode( $token )
            . ( $rec_version > 0 ? '&_v=' . $rec_version : '' ) );

        $microlink_cdn = '';
        $mlink_resp    = wp_remote_get(
            'https://api.microlink.io/?' . http_build_query( [
                'url'        => $preview_url,
                'screenshot' => 'true',
                'meta'       => 'false',
            ] ),
            [ 'timeout' => 5, 'sslverify' => false ]
        );
        if ( ! is_wp_error( $mlink_resp ) ) {
            $mlink_code = wp_remote_retrieve_response_code( $mlink_resp );
            if ( $mlink_code >= 200 && $mlink_code < 300 ) {
                $mlink_body    = json_decode( wp_remote_retrieve_body( $mlink_resp ), true );
                $microlink_cdn = $mlink_body['data']['screenshot']['url'] ?? '';
                if ( ! filter_var( $microlink_cdn, FILTER_VALIDATE_URL ) ) {
                    $microlink_cdn = '';
                }
            }
        }

        if ( $microlink_cdn !== '' ) {
            // Download the bytes from Microlink's CDN so we can serve them
            // directly (no redirect, no CDN-URL expiry issues for Discord).
            $img_resp  = wp_remote_get( $microlink_cdn, [ 'timeout' => 4, 'sslverify' => false ] );
            $img_bytes = ( ! is_wp_error( $img_resp ) && wp_remote_retrieve_response_code( $img_resp ) === 200 )
                ? wp_remote_retrieve_body( $img_resp )
                : '';

            if ( strlen( $img_bytes ) > 500 ) {
                // Cache locally so future hits are served from disk (no Microlink round-trip).
                $upload    = wp_upload_dir();
                $cache_dir = trailingslashit( $upload['basedir'] ) . 'mlp-og-cache';
                wp_mkdir_p( $cache_dir );
                $file_path = $cache_dir . '/' . $transient_key . '.png';
                // phpcs:ignore WordPress.WP.AlternativeFunctions.file_system_operations_file_put_contents
                file_put_contents( $file_path, $img_bytes );
                set_transient( $transient_key, $file_path, 90 * DAY_IN_SECONDS );

                ob_end_clean();
                header( 'Content-Type: image/png' );
                header( 'Content-Length: ' . strlen( $img_bytes ) );
                header( 'Cache-Control: public, max-age=86400' );
                echo $img_bytes;
                exit;
            }

            // Download failed but we have the CDN URL — cache it (legacy format)
            // so the next request proxies it from the "Legacy format" branch above.
            set_transient( $transient_key, $microlink_cdn, 24 * HOUR_IN_SECONDS );
            // Fall through to serve GD card for this immediate request.
        }

        // Microlink timed out or failed — fall back to GD card so Discord always
        // shows something. Also fire the background attempt as a safety net; it
        // might succeed on hosts that do allow loopback requests.
        self::mlp_trigger_bg_screenshot( $token );

        // Immediately serve a GD-generated code-preview card so Discord always
        // shows an image on first embed — no external round-trip, no timeout.
        if ( ! function_exists( 'imagecreatetruecolor' ) ) {
            ob_end_clean();
            $fallback = get_site_icon_url( 256 );
            if ( $fallback ) {
                wp_redirect( $fallback );
            } else {
                status_header( 503 );
            }
            exit;
        }

        // ── Extract first-tab HTML source ─────────────────────────────────────
        // Mirror the same priority used in mlp_handle_preview_endpoint so the
        // embed always shows the user's actual edited code, not the stale
        // top-level 'html' field which holds the original default template.
        $raw_pl   = [];
        if ( ! empty( $record['payload'] ) ) {
            $decoded = json_decode( $record['payload'], true );
            if ( is_array( $decoded ) ) $raw_pl = $decoded;
        }
        $html_src = isset( $raw_pl['html'] ) ? (string) $raw_pl['html'] : '';
        // Fall back to savedTabs when allTabs is absent — this happens for projects
        // that were published with only saved (💾) tabs and no active editing session.
        $all_tabs = ( isset( $raw_pl['allTabs'] ) && is_array( $raw_pl['allTabs'] ) && count( $raw_pl['allTabs'] ) > 0 )
            ? $raw_pl['allTabs']
            : ( ( isset( $raw_pl['savedTabs'] ) && is_array( $raw_pl['savedTabs'] ) )
                ? $raw_pl['savedTabs']
                : [] );

        if ( count( $all_tabs ) === 1 ) {
            // Single-tab: tab content wins over the stale top-level field.
            $sole_tab = reset( $all_tabs );
            if ( is_array( $sole_tab ) ) {
                $tab_html = '';
                if ( isset( $sole_tab['html'] ) && $sole_tab['html'] !== '' ) {
                    $tab_html = (string) $sole_tab['html'];
                } elseif ( isset( $sole_tab['content'] ) && $sole_tab['content'] !== '' ) {
                    $tab_html = (string) $sole_tab['content'];
                }
                if ( $tab_html !== '' ) $html_src = $tab_html;
            }
        } elseif ( count( $all_tabs ) > 1 ) {
            // Multi-tab: prefer the HTML-labelled tab, fall back to first tab.
            $tab_html_found = '';
            $first_tab_html = '';
            $is_first       = true;
            foreach ( $all_tabs as $tab_item ) {
                if ( ! is_array( $tab_item ) ) continue;
                $tab_content = '';
                if ( isset( $tab_item['html'] ) && $tab_item['html'] !== '' ) {
                    $tab_content = (string) $tab_item['html'];
                } elseif ( isset( $tab_item['content'] ) && $tab_item['content'] !== '' ) {
                    $tab_content = (string) $tab_item['content'];
                }
                if ( $is_first ) { $first_tab_html = $tab_content; $is_first = false; }
                if ( $tab_html_found === '' && $tab_content !== '' ) {
                    $tab_label = strtolower( isset( $tab_item['name'] ) ? (string) $tab_item['name'] : ( isset( $tab_item['title'] ) ? (string) $tab_item['title'] : '' ) );
                    if ( $tab_label === 'html' || strpos( $tab_label, '.html' ) !== false ) {
                        $tab_html_found = $tab_content;
                    }
                }
            }
            $resolved = ( $tab_html_found !== '' ) ? $tab_html_found : $first_tab_html;
            if ( $resolved !== '' ) $html_src = $resolved;
        }

        // ── Extract visible rendered text from the HTML ───────────────────────
        // Truncate to 30 KB before any regex work — large HTML documents (full
        // pages with big <style> blocks) can cause PCRE to hit its backtrack
        // limit or PHP's execution-time limit, which would return a 500 error
        // instead of a valid PNG and make Discord suppress the entire embed.
        $html_src_safe = mb_substr( $html_src, 0, 30000 );
        // Remove script/style so their source text doesn't appear in the preview.
        $html_work = preg_replace( '/<(script|style)[^>]*>.*?<\/(script|style)>/si', '', $html_src_safe );
        $preview_items = [];
        if ( preg_match_all(
            '/<(h[1-6]|p|li|dt|dd|blockquote|figcaption|th|td|label|a|strong|b|em|i|span|div|section|article|header|footer|main|nav)[^>]*>(.*?)<\/\1>/si',
            $html_work,
            $bm
        ) ) {
            foreach ( $bm[1] as $bi => $btag ) {
                $btext = trim( strip_tags( $bm[2][$bi] ) );
                if ( $btext === '' ) continue;
                $preview_items[] = [ 'tag' => strtolower( $btag ), 'text' => $btext ];
            }
        }
        if ( empty( $preview_items ) ) {
            $plain = trim( strip_tags( $html_work ) );
            foreach ( preg_split( '/\r?\n+/', $plain ) as $pl ) {
                $pl = trim( $pl );
                if ( $pl !== '' ) $preview_items[] = [ 'tag' => 'p', 'text' => $pl ];
            }
        }

        $meta      = self::mlp_record_meta( $record );
        $proj_name = $meta['name'];
        $author    = $meta['author'];
        $site      = get_bloginfo( 'name' );

        $W = 1200; $H = 630;
        $img = imagecreatetruecolor( $W, $H );

        // ── Colours ───────────────────────────────────────────────────────────
        $c_bg        = imagecolorallocate( $img,  13,  17,  23 ); // #0d1117 dark header bg
        $c_bar       = imagecolorallocate( $img, 234,  88,  12 ); // #ea580c orange
        $c_border    = imagecolorallocate( $img,  48,  54,  61 ); // #30363d
        $c_white     = imagecolorallocate( $img, 230, 237, 243 ); // #e6edf3
        $c_muted     = imagecolorallocate( $img, 110, 118, 129 ); // #6e7681
        $c_accent    = imagecolorallocate( $img, 234,  88,  12 ); // orange
        $c_prev_bg   = imagecolorallocate( $img, 255, 255, 255 ); // white preview
        $c_prev_bdr  = imagecolorallocate( $img, 208, 215, 222 ); // #d0d7de border
        $c_prev_h1   = imagecolorallocate( $img,  13,  17,  23 ); // near-black
        $c_prev_h2   = imagecolorallocate( $img,  36,  41,  47 ); // dark grey
        $c_prev_p    = imagecolorallocate( $img,  87,  96, 106 ); // medium grey

        // ── Full dark background ──────────────────────────────────────────────
        imagefilledrectangle( $img, 0, 0, $W, $H, $c_bg );

        // ── Top orange accent bar ─────────────────────────────────────────────
        imagefilledrectangle( $img, 0, 0, $W, 5, $c_bar );

        // ── Dark header bar ───────────────────────────────────────────────────
        $header_h = 70;

        // Badge
        imagefilledrectangle( $img, 20, 12, 60, 48, $c_accent );
        $bt = '</>';
        imagestring( $img, 3, 20 + intval( ( 40 - strlen( $bt ) * imagefontwidth( 3 ) ) / 2 ), 21, $bt, $c_white );

        // Site name
        imagestring( $img, 2, 70, 16, $site, $c_muted );

        // Project name (truncated to fit)
        $fn5w = imagefontwidth( 5 );
        $max5 = intval( ( $W - 90 ) / $fn5w );
        $pdisp = mb_strlen( $proj_name ) > $max5 ? mb_substr( $proj_name, 0, $max5 - 1 ) . '…' : $proj_name;
        imagestring( $img, 5, 70, 30, $pdisp, $c_white );

        // Author
        if ( $author ) {
            imagestring( $img, 2, 70, 52, 'by ' . $author, $c_muted );
        }

        // "Open & remix" on the right of the header
        $remix_txt = 'Open & remix for free';
        $remix_x   = $W - strlen( $remix_txt ) * imagefontwidth( 2 ) - 20;
        imagestring( $img, 2, $remix_x, 52, $remix_txt, $c_accent );

        // Divider below header
        imagefilledrectangle( $img, 0, $header_h, $W, $header_h + 1, $c_border );

        // ── Full-width white preview area ─────────────────────────────────────
        $pv_x1 = 0;
        $pv_y1 = $header_h + 2;
        $pv_x2 = $W;
        $pv_y2 = $H - 5;
        imagefilledrectangle( $img, $pv_x1, $pv_y1, $pv_x2, $pv_y2, $c_prev_bg );

        // Render extracted text items
        $px   = $pv_x1 + 24;
        $py   = $pv_y1 + 20;
        $pmax = $pv_x2 - $px - 24;

        foreach ( $preview_items as $pitem ) {
            $ptag  = $pitem['tag'];
            $ptext = $pitem['text'];

            if ( $ptag === 'h1' ) {
                $pfn = 5; $pclr = $c_prev_h1; $gap_before = 8; $gap_after = 10;
            } elseif ( in_array( $ptag, [ 'h2', 'h3' ], true ) ) {
                $pfn = 4; $pclr = $c_prev_h1; $gap_before = 6; $gap_after = 8;
            } elseif ( in_array( $ptag, [ 'h4', 'h5', 'h6' ], true ) ) {
                $pfn = 3; $pclr = $c_prev_h2; $gap_before = 4; $gap_after = 6;
            } elseif ( in_array( $ptag, [ 'strong', 'b', 'em', 'i' ], true ) ) {
                $pfn = 3; $pclr = $c_prev_h2; $gap_before = 2; $gap_after = 4;
            } else {
                $pfn = 2; $pclr = $c_prev_p; $gap_before = 2; $gap_after = 8;
            }

            $py += $gap_before;
            $fw_p    = imagefontwidth( $pfn );
            $fh_p    = imagefontheight( $pfn );
            $chr_max = max( 1, intval( $pmax / $fw_p ) );
            $wrapped = wordwrap( $ptext, $chr_max, "\n", true );
            foreach ( explode( "\n", $wrapped ) as $wl ) {
                if ( $py + $fh_p > $pv_y2 - 12 ) break 2;
                imagestring( $img, $pfn, $px, $py, $wl, $pclr );
                $py += $fh_p + 3;
            }
            $py += $gap_after;
        }

        if ( empty( $preview_items ) ) {
            $et = 'No preview available';
            imagestring( $img, 3, $px, $pv_y1 + 20, $et, $c_prev_p );
        }

        // ── Bottom orange accent bar ──────────────────────────────────────────
        imagefilledrectangle( $img, 0, $H - 5, $W, $H, $c_bar );

        // ── Serve PNG ─────────────────────────────────────────────────────────
        // Discard any stray PHP output (notices, warnings) accumulated during
        // image generation so they don't corrupt the PNG byte stream.
        ob_end_clean();
        header( 'Content-Type: image/png' );
        header( 'Cache-Control: public, max-age=86400' ); // 24 h fallback; real screenshot caches 90d
        header( 'Vary: User-Agent' );
        imagepng( $img );
        imagedestroy( $img );
        exit;
    }

    /**
     * Returns a CodePen-style iframe embed code for a given share token.
     * The iframe src points to the standalone HTML preview endpoint
     * (?mlp_html_preview=TOKEN), which renders the project's HTML, CSS,
     * and JS as a self-contained page — identical to how CodePen pens work.
     *
     * @param  string $token   The share token.
     * @param  string $title   The project name (used for the iframe title attribute).
     * @param  int    $height  Iframe height in pixels (default 300).
     * @return string          Ready-to-paste HTML embed code.
     */
    public static function mlp_get_embed_code( $token, $title = '', $height = 300 ) {
        $src   = esc_url( home_url( '/?mlp_html_preview=' . rawurlencode( $token ) ) );
        $title = $title ? esc_attr( $title ) : 'Embedded Project';
        return '<iframe'
             . ' height="' . absint( $height ) . '"'
             . ' style="width:100%;"'
             . ' scrolling="no"'
             . ' title="' . $title . '"'
             . ' src="' . $src . '"'
             . ' frameborder="no"'
             . ' loading="lazy"'
             . ' allowtransparency="true"'
             . ' allowfullscreen="true">'
             . '</iframe>';
    }

    /**
     * AJAX endpoint: returns the CodePen-style iframe embed code for a token.
     *
     * POST params: nonce (mlp_share_project), token
     */
    public static function ajax_get_embed_code() {
        if ( ! check_ajax_referer( 'mlp_share_project', 'nonce', false ) ) {
            wp_send_json_error( [ 'message' => 'Invalid request.' ], 403 );
        }

        $token = isset( $_POST['token'] ) ? sanitize_key( wp_unslash( $_POST['token'] ) ) : '';
        if ( $token === '' ) {
            wp_send_json_error( [ 'message' => 'Missing token.' ], 400 );
        }

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || empty( $record['payload'] ) || ! empty( $record['admin_deleted'] ) ) {
            wp_send_json_error( [ 'message' => 'Project not found.' ], 404 );
        }

        $payload = json_decode( $record['payload'], true );
        $name    = ( is_array( $payload ) && ! empty( $payload['name'] ) )
            ? $payload['name']
            : 'Embedded Project';

        wp_send_json_success( [
            'embed_code' => self::mlp_get_embed_code( $token, $name ),
        ] );
    }

    /**
     * Background AJAX handler — called via a non-blocking self-request from
     * mlp_handle_og_image_endpoint() the first time a project's OG image is
     * requested.  Fetches a Microlink screenshot and caches it so the next
     * Discord embed refresh shows the real project preview instead of the GD card.
     *
     * Auth: simple HMAC key (wp_hash) — no nonce needed for a fire-and-forget
     * internal request.  Logged-in and logged-out both allowed (nopriv).
     */
    public static function ajax_bg_fetch_screenshot() {
        $token = isset( $_POST['token'] ) ? sanitize_key( wp_unslash( $_POST['token'] ) ) : '';
        $key   = isset( $_POST['key']   ) ? sanitize_text_field( wp_unslash( $_POST['key'] ) ) : '';

        // Verify the simple HMAC key to block arbitrary external calls.
        if ( $token === '' || $key !== substr( wp_hash( 'mlp_bg_' . $token ), 0, 16 ) ) {
            wp_die( '', '', [ 'response' => 403 ] );
        }

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || ! empty( $record['admin_deleted'] ) ) {
            wp_die();
        }

        // Use the same version-aware transient key used by mlp_handle_og_image_endpoint.
        // This ensures the cached screenshot always corresponds to the correct
        // version of the project — a new publish updates the key, so stale
        // screenshots from a previous version are never served.
        $version       = isset( $record['updated'] ) ? (int) $record['updated']
                       : ( isset( $record['created'] ) ? (int) $record['created'] : time() );
        $transient_key = 'mlp_ogimg_' . $token . ( $version > 0 ? '_' . $version : '' );

        // Already cached by a concurrent request — nothing to do.
        if ( get_transient( $transient_key ) ) {
            wp_die();
        }

        // Append the record's updated/created timestamp as a cache-buster.
        // Microlink caches screenshots by URL, so without this a republished
        // project would keep showing the old screenshot indefinitely.
        $preview_url    = home_url( '/?mlp_html_preview=' . rawurlencode( $token ) . '&_v=' . $version );
        $screenshot_url = self::mlp_fetch_microlink_screenshot( $preview_url );
        if ( $screenshot_url ) {
            // Download the screenshot bytes and save them as a local file.
            // The image endpoint can then serve bytes directly (readfile) which
            // is always reliable — no redirect to an external CDN that may expire.
            $img_resp = wp_remote_get( $screenshot_url, [ 'timeout' => 20, 'sslverify' => false ] );
            if ( ! is_wp_error( $img_resp ) && wp_remote_retrieve_response_code( $img_resp ) === 200 ) {
                $img_bytes = wp_remote_retrieve_body( $img_resp );
                if ( strlen( $img_bytes ) > 500 ) {
                    $upload    = wp_upload_dir();
                    $cache_dir = $upload['basedir'] . '/mlp-og-cache';
                    wp_mkdir_p( $cache_dir );
                    $file_path = $cache_dir . '/' . $transient_key . '.png';
                    file_put_contents( $file_path, $img_bytes );
                    set_transient( $transient_key, $file_path, 90 * DAY_IN_SECONDS );
                } else {
                    set_transient( $transient_key, $screenshot_url, 90 * DAY_IN_SECONDS );
                }
            } else {
                // Download failed — store URL as fallback for legacy proxy path.
                set_transient( $transient_key, $screenshot_url, 90 * DAY_IN_SECONDS );
            }
        }

        wp_die();
    }
}

