/* ── WordPress user deletion → wipe that user's share records ──────────── */
add_action( 'deleted_user', function( $user_id ) {
    $user = get_userdata( $user_id );
    if ( ! $user ) {
        return;
    }
    $display_name = $user->display_name;
    $login        = $user->user_login;

    global $wpdb;
    $rows = $wpdb->get_results(
        "SELECT option_name, option_value FROM {$wpdb->options}
         WHERE option_name LIKE 'mlp\_share\_%'",
        ARRAY_A
    );

    foreach ( $rows as $row ) {
        $data = maybe_unserialize( $row['option_value'] );
        if ( ! is_array( $data ) ) {
            continue;
        }
        $shared_by = isset( $data['shared_by'] ) ? (string) $data['shared_by'] : '';
        if ( $shared_by === '' ) {
            continue;
        }
        if ( $shared_by === $display_name || $shared_by === $login ) {
            delete_option( $row['option_name'] );
        }
    }
} );

/* ── Frontend "Delete my published projects" button ── wp_footer output ── */
add_action( 'wp_footer', function() {
    if ( ! is_admin() ) {
        $nonce    = wp_create_nonce( 'mlp_share_project' );
        $ajax_url = admin_url( 'admin-ajax.php' );
        ?>
<script id="mlp-delete-my-shares-widget">
(function(){
    'use strict';
    var NONCE = <?php echo wp_json_encode( $nonce ); ?>;
    var AJAX  = <?php echo wp_json_encode( $ajax_url ); ?>;

    document.addEventListener('click', function(e) {
        var btn = e.target.closest('#mlp-delete-my-shares-btn');
        if (!btn) return;
        e.stopPropagation();
        if (btn.disabled) return;
        if (!window.confirm('This will permanently delete ALL your published share links from the server. This cannot be undone. Continue?')) return;

        var ids = [];
        try {
            var raw = localStorage.getItem('mlp_projects');
            if (raw) {
                var projects = JSON.parse(raw);
                if (Array.isArray(projects)) {
                    projects.forEach(function(p) { if (p && p.id) ids.push(String(p.id)); });
                }
            }
        } catch(ex) {}

        if (ids.length === 0) {
            window.alert('No local projects found — nothing to delete.');
            return;
        }

        btn.disabled = true;
        btn.textContent = 'Deleting\u2026';

        var fd = new FormData();
        fd.append('action', 'mlp_delete_my_shares');
        fd.append('nonce',  NONCE);
        ids.forEach(function(id) { fd.append('project_ids[]', id); });

        fetch(AJAX, { method: 'POST', body: fd, credentials: 'same-origin' })
            .then(function(r) { return r.json(); })
            .then(function(resp) {
                var count = (resp && resp.success && resp.data) ? (resp.data.deleted || 0) : 0;
                window.alert('Done \u2014 ' + count + ' published project(s) deleted from the server.');
            })
            .catch(function() { window.alert('Could not reach the server. Please try again.'); })
            .finally(function() {
                btn.disabled = false;
                btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/><path d="M9 6V4h6v2"/></svg> Delete my published projects';
            });
    });
})();
</script>
        <?php
    }
}, 20 );

/* ======================================================================== */
/*  MLP Projects — Admin Dashboard                                           */
/* ======================================================================== */

if ( ! class_exists( 'MLP_Projects_Admin' ) ) :

class MLP_Projects_Admin {

    const PER_PAGE      = 10;
    const IGNORED_OPT   = 'mlp_admin_ignored_tokens'; // tokens admin has "Ignored & Safe"
    const DELETED_OPT   = 'mlp_admin_deleted_tokens'; // tokens admin has "Deleted" (project set private)

    /* ── Boot ─────────────────────────────────────────────────────────── */
    public static function init() {
        add_action( 'admin_menu',  [ __CLASS__, 'register_menu'    ] );
        add_action( 'admin_enqueue_scripts', [ __CLASS__, 'enqueue_assets' ] );
        add_action( 'wp_ajax_mlp_admin_ignore_project',   [ __CLASS__, 'ajax_ignore'        ] );
        add_action( 'wp_ajax_mlp_admin_delete_project',   [ __CLASS__, 'ajax_delete'        ] );
        add_action( 'wp_ajax_mlp_admin_unban_project',    [ __CLASS__, 'ajax_unban'         ] );
        add_action( 'wp_ajax_mlp_admin_unban_by_url',     [ __CLASS__, 'ajax_unban_by_url'  ] );
        add_action( 'wp_ajax_mlp_admin_refresh_thumb',    [ __CLASS__, 'ajax_refresh_thumb' ] );
    }

    /* ── AJAX: Refresh Preview — clears OG image cache and regenerates screenshot ── */
    public static function ajax_refresh_thumb() {
        check_ajax_referer( 'mlp_admin_action', 'nonce' );
        if ( ! current_user_can( 'manage_options' ) ) wp_send_json_error( [], 403 );
        $token = sanitize_key( $_POST['token'] ?? '' );
        if ( ! $token ) wp_send_json_error( [ 'message' => 'Missing token.' ], 400 );

        // Clear cached OG screenshot so the next call regenerates it.
        delete_transient( 'mlp_ogimg_' . $token );

        // Pre-generate immediately and cache so it's ready right away.
        $preview_url = home_url( '/?mlp_html_preview=' . $token );
        $image_url   = MLP_Projects::mlp_resolve_screenshot( $preview_url, $token );
        set_transient( 'mlp_ogimg_' . $token, $image_url, 90 * DAY_IN_SECONDS );

        wp_send_json_success( [ 'image_url' => $image_url ] );
    }

    /* ── Admin menu ───────────────────────────────────────────────────── */
    public static function register_menu() {
        add_menu_page(
            'MLP Published Projects',
            'MLP Projects',
            'manage_options',
            'mlp-published-projects',
            [ __CLASS__, 'render_page' ],
            'dashicons-share',
            30
        );
    }

    /* ── Enqueue page styles (only on our page) ───────────────────────── */
    public static function enqueue_assets( $hook ) {
        if ( $hook !== 'toplevel_page_mlp-published-projects' ) return;
        wp_add_inline_style( 'wp-admin', self::get_admin_css() );
    }

    /* ── Increment fork counter ────────────────────────────────────── */
    /**
     * Records a fork event for a shared project. Called when a non-owner
     * forks a project from the Explore view. Per-IP deduplication uses a
     * 24-hour transient so multiple forks of the same token from one IP
     * only count once per day.
     *
     * POST: nonce (mlp_share_project), token
     */
    public static function ajax_increment_fork() {
        if ( ! check_ajax_referer( 'mlp_share_project', 'nonce', false ) ) {
            wp_send_json_error( [ 'message' => 'Invalid request.' ], 403 );
        }

        $token = isset( $_POST['token'] ) ? sanitize_key( wp_unslash( $_POST['token'] ) ) : '';
        if ( $token === '' ) {
            wp_send_json_error( [ 'message' => 'Missing token.' ], 400 );
        }

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) || empty( $record['payload'] ) ) {
            wp_send_json_error( [ 'message' => 'Share link not found.' ], 404 );
        }
        if ( ! empty( $record['admin_deleted'] ) ) {
            wp_send_json_error( [ 'message' => 'This project is no longer available.' ], 410 );
        }

        // Increment fork counter (JS button disables after first click to prevent spam)
        $current = isset( $record['forks'] ) ? intval( $record['forks'] ) : 0;
        $record['forks']     = $current + 1;
        $record['forked_at'] = time();
        update_option( 'mlp_share_' . $token, $record, false );

        wp_send_json_success( [
            'token' => $token,
            'forks' => $record['forks'],
        ] );
    }


    /* ── Collect all shared projects from wp_options ─────────────────── */
    private static function get_all_shared_projects() {
        global $wpdb;
        $rows = $wpdb->get_results(
            "SELECT option_name, option_value FROM {$wpdb->options}
             WHERE option_name LIKE 'mlp_share_%'
             ORDER BY option_id DESC",
            ARRAY_A
        );
        $projects = [];
        foreach ( $rows as $row ) {
            $token = substr( $row['option_name'], strlen( 'mlp_share_' ) );
            $data  = maybe_unserialize( $row['option_value'] );
            if ( ! is_array( $data ) || empty( $data['payload'] ) ) continue;
            $payload = json_decode( $data['payload'], true );
            $share_url = home_url( '/?mlpsht=' . $token );
            $projects[] = [
                'token'        => $token,
                'created'      => $data['created']      ?? 0,
                'updated'      => $data['updated']      ?? null,
                'name'         => $payload['name']      ?? 'Untitled',
                'sharedBy'     => $payload['sharedBy']  ?? '',
                'shareUrl'     => $share_url,
                'html'         => $payload['html']      ?? '',
                'css'          => $payload['css']       ?? '',
                'js'           => $payload['js']        ?? '',
                'savedTabs'    => $payload['savedTabs'] ?? [],
                'allTabs'      => $payload['allTabs']   ?? [],
                'republished'  => ! empty( $data['updated'] ),
                'admin_deleted'=> ! empty( $data['admin_deleted'] ),
                'banned_at'    => $data['admin_banned_at'] ?? null,
            ];
        }
        return $projects;
    }

    /* ── AJAX: Ignore & Safe ──────────────────────────────────────────── */
    public static function ajax_ignore() {
        check_ajax_referer( 'mlp_admin_action', 'nonce' );
        if ( ! current_user_can( 'manage_options' ) ) wp_send_json_error( [], 403 );
        $token = sanitize_key( $_POST['token'] ?? '' );
        if ( ! $token ) wp_send_json_error( [ 'message' => 'Missing token.' ], 400 );
        $ignored = get_option( self::IGNORED_OPT, [] );
        if ( ! in_array( $token, $ignored, true ) ) {
            $ignored[] = $token;
            update_option( self::IGNORED_OPT, $ignored, false );
        }
        wp_send_json_success();
    }

    /* ── AJAX: Ban Project (admin — soft-hides the project, data is kept) ── */
    public static function ajax_delete() {
        check_ajax_referer( 'mlp_admin_action', 'nonce' );
        if ( ! current_user_can( 'manage_options' ) ) wp_send_json_error( [], 403 );
        $token = sanitize_key( $_POST['token'] ?? '' );
        if ( ! $token ) wp_send_json_error( [ 'message' => 'Missing token.' ], 400 );

        // Soft-ban: set admin_deleted flag on the record instead of permanently
        // erasing it. This allows the admin to unban the project later.
        $record = get_option( 'mlp_share_' . $token, null );
        if ( is_array( $record ) ) {
            $record['admin_deleted']   = true;
            $record['admin_banned_at'] = time();
            update_option( 'mlp_share_' . $token, $record, false );
        }

        // Track in banned list (admin reference / audit trail).
        $deleted = get_option( self::DELETED_OPT, [] );
        if ( ! in_array( $token, $deleted, true ) ) {
            $deleted[] = $token;
            update_option( self::DELETED_OPT, $deleted, false );
        }

        // Return the token so the JS can mark the project as private in the frontend.
        wp_send_json_success( [ 'token' => $token ] );
    }

    /* ── AJAX: Unban Project (admin — clears admin_deleted flag, restores project) ── */
    public static function ajax_unban() {
        check_ajax_referer( 'mlp_admin_action', 'nonce' );
        if ( ! current_user_can( 'manage_options' ) ) wp_send_json_error( [], 403 );
        $token = sanitize_key( $_POST['token'] ?? '' );
        if ( ! $token ) wp_send_json_error( [ 'message' => 'Missing token.' ], 400 );

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) ) {
            wp_send_json_error( [ 'message' => 'Project not found.' ], 404 );
            return;
        }

        // Clear the ban flags.
        unset( $record['admin_deleted'] );
        unset( $record['admin_banned_at'] );
        unset( $record['admin_unbanned_at'] );
        update_option( 'mlp_share_' . $token, $record, false );

        // Remove from banned/deleted tracking list.
        $deleted = get_option( self::DELETED_OPT, [] );
        $deleted = array_values( array_filter( $deleted, function( $t ) use ( $token ) {
            return $t !== $token;
        } ) );
        update_option( self::DELETED_OPT, $deleted, false );

        $share_url = home_url( '/?mlpsht=' . $token );

        wp_send_json_success( [
            'token'     => $token,
            'share_url' => $share_url,
        ] );
    }

    /* ── AJAX: Unban Project by URL (admin — looks up token from a share URL) ── */
    public static function ajax_unban_by_url() {
        check_ajax_referer( 'mlp_admin_action', 'nonce' );
        if ( ! current_user_can( 'manage_options' ) ) wp_send_json_error( [], 403 );

        $url = isset( $_POST['url'] ) ? sanitize_text_field( wp_unslash( $_POST['url'] ) ) : '';
        if ( ! $url ) wp_send_json_error( [ 'message' => 'Missing URL.' ], 400 );

        // Extract the share token from ?mlpsht=TOKEN or /mlp-share/TOKEN.
        $token  = '';
        $parsed = wp_parse_url( $url );
        if ( ! empty( $parsed['query'] ) ) {
            parse_str( $parsed['query'], $qvars );
            if ( ! empty( $qvars['mlpsht'] ) ) {
                $token = sanitize_key( $qvars['mlpsht'] );
            }
        }
        if ( ! $token && ! empty( $parsed['path'] ) ) {
            if ( preg_match( '#/mlp-share/([a-z0-9_-]+)#i', $parsed['path'], $m ) ) {
                $token = sanitize_key( $m[1] );
            }
        }

        if ( ! $token ) {
            wp_send_json_error( [ 'message' => 'Could not extract a valid share token from the URL. Make sure the URL contains ?mlpsht=TOKEN or /mlp-share/TOKEN.' ], 400 );
            return;
        }

        $record = get_option( 'mlp_share_' . $token, null );
        if ( ! is_array( $record ) ) {
            wp_send_json_error( [ 'message' => 'No project found for this URL (token: ' . esc_html( $token ) . ').' ], 404 );
            return;
        }

        if ( empty( $record['admin_deleted'] ) ) {
            wp_send_json_success( [ 'token' => $token, 'already_active' => true, 'message' => 'This project is already active (not banned).' ] );
            return;
        }

        // Clear the ban flags.
        unset( $record['admin_deleted'] );
        unset( $record['admin_banned_at'] );
        unset( $record['admin_unbanned_at'] );
        update_option( 'mlp_share_' . $token, $record, false );

        $deleted_list = get_option( self::DELETED_OPT, [] );
        $deleted_list = array_values( array_filter( $deleted_list, function( $t ) use ( $token ) {
            return $t !== $token;
        } ) );
        update_option( self::DELETED_OPT, $deleted_list, false );

        $share_url = home_url( '/?mlpsht=' . $token );

        wp_send_json_success( [
            'token'          => $token,
            'already_active' => false,
            'message'        => 'Project successfully unbanned.',
            'share_url'      => $share_url,
        ] );
    }

    /* ── Render the admin page ────────────────────────────────────────── */
    public static function render_page() {
        if ( ! current_user_can( 'manage_options' ) ) {
            wp_die( 'Access denied.' );
        }

        $all_projects = self::get_all_shared_projects();
        $ignored      = get_option( self::IGNORED_OPT, [] );
        $nonce        = wp_create_nonce( 'mlp_admin_action' );
        $ajax_url     = admin_url( 'admin-ajax.php' );

        // Separate: today vs rest vs banned, filtered by ignored
        $today_start  = strtotime( 'today midnight' );
        $today        = [];
        $all_active   = [];
        $all_banned   = [];

        foreach ( $all_projects as $p ) {
            $is_ignored = in_array( $p['token'], $ignored, true );
            $is_banned  = ! empty( $p['admin_deleted'] );

            if ( $is_banned ) {
                $all_banned[] = $p;
                continue; // Banned projects get their own section, not the active ones
            }

            // "Today" = created today OR republished today, and not ignored
            $last_action = $p['updated'] ?? $p['created'];
            $is_today    = ( $last_action >= $today_start );
            if ( ! $is_ignored && $is_today ) {
                $today[] = $p;
            }
            if ( ! $is_ignored ) {
                $all_active[] = $p;
            }
        }

        // Pagination for all active projects
        $total      = count( $all_active );
        $per_page   = self::PER_PAGE;
        $page       = max( 1, intval( $_GET['paged'] ?? 1 ) );
        $total_pages = max( 1, (int) ceil( $total / $per_page ) );
        $page       = min( $page, $total_pages );
        $offset     = ( $page - 1 ) * $per_page;
        $page_items = array_slice( $all_active, $offset, $per_page );

        $admin_url_base = admin_url( 'admin.php?page=mlp-published-projects' );

        ?>
        <div class="wrap mlp-admin-wrap">
            <h1 class="mlp-admin-title">
                <span class="dashicons dashicons-share" style="font-size:26px;width:26px;height:26px;margin-right:8px;vertical-align:middle;color:#6d28d9;"></span>
                MLP — Published Projects
            </h1>
            <p class="mlp-admin-subtitle">All projects shared by users. Use <strong>Ignore &amp; Safe</strong> to clear from view (reappears if republished). Use <strong>Ban</strong> to hide the project (soft-delete — data is kept, user sees an Appeal prompt). Use <strong>Unban</strong> to restore a banned project.</p>

            <!-- Unban by URL -->
            <div class="mlp-unban-url-wrap">
                <label for="mlp-unban-url-input" style="font-size:13px;font-weight:600;display:block;margin-bottom:6px;">🔓 Unban a project by its share URL</label>
                <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
                    <input type="text" id="mlp-unban-url-input" class="mlp-search-input-bar" placeholder="Paste share URL here (e.g. https://…/?mlpsht=abc123)" style="max-width:520px;flex:1;" autocomplete="off" spellcheck="false" />
                    <button id="mlp-unban-url-btn" class="mlp-btn-unban" style="white-space:nowrap;">🔓 Unban Project</button>
                </div>
                <div id="mlp-unban-url-result" style="margin-top:8px;font-size:13px;min-height:20px;"></div>
            </div>

            <!-- Search bar -->
            <div class="mlp-search-bar-wrap">
                <div class="mlp-search-icon">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
                </div>
                <input
                    type="text"
                    id="mlp-admin-search"
                    class="mlp-search-input-bar"
                    placeholder="Search by project name, owner, or share URL…"
                    autocomplete="off"
                    spellcheck="false"
                />
                <button id="mlp-search-clear" class="mlp-search-clear" title="Clear search" style="display:none;">&#x2715;</button>
                <span id="mlp-search-results-count" class="mlp-search-results-count" style="display:none;"></span>
            </div>
            <!-- Search results panel (shown when searching) -->
            <div id="mlp-search-results-section" class="mlp-admin-section mlp-admin-search-section" style="display:none;">
                <div class="mlp-admin-section-header">
                    <span class="mlp-admin-section-dot" style="background:#0ea5e9;box-shadow:0 0 0 3px #e0f2fe;"></span>
                    <h2 class="mlp-admin-section-title">Search Results <span class="mlp-admin-count-chip" id="mlp-search-match-count">0</span></h2>
                </div>
                <div class="mlp-admin-grid" id="mlp-search-grid"></div>
                <div id="mlp-search-empty" class="mlp-admin-empty" style="display:none;">No projects match your search.</div>
            </div>

            <?php /* ── TODAY section ── */ ?>
            <div class="mlp-admin-section mlp-admin-today-section">
                <div class="mlp-admin-section-header">
                    <span class="mlp-admin-section-dot mlp-dot-today"></span>
                    <h2 class="mlp-admin-section-title">Codes Published &amp; Republished Today
                        <span class="mlp-admin-count-chip"><?php echo count( $today ); ?></span>
                    </h2>
                </div>
                <?php if ( empty( $today ) ) : ?>
                    <div class="mlp-admin-empty">No projects published or republished today.</div>
                <?php else : ?>
                    <div class="mlp-admin-grid" id="mlp-today-grid">
                        <?php foreach ( $today as $p ) : ?>
                            <?php self::render_card( $p, $nonce, $ajax_url, true ); ?>
                        <?php endforeach; ?>
                    </div>
                <?php endif; ?>
            </div>

            <?php /* ── ALL ACTIVE section ── */ ?>
            <div class="mlp-admin-section">
                <div class="mlp-admin-section-header">
                    <span class="mlp-admin-section-dot mlp-dot-all"></span>
                    <h2 class="mlp-admin-section-title">All Published Projects
                        <span class="mlp-admin-count-chip"><?php echo $total; ?></span>
                    </h2>
                    <?php if ( $total_pages > 1 ) : ?>
                        <span class="mlp-admin-page-info">Page <?php echo $page; ?> of <?php echo $total_pages; ?></span>
                    <?php endif; ?>
                </div>

                <?php if ( empty( $all_active ) ) : ?>
                    <div class="mlp-admin-empty">No published projects yet.</div>
                <?php else : ?>
                    <div class="mlp-admin-grid" id="mlp-all-grid">
                        <?php foreach ( $page_items as $p ) : ?>
                            <?php self::render_card( $p, $nonce, $ajax_url, false ); ?>
                        <?php endforeach; ?>
                    </div>

                    <?php if ( $total_pages > 1 ) : ?>
                        <div class="mlp-admin-pagination">
                            <?php if ( $page > 1 ) : ?>
                                <a class="mlp-page-btn" href="<?php echo esc_url( add_query_arg( 'paged', $page - 1, $admin_url_base ) ); ?>">&#8592; Prev</a>
                            <?php endif; ?>
                            <?php for ( $i = 1; $i <= $total_pages; $i++ ) : ?>
                                <?php if ( abs( $i - $page ) <= 2 || $i === 1 || $i === $total_pages ) : ?>
                                    <a class="mlp-page-btn <?php echo $i === $page ? 'mlp-page-current' : ''; ?>"
                                       href="<?php echo esc_url( add_query_arg( 'paged', $i, $admin_url_base ) ); ?>">
                                        <?php echo $i; ?>
                                    </a>
                                <?php elseif ( abs( $i - $page ) === 3 ) : ?>
                                    <span class="mlp-page-ellipsis">&hellip;</span>
                                <?php endif; ?>
                            <?php endfor; ?>
                            <?php if ( $page < $total_pages ) : ?>
                                <a class="mlp-page-btn" href="<?php echo esc_url( add_query_arg( 'paged', $page + 1, $admin_url_base ) ); ?>">Next &#8594;</a>
