    /* ──────────────────────────────────────────────────────────────────
     *  JavaScript
     * ────────────────────────────────────────────────────────────────── */
    public static function output_js() {
        ?>
<script>
(function () {
    'use strict';

    /* ─────────────  Storage helpers  ───────────── */
    var LS_PROJECTS    = 'mlp_projects';
    var LS_GIST_TOKEN  = 'mlp_gist_token';
    var LS_GIST_ID     = 'mlp_gist_id';
    var LS_LAST_SYNC   = 'mlp_gist_last_sync';
    var LS_GH_META     = 'mlp_github_meta';      // per-project github metadata

    function getToken()   { try { return localStorage.getItem(LS_GIST_TOKEN) || ''; } catch(e) { return ''; } }
    function getGistId()  { try { return localStorage.getItem(LS_GIST_ID)    || ''; } catch(e) { return ''; } }
    function getLastSync(){ try { return localStorage.getItem(LS_LAST_SYNC)  || ''; } catch(e) { return ''; } }

    function getProjects() {
        try { var raw = localStorage.getItem(LS_PROJECTS); if (!raw) return []; var v = JSON.parse(raw); return Array.isArray(v) ? v : []; }
        catch(e){ return []; }
    }
    function saveProjects(arr) {
        try { localStorage.setItem(LS_PROJECTS, JSON.stringify(arr)); } catch(e) {}
        /* Debounce: rapid Gist syncs batch into a single render 400 ms after
           the last write instead of re-rendering the full card grid on every push */
        try {
            if (typeof window._mlpRenderProjects === 'function') {
                if (window._mlpGhSyncRenderTimer) clearTimeout(window._mlpGhSyncRenderTimer);
                window._mlpGhSyncRenderTimer = setTimeout(function() {
                    window._mlpGhSyncRenderTimer = null;
                    try { window._mlpRenderProjects(); } catch(e2) {}
                }, 400);
            }
        } catch(e) {}
    }
    function getMeta() {
        try { var raw = localStorage.getItem(LS_GH_META); if (!raw) return {}; var v = JSON.parse(raw); return (v && typeof v==='object') ? v : {}; }
        catch(e){ return {}; }
    }
    function saveMeta(m) {
        try { localStorage.setItem(LS_GH_META, JSON.stringify(m)); } catch(e) {}
    }
    function getProjectMeta(id) {
        var m = getMeta(); return (m[id] && typeof m[id]==='object') ? m[id] : {};
    }
    function setProjectMeta(id, patch) {
        var m = getMeta(); m[id] = Object.assign({}, m[id] || {}, patch || {}); saveMeta(m); return m[id];
    }

    function toast(title, msg, type, durationMs) {
        try {
            if (typeof window._mlpShowToast === 'function') {
                window._mlpShowToast(title, msg, type || 'info', durationMs || 4000);
                return;
            }
        } catch(e) {}
        try { console.log('[MLP-GH]', title, '—', msg); } catch(e) {}
    }

    function escHtml(s) {
        return String(s == null ? '' : s).replace(/[&<>"']/g, function(c){
            return { '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#39;' }[c];
        });
    }

    /* ─────────────  GitHub API wrapper  ───────────── */
    function gh(path, opts) {
        opts = opts || {};
        var token = getToken();
        if (!token) return Promise.reject(new Error('NO_TOKEN'));
        var url = path.indexOf('http') === 0 ? path : ('https://api.github.com' + path);
        var headers = Object.assign({
            'Authorization': 'token ' + token,
            'Accept':        'application/vnd.github+json',
            'X-GitHub-Api-Version': '2022-11-28'
        }, opts.headers || {});
        if (opts.body && typeof opts.body !== 'string') {
            headers['Content-Type'] = 'application/json';
            opts.body = JSON.stringify(opts.body);
        }
        return fetch(url, { method: opts.method || 'GET', headers: headers, body: opts.body || undefined })
            .then(function(res) {
                return res.text().then(function(text) {
                    var json = null;
                    try { json = text ? JSON.parse(text) : null; } catch(e) { json = null; }
                    if (!res.ok) {
                        var err = new Error((json && json.message) || ('HTTP ' + res.status));
                        err.status = res.status;
                        err.body   = json;
                        throw err;
                    }
                    return { data: json, headers: res.headers };
                });
            });
    }

    // Cached "/user" lookup so we don't keep re-asking GitHub
    var _ghUser = null;
    function getGhUser() {
        if (_ghUser) return Promise.resolve(_ghUser);
        return gh('/user').then(function(r){ _ghUser = r.data; return _ghUser; });
    }

    // Token scope check (only meaningful for classic ghp_ tokens)
    function getTokenScopes() {
        var token = getToken();
        if (!token) return Promise.resolve([]);
        return fetch('https://api.github.com/user', {
            headers: { 'Authorization': 'token ' + token, 'Accept': 'application/vnd.github+json' }
        }).then(function(res) {
            var hdr = res.headers.get('X-OAuth-Scopes') || '';
            return hdr.split(',').map(function(s){return s.trim();}).filter(Boolean);
        }).catch(function(){ return []; });
    }

    /* ─────────────  Project content → file map  ───────────── */
    // Pull HTML / CSS / JS out of a project. Falls back to the most
    // recently edited tab of each language so this works regardless of
    // which custom-tab structure the user has.
    function projectToFiles(p) {
        var files = { 'index.html': '', 'style.css': '', 'script.js': '' };
        if (!p) return files;
        var tabs = (p.tabs && typeof p.tabs === 'object') ? p.tabs : null;
        function pickFromArr(arr) {
            if (!Array.isArray(arr)) return '';
            var best = null;
            for (var i = 0; i < arr.length; i++) {
                var t = arr[i];
                if (!t) continue;
                if (!best) { best = t; continue; }
                if ((t.updatedAt || 0) > (best.updatedAt || 0)) best = t;
            }
            return (best && (best.content || best.code || best.value)) || '';
        }
        if (tabs) {
            files['index.html'] = pickFromArr(tabs.html) || (tabs.htmlContent || '');
            files['style.css']  = pickFromArr(tabs.css)  || (tabs.cssContent  || '');
            files['script.js']  = pickFromArr(tabs.js)   || (tabs.jsContent   || '');
        }
        // Bare-string fallbacks used by older projects
        if (!files['index.html'] && typeof p.html === 'string') files['index.html'] = p.html;
        if (!files['style.css']  && typeof p.css  === 'string') files['style.css']  = p.css;
        if (!files['script.js']  && typeof p.js   === 'string') files['script.js']  = p.js;

        // Drop fully empty files so Gist doesn't reject the request
        Object.keys(files).forEach(function(k){ if (!files[k]) delete files[k]; });
        if (!Object.keys(files).length) files['index.html'] = '<!-- empty project -->';
        return files;
    }

    // Wrap raw files into the shape the Gists API expects
    function filesToGistPayload(files) {
        var out = {};
        Object.keys(files).forEach(function(name){ out[name] = { content: files[name] }; });
        return out;
    }

    // Base64 (UTF-8 safe) used by the Contents API
    function b64Utf8(str) {
        try {
            return btoa(unescape(encodeURIComponent(String(str || ''))));
        } catch(e) { return btoa(String(str || '')); }
    }

    /* ─────────────  Modal show/hide helpers  ───────────── */
    function showModal(id) {
        var el = document.getElementById(id);
        if (el) el.style.display = 'flex';
    }
    function hideModal(id) {
        var el = document.getElementById(id);
        if (el) el.style.display = 'none';
    }

    /* ─────────────  Inject extra dropdown items  ─────────────
     * The whole injected block is wrapped in a single container that
     * stays hidden until a Gist token AND a valid backup Gist id both
     * exist in localStorage. This matches the expectation that GitHub
     * options should only surface once the user has actually connected
     * to a working Gist (so we never show menu items that would just
     * fail with "no token" toasts). */
    function injectDropdownItems() {
        var dd = document.getElementById('mlp-github-dropdown');
        if (!dd || dd.dataset.mlpGhExt === '1') return;
        dd.dataset.mlpGhExt = '1';

        var html = ''
            + '<div id="mlp-gh-ext-wrap" style="display:none;">'

            +   '<div class="mlp-gh-ext-divider"></div>'
            +   '<div class="mlp-gh-ext-section">Backup Gist</div>'

            +   '<button class="mlp-profile-dropdown-item" id="mlp-gh-dd-open-gist" role="menuitem" type="button">'
            +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">'
            +       '<path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/>'
            +     '</svg>'
            +     'Open backup Gist'
            +   '</button>'

            +   '<button class="mlp-profile-dropdown-item" id="mlp-gh-dd-history" role="menuitem" type="button">'
            +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">'
            +       '<path d="M3 12a9 9 0 1 0 3-6.7"/><polyline points="3 4 3 10 9 10"/><polyline points="12 7 12 12 16 14"/>'
            +     '</svg>'
            +     'Backup history &amp; restore'
            +   '</button>'

            +   '<div class="mlp-gh-ext-divider"></div>'
            +   '<div class="mlp-gh-ext-section">Per-project</div>'

            +   '<button class="mlp-profile-dropdown-item" id="mlp-gh-dd-project" role="menuitem" type="button">'
            +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">'
            +       '<path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/>'
            +     '</svg>'
            +     'Project on GitHub …'
            +   '</button>'

            + '</div>';

        dd.insertAdjacentHTML('beforeend', html);

        document.getElementById('mlp-gh-dd-open-gist').addEventListener('click', function(e){
            e.stopPropagation();
            closeGithubDropdownSafe();
            openBackupGist();
        });
        document.getElementById('mlp-gh-dd-history').addEventListener('click', function(e){
            e.stopPropagation();
            closeGithubDropdownSafe();
            openHistoryModal();
        });
        document.getElementById('mlp-gh-dd-project').addEventListener('click', function(e){
            e.stopPropagation();
            closeGithubDropdownSafe();
            openProjectPicker();
        });

        // Re-check visibility every time the dropdown is opened so the
        // GitHub items appear automatically right after the user saves
        // their Gist token / completes their first backup push.
        var ghBtn = document.getElementById('mlp-github-btn');
        if (ghBtn) ghBtn.addEventListener('click', function(){
            // Run twice: once now (for "open" state) and once on the next
            // animation frame (in case the dropdown re-renders its items).
            refreshDropdownState();
            requestAnimationFrame(refreshDropdownState);
        });

        // Cross-tab sync: if the token / gist id is set in another tab
        // (e.g. the token modal was just submitted), update visibility.
        window.addEventListener('storage', function(ev){
            if (!ev || !ev.key) return;
            if (ev.key === LS_GIST_TOKEN || ev.key === LS_GIST_ID) {
                refreshDropdownState();
            }
        });

        // Same-tab sync: poll lightly so the items appear within a second
        // after the user pastes a token or after the auto-backup creates
        // the first Gist id (no other clean hook fires in this codebase).
        setInterval(refreshDropdownState, 1500);

        refreshDropdownState();
    }

    function refreshDropdownState() {
        var wrap = document.getElementById('mlp-gh-ext-wrap');
        if (!wrap) return;
        var token  = getToken();
        var gistId = getGistId();
        // Whole block hidden until BOTH token and a valid backup Gist exist.
        wrap.style.display = (token && gistId) ? '' : 'none';
    }
    function closeGithubDropdownSafe() {
        var dd = document.getElementById('mlp-github-dropdown');
        if (dd) dd.style.display = 'none';
        var btn = document.getElementById('mlp-github-btn');
        if (btn) btn.setAttribute('aria-expanded', 'false');
        var caret = document.getElementById('mlp-github-caret');
        if (caret) caret.classList.remove('mlp-profile-caret-open');
    }

    /* ─────────────  1. Open backup Gist on GitHub  ───────────── */
    function openBackupGist() {
        var gid = getGistId();
        if (!gid) {
            toast('No backup yet', 'Connect a Gist token and save a project first to create a backup Gist.', 'warning', 5000);
            return;
        }
        window.open('https://gist.github.com/' + gid, '_blank', 'noopener');
    }

    /* ─────────────  2. Backup Gist history + restore  ───────────── */
    function openHistoryModal() {
        var token = getToken(), gid = getGistId();
        if (!token || !gid) {
            toast('Backup not connected', 'Add a Gist token and let it create a backup first.', 'warning', 5000);
            return;
        }
        var status = document.getElementById('mlp-gh-history-status');
        var list   = document.getElementById('mlp-gh-history-list');
        list.innerHTML = '';
        status.innerHTML = '<span class="mlp-gh-spin"></span> Loading revisions…';
        showModal('mlp-gh-history-modal');

        gh('/gists/' + gid + '/commits?per_page=30').then(function(r) {
            status.textContent = '';
            var commits = r.data || [];
            if (!commits.length) {
                list.innerHTML = '<p style="font-size:.78rem;color:var(--mlp-text-muted);text-align:center;padding:18px 0;">No revisions found yet.</p>';
                return;
            }
            list.innerHTML = commits.map(function(c, i) {
                var when  = c.committed_at ? new Date(c.committed_at).toLocaleString() : '';
                var sha   = (c.version || '').slice(0, 7);
                var label = (i === 0 ? 'Latest' : (i === commits.length - 1 ? 'Oldest' : ('#' + (commits.length - i))));
                return ''
                    + '<div class="mlp-gh-hist-row">'
                    +   '<div class="mlp-gh-hist-meta">'
                    +     '<strong>' + escHtml(label) + '</strong> · ' + escHtml(when)
                    +     '<small>' + escHtml(sha) + '</small>'
                    +   '</div>'
                    +   '<button class="mlp-gh-mini-btn mlp-gh-mini-btn-primary" data-sha="' + escHtml(c.version) + '">Restore</button>'
                    + '</div>';
            }).join('');
            list.querySelectorAll('button[data-sha]').forEach(function(btn){
                btn.addEventListener('click', function() {
                    if (!confirm('Restore your project library to this revision?\n\nA safety backup of the current state will be pushed to GitHub first.')) return;
                    restoreGistRevision(btn.getAttribute('data-sha'), btn);
                });
            });
        }).catch(function(err){
            status.style.color = 'var(--mlp-danger, #dc2626)';
            status.textContent = '✗ ' + (err.message || 'Failed to load revisions.');
        });
    }
    function restoreGistRevision(sha, btn) {
        if (btn) { btn.disabled = true; btn.innerHTML = '<span class="mlp-gh-spin"></span>'; }
        var gid = getGistId();
        // Push current state as a safety snapshot first
        var current = getProjects();
        var safety = gh('/gists/' + gid, {
            method: 'PATCH',
            body: { files: { 'mlp-projects-backup.json': { content: JSON.stringify(current, null, 2) } } }
        }).catch(function(){ /* non-fatal */ });
        safety.then(function() {
            return gh('/gists/' + gid + '/' + sha);
        }).then(function(r) {
            var files = (r.data && r.data.files) || {};
            var fname = Object.keys(files)[0];
            if (!fname) throw new Error('Revision is empty.');
            var content = files[fname].content || '';
            var arr;
            try { arr = JSON.parse(content); } catch(e) { throw new Error('Backup file is not valid JSON.'); }
            if (!Array.isArray(arr)) throw new Error('Backup is not a project array.');
            saveProjects(arr);
            toast('Restored', 'Library reverted to selected revision.', 'success', 4000);
            hideModal('mlp-gh-history-modal');
        }).catch(function(err){
            if (btn) { btn.disabled = false; btn.textContent = 'Restore'; }
            toast('Restore failed', err.message || 'Could not restore that revision.', 'error', 5000);
        });
    }

    /* ─────────────  3. Project picker  ───────────── */
    function openProjectPicker() {
        var token = getToken();
        if (!token) {
            toast('Add a Gist token first', 'Open the GitHub menu → Gist Token to connect your account.', 'warning', 5000);
            return;
        }
        var listEl = document.getElementById('mlp-gh-pick-list');
        var emptyEl = document.getElementById('mlp-gh-pick-empty');
        var projects = getProjects();
        var meta = getMeta();
        listEl.innerHTML = '';
        if (!projects.length) {
            emptyEl.style.display = '';
            showModal('mlp-gh-pick-modal');
            return;
        }
        emptyEl.style.display = 'none';
        listEl.innerHTML = projects.map(function(p) {
            var pm = (meta[p.id] && typeof meta[p.id] === 'object') ? meta[p.id] : {};
            var badges = [];
            if (pm.gistId) badges.push('<span class="mlp-gh-badge mlp-gh-badge-gist">Gist</span>');
            if (pm.repo && pm.repo.name) badges.push('<span class="mlp-gh-badge mlp-gh-badge-repo">Repo</span>');
            if (pm.repo && pm.repo.pagesEnabled) badges.push('<span class="mlp-gh-badge mlp-gh-badge-pages">Pages</span>');
            return ''
                + '<div class="mlp-gh-pick-row" data-id="' + escHtml(p.id) + '">'
                +   '<div class="mlp-gh-pick-emoji">' + escHtml(p.emoji || '📁') + '</div>'
                +   '<div class="mlp-gh-pick-name">'
                +     '<div class="mlp-gh-pick-name-line">' + escHtml(p.name || 'Untitled project') + '</div>'
                +     (badges.length ? ('<div class="mlp-gh-pick-sub">' + badges.join('') + '</div>') : '')
                +   '</div>'
                + '</div>';
        }).join('');
        listEl.querySelectorAll('.mlp-gh-pick-row').forEach(function(row){
            row.addEventListener('click', function() {
                var id = row.getAttribute('data-id');
                hideModal('mlp-gh-pick-modal');
                openProjectActions(id);
            });
        });
        showModal('mlp-gh-pick-modal');
    }

    /* ─────────────  4. Per-project actions modal  ───────────── */
    var _activeProjectId = null;

    function openProjectActions(id) {
        var p = getProjects().find(function(x){ return x && x.id === id; });
        if (!p) { toast('Project not found', 'It may have been deleted.', 'error', 4000); return; }
        _activeProjectId = id;
        renderProjectActions(p);
        showModal('mlp-gh-actions-modal');
    }
    function renderProjectActions(p) {
        var titleEl = document.getElementById('mlp-gh-actions-title');
        var bodyEl  = document.getElementById('mlp-gh-actions-body');
        titleEl.innerHTML = '<span style="font-size:1rem;">' + escHtml(p.emoji || '📁') + '</span>'
                          + '<span style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + escHtml(p.name || 'Untitled') + '</span>';

        var pm = getProjectMeta(p.id);
        var hasGist = !!pm.gistId;

        var html = '';

        // ── Card 1: Single-project Gist ──
        html += '<div class="mlp-gh-actions-card">'
              +   '<div class="mlp-gh-actions-card-title">'
              +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M12 .5C5.65.5.5 5.65.5 12c0 5.08 3.29 9.39 7.86 10.91.58.11.79-.25.79-.56 0-.27-.01-1-.02-1.96-3.2.7-3.87-1.54-3.87-1.54-.52-1.33-1.27-1.69-1.27-1.69-1.04-.71.08-.7.08-.7 1.15.08 1.76 1.18 1.76 1.18 1.02 1.75 2.68 1.25 3.34.96.1-.74.4-1.25.73-1.54-2.55-.29-5.24-1.28-5.24-5.69 0-1.26.45-2.28 1.18-3.09-.12-.29-.51-1.46.11-3.05 0 0 .96-.31 3.16 1.18a10.95 10.95 0 0 1 5.75 0c2.2-1.49 3.16-1.18 3.16-1.18.62 1.59.23 2.76.11 3.05.74.81 1.18 1.83 1.18 3.09 0 4.42-2.69 5.4-5.25 5.68.41.36.78 1.07.78 2.16 0 1.56-.01 2.82-.01 3.21 0 .31.21.68.79.56C20.21 21.39 23.5 17.08 23.5 12 23.5 5.65 18.35.5 12 .5z"/></svg>'
              +     (hasGist ? 'Single-project Gist' : 'Save project as Gist')
              +   '</div>'
              +   '<div class="mlp-gh-actions-card-desc">'
              +     'A Gist that holds just this project\'s files. Updates the existing Gist on subsequent saves.'
              +   '</div>'
              +   '<div class="mlp-gh-actions-card-buttons">';
        if (!hasGist) {
            html += '<button class="mlp-gh-mini-btn mlp-gh-mini-btn-primary" id="mlp-gh-act-savegist">Save as Gist</button>';
        } else {
            html += '<button class="mlp-gh-mini-btn mlp-gh-mini-btn-primary" id="mlp-gh-act-updategist">Update Gist</button>'
                 +  '<button class="mlp-gh-mini-btn" id="mlp-gh-act-opengist">Open on GitHub</button>'
                 +  '<button class="mlp-gh-mini-btn" id="mlp-gh-act-previewgist">Preview rendered</button>'
                 +  '<button class="mlp-gh-mini-btn" id="mlp-gh-act-sharelink" title="Copy gistpreview.github.io share link to clipboard">'
                 +    '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg>'
                 +    ' Copy share link'
                 +  '</button>'
                 +  '<button class="mlp-gh-mini-btn mlp-gh-mini-btn-danger" id="mlp-gh-act-unlinkgist">Unlink</button>';
        }
        html +=   '</div>';
        if (hasGist) {
            html += '<div class="mlp-gh-status-line">'
                  +   '<a href="https://gist.github.com/' + escHtml(pm.gistId) + '" target="_blank" rel="noopener">' + escHtml(pm.gistId) + '</a>'
                  +   (pm.gistUpdatedAt ? ' &middot; last pushed ' + escHtml(new Date(pm.gistUpdatedAt).toLocaleString()) : '')
                  + '</div>';
            html += '<div class="mlp-gh-actions-card-buttons" style="margin-top:8px;">'
                  +   '<button class="mlp-gh-mini-btn" id="mlp-gh-act-togglepreview">'
                  +     '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>'
                  +     ' Inline preview'
                  +   '</button>'
                  + '</div>'
                  + '<div class="mlp-gh-preview-wrap" id="mlp-gh-preview-wrap" style="display:none;">'
                  +   '<iframe id="mlp-gh-preview-frame" class="mlp-gh-preview-frame" allowfullscreen></iframe>'
                  + '</div>';
        }
        html += '</div>';

        // ── Card 2: Download as ZIP ──
        html += '<div class="mlp-gh-actions-card">'
              +   '<div class="mlp-gh-actions-card-title">'
              +     '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>'
              +     'Download as ZIP'
              +   '</div>'
              +   '<div class="mlp-gh-actions-card-desc">'
              +     'Export this project&rsquo;s HTML, CSS and JS files as a local .zip — no GitHub account required.'
              +   '</div>'
              +   '<div class="mlp-gh-actions-card-buttons">'
              +     '<button class="mlp-gh-mini-btn mlp-gh-mini-btn-primary" id="mlp-gh-act-dlzip">Download ZIP</button>'
              +   '</div>'
              + '</div>';

        bodyEl.innerHTML = html;
        wireProjectActionButtons(p);
    }

    function wireProjectActionButtons(p) {
        function on(id, fn) {
            var el = document.getElementById(id);
            if (el) el.addEventListener('click', fn);
        }
        var pm = getProjectMeta(p.id);

        // Single-project Gist
        on('mlp-gh-act-savegist',    function(){ saveProjectAsGist(p, false); });
        on('mlp-gh-act-updategist',  function(){ saveProjectAsGist(p, true);  });
        on('mlp-gh-act-opengist',    function(){
            if (pm.gistId) window.open('https://gist.github.com/' + pm.gistId, '_blank', 'noopener');
        });
        on('mlp-gh-act-previewgist', function(){
            if (pm.gistId) window.open('https://gistpreview.github.io/?' + pm.gistId, '_blank', 'noopener');
        });
        on('mlp-gh-act-unlinkgist',  function(){
            if (!confirm('Unlink this project from its Gist? The Gist on GitHub will not be deleted.')) return;
            setProjectMeta(p.id, { gistId: null, gistUpdatedAt: null });
            renderProjectActions(p);
            toast('Unlinked', 'Project is no longer linked to a Gist.', 'success', 3500);
        });

        // Share link — copy gistpreview URL to clipboard
        on('mlp-gh-act-sharelink', function() {
            var gistId = pm.gistId;
            if (!gistId) return;
            var url = 'https://gistpreview.github.io/?' + gistId;
            function fallback() {
                var ta = document.createElement('textarea');
                ta.value = url;
                ta.style.cssText = 'position:fixed;top:-9999px;left:-9999px;opacity:0;';
                document.body.appendChild(ta);
                ta.focus(); ta.select();
                try {
                    document.execCommand('copy');
                    toast('Copied!', 'Share link copied to clipboard.', 'success', 3000);
                } catch(e) {
                    toast('Copy failed', url, 'info', 6000);
                }
                document.body.removeChild(ta);
            }
            if (navigator.clipboard && navigator.clipboard.writeText) {
                navigator.clipboard.writeText(url).then(function() {
                    toast('Copied!', 'Share link copied to clipboard.', 'success', 3000);
                }).catch(fallback);
            } else { fallback(); }
        });

        // Toggle inline preview
        on('mlp-gh-act-togglepreview', function() {
            var wrap  = document.getElementById('mlp-gh-preview-wrap');
            var frame = document.getElementById('mlp-gh-preview-frame');
            var btn   = document.getElementById('mlp-gh-act-togglepreview');
            if (!wrap || !frame) return;
            var visible = wrap.style.display !== 'none';
            if (visible) {
                wrap.style.display = 'none';
                frame.removeAttribute('srcdoc');
                if (btn) btn.innerHTML = '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg> Inline preview';
            } else {
                var files = projectToFiles(p);
                var srcdoc = '<!DOCTYPE html><html><head><meta charset="utf-8"><style>'
                    + (files['style.css'] || '') + '</style></head><body>'
                    + (files['index.html'] || '')
                    + '<script>' + (files['script.js'] || '') + '<\/script>'
                    + '</body></html>';
                frame.srcdoc = srcdoc;
                wrap.style.display = '';
                if (btn) btn.innerHTML = '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg> Close preview';
            }
        });

        // Download as ZIP
        on('mlp-gh-act-dlzip', function() {
            if (typeof window._mlpExportProjectAsZip === 'function') {
                window._mlpExportProjectAsZip(p);
            } else {
                toast('Not available', 'The ZIP export feature is not loaded yet. Try again in a moment.', 'error', 4000);
            }
        });

    }

    /* ─────────────  5. Save / update single-project Gist  ───────────── */
    function saveProjectAsGist(p, isUpdate) {
        if (!getToken()) { toast('No token', 'Add a Gist token first.', 'warning', 4000); return; }
        var files = projectToFiles(p);
        var pm    = getProjectMeta(p.id);
        var desc  = (p.name || 'Untitled') + ' — Mobile Live Preview project';

        var req;
        if (isUpdate && pm.gistId) {
            req = gh('/gists/' + pm.gistId, {
                method: 'PATCH',
                body: { description: desc, files: filesToGistPayload(files) }
            });
        } else {
            req = gh('/gists', {
                method: 'POST',
                body: { description: desc, public: false, files: filesToGistPayload(files) }
            });
        }
        toast(isUpdate ? 'Updating Gist…' : 'Creating Gist…', 'Talking to GitHub.', 'info', 1500);
        req.then(function(r) {
            var gid = r.data && r.data.id;
            if (!gid) throw new Error('GitHub response had no Gist id.');
            setProjectMeta(p.id, { gistId: gid, gistUpdatedAt: Date.now() });
            toast(isUpdate ? 'Gist updated' : 'Gist created', 'Saved to GitHub.', 'success', 4000);
            var current = getProjects().find(function(x){ return x && x.id === _activeProjectId; });
            if (current) renderProjectActions(current);
        }).catch(function(err){
            toast('Gist failed', err.message || 'Could not save to GitHub.', 'error', 5500);
        });
    }

    /* ─────────────  Public helper: attach a project to a user-supplied Gist ─────────────
     * Used by the New Project modal when the user picks "GitHub Gist" as the
     * storage option. Persists the gist linkage in github meta and pushes the
     * project's current files (HTML/CSS/JS) into that gist via PATCH.
     * Returns a Promise that resolves on success / rejects on failure.
     */
    /* ─────────────  Public helper: create a brand-new private Gist for a project ─────
     * Used by the New Project modal when the user picks "GitHub Gist" storage but
     * doesn't paste an existing Gist URL/ID. Creates a new private Gist on GitHub,
     * stores its id in the github meta map, and resolves with the new gistId.
     */
    window._mlpCreateNewGistForProject = function(p) {
        if (!p)            return Promise.reject(new Error('Missing project.'));
        if (!getToken())   return Promise.reject(new Error('No Gist token. Add one via the GitHub menu first.'));
        var files = projectToFiles(p);
        var desc  = (p.name || 'Untitled') + ' — Mobile Live Preview project';
        return gh('/gists', {
            method: 'POST',
            body:   { description: desc, public: false, files: filesToGistPayload(files) }
        }).then(function(r) {
            var gid = r.data && r.data.id;
            if (!gid) throw new Error('GitHub did not return a Gist id.');
            setProjectMeta(p.id, { gistId: gid, gistUpdatedAt: Date.now() });
            return gid;
        });
    };

    window._mlpAttachProjectToGist = function(p, gistId) {
        if (!p || !gistId)        return Promise.reject(new Error('Missing project or Gist ID.'));
        if (!getToken())          return Promise.reject(new Error('No Gist token. Add one via the GitHub menu first.'));

        // 1) Persist the gist linkage so existing per-project actions (Update Gist,
        //    history, etc.) work seamlessly afterwards.
        setProjectMeta(p.id, { gistId: gistId, gistUpdatedAt: Date.now() });

        // 2) Push the current project files into the user-supplied Gist.
        var files = projectToFiles(p);
        var desc  = (p.name || 'Untitled') + ' — Mobile Live Preview project';
        return gh('/gists/' + encodeURIComponent(gistId), {
            method: 'PATCH',
            body:   { description: desc, files: filesToGistPayload(files) }
        }).then(function(r) {
            setProjectMeta(p.id, { gistId: gistId, gistUpdatedAt: Date.now() });
            return r && r.data;
        });
    };

    /* ─────────────  Test Gist (validate URL/ID + token write access)  ─────────────
     * Performs a HEAD-style GET to confirm the Gist exists and the current token
     * can read it. Then verifies write access by issuing a no-op PATCH (sets the
     * description to itself). Resolves with { id, owner, description, writable }.
     */
    window._mlpTestGist = function(gistId) {
        if (!gistId) return Promise.reject(new Error('Missing Gist ID.'));
        if (!getToken()) return Promise.reject(new Error('No Gist token.'));
        return gh('/gists/' + encodeURIComponent(gistId), { method: 'GET' }).then(function(r) {
            var data = r && r.data || {};
            var desc = data.description || '';
            // No-op PATCH to confirm write access (re-set description to itself)
            return gh('/gists/' + encodeURIComponent(gistId), {
                method: 'PATCH',
                body:   { description: desc }
            }).then(function() {
                return {
                    id:          data.id || gistId,
                    owner:       data.owner && data.owner.login,
                    description: desc,
                    writable:    true
                };
            });
        });
    };

    /* ─────────────  Read per-project gist meta (for the main scope)  ───────────── */
    window._mlpGetProjectGistMeta = function(projectId) {
        if (!projectId) return null;
        try {
            var pm = getProjectMeta(projectId);
            if (!pm || !pm.gistId) return null;
            return { gistId: pm.gistId, gistUpdatedAt: pm.gistUpdatedAt || null };
        } catch(e) { return null; }
    };

    /* ─────────────  Auto-sync linked projects to their gists (debounced)  ─────────────
     * Called from saveProjects() in the main scope after every write. Looks for
     * projects with storage === 'github-gist' and a valid gistId, and pushes them
     * (debounced ~3s) to their gists. Updates the editor sync pill if the active
     * project is being synced.
     */
    var _autoSyncTimers      = {};   // id → setTimeout handle
    var _autoSyncInflight    = {};   // id → bool
    var _autoSyncLastHash    = {};   // id → string (skip if unchanged)
    var _autoSyncFailures    = {};   // id → { count, lastErrorAt }
    var AUTO_SYNC_DEBOUNCE_MS = 3000;

    function _autoSyncHashOfProject(p) {
        try {
            var f = projectToFiles(p);
            return JSON.stringify({
                n: p.name || '',
                h: f['index.html'] || '',
                c: f['style.css']  || '',
                j: f['script.js']  || ''
            });
        } catch(e) { return String(Date.now()); }
    }

    function _setBadgeForProject(projectId, state) {
        // Update any visible storage badge / sync controls for this project row.
        try {
            var badge = document.querySelector('.mlp-storage-badge[data-proj-id="' + projectId + '"]');
            if (badge) {
                badge.classList.remove('mlp-storage-badge-gist','mlp-storage-badge-syncing','mlp-storage-badge-error');
                if (state === 'syncing') badge.classList.add('mlp-storage-badge-syncing');
                else if (state === 'error') badge.classList.add('mlp-storage-badge-error');
                else badge.classList.add('mlp-storage-badge-gist');
            }
        } catch(e) {}
    }

    function _doProjectGistPush(p) {
        if (!p || !p.id) return Promise.resolve();
        var pm = getProjectMeta(p.id);
        var gid = pm.gistId;
        if (!gid) return Promise.resolve();
        if (!getToken()) return Promise.reject(new Error('No Gist token.'));

        var hash = _autoSyncHashOfProject(p);
        if (_autoSyncLastHash[p.id] === hash) {
            return Promise.resolve(); // nothing actually changed
        }

        if (window.mlpCurrentProjectId === p.id) {
            window._mlpUpdateSyncPill && window._mlpUpdateSyncPill('syncing');
        }
        _setBadgeForProject(p.id, 'syncing');
        _autoSyncInflight[p.id] = true;

        var files = projectToFiles(p);
        var desc  = (p.name || 'Untitled') + ' — Mobile Live Preview project';
        return gh('/gists/' + encodeURIComponent(gid), {
            method: 'PATCH',
            body:   { description: desc, files: filesToGistPayload(files) }
        }).then(function() {
            _autoSyncInflight[p.id] = false;
            _autoSyncLastHash[p.id] = hash;
            _autoSyncFailures[p.id] = null;
            setProjectMeta(p.id, { gistId: gid, gistUpdatedAt: Date.now() });
            if (window.mlpCurrentProjectId === p.id) {
                window._mlpUpdateSyncPill && window._mlpUpdateSyncPill('ok');
            }
            _setBadgeForProject(p.id, 'gist');
            // Refresh any visible "last synced" stamp
            try {
                var stampEl = document.querySelector('.mlp-row-lastsync[data-proj-id="' + p.id + '"]');
                if (stampEl) stampEl.textContent = 'Synced just now';
            } catch(e){}
        }).catch(function(err) {
            _autoSyncInflight[p.id] = false;
            var prev = _autoSyncFailures[p.id] || { count: 0 };
            _autoSyncFailures[p.id] = { count: prev.count + 1, lastErrorAt: Date.now(), message: (err && err.message) || 'Sync failed' };
            if (window.mlpCurrentProjectId === p.id) {
                window._mlpUpdateSyncPill && window._mlpUpdateSyncPill('err', _autoSyncFailures[p.id]);
            }
            _setBadgeForProject(p.id, 'error');
            // Don't toast on every silent debounced failure; first one only.
            if (prev.count === 0 && typeof window.showToast === 'function') {
                window.showToast('Gist sync failed', (err && err.message) || 'Could not sync to GitHub. Local copy is still saved.', 'danger', 5000);
            }
        });
    }

    window._mlpAutoSyncProjects = function(arr) {
        if (!Array.isArray(arr) || !arr.length) return;
        if (!getToken()) return; // no token → nothing to sync, silently skip
        for (var i = 0; i < arr.length; i++) {
            var p = arr[i];
            if (!p || p.storage !== 'github-gist') continue;
            var pm = getProjectMeta(p.id);
            if (!pm.gistId) continue;
            (function(proj) {
                if (_autoSyncTimers[proj.id]) clearTimeout(_autoSyncTimers[proj.id]);
                _autoSyncTimers[proj.id] = setTimeout(function() {
                    _autoSyncTimers[proj.id] = null;
                    // Re-read freshest copy before pushing
                    var fresh = getProjects().find(function(x){ return x && x.id === proj.id; });
                    if (!fresh || fresh.storage !== 'github-gist') return;
                    _doProjectGistPush(fresh);
                }, AUTO_SYNC_DEBOUNCE_MS);
            })(p);
        }
    };

    /* ─────────────  Manual "Sync now" — runs immediately, returns promise  ───────────── */
    window._mlpSyncProjectNow = function(projectId) {
        if (!projectId) return Promise.reject(new Error('Missing project id.'));
        if (!getToken()) return Promise.reject(new Error('No Gist token.'));
        if (_autoSyncTimers[projectId]) {
            clearTimeout(_autoSyncTimers[projectId]);
            _autoSyncTimers[projectId] = null;
        }
        var p = getProjects().find(function(x){ return x && x.id === projectId; });
        if (!p) return Promise.reject(new Error('Project not found.'));
        if (p.storage !== 'github-gist') return Promise.reject(new Error('Project is not linked to a Gist.'));
        _autoSyncLastHash[projectId] = ''; // force push even if hash matches
        return _doProjectGistPush(p);
    };

    /* ─────────────  Sync pill updater (called when sync state changes)  ───────────── */
    window._mlpUpdateSyncPill = function(state, info) {
        var pill  = document.getElementById('mlp-sync-pill');
        var label = document.getElementById('mlp-sync-pill-label');
        if (!pill || !label) return;
        pill.classList.remove('mlp-sync-idle','mlp-sync-syncing','mlp-sync-ok','mlp-sync-err');
        pill.style.display = '';
        if (state === 'syncing') {
            pill.classList.add('mlp-sync-syncing');
            label.textContent = 'Syncing…';
            pill.title = 'Pushing changes to GitHub Gist…';
        } else if (state === 'ok') {
            pill.classList.add('mlp-sync-ok');
            label.textContent = 'Synced ✓';
            pill.title = 'All changes pushed to GitHub Gist.';
        } else if (state === 'err') {
            pill.classList.add('mlp-sync-err');
            label.textContent = 'Sync failed';
            pill.title = (info && info.message) ? ('Sync failed: ' + info.message + ' (click to retry)') : 'Sync failed (click to retry)';
        } else if (state === 'hidden') {
            pill.style.display = 'none';
        } else {
            pill.classList.add('mlp-sync-idle');
            label.textContent = 'Local only';
            pill.title = 'This project is stored only on this device.';
        }
    };
    // Click-to-retry on the sync pill
    document.addEventListener('click', function(e) {
        var pill = e.target && e.target.closest && e.target.closest('#mlp-sync-pill');
        if (!pill) return;
        if (!pill.classList.contains('mlp-sync-err')) return;
        var pid = window.mlpCurrentProjectId;
        if (!pid) return;
        window._mlpSyncProjectNow(pid).catch(function(){});
    });

    /* ─────────────  Refresh sync pill when active project changes  ─────────────
     * Called from main scope after window.mlpLoadProject / project switch.
     */
    window._mlpRefreshSyncPillForActive = function() {
        var pid = window.mlpCurrentProjectId;
        if (!pid) { window._mlpUpdateSyncPill('hidden'); return; }
        var p = getProjects().find(function(x){ return x && x.id === pid; });
        if (!p) { window._mlpUpdateSyncPill('hidden'); return; }
        if (p.storage !== 'github-gist') { window._mlpUpdateSyncPill('hidden'); return; }
        var pm = getProjectMeta(pid);
        if (!pm.gistId) { window._mlpUpdateSyncPill('idle'); return; }
        if (_autoSyncInflight[pid]) { window._mlpUpdateSyncPill('syncing'); return; }
        if (_autoSyncFailures[pid]) { window._mlpUpdateSyncPill('err', _autoSyncFailures[pid]); return; }
        window._mlpUpdateSyncPill('ok');
    };

    /* ─────────────  Move existing local project → linked Gist  ───────────── */
    window._mlpMoveProjectToGist = function(projectId, gistId) {
        if (!projectId || !gistId) return Promise.reject(new Error('Missing project or Gist ID.'));
        var projects = getProjects();
        var idx = -1;
        for (var i = 0; i < projects.length; i++) { if (projects[i] && projects[i].id === projectId) { idx = i; break; } }
        if (idx < 0) return Promise.reject(new Error('Project not found.'));
        var p = projects[idx];
        return window._mlpAttachProjectToGist(p, gistId).then(function() {
            // Re-read (attach may have mutated meta) and flip storage flag
            var arr = getProjects();
            for (var j = 0; j < arr.length; j++) {
                if (arr[j] && arr[j].id === projectId) {
                    arr[j].storage   = 'github-gist';
                    arr[j].gistId    = gistId;
                    arr[j].updatedAt = new Date().toISOString();
                    break;
                }
            }
            saveProjects(arr);
        });
    };

    /* ─────────────  Bulk migrate: create a new gist for each local-only project  ───────────── */
    window._mlpBulkMigrateLocalToGist = function(onProgress) {
        if (!getToken()) return Promise.reject(new Error('No Gist token.'));
        var projects = getProjects();
        var locals = projects.filter(function(p){ return p && p.storage !== 'github-gist'; });
        var total  = locals.length;
        var done   = 0, failed = 0;
        if (!total) return Promise.resolve({ total: 0, done: 0, failed: 0 });

        function next(i) {
            if (i >= total) return Promise.resolve({ total: total, done: done, failed: failed });
            var p = locals[i];
            var files = projectToFiles(p);
            var desc  = (p.name || 'Untitled') + ' — Mobile Live Preview project';
            return gh('/gists', {
                method: 'POST',
                body:   { description: desc, public: false, files: filesToGistPayload(files) }
            }).then(function(r) {
                var gid = r.data && r.data.id;
                if (gid) {
                    setProjectMeta(p.id, { gistId: gid, gistUpdatedAt: Date.now() });
                    var arr = getProjects();
                    for (var k = 0; k < arr.length; k++) {
                        if (arr[k] && arr[k].id === p.id) {
                            arr[k].storage = 'github-gist';
                            arr[k].gistId  = gid;
                            arr[k].updatedAt = new Date().toISOString();
                            break;
                        }
                    }
                    saveProjects(arr);
                    done++;
                } else {
                    failed++;
                }
            }).catch(function() {
                failed++;
            }).then(function() {
                if (typeof onProgress === 'function') {
                    try { onProgress({ index: i + 1, total: total, done: done, failed: failed, project: p }); } catch(e){}
                }
                return next(i + 1);
            });
        }
        return next(0);
    };

    /* ─────────────  Wire modal close handlers  ───────────── */
    function wireCloseHandlers() {
        function bind(id, ids) {
            ids.forEach(function(close) {
                var el = document.getElementById(close);
                if (el) el.addEventListener('click', function(){ hideModal(id); });
            });
            var modal = document.getElementById(id);
            if (modal) modal.addEventListener('click', function(e){ if (e.target === modal) hideModal(id); });
        }
        bind('mlp-gh-pick-modal',    ['mlp-gh-pick-close']);
        bind('mlp-gh-actions-modal', ['mlp-gh-actions-close', 'mlp-gh-actions-done']);
        bind('mlp-gh-history-modal', ['mlp-gh-history-close', 'mlp-gh-history-cancel']);
        bind('mlp-import-modal',     ['mlp-import-close', 'mlp-import-cancel']);

        var backBtn = document.getElementById('mlp-gh-actions-back');
        if (backBtn) backBtn.addEventListener('click', function() {
            hideModal('mlp-gh-actions-modal');
            openProjectPicker();
        });

        document.addEventListener('keydown', function(e) {
            if (e.key !== 'Escape') return;
            ['mlp-gh-pick-modal','mlp-gh-actions-modal','mlp-gh-history-modal','mlp-import-modal'].forEach(function(id){
                var m = document.getElementById(id);
                if (m && m.style.display !== 'none' && m.style.display !== '') hideModal(id);
            });
        });
    }

    /* ─────────────  Import modal logic  ───────────── */
    function wireImportModal() {
        // ── Tab switching ──
        var tabBtns = document.querySelectorAll('#mlp-import-modal .mlp-import-tab');
        tabBtns.forEach(function(tab) {
            tab.addEventListener('click', function() {
                var target = tab.getAttribute('data-tab');
                tabBtns.forEach(function(t) { t.classList.remove('mlp-import-tab-active'); });
                tab.classList.add('mlp-import-tab-active');
                ['gist','zip'].forEach(function(name) {
                    var panel = document.getElementById('mlp-import-tab-' + name);
                    if (panel) panel.style.display = (name === target) ? '' : 'none';
                });
            });
        });

        // ── From Gist URL ──
        var gistBtn    = document.getElementById('mlp-import-gist-btn');
        var gistInput  = document.getElementById('mlp-import-gist-url');
        var gistStatus = document.getElementById('mlp-import-gist-status');

        function setGistStatus(msg, isErr) {
            if (gistStatus) { gistStatus.textContent = msg; gistStatus.style.color = isErr ? '#dc2626' : ''; }
        }

        if (gistBtn) {
            gistBtn.addEventListener('click', function() {
                var raw = gistInput ? gistInput.value.trim() : '';
                if (!raw) { setGistStatus('Please enter a Gist URL or ID.', true); return; }

                // Extract bare Gist ID from various URL forms
                var gistId = raw
                    .replace(/^https?:\/\/gist\.github\.com\/[^/]+\//i, '')
                    .replace(/\?.*$/, '').replace(/#.*$/, '')
                    .replace(/\/$/, '').trim();
                // If it still looks like a full URL, try the last path segment
                if (gistId.indexOf('/') !== -1) {
                    gistId = gistId.split('/').filter(Boolean).pop() || '';
                }
                if (!gistId || gistId.length < 4) { setGistStatus('Could not parse a Gist ID from that value.', true); return; }

                setGistStatus('Fetching Gist…');
                gistBtn.disabled = true;

                var token = getToken();
                var headers = { 'Accept': 'application/vnd.github+json', 'X-GitHub-Api-Version': '2022-11-28' };
                if (token) headers['Authorization'] = 'token ' + token;

                fetch('https://api.github.com/gists/' + encodeURIComponent(gistId), { headers: headers })
                    .then(function(res) {
                        if (!res.ok) throw new Error('GitHub returned HTTP ' + res.status + (res.status === 404 ? ' — Gist not found or is private (add a token).' : '.'));
                        return res.json();
                    })
                    .then(function(data) {
                        var gFiles = data.files || {};
                        var html = '', css = '', js = '';
                        Object.keys(gFiles).forEach(function(fname) {
                            var f = gFiles[fname];
                            var ext = fname.split('.').pop().toLowerCase();
                            var content = f.content || '';
                            if (ext === 'html') html = content;
                            else if (ext === 'css') css = content;
                            else if (ext === 'js') js = content;
                        });
                        var now = Date.now();
                        var newP = {
                            id:          'p_' + now + '_' + Math.random().toString(36).slice(2, 9),
                            name:        (data.description || ('Gist ' + gistId.slice(0, 8))).slice(0, 80),
                            emoji:       '📥',
                            html:        html,
                            css:         css,
                            js:          js,
                            createdAt:   now,
                            updatedAt:   now,
                            status:      'private'
                        };
                        var projects = getProjects();
                        projects.unshift(newP);
                        saveProjects(projects);
                        setProjectMeta(newP.id, { gistId: gistId, gistUpdatedAt: now });
                        if (gistInput) gistInput.value = '';
                        setGistStatus('');
                        hideModal('mlp-import-modal');
                        toast('Imported!', '"' + newP.name + '" has been imported from Gist.', 'success', 4500);
                    })
                    .catch(function(err) {
                        setGistStatus(err.message || 'Could not fetch Gist.', true);
                    })
                    .then(function() { gistBtn.disabled = false; });
            });
            // Allow Enter key in the input to trigger import
            if (gistInput) {
                gistInput.addEventListener('keydown', function(e) {
                    if (e.key === 'Enter') gistBtn.click();
                });
            }
        }

        // ── From ZIP / JSON — delegate to the existing backup load input ──
        var zipSelectBtn = document.getElementById('mlp-import-zip-select-btn');
        var zipStatus    = document.getElementById('mlp-import-zip-status');
        if (zipSelectBtn) {
            zipSelectBtn.addEventListener('click', function() {
                var existing = document.getElementById('mlp-load-backup-input');
                if (existing) {
                    existing.value = '';
                    existing.click();
                    hideModal('mlp-import-modal');
                } else {
                    if (zipStatus) zipStatus.textContent = 'Restore input not found — please use the main toolbar restore button.';
                }
            });
        }
    }

    /* ─────────────  Toolbar Import button  ───────────── */
    function wireImportToolbarBtn() {
        var btn = document.getElementById('mlp-gh-import-btn');
        if (!btn) return;
        btn.addEventListener('click', function() {
            // Reset tab to Gist on open
            var gistTab = document.querySelector('#mlp-import-modal .mlp-import-tab[data-tab="gist"]');
            var zipTab  = document.querySelector('#mlp-import-modal .mlp-import-tab[data-tab="zip"]');
            var gistPanel = document.getElementById('mlp-import-tab-gist');
            var zipPanel  = document.getElementById('mlp-import-tab-zip');
            if (gistTab)  { gistTab.classList.add('mlp-import-tab-active');    }
            if (zipTab)   { zipTab.classList.remove('mlp-import-tab-active');  }
            if (gistPanel){ gistPanel.style.display = '';    }
            if (zipPanel) { zipPanel.style.display  = 'none'; }
            var statusEl = document.getElementById('mlp-import-gist-status');
            if (statusEl) statusEl.textContent = '';
            showModal('mlp-import-modal');
        });
    }

    /* ─────────────  Boot  ───────────── */
    function boot() {
        injectDropdownItems();
        wireCloseHandlers();
        wireImportModal();
        wireImportToolbarBtn();
    }
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', boot);
    } else {
        // Slight defer so we run AFTER mlp-projects.php finishes wiring.
        setTimeout(boot, 0);
    }
})();
</script>
        <?php
    }
}


/* Auto-bootstrap: register the GitHub-extension hooks as soon as this file loads.
 * wp_footer only fires on frontend, so this is a no-op in wp-admin. */
MLP_Projects_Github::init();





/* ======================================================================== */
/*  MLP Projects — Analytics in Stats Sidebar                                */
/*                                                                           */
/*  Renders per-share view analytics INSIDE the existing Project Stats       */
/*  sidebar (#mlp-stats-panel → #mlp-stats-views-section), right alongside   */
/*  Lines of Code / Total Size / etc. Adds a real chart, range tabs, and    */
/*  referrer / country / device breakdowns powered by                       */
/*  MLP_Projects::ajax_get_project_analytics().                             */
/* ======================================================================== */

class MLP_Projects_Analytics {

    public static function init() {
        // Run AFTER the main popup CSS/HTML and the GitHub extension so we
        // can attach to the rendered #mlp-stats-views-section in the DOM.
        add_action( 'wp_footer', [ __CLASS__, 'output_styles' ], 7 );
        add_action( 'wp_footer', [ __CLASS__, 'output_js' ],     8 );
    }

    /* Styles — scoped to the existing stats panel so we inherit its
     * tokens (--mlp-surface, --mlp-text, etc.) and look native. */
    public static function output_styles() {
        ?>
<style id="mlp-an-styles">
/* Container injected into #mlp-stats-views-section by JS */
#mlp-projects-overlay .mlp-an-wrap{
    margin-top:14px;
    display:flex; flex-direction:column; gap:14px;
}

/* Range tabs (7 / 30 / 90 days) */
#mlp-projects-overlay .mlp-an-range{
    display:inline-flex; padding:3px;
    background:var(--mlp-border-muted, rgba(148,163,184,0.14));
    border-radius:8px; align-self:flex-start;
}
#mlp-projects-overlay .mlp-an-range-btn{
    background:transparent; border:none; cursor:pointer;
    padding:4px 10px; border-radius:6px;
    font-size:0.7rem; font-weight:600;
    color:var(--mlp-text-muted, #64748b);
    font-family:inherit;
    transition:background .15s, color .15s, box-shadow .15s;
}
#mlp-projects-overlay .mlp-an-range-btn.is-active{
    background:var(--mlp-surface, #fff);
    color:var(--mlp-text, #0f172a);
    box-shadow:0 1px 2px rgba(0,0,0,.08);
}

/* Mini stat row: peak day + countries + top device */
#mlp-projects-overlay .mlp-an-mini{
    display:grid; grid-template-columns:repeat(3, minmax(0,1fr)); gap:6px;
    font-size:0.7rem;
}
#mlp-projects-overlay .mlp-an-mini-cell{
    background:var(--mlp-border-muted, rgba(148,163,184,0.10));
    border-radius:7px; padding:7px 8px; min-width:0;
}
#mlp-projects-overlay .mlp-an-mini-key{
    color:var(--mlp-text-muted, #64748b);
    font-size:0.6rem; font-weight:600;
    letter-spacing:0.04em; text-transform:uppercase;
    margin-bottom:2px;
    white-space:nowrap; overflow:hidden; text-overflow:ellipsis;
}
#mlp-projects-overlay .mlp-an-mini-val{
    color:var(--mlp-text, #0f172a);
    font-weight:700; font-size:0.82rem;
    font-variant-numeric:tabular-nums;
    white-space:nowrap; overflow:hidden; text-overflow:ellipsis;
}

/* Chart card */
