    /* JS — exposes window.mlpRenderProjectAnalytics(token, projectName) which
     * the existing populateStats() call site invokes. */
    public static function output_js() {
        $ajax_url = esc_js( admin_url( 'admin-ajax.php' ) );
        ?>
<script id="mlp-an-js">
(function(){
    'use strict';

    var AJAX_URL = '<?php echo $ajax_url; ?>';

    var DEVICE_ICONS = {
        desktop: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="20" height="14" rx="2"/><path d="M8 21h8M12 17v4"/></svg>',
        mobile:  '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="6" y="2" width="12" height="20" rx="2.5"/><path d="M11 18h2"/></svg>',
        tablet:  '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="4" y="2" width="16" height="20" rx="2"/><path d="M11 18h2"/></svg>'
    };
    var GLOBE_ICON = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2a15.3 15.3 0 0 1 0 20M12 2a15.3 15.3 0 0 0 0 20"/></svg>';

    var state = { token:null, name:'', range:30, data:null };
    var fetchSeq = 0; // guards stale responses

    /* Build (or retrieve) the augment container inside #mlp-stats-views-section. */
    function ensureWrap(){
        var section = document.getElementById('mlp-stats-views-section');
        if(!section) return null;

        // Hide the synthetic sparkline that ships in the section — we replace
        // it with a real, data-backed chart further down.
        var spark = section.querySelector('.mlp-stats-sparkline-wrap');
        if(spark) spark.style.display = 'none';

        var wrap = section.querySelector('.mlp-an-wrap');
        if(wrap) return wrap;

        wrap = document.createElement('div');
        wrap.className = 'mlp-an-wrap';
        wrap.innerHTML =
            '<div class="mlp-an-range" role="tablist">' +
                '<button type="button" role="tab" class="mlp-an-range-btn" data-range="7">7d</button>' +
                '<button type="button" role="tab" class="mlp-an-range-btn is-active" data-range="30">30d</button>' +
                '<button type="button" role="tab" class="mlp-an-range-btn" data-range="90">90d</button>' +
            '</div>' +
            '<div class="mlp-an-mini" id="mlp-an-mini">' +
                '<div class="mlp-an-mini-cell"><div class="mlp-an-mini-key">Range</div><div class="mlp-an-mini-val" id="mlp-an-mini-range">—</div></div>' +
                '<div class="mlp-an-mini-cell"><div class="mlp-an-mini-key">Peak day</div><div class="mlp-an-mini-val" id="mlp-an-mini-peak">—</div></div>' +
                '<div class="mlp-an-mini-cell"><div class="mlp-an-mini-key">Top device</div><div class="mlp-an-mini-val" id="mlp-an-mini-device">—</div></div>' +
            '</div>' +
            '<div class="mlp-an-chart-card">' +
                '<div class="mlp-an-chart-head">' +
                    '<div class="mlp-an-chart-title">Views over time</div>' +
                    '<div class="mlp-an-chart-hint" id="mlp-an-chart-hint">—</div>' +
                '</div>' +
                '<div class="mlp-an-chart-wrap" id="mlp-an-chart-wrap">' +
                    '<svg class="mlp-an-chart" id="mlp-an-chart" preserveAspectRatio="none"></svg>' +
                    '<div class="mlp-an-tooltip" id="mlp-an-tooltip"></div>' +
                '</div>' +
            '</div>' +
            '<div id="mlp-an-refs"></div>' +
            '<div id="mlp-an-countries"></div>' +
            '<div id="mlp-an-devices"></div>';

        section.appendChild(wrap);

        // Range tab clicks
        wrap.querySelectorAll('.mlp-an-range-btn').forEach(function(b){
            b.addEventListener('click', function(){
                var r = parseInt(b.getAttribute('data-range'), 10);
                if(!r || r === state.range) return;
                state.range = r;
                wrap.querySelectorAll('.mlp-an-range-btn').forEach(function(x){
                    x.classList.toggle('is-active', x === b);
                });
                if(state.token) loadAnalytics();
            });
        });

        return wrap;
    }

    /* Public renderer, called from populateStats(). */
    window.mlpRenderProjectAnalytics = function(token, projectName){
        if(!token){ teardown(); return; }
        state.token = token;
        state.name  = projectName || '';
        ensureWrap();
        loadAnalytics();
    };

    /* If the panel is opened on a non-shared / private project, hide the
     * augment so leftover content from a previous project doesn't show. */
    function teardown(){
        var section = document.getElementById('mlp-stats-views-section');
        if(!section) return;
        var wrap = section.querySelector('.mlp-an-wrap');
        if(wrap) wrap.remove();
    }

    /* Fetch + render */
    function loadAnalytics(){
        var wrap = ensureWrap();
        if(!wrap) return;
        var token = state.token, range = state.range, seq = ++fetchSeq;

        // Skeletons
        var hint = document.getElementById('mlp-an-chart-hint');
        if(hint) hint.textContent = 'Last ' + range + ' days';
        var refs = document.getElementById('mlp-an-refs');
        var ctrs = document.getElementById('mlp-an-countries');
        var devs = document.getElementById('mlp-an-devices');
        if(refs) refs.innerHTML = '<div class="mlp-an-skeleton" style="height:42px;"></div>';
        if(ctrs) ctrs.innerHTML = '<div class="mlp-an-skeleton" style="height:42px;"></div>';
        if(devs) devs.innerHTML = '<div class="mlp-an-skeleton" style="height:42px;"></div>';
        var chart = document.getElementById('mlp-an-chart');
        if(chart) chart.innerHTML = '';

        var url = AJAX_URL + '?action=mlp_get_project_analytics'
            + '&token=' + encodeURIComponent(token)
            + '&range=' + encodeURIComponent(range)
            + '&_=' + Date.now();
        fetch(url, { credentials:'same-origin' })
            .then(function(r){ return r.json(); })
            .then(function(j){
                if(seq !== fetchSeq) return;        // stale
                if(!j || !j.success){ renderError(); return; }
                state.data = j.data;
                renderMini(j.data);
                requestAnimationFrame(function(){ drawChart(j.data); });
                renderRefs(j.data);
                renderCountries(j.data);
                renderDevices(j.data);
                requestAnimationFrame(function(){
                    wrap.querySelectorAll('.mlp-an-row-bar-fill[data-w]').forEach(function(b){
                        b.style.width = b.getAttribute('data-w');
                    });
                });
            })
            .catch(function(){ if(seq === fetchSeq) renderError(); });
    }

    function renderError(){
        var refs = document.getElementById('mlp-an-refs');
        if(refs) refs.innerHTML = '<div class="mlp-an-empty">Could not load analytics.</div>';
        var ctrs = document.getElementById('mlp-an-countries'); if(ctrs) ctrs.innerHTML = '';
        var devs = document.getElementById('mlp-an-devices');   if(devs) devs.innerHTML = '';
    }

    function renderMini(d){
        var rangeEl  = document.getElementById('mlp-an-mini-range');
        var peakEl   = document.getElementById('mlp-an-mini-peak');
        var deviceEl = document.getElementById('mlp-an-mini-device');
        if(rangeEl) rangeEl.textContent = formatNum(d.total_range || 0) + ' views';

        if(peakEl){
            if(d.peak && d.peak.views > 0){
                peakEl.textContent = formatNum(d.peak.views) + ' · ' + shortDate(d.peak.date);
            }else{
                peakEl.textContent = '—';
            }
        }

        if(deviceEl){
            var dv = d.devices || {};
            var total = (dv.desktop||0) + (dv.mobile||0) + (dv.tablet||0);
            if(total === 0){
                deviceEl.textContent = '—';
            }else{
                var ent = [['Desktop',dv.desktop||0],['Mobile',dv.mobile||0],['Tablet',dv.tablet||0]];
                ent.sort(function(a,b){ return b[1] - a[1]; });
                var pct = Math.round(ent[0][1] / total * 100);
                deviceEl.textContent = ent[0][0] + ' · ' + pct + '%';
            }
        }
    }

    /* SVG chart with grid, smoothed area+line, hover crosshair, peak marker. */
    function drawChart(d){
        var svg  = document.getElementById('mlp-an-chart');
        var wrap = document.getElementById('mlp-an-chart-wrap');
        var tip  = document.getElementById('mlp-an-tooltip');
        if(!svg || !wrap) return;

        var data = d.daily || [];
        if(!data.length){
            svg.innerHTML = '';
            svg.outerHTML = '<div class="mlp-an-empty" id="mlp-an-chart">No views in this period yet.</div>';
            return;
        }

        var hasViews = data.some(function(p){ return p.views > 0; });
        if(!hasViews){
            svg.innerHTML = '';
            // Soft empty state but keep the chart container, so range switching still works.
            var W0 = Math.max(240, wrap.clientWidth || 240);
            svg.setAttribute('viewBox', '0 0 ' + W0 + ' 120');
            svg.setAttribute('width', W0);
            svg.setAttribute('height', 120);
            svg.innerHTML = '<text class="axis-text" x="' + (W0/2) + '" y="64" text-anchor="middle" style="font-size:10px;">No views in this period</text>';
            if(tip) tip.style.opacity = 0;
            return;
        }

        var W = Math.max(240, wrap.clientWidth || 240);
        var H = 150;
        var pad = { top:10, right:6, bottom:22, left:28 };
        svg.setAttribute('viewBox', '0 0 ' + W + ' ' + H);
        svg.setAttribute('width',  W);
        svg.setAttribute('height', H);

        var maxV = 0;
        data.forEach(function(p){ if(p.views > maxV) maxV = p.views; });
        var yMax = niceMax(Math.max(1, maxV));

        var xStep = (W - pad.left - pad.right) / Math.max(1, data.length - 1);
        var yScale = function(v){ return pad.top + (H - pad.top - pad.bottom) * (1 - (v / yMax)); };
        var xScale = function(i){ return pad.left + i * xStep; };

        var pts = data.map(function(p, i){ return [ xScale(i), yScale(p.views) ]; });
        var linePath = smoothPath(pts);
        var areaPath = linePath +
            ' L ' + pts[pts.length - 1][0] + ' ' + (H - pad.bottom) +
            ' L ' + pts[0][0]               + ' ' + (H - pad.bottom) + ' Z';

        var ticks = 3;
        var grid = '', yLabels = '';
        for(var t = 0; t <= ticks; t++){
            var v = Math.round(yMax * (t / ticks));
            var y = yScale(v);
            grid    += '<line class="grid-line" x1="' + pad.left + '" x2="' + (W - pad.right) + '" y1="' + y + '" y2="' + y + '"/>';
            yLabels += '<text class="axis-text" x="' + (pad.left - 5) + '" y="' + (y + 3) + '" text-anchor="end">' + formatNum(v) + '</text>';
        }

        var xLabels = '';
        var labelCount = Math.min(4, data.length);
        for(var i = 0; i < labelCount; i++){
            var idx = Math.round(i * (data.length - 1) / Math.max(1, labelCount - 1));
            var x   = xScale(idx);
            xLabels += '<text class="axis-text" x="' + x + '" y="' + (H - 8) + '" text-anchor="middle">' + escapeHtml(shortDate(data[idx].date)) + '</text>';
        }

        var peakIdx = -1, peakVal = -1;
        data.forEach(function(p, i){ if(p.views > peakVal){ peakVal = p.views; peakIdx = i; } });
        var peakMarker = '';
        if(peakVal > 0 && peakIdx >= 0){
            peakMarker = '<circle class="peak-marker" cx="' + xScale(peakIdx) + '" cy="' + yScale(peakVal) + '" r="3"/>';
        }

        svg.innerHTML =
            '<defs><linearGradient id="mlp-an-area-grad" x1="0" y1="0" x2="0" y2="1">' +
                '<stop offset="0%"  stop-color="#3b82f6" stop-opacity="0.30"/>' +
                '<stop offset="65%" stop-color="#3b82f6" stop-opacity="0.06"/>' +
                '<stop offset="100%" stop-color="#3b82f6" stop-opacity="0"/>' +
            '</linearGradient></defs>' +
            grid + yLabels +
            '<path class="area-path" d="' + areaPath + '"/>' +
            '<path class="line-path" d="' + linePath + '" stroke-dasharray="1500" stroke-dashoffset="1500">' +
                '<animate attributeName="stroke-dashoffset" from="1500" to="0" dur="0.8s" fill="freeze" calcMode="spline" keySplines="0.22 0.94 0.44 1"/>' +
            '</path>' +
            peakMarker +
            '<line class="hover-line" id="mlp-an-hover-line" x1="0" x2="0" y1="' + pad.top + '" y2="' + (H - pad.bottom) + '" style="opacity:0"/>' +
            '<circle class="hover-dot" id="mlp-an-hover-dot" cx="0" cy="0" r="3.5" style="opacity:0"/>' +
            xLabels +
            '<rect x="' + pad.left + '" y="' + pad.top + '" width="' + (W - pad.left - pad.right) + '" height="' + (H - pad.top - pad.bottom) + '" fill="transparent" id="mlp-an-hit-area"/>';

        var hit  = document.getElementById('mlp-an-hit-area');
        var hLn  = document.getElementById('mlp-an-hover-line');
        var hDot = document.getElementById('mlp-an-hover-dot');

        function setHover(idx){
            if(idx < 0 || idx >= data.length){
                hLn.style.opacity = 0; hDot.style.opacity = 0; if(tip) tip.style.opacity = 0; return;
            }
            var x = xScale(idx), y = yScale(data[idx].views);
            hLn.setAttribute('x1', x); hLn.setAttribute('x2', x); hLn.style.opacity = 1;
            hDot.setAttribute('cx', x); hDot.setAttribute('cy', y); hDot.style.opacity = 1;
            if(tip){
                var rect = svg.getBoundingClientRect();
                tip.innerHTML = '<span class="mlp-an-tooltip-date">' + escapeHtml(formatDate(data[idx].date)) + '</span>' +
                                formatNum(data[idx].views) + (data[idx].views === 1 ? ' view' : ' views');
                tip.style.left = (x * (rect.width / W)) + 'px';
                tip.style.top  = (y * (rect.height / H)) + 'px';
                tip.style.opacity = 1;
            }
        }
        if(hit){
            hit.addEventListener('mousemove', function(e){
                var rect = svg.getBoundingClientRect();
                var localX = (e.clientX - rect.left) * (W / rect.width);
                var idx = Math.round((localX - pad.left) / xStep);
                if(idx < 0) idx = 0;
                if(idx >= data.length) idx = data.length - 1;
                setHover(idx);
            });
            hit.addEventListener('mouseleave', function(){ setHover(-1); });
        }

        if(window.ResizeObserver && !drawChart._observed){
            drawChart._observed = true;
            var ro = new ResizeObserver(function(){
                if(state.data) drawChart(state.data);
            });
            ro.observe(wrap);
        }
    }

    function smoothPath(pts){
        if(!pts.length) return '';
        if(pts.length === 1) return 'M ' + pts[0][0] + ' ' + pts[0][1];
        if(pts.length === 2) return 'M ' + pts[0][0] + ' ' + pts[0][1] + ' L ' + pts[1][0] + ' ' + pts[1][1];
        var d = 'M ' + pts[0][0] + ' ' + pts[0][1];
        for(var i = 0; i < pts.length - 1; i++){
            var p0 = pts[i - 1] || pts[i];
            var p1 = pts[i];
            var p2 = pts[i + 1];
            var p3 = pts[i + 2] || p2;
            var c1x = p1[0] + (p2[0] - p0[0]) / 6;
            var c1y = p1[1] + (p2[1] - p0[1]) / 6;
            var c2x = p2[0] - (p3[0] - p1[0]) / 6;
            var c2y = p2[1] - (p3[1] - p1[1]) / 6;
            d += ' C ' + c1x + ' ' + c1y + ', ' + c2x + ' ' + c2y + ', ' + p2[0] + ' ' + p2[1];
        }
        return d;
    }
    function niceMax(v){
        if(v <= 1) return 1;
        var pow = Math.pow(10, Math.floor(Math.log10(v)));
        var n = v / pow, nice;
        if      (n <= 1) nice = 1;
        else if (n <= 2) nice = 2;
        else if (n <= 5) nice = 5;
        else             nice = 10;
        return nice * pow;
    }

    /* Breakdowns */
    function renderRefs(d){
        var host = document.getElementById('mlp-an-refs');
        if(!host) return;
        var rows = (d.referrers || []).slice();
        if(d.direct_views && d.direct_views > 0){
            rows.push({ host:'__direct__', views:d.direct_views });
        }
        if(!rows.length){
            host.innerHTML = section('Top referrers', '<div class="mlp-an-empty">No referrers yet.</div>');
            return;
        }
        var max = Math.max.apply(null, rows.map(function(r){ return r.views; }));
        var totalCat = rows.reduce(function(s,r){ return s + r.views; }, 0);
        var html = '<div class="mlp-an-rows">';
        rows.forEach(function(r){
            var pct = totalCat > 0 ? Math.round(r.views / totalCat * 100) : 0;
            var label = r.host === '__direct__'
                ? '<span class="mlp-an-row-icon">' + GLOBE_ICON + '</span><span class="mlp-an-row-name">Direct / unknown</span>'
                : '<img class="mlp-an-row-favicon" alt="" loading="lazy" src="https://www.google.com/s2/favicons?sz=32&domain=' + encodeURIComponent(r.host) + '" onerror="this.style.visibility=\'hidden\'"/><span class="mlp-an-row-name">' + escapeHtml(r.host) + '</span>';
            html += '<div class="mlp-an-row">' +
                '<div class="mlp-an-row-label">' + label + '</div>' +
                '<div class="mlp-an-row-stats"><span class="mlp-an-row-views">' + formatNum(r.views) + '</span><span>' + pct + '%</span></div>' +
                '<div class="mlp-an-row-bar"><div class="mlp-an-row-bar-fill" data-w="' + Math.max(2, r.views / max * 100) + '%"></div></div>' +
            '</div>';
        });
        html += '</div>';
        host.innerHTML = section('Top referrers', html);
    }
    function renderCountries(d){
        var host = document.getElementById('mlp-an-countries');
        if(!host) return;
        var rows = d.countries || [];
        if(!rows.length){
            host.innerHTML = section('Countries', '<div class="mlp-an-empty">Country data appears once viewers come in.</div>');
            return;
        }
        var max = Math.max.apply(null, rows.map(function(r){ return r.views; }));
        var totalCat = d.country_total || rows.reduce(function(s,r){ return s + r.views; }, 0);
        var html = '<div class="mlp-an-rows">';
        rows.forEach(function(r){
            var pct = totalCat > 0 ? Math.round(r.views / totalCat * 100) : 0;
            html += '<div class="mlp-an-row">' +
                '<div class="mlp-an-row-label">' +
                    '<span class="mlp-an-row-flag">' + (r.flag || '🌐') + '</span>' +
                    '<span class="mlp-an-row-name">' + escapeHtml(r.name || r.code) + '</span>' +
                '</div>' +
                '<div class="mlp-an-row-stats"><span class="mlp-an-row-views">' + formatNum(r.views) + '</span><span>' + pct + '%</span></div>' +
                '<div class="mlp-an-row-bar"><div class="mlp-an-row-bar-fill" data-w="' + Math.max(2, r.views / max * 100) + '%"></div></div>' +
            '</div>';
        });
        html += '</div>';
        host.innerHTML = section('Countries', html);
    }
    function renderDevices(d){
        var host = document.getElementById('mlp-an-devices');
        if(!host) return;
        var dv = d.devices || {};
        var total = (dv.desktop||0) + (dv.mobile||0) + (dv.tablet||0);
        if(total === 0){
            host.innerHTML = section('Devices', '<div class="mlp-an-empty">No device data yet.</div>');
            return;
        }
        var rows = [
            { key:'desktop', label:'Desktop', views:dv.desktop||0 },
            { key:'mobile',  label:'Mobile',  views:dv.mobile||0  },
            { key:'tablet',  label:'Tablet',  views:dv.tablet||0  }
        ].filter(function(r){ return r.views > 0; })
         .sort(function(a,b){ return b.views - a.views; });
        var max = rows[0].views;
        var html = '<div class="mlp-an-rows">';
        rows.forEach(function(r){
            var pct = Math.round(r.views / total * 100);
            html += '<div class="mlp-an-row">' +
                '<div class="mlp-an-row-label">' +
                    '<span class="mlp-an-row-icon">' + DEVICE_ICONS[r.key] + '</span>' +
                    '<span class="mlp-an-row-name">' + r.label + '</span>' +
                '</div>' +
                '<div class="mlp-an-row-stats"><span class="mlp-an-row-views">' + formatNum(r.views) + '</span><span>' + pct + '%</span></div>' +
                '<div class="mlp-an-row-bar"><div class="mlp-an-row-bar-fill" data-w="' + Math.max(4, r.views / max * 100) + '%"></div></div>' +
            '</div>';
        });
        html += '</div>';
        host.innerHTML = section('Devices', html);
    }
    function section(title, inner){
        return '<div class="mlp-an-section-label">' + escapeHtml(title) + '</div>' + inner;
    }

    /* Helpers */
    function escapeHtml(s){
        return String(s == null ? '' : s)
            .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
            .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
    }
    function formatNum(n){
        n = Number(n) || 0;
        if(n >= 1000000) return (n / 1000000).toFixed(n >= 10000000 ? 0 : 1) + 'M';
        if(n >= 10000)   return (n / 1000).toFixed(0) + 'k';
        if(n >= 1000)    return (n / 1000).toFixed(1) + 'k';
        return String(n);
    }
    function formatDate(iso){
        if(!iso) return '';
        var p = iso.split('-');
        if(p.length !== 3) return iso;
        var d = new Date(parseInt(p[0],10), parseInt(p[1],10) - 1, parseInt(p[2],10));
        if(isNaN(d.getTime())) return iso;
        return d.toLocaleDateString(undefined, { month:'short', day:'numeric', year:'numeric' });
    }
    function shortDate(iso){
        if(!iso) return '';
        var p = iso.split('-');
        if(p.length !== 3) return iso;
        var d = new Date(parseInt(p[0],10), parseInt(p[1],10) - 1, parseInt(p[2],10));
        if(isNaN(d.getTime())) return iso;
        return d.toLocaleDateString(undefined, { month:'short', day:'numeric' });
    }
})();
</script>
        <?php
    }
}

